// ./plugins/rpg_mongo_plugin.js
// Torn-style RPG plugin for Platinum-V2 (MongoDB / Mongoose version) — Weirdos World V14 (Debt, Armory & God-Mode)

const mongoose = require('mongoose');
const { cast, makeSmartQuote } = require('../cast');
const fs = require('fs');
const path = require('path');
const { lidToPhone, cleanPN } = require('../lib/lid'); 

// ── Global connection store — captured from first command, used by background ticks ──
if (!global.wwConn)      global.wwConn      = null;  // WhatsApp connection object
if (!global.wwGameChat)  global.wwGameChat  = null;  // Group JID where the game is played
// Note: wwGameChat is restored from DB inside loadGameConfig() below

// Called by background ticks to broadcast messages to the game group
async function broadcastToGame(text, mentions) {
    try {
        if (!global.wwConn || !global.wwGameChat) return;
        await global.wwConn.sendMessage(global.wwGameChat, {
            text,
            ...(mentions?.length ? { mentions } : {})
        });
    } catch(e) { /* silent — background broadcast failure shouldn't crash tick */ }
}

const MONGO_URI = process.env.MONGO_URI || "mongodb+srv://botUser:susanoo900@cluster0.6m9ra.mongodb.net/?retryWrites=true&w=majority&appName=Cluster0";

async function ensureMongo() {
    try {
        if (mongoose.connection.readyState === 1) return;
        await mongoose.connect(MONGO_URI);
        console.log('✅ RPG plugin connected to MongoDB');
    } catch (e) {
        console.error('❌ RPG plugin failed to connect to MongoDB:', e.message);
    }
}
ensureMongo();

