const FactionSchema = new Schema({
    name: { type: String, required: true, unique: true },
    tag:  { type: String, default: '' },           // short tag like [WW]
    owner: { type: String, required: true }, 
    officers: { type: [String], default: [] },     // officer role — can invite/kick
    members: { type: [String], default: [] },
    funds: { type: Number, default: 0 },
    bank: { type: Number, default: 0 },            // faction bank separate from funds
    armory: { type: Map, of: Number, default: {} },
    prestige: { type: Number, default: 0 },
    level: { type: Number, default: 1 },           // faction level 1-10
    xp: { type: Number, default: 0 },              // faction XP toward next level
    maxMembers: { type: Number, default: 10 },     // grows with level
    territory: { type: String, default: null },    // city they control
    description: { type: String, default: '' },
    // ── COOLDOWNS ──
    lastFactionCrime: { type: Number, default: 0 },
    lastWar: { type: Number, default: 0 },
    lastHeist: { type: Number, default: 0 },
    lastTerritoryAttack: { type: Number, default: 0 },
    // ── WAR HISTORY ──
    warsWon:  { type: Number, default: 0 },
    warsLost: { type: Number, default: 0 },
    warHistory: { type: [String], default: [] },   // last 10 war results
    // ── RECRUITMENT ──
    recruiting: { type: Boolean, default: false }, // open to applications
    pendingApplicants: { type: [String], default: [] },
    // ── FACTION WAR (live) ──
    activeWar: {
        type: new Schema({
            enemyId:        { type: String },
            enemyName:      { type: String },
            startedAt:      { type: Number },
            endsAt:         { type: Number },
            score:          { type: Number, default: 0 },
            enemyScore:     { type: Number, default: 0 },
            contributions:  { type: Schema.Types.Mixed, default: {} },
            warLog:         { type: [String], default: [] },
        }, { _id: false }),
        default: null
    },
    pendingWarChallenge: {
        type: new Schema({
            fromId:     { type: String },
            fromName:   { type: String },
            challengedAt: { type: Number },
        }, { _id: false }),
        default: null
    },
    createdAt: { type: Date, default: Date.now }
});

const BountySchema2 = new Schema({
    targetId:   { type: String, required: true },
    posterId:   { type: String, required: true },
    amount:     { type: Number, required: true },
    reason:     { type: String, default: '' },
    postedAt:   { type: Number, default: Date.now },
    expiresAt:  { type: Number, default: () => Date.now() + 7*24*60*60*1000 },
    claimedBy:  { type: String, default: null },
    claimed:    { type: Boolean, default: false },
}, { collection: 'weirdo_bounties' });

const TournamentSchema = new Schema({
    id:         { type: String, required: true, unique: true },
    status:     { type: String, default: 'open' }, // open|active|finished
    entryFee:   { type: Number, default: 50000 },
    prizePool:  { type: Number, default: 0 },
    players:    { type: [Schema.Types.Mixed], default: [] }, // [{playerId, name, wins, eliminated}]
    rounds:     { type: [Schema.Types.Mixed], default: [] },
    winner:     { type: String, default: null },
    createdAt:  { type: Number, default: Date.now },
    startedAt:  { type: Number, default: 0 },
}, { collection: 'weirdo_tournaments' });

const CarRaceSchema = new Schema({
    raceId:      { type: String, required: true, unique: true },
    track:       { type: String, default: 'City Circuit' },
    city:        { type: String, default: 'Weirdos World' },
    players:     { type: [Schema.Types.Mixed], default: [] }, // [{playerId,carId,carName,speed,handling,score}]
    maxSlots:    { type: Number, default: 6 },
    entryFee:    { type: Number, default: 5000 },
    prizePool:   { type: Number, default: 0 },
    status:      { type: String, default: 'open' }, // open|racing|finished
    results:     { type: [Schema.Types.Mixed], default: [] },
    createdAt:   { type: Number, default: Date.now },
    startedAt:   { type: Number, default: 0 },
}, { collection: 'weirdo_races' });

const ElectionSchema = new Schema({
    electionId:  { type: String, required: true, unique: true },
    city:        { type: String, default: 'Weirdos World' },
    candidates:  { type: [Schema.Types.Mixed], default: [] }, // [{playerId,name,votes,platform}]
    votes:       { type: Schema.Types.Mixed, default: {} },   // {voterId: candidateId}
    status:      { type: String, default: 'open' },           // open|closed
    winner:      { type: String, default: null },
    startedAt:   { type: Number, default: Date.now },
    endsAt:      { type: Number, default: 0 },
}, { collection: 'weirdo_elections' });

const AuctionSchema = new Schema({
    auctionId: { type: String, required: true, unique: true }, 
    itemId: String,
    qty: { type: Number, default: 1 },
    seller: { type: String, required: true }, 
    startingBid: { type: Number, default: 10 },
    highestBid: { type: Number, default: 0 },
    highestBidder: { type: String, default: null },
    endsAt: { type: Number, required: true }, 
    open: { type: Boolean, default: true }
});

const RentalSchema = new Schema({
    rentalId: { type: String, required: true, unique: true },
    propertyId: { type: String, required: true },
    ownerId: { type: String, required: true },
    renterId: { type: String, default: null },
    price: { type: Number, required: true },
    durationMs: { type: Number, required: true },
    expiresAt: { type: Number, default: 0 },
    active: { type: Boolean, default: true }
});

const BountySchema = new Schema({
    targetId: { type: String, required: true, unique: true },
    amount: { type: Number, default: 0 }
});

const ShopItemSchema = new Schema({
    id: String, 
    name: String, 
    type: { type: String, default: 'consumable' }, 
    region: { type: String, default: 'All' }, 
    price: Number, 
    description: String, 
    heal: { type: Number, default: 0 }, 
    energy: { type: Number, default: 0 }, 
    atkBonus: { type: Number, default: 0 },
    defBonus: { type: Number, default: 0 },
    strBonus: { type: Number, default: 0 },    // gear: raw stat bonus to STR
    spdBonus: { type: Number, default: 0 },    // gear: raw stat bonus to SPD
    dexBonus: { type: Number, default: 0 },    // gear: raw stat bonus to DEX
    gearSlot: { type: String, default: null }, // head/hands/body/legs/feet
    rarity: { type: String, default: 'common' }, // common/uncommon/rare/epic/legendary
    incomeRate: { type: Number, default: 0 }, 
    trainBoost: { type: Number, default: 0 }, 
    hpBoost: { type: Number, default: 0 }, 
    stock: { type: Number, default: 0 },
    maxStock: { type: Number, default: 100 }
});

const Player = mongoose.models.RPGPlayer || mongoose.model('RPGPlayer', PlayerSchema, 'weirdo_rpg');
const Faction    = mongoose.models.RPGFaction  || mongoose.model('RPGFaction',  FactionSchema,  'weirdo_factions');
const CarRace    = mongoose.models.WWCarRace   || mongoose.model('WWCarRace',   CarRaceSchema);
const Election   = mongoose.models.WWElection  || mongoose.model('WWElection',  ElectionSchema);
const Bounty2    = mongoose.models.WWBounty2   || mongoose.model('WWBounty2',   BountySchema2);
const Tournament = mongoose.models.WWTournament|| mongoose.model('WWTournament',TournamentSchema);
const Auction    = mongoose.models.RPGAuction  || mongoose.model('RPGAuction',  AuctionSchema,  'weirdo_auctions');
const Rental     = mongoose.models.RPGRental   || mongoose.model('RPGRental',   RentalSchema);
const ShopItem = mongoose.models.RPGShopItem || mongoose.model('RPGShopItem', ShopItemSchema, 'weirdo_shop');
const Bounty = mongoose.models.RPGBounty || mongoose.model('RPGBounty', BountySchema);

// ── Duel Schema ───────────────────────────────────────────────────────────────
const DuelSchema = new Schema({
    challengerId: { type: String, required: true },
    defenderId:   { type: String, required: true },
    betAmount:    { type: Number, default: 0 },
    status:       { type: String, default: 'pending' }, // pending | accepted | declined | expired
    createdAt:    { type: Number, default: Date.now },
    expiresAt:    { type: Number, default: () => Date.now() + 5*60*1000 }, // 5 min to accept
}, { _id: true });
const Duel = mongoose.models.WWDuel || mongoose.model('WWDuel', DuelSchema, 'weirdo_duels');

// ── Trade Schema ──────────────────────────────────────────────────────────────
const TradeSchema = new Schema({
    proposerId:   { type: String, required: true },
    receiverId:   { type: String, required: true },
    offeredItem:  { type: String, required: true },
    offeredQty:   { type: Number, default: 1 },
    wantedItem:   { type: String, required: true },
    wantedQty:    { type: Number, default: 1 },
    status:       { type: String, default: 'pending' }, // pending | accepted | declined | expired
    createdAt:    { type: Number, default: Date.now },
    expiresAt:    { type: Number, default: () => Date.now() + 10*60*1000 }, // 10 min
}, { _id: true });
const Trade = mongoose.models.WWTrade || mongoose.model('WWTrade', TradeSchema, 'weirdo_trades');

const GameLogSchema = new Schema({
    ts:     { type: Number, default: Date.now },         // epoch ms for sorting
    emoji:  { type: String, default: '📌' },
    text:   { type: String, required: true },
});
const GameLog = mongoose.models.RPGGameLog || mongoose.model('RPGGameLog', GameLogSchema);

// ─── PERSISTENT GAME CONFIG ───────────────────────────────────────────────────
const GameConfigSchema = new Schema({
    _id:               { type: String, default: 'game_config' },
    inflationMult:     { type: Number, default: 1 },
    drainsEnabled:     { type: Boolean, default: true },
    wealthDrainEnabled:{ type: Boolean, default: true },
    taxEnabled:        { type: Boolean, default: true },
    lotteryJackpot:    { type: Number, default: 5000000 },
    lotteryDrawKey:    { type: String, default: '' },
    lotteryTotalTickets:{ type: Number, default: 0 },
    rpgGameChat:       { type: String, default: null },   // JID of the game group — persists across restarts
}, { _id: false });
const GameConfig = mongoose.models.RPGGameConfig || mongoose.model('RPGGameConfig', GameConfigSchema, 'weirdo_config');

// Load config from DB into globals on startup
async function loadGameConfig() {
    try {
        await ensureMongo();
        let cfg = await GameConfig.findById('game_config').exec();
        if (!cfg) { cfg = new GameConfig(); await cfg.save(); }
        global.INFLATION_MULT        = cfg.inflationMult ?? 1;
        global.weirdo_drains_enabled = cfg.drainsEnabled ?? true;
        global.wealth_drain_enabled  = cfg.wealthDrainEnabled ?? true;
        global.weirdo_tax_enabled    = cfg.taxEnabled ?? true;
        // Restore game chat JID — the key fix: this is now in the schema so it persists properly
        if (cfg.rpgGameChat) {
            global.wwGameChat = cfg.rpgGameChat;
            console.log(`✅ RPG game chat restored: ${cfg.rpgGameChat}`);
        }
        console.log(`✅ Game config loaded — inflation: x${global.INFLATION_MULT}, drains: ${global.weirdo_drains_enabled}, wealth drain: ${global.wealth_drain_enabled}`);
    } catch (e) {
        console.error('❌ Failed to load game config:', e.message);
        global.INFLATION_MULT        = global.INFLATION_MULT ?? 1;
        global.weirdo_drains_enabled = global.weirdo_drains_enabled ?? true;
        global.weirdo_tax_enabled    = global.weirdo_tax_enabled    ?? true;
    }
}
loadGameConfig();

async function saveGameConfig() {
    try {
        await GameConfig.findByIdAndUpdate(
            'game_config',
            {
                inflationMult:      global.INFLATION_MULT,
                drainsEnabled:      global.weirdo_drains_enabled,
                wealthDrainEnabled: global.wealth_drain_enabled,
                taxEnabled:         global.weirdo_tax_enabled,
                rpgGameChat:        global.wwGameChat || null,
            },
            { upsert: true, new: true }
        ).exec();
    } catch (e) { console.error('saveGameConfig error:', e.message); }
}


