function initMarket() {
    if (!global.ECON_INDEX)     global.ECON_INDEX    = 1.0;
    if (!global.ECON_TREND)     global.ECON_TREND    = 0;
    if (!global.WAGE_INDEX)     global.WAGE_INDEX    = 1.0;
    if (!global.MARKET_PRICES)  global.MARKET_PRICES = {};
    if (!global.LAST_MARKET_UPDATE) global.LAST_MARKET_UPDATE = Date.now();
// Pre-initialize tax flag so applyVAT works before loadGameConfig resolves
if (global.weirdo_tax_enabled === undefined) global.weirdo_tax_enabled = true;

    // Ensure every shop item has a price multiplier
    for (const it of DEFAULT_SHOP) {
        if (!global.MARKET_PRICES[it.id]) global.MARKET_PRICES[it.id] = 1.0;
    }
}

function tickMarket() {
    initMarket();

    // ── Economy index — random walk with mean reversion toward 1.0 ─────────
    // Trend adds momentum (markets don't reverse instantly)
    const shock     = (Math.random() - 0.48) * 0.12;    // slight upward bias
    global.ECON_TREND = global.ECON_TREND * 0.6 + shock; // trend decays
    const meanPull  = (1.0 - global.ECON_INDEX) * 0.08;  // revert to mean
    global.ECON_INDEX = Math.max(0.40, Math.min(2.50, global.ECON_INDEX + global.ECON_TREND + meanPull));

    // ── Wage index — moves similarly but separately ───────────────────────
    const wageShock = (Math.random() - 0.49) * 0.10;
    const wagePull  = (1.0 - global.WAGE_INDEX) * 0.06;
    global.WAGE_INDEX = Math.max(0.50, Math.min(2.00, global.WAGE_INDEX + wageShock + wagePull));

    // ── Per-item price drift — each item moves independently ─────────────
    // Some items are volatile (weapons, drugs), some stable (food, ammo)
    const ITEM_VOLATILITY = {
        // Low volatility — basic necessities
        medkit: 0.03, energydrink: 0.03, hamburger: 0.03, bullets: 0.04,
        burrito: 0.03, tequila: 0.04, fishchips: 0.03, tea: 0.02,
        // Medium volatility — standard gear
        kevlar: 0.06, pistol: 0.06, shotgun: 0.06, ar15: 0.07,
        taser: 0.06, combatboots: 0.05, brassknuckles: 0.05,
        // High volatility — drugs and exotic items
        marijuana: 0.12, xanax: 0.10, steroids: 0.14, cocaine: 0.16,
        adderall: 0.11, mdma: 0.13,
        // Very high volatility — rare/legendary gear
        nuclearbriefcase: 0.18, godspear: 0.18, royalsword: 0.16,
        oniblade: 0.16, dragonscale: 0.15, railgun: 0.17,
        // Properties — slow moving
        shack: 0.04, condo: 0.04, island: 0.03, apartment: 0.04,
        cartelmansion: 0.05, dojo: 0.04, pachinko: 0.06, swissvault: 0.05,
    };
    const DEFAULT_VOL = 0.08;

    for (const it of DEFAULT_SHOP) {
        const vol      = ITEM_VOLATILITY[it.id] || DEFAULT_VOL;
        const drift    = (Math.random() - 0.49) * vol;
        const pull     = (1.0 - global.MARKET_PRICES[it.id]) * 0.07; // revert to 1.0
        const econPush = (global.ECON_INDEX - 1.0) * 0.04;            // follow economy
        global.MARKET_PRICES[it.id] = Math.max(0.30, Math.min(3.50,
            (global.MARKET_PRICES[it.id] || 1.0) + drift + pull + econPush
        ));
    }

    global.LAST_MARKET_UPDATE = Date.now();
    console.log(`📈 Market tick — Economy: ${global.ECON_INDEX.toFixed(3)} | Wages: ${global.WAGE_INDEX.toFixed(3)}`);
}

// Run market tick every 20 minutes
if (global.marketTickIntervalId) clearInterval(global.marketTickIntervalId);
global.marketTickIntervalId = setInterval(tickMarket, 20 * 60 * 1000);
// Also run once at startup after a short delay so globals exist
setTimeout(() => { initMarket(); }, 3000);

// Helper: get current live price of a shop item (base × inflation × market drift)
function livePrice(item) {
    initMarket();
    const marketMult = global.MARKET_PRICES[item.id] || 1.0;
    return Math.max(1, Math.ceil(item.price * (global.INFLATION_MULT ?? 1) * marketMult));
}

// Helper: get current live job pay range
function liveJobPay(min, max) {
    initMarket();
    const m = global.WAGE_INDEX ?? 1.0;
    return { min: Math.ceil(min * m), max: Math.ceil(max * m) };
}

// Helper: get current live crime reward range
function liveCrimeReward(min, max) {
    initMarket();
    const m = 0.6 + (global.ECON_INDEX ?? 1.0) * 0.4;
    return { min: Math.ceil(min * m), max: Math.ceil(max * m) };
}

// Helper: get current live property income rate
function livePropertyIncome(baseRate, player) {
    initMarket();
    const m = 0.5 + (global.ECON_INDEX ?? 1.0) * 0.5;
    // Labor stat: each point adds 0.5% to property income
    // Labor adds 0.5% per point but capped at +100% (2× max) — prevents obby abuse
    const laborBonus = player ? Math.min(2.0, 1 + ((player.labor || 0) * 0.005)) : 1;
    return Math.ceil(baseRate * m * laborBonus);
}

// Helper: economy condition label
function econLabel() {
    const e = global.ECON_INDEX ?? 1.0;
    if (e >= 2.0) return '🚀 BOOMING';
    if (e >= 1.5) return '📈 Thriving';
    if (e >= 1.2) return '💹 Growing';
    if (e >= 0.9) return '📊 Stable';
    if (e >= 0.7) return '📉 Slowing';
    if (e >= 0.5) return '🔻 Recession';
    return '💀 CRASHED';
}


