// Base travel costs — NEVER mutate these. iC() applies the persisted multiplier at runtime.
const LOCATIONS_BASE_COSTS = LOCATIONS.map(l => l.cost);


// Wallet negative floor — players can go into debt up to this amount
const MIN_WALLET  = -500_000;
const MAX_BALANCE = 999_000_000_000; // $999 billion hard cap
function capBal(n){ return Math.min(n, MAX_BALANCE); }

// Helper: scale any hardcoded cost by the persisted inflation multiplier
function iC(baseCost) { return Math.ceil(baseCost * (global.INFLATION_MULT ?? 1)); }

// ── Location normaliser ───────────────────────────────────────────────────────
// Maps every historical/alias location name to its current canonical name.
