// ----------------- Helpers & Global Engines -----------------
function fmtMoney(x) { return `$${Number(x).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 2 })}`; }
function now() { return Date.now(); }
function shortTime(ms) {
    if (ms <= 0) return '0s';
    const s = Math.floor(ms/1000); if (s < 60) return `${s}s`;
    const m = Math.floor(s/60); if (m < 60) return `${m}m ${s%60}s`;
    const h = Math.floor(m/60); return `${h}h ${m%60}m`;
}
function xpToLevel(level) { return level * 100; }
function toJid(id) { return id.includes('@') ? id : `${id}@s.whatsapp.net`; }

function logAction(player, actionString) {
    const d = new Date();
    const timeStr = `${d.getHours().toString().padStart(2,'0')}:${d.getMinutes().toString().padStart(2,'0')}`;
    player.actionHistory.push(`[${timeStr}] ${actionString}`);
    if (player.actionHistory.length > 20) {
        player.actionHistory.shift();
    }
}

function logFinancial(player, description, amount) {
    const d = new Date();
    const timeStr = `${d.toLocaleDateString('en-GB', { day:'2-digit', month:'short' })} ${d.getHours().toString().padStart(2,'0')}:${d.getMinutes().toString().padStart(2,'0')}`;
    const sign = amount >= 0 ? `+${fmtMoney(amount)}` : `-${fmtMoney(Math.abs(amount))}`;
    player.financialHistory = player.financialHistory || [];
    player.financialHistory.push(`[${timeStr}] ${sign} — ${description}`);
    if (player.financialHistory.length > 100) {
        player.financialHistory.shift();
    }
}

function isInFlight(player) {
    return player.travelingUntil && player.travelingUntil > Date.now();
}

