// Each pet has: attack power, icon, and flavour lines for attack and defence.
// Larger power = more damage per round. Dragon/Shark are endgame pets.
const PET_COMBAT_DATA = {
    dog:     { power: 18,  icon: '🐶', atkLine: 'lunges and bites the defender,',        defLine: 'leaps in front of its owner growling,' },
    cat:     { power: 14,  icon: '🐱', atkLine: 'scratches the defender across the face,', defLine: 'hisses and swipes at the attacker,' },
    parrot:  { power: 20,  icon: '🦜', atkLine: 'dive-bombs the defender\'s head,',       defLine: 'screeches and claws at the attacker,' },
    penguin: { power: 22,  icon: '🐧', atkLine: 'body-slams the defender,',              defLine: 'blocks the attacker with surprising force,' },
    wolf:    { power: 55,  icon: '🐺', atkLine: 'goes for the throat,',                  defLine: 'positions itself between you and the attacker,' },
    bear:    { power: 80,  icon: '🐻', atkLine: 'charges and mauls the defender,',       defLine: 'roars and swipes the attacker away,' },
    shark:   { power: 120, icon: '🦈', atkLine: 'erupts from nowhere and shreds the defender,', defLine: 'thrashes at the attacker viciously,' },
    dragon:  { power: 200, icon: '🐉', atkLine: 'breathes fire on the defender,',        defLine: 'unleashes a devastating fire blast on the attacker,' },
};

// Returns combat data if player has a live, fed pet — null otherwise
// Combat power scales with pet level: +12% per level above 1
function getPetCombatData(player) {
    if (!player.pet?.type) return null;
    const data = PET_COMBAT_DATA[player.pet.type];
    if (!data) return null;
    if ((Date.now() - (player.pet.lastFed || 0)) > 24 * 60 * 60 * 1000) return null;
    const petLevel    = player.pet.level || 1;
    const scaledPower = Math.floor(data.power * (1 + (petLevel - 1) * 0.12));
    // Use nickname if set, otherwise species name + level
    const displayName = player.pet.nickname
        ? `${player.pet.nickname} the ${player.pet.type.charAt(0).toUpperCase() + player.pet.type.slice(1)}`
        : `${player.pet.type.charAt(0).toUpperCase() + player.pet.type.slice(1)}${petLevel > 1 ? ` Lv${petLevel}` : ''}`;
    return { ...data, power: scaledPower, name: displayName };
}



// ─── GEAR BONUSES (sync, uses DEFAULT_SHOP) ──────────────────────────────────
function getGearBonuses(p) {
    let atkBonus = 0, defBonus = 0, strBonus = 0, spdBonus = 0, dexBonus = 0;
    const checkSlots = ['equippedWeapon', 'equippedArmor', 'equippedHelmet', 'equippedGloves', 'equippedKneePads', 'equippedBoots'];
    for (const slot of checkSlots) {
        if (!p[slot]) continue;
        const item = DEFAULT_SHOP.find(s => s.id === p[slot]);
        if (!item) continue;
        atkBonus += item.atkBonus || 0;
        defBonus += item.defBonus || 0;
        strBonus += item.strBonus || 0;
        spdBonus += item.spdBonus || 0;
        dexBonus += item.dexBonus || 0;
    }
    return { atkBonus, defBonus, strBonus, spdBonus, dexBonus };
}

