const FACTION_PERK_TIERS = [
    { tier: 0, prestige: 0,    name: 'Recruits',    trainPct: 0,  energyBonus: 0,  hpBonus: 0,   strBonus: 0 },
    { tier: 1, prestige: 100,  name: 'Street Gang', trainPct: 5,  energyBonus: 0,  hpBonus: 0,   strBonus: 0 },
    { tier: 2, prestige: 500,  name: 'Syndicate',   trainPct: 10, energyBonus: 10, hpBonus: 0,   strBonus: 0 },
    { tier: 3, prestige: 2000, name: 'Cartel',      trainPct: 15, energyBonus: 20, hpBonus: 50,  strBonus: 5 },
    { tier: 4, prestige: 5000, name: 'Mafia',       trainPct: 25, energyBonus: 30, hpBonus: 100, strBonus: 10 },
];

function getFactionPerkTier(prestige) {
    let current = FACTION_PERK_TIERS[0];
    for (const t of FACTION_PERK_TIERS) { if (prestige >= t.prestige) current = t; }
    return current;
}

function applyFactionPerks(p, perkTier) {
    // Remove old perks first
    removeFactionPerks(p);
    if (perkTier.tier === 0) return;
    p.maxEnergy = (p.maxEnergy || 100) + perkTier.energyBonus;
    p.maxHealth = (p.maxHealth || 100) + perkTier.hpBonus;
    p.strength  = (p.strength  || 1)   + perkTier.strBonus;
    p.factionPerkTier = perkTier.tier;
}

function removeFactionPerks(p) {
    if (!p.factionPerkTier || p.factionPerkTier === 0) return;
    const old = FACTION_PERK_TIERS.find(t => t.tier === p.factionPerkTier);
    if (!old) return;
    p.maxEnergy = Math.max(100, (p.maxEnergy || 100) - old.energyBonus);
    p.maxHealth = Math.max(100, (p.maxHealth || 100) - old.hpBonus);
    p.strength  = Math.max(1,   (p.strength  || 1)   - old.strBonus);
    p.factionPerkTier = 0;
}

