// ─── ECONOMY SINKS ────────────────────────────────────────────────────────────
const PROPERTY_TAX_RATE  = 0.002;   // 0.2% of property purchase price per hour
const WEALTH_TAX_BRACKETS = [
    { threshold: 100_000_000_000, rate: 0.400 }, // $100B+ → 40%/hr  (you're done)
    { threshold: 10_000_000_000,  rate: 0.200 }, // $10B+  → 20%/hr  (brutal)
    { threshold: 1_000_000_000,   rate: 0.080 }, // $1B+   → 8%/hr   (painful)
    { threshold: 100_000_000,     rate: 0.025 }, // $100M+ → 2.5%/hr
    { threshold: 10_000_000,      rate: 0.010 }, // $10M+  → 1%/hr
    { threshold: 1_000_000,       rate: 0.003 }, // $1M+   → 0.3%/hr
];
// Base maintenance costs per hour — iC() applied at calculation time
const GEAR_MAINTENANCE_BASE = {
    legendary: 50000,
    epic:      15000,
    rare:       5000,
    uncommon:   1000,
    common:      200,
};
const FACTION_DUES_BASE = 25000; // per member per day (was hourly at 5k = 120k/day)

function getWealthTaxRate(balance) {
    for (const b of WEALTH_TAX_BRACKETS) {
        if (balance >= b.threshold) return b.rate;
    }
    return 0;
}

function getItemRarity(itemId) {
    const it = DEFAULT_SHOP.find(s => s.id === itemId);
    return it?.rarity || 'common';
}

// Apply hourly drains to a player — called from getOrCreatePlayer
async function applyHourlyDrains(p) {
    if (!global.weirdo_drains_enabled) return; // creator has suspended all drains
    const currentTime = now();
    const hourMs = 3_600_000;
    let totalDrained = 0;
    const drainLog = [];

    // ── PROPERTY TAX ─────────────────────────────────────────────────────────
    const hoursSincePropTax = (currentTime - (p.lastPropertyTax || currentTime)) / hourMs;
    if (hoursSincePropTax >= 1 && p.properties && p.properties.size > 0) {
        const ticks = Math.floor(hoursSincePropTax);
        let propTax = 0;
        const evictedProps = [];
        for (const [propId, qty] of p.properties.entries()) {
            const shopIt = DEFAULT_SHOP.find(s => s.id === propId);
            if (shopIt && qty > 0) {
                propTax += Math.ceil(shopIt.price * PROPERTY_TAX_RATE * qty * ticks);
            }
        }
        if (propTax > 0) {
            if (p.money >= propTax) {
                p.money -= propTax;
                totalDrained += propTax;
                drainLog.push(`🏠 Property tax: -${fmtMoney(propTax)}`);
            } else {
                // Can't pay — evict from most expensive property
                const allProps = Array.from(p.properties.entries()).filter(([,v]) => v > 0);
                allProps.sort((a, b) => {
                    const pa = DEFAULT_SHOP.find(s => s.id === a[0])?.price || 0;
                    const pb = DEFAULT_SHOP.find(s => s.id === b[0])?.price || 0;
                    return pb - pa;
                });
                if (allProps.length > 0) {
                    const [evictId] = allProps[0];
                    const newQty = p.properties.get(evictId) - 1;
                    if (newQty <= 0) p.properties.delete(evictId); else p.properties.set(evictId, newQty);
                    if (p.home === evictId) p.home = 'streets';
                    evictedProps.push(evictId);
                    drainLog.push(`⚠️ Evicted from *${evictId}* (couldn't pay property tax)`);
                }
                p.money = Math.max(MIN_WALLET, p.money - propTax); // can go negative
                totalDrained += Math.min(p.money, propTax);
            }
        }
        p.lastPropertyTax = currentTime;
    }

    // ── WEALTH TAX ────────────────────────────────────────────────────────────
    // Has its own toggle (togglewealthdrain) separate from the main drains toggle
    const wealthDrainOn = global.wealth_drain_enabled !== false; // defaults ON unless toggled
    const hoursSinceWealthTax = (currentTime - (p.lastWealthTax || currentTime)) / hourMs;
    if (wealthDrainOn && hoursSinceWealthTax >= 1) {
        const ticks = Math.floor(hoursSinceWealthTax);
        const total = p.money + (p.bank || 0);
        const rate = getWealthTaxRate(total);
        if (rate > 0) {
            // Tax split: 60% wallet, 40% bank
            const walletTax = Math.ceil(p.money * rate * ticks);
            const bankTax   = Math.ceil((p.bank || 0) * rate * ticks);
            p.money = Math.max(MIN_WALLET, p.money - walletTax); // can go negative
            p.bank  = Math.max(0, (p.bank || 0) - bankTax);
            totalDrained += walletTax + bankTax;
            if (walletTax + bankTax > 0) drainLog.push(`💸 Wealth tax (${(rate*100).toFixed(1)}%/hr): -${fmtMoney(walletTax + bankTax)}`);
        }
        p.lastWealthTax = currentTime;
    }

    // ── GEAR MAINTENANCE ──────────────────────────────────────────────────────
    const hoursSinceGear = (currentTime - (p.lastGearMaintenance || currentTime)) / hourMs;
    if (hoursSinceGear >= 1) {
        const ticks = Math.floor(hoursSinceGear);
        const gearSlots = ['equippedWeapon','equippedArmor','equippedHelmet','equippedGloves','equippedKneePads','equippedBoots'];
        let gearCost = 0;
        const broken = [];
        for (const slot of gearSlots) {
            if (!p[slot]) continue;
            const rarity = getItemRarity(p[slot]);
            const costPerHour = iC(GEAR_MAINTENANCE_BASE[rarity] || 200);
            const cost = costPerHour * ticks;
            if (p.money >= cost) {
                p.money -= cost;
                gearCost += cost;
            } else {
                // Can't maintain — unequip
                broken.push(p[slot]);
                if (p[slot] !== 'equippedWeapon') {
                    p.inventory.set(p[slot], (p.inventory.get(p[slot]) || 0) + 1);
                }
                p[slot] = null;
                drainLog.push(`🔧 *${broken[broken.length-1]}* broke down (no maintenance funds) — unequipped`);
            }
        }
        if (gearCost > 0) { totalDrained += gearCost; drainLog.push(`🔧 Gear maintenance: -${fmtMoney(gearCost)}`); }
        p.lastGearMaintenance = currentTime;
    }

    // ── FACTION DUES ──────────────────────────────────────────────────────────
    // Only charge if they've been in faction for >24h (grace period for new members)
    // lastFactionDues = 0 means newly set — start the clock, don't charge yet
    if (p.faction) {
        const lastDues = p.lastFactionDues || 0;
        if (lastDues === 0) {
            // First time — just set the clock, no charge
            p.lastFactionDues = currentTime;
        } else {
            const DAY_MS_DUES      = 24 * 60 * 60 * 1000;
            const daysSinceDues    = (currentTime - lastDues) / DAY_MS_DUES;
            if (daysSinceDues >= 1) {
                const ticks = Math.floor(daysSinceDues);
                const dues  = iC(FACTION_DUES_BASE) * ticks; // per day
                if (p.money >= dues) {
                    p.money -= dues;
                    totalDrained += dues;
                    drainLog.push(`🏢 Faction dues: -${fmtMoney(dues)}`);
                } else {
                    // Kick from faction for non-payment — but only if dues > $50k (meaningful amount)
                    // Small amounts just go into debt rather than instant kick
                    if (dues > 50000) {
                        const f = await Faction.findById(p.faction).exec();
                        if (f) {
                            f.members = f.members.filter(m => m !== p._id.toString());
                            await f.save();
                        }
                        removeFactionPerks(p);
                        p.faction = null;
                        p.lastFactionDues = 0;
                        drainLog.push(`🏢 *Kicked from faction* — couldn't pay ${fmtMoney(dues)} in dues`);
                    } else {
                        // Small dues — just go negative, don't kick
                        p.money -= dues;
                        totalDrained += dues;
                        drainLog.push(`🏢 Faction dues: -${fmtMoney(dues)} (wallet in debt)`);
                    }
                }
                p.lastFactionDues = currentTime;
            }
        }
    }

    // Log all drains to financial history so statement captures them
    for (const entry of drainLog) {
        const amtMatch = entry.match(/[\-]?\$?([\d,]+(?:\.\d+)?)/);
        const amt = amtMatch ? -Math.abs(parseFloat(amtMatch[1].replace(/,/g,''))) : 0;
        logFinancial(p, entry.replace(/^[^\w]*/, ''), amt);
    }
    return { totalDrained, drainLog };
}

async function logGlobal(emoji, text) {
    // Feed the in-memory news ticker
    try {
        if (!global.wwNewsLog) global.wwNewsLog = [];
        const ts = new Date().toLocaleTimeString('en-GB', { hour:'2-digit', minute:'2-digit' });
        const entry = { ts, category: emoji, msg: `${emoji} ${text}` };
        global.wwNewsLog.unshift(entry);
        if (global.wwNewsLog.length > 100) global.wwNewsLog.pop();
        // Also persist to DB so news survives restarts
        try {
            const db = await connectDB();
            await db.collection('ww_news').insertOne({ ...entry, at: Date.now() });
            await db.collection('ww_news').deleteMany({ at: { $lt: Date.now() - 7*24*60*60*1000 } }); // keep 7 days
        } catch(_) {}
    } catch(_) {}
    try {
        const d = new Date();
        const timeStr = `${d.toLocaleDateString('en-GB', { day:'2-digit', month:'short' })} ${d.getHours().toString().padStart(2,'0')}:${d.getMinutes().toString().padStart(2,'0')}`;
        const entry2 = new GameLog({ ts: Date.now(), emoji, text: `[${timeStr}] ${emoji} ${text}` });
        await entry2.save();
        const count = await GameLog.countDocuments();
        if (count > 100) {
            const oldest = await GameLog.findOne().sort({ ts: 1 }).exec();
            if (oldest) await GameLog.deleteOne({ _id: oldest._id });
        }
    } catch (e) { /* silent */ }
}

