// ─── OVERDOSE ENGINE ───────────────────────────────────────────────────────────
// Triggered when a player pushes past the drug stack limit.
// They die immediately. Random penalties strip cash, stats, or a property.
// The full report is stored in overdosePenaltyLog and shown on next revive.
function triggerOverdose(p) {
    const losses = [];

    // 1. Kill — 60-minute hospital stay
    p.health      = 0;
    p.jailedUntil = now() + (60 * 60 * 1000);
    p.inJail      = false;
    p.activeDrugs = []; // all drugs wiped from system
    p.markModified('activeDrugs');

    // 2. Cash penalty — lose 20-50% of TOTAL holdings (wallet + bank combined)
    const totalCash = (p.money || 0) + (p.bank || 0);
    if (totalCash > 0) {
        const pct      = 0.20 + Math.random() * 0.30;
        const lost     = Math.floor(totalCash * pct);
        // Drain wallet first, then bank for the remainder
        const fromWallet = Math.min(p.money || 0, lost);
        p.money          = Math.max(0, (p.money || 0) - fromWallet);
        const fromBank   = Math.min(p.bank || 0, lost - fromWallet);
        p.bank           = Math.max(0, (p.bank || 0) - fromBank);
        losses.push(`💸 Lost *${fmtMoney(lost)}* (${(pct*100).toFixed(0)}% of total holdings — wallet + bank)`);
        logFinancial(p, `Overdose — cash penalty`, -lost);
    }

    // 3. Stat penalty — lose 10-30% of a random stat
    const STATS = ['strength','defense','speed','dexterity'];
    const stat  = STATS[Math.floor(Math.random() * STATS.length)];
    if ((p[stat] || 0) > 5) {
        const pct     = 0.10 + Math.random() * 0.20;
        const statLost = Math.max(1, Math.floor((p[stat] || 0) * pct));
        p[stat]        = Math.max(1, (p[stat] || 0) - statLost);
        losses.push(`📉 Lost *${statLost}* ${stat} (overdose brain/muscle damage)`);
    }

    // 4. Property loss — 25% chance to lose one random property
    if (Math.random() < 0.25 && p.properties) {
        const props = [...p.properties.entries()].filter(([,q]) => q > 0);
        if (props.length > 0) {
            const [propId, qty] = props[Math.floor(Math.random() * props.length)];
            p.properties.set(propId, Math.max(0, qty - 1));
            losses.push(`🏠 Lost 1x *${propId}* (seized while hospitalised)`);
        }
    }

    // 5. Store the full report — shown on next command after revive
    const drugList = [...new Set((p.activeDrugs||[]).map(d=>d.drug))].join(', ') || 'unknown drugs';
    p.overdosePenaltyLog = [
        `☠️ *YOU OVERDOSED ON ${drugList.toUpperCase()}*`,
        ``,
        `You were rushed to hospital and woke up missing:`,
        ...losses,
        ``,
        `Your active drugs have been wiped from your system.`,
        `Next time — know your limits.`
    ].join('\n');

    logAction(p, `💀 OVERDOSED — hospitalised 60min, penalties applied`);
    logGlobal('💀', `*${p.username || p._id}* overdosed and woke up in hospital. 60 minutes.`);

    return losses.length;
}

