// ----------------- MEAN-REVERSION CRYPTO ENGINE -----------------
// Supply caps (max coins in circulation, like real crypto)
// Scan all player wallets to get REAL total supply in circulation
// Runs once on startup, then kept accurate via buycrypto/sellcrypto/wirecrypto
async function recalcCryptoSupply() {
    try {
        await ensureMongo();
        const players = await Player.find(
            { cryptoPortfolio: { $exists: true } },
            { cryptoPortfolio: 1 }
        ).lean().exec();
        const totals = {};
        for (const pl of players) {
            const port = pl.cryptoPortfolio;
            if (!port) continue;
            const entries = port instanceof Map ? [...port.entries()] : Object.entries(port);
            for (const [coin, amt] of entries) {
                if (amt > 0) totals[coin] = (totals[coin] || 0) + amt;
            }
        }
        global.cryptoSupplySold = totals;
        console.log(`✅ Crypto supply scan: ${Object.entries(totals).map(([c,v])=>`${c}=${v.toFixed(2)}`).join(', ')}`);
    } catch(e) {
        console.error('recalcCryptoSupply error:', e.message);
        global.cryptoSupplySold = {};
    }
}
