// ── Daily pay helper ─────────────────────────────────────────────────────────
function getCareerDailyPay(p) {
    if (!p.career?.jobId) return 0;
    const company = COMPANIES[p.career.companyId];
    const job     = CAREER_JOBS[p.career.jobId];
    if (!company || !job) return 0;
    const rank     = Math.min(5, p.career.rank || 1);
    const rankMult = JOB_RANK_MULT[rank - 1];
    // Qualification bonus: higher degree than minimum earns a bonus
    const playerQual   = getPlayerQualLevel(p, job.field);
    const qualBonus    = 1 + Math.max(0, playerQual - job.minQual) * 0.25; // +25% per extra qual level
    const intBonus     = 1 + Math.max(0, ((p.intelligence || 1) - 1) * 0.008);
    const wageM        = global.WAGE_INDEX ?? 1.0;
    return Math.floor(job.basePay * rankMult * qualBonus * intBonus * wageM);
}

// Get a player's highest qualification level in a field (0=none, 1=cert, 2=dip, 3=masters, 4=phd)
function getPlayerQualLevel(p, field) {
    const degrees = p.degrees || [];
    let max = 0;
    for (const d of degrees) {
        if (d.startsWith(field + '_')) {
            const lvl = parseInt(d.split('_')[1]) || 0;
            if (lvl > max) max = lvl;
        }
    }
    return max;
}




