// Alias for backward compat
function getCareerHourlySalary(p) { return Math.floor(getCareerDailyPay(p) / 24); }

async function getOrCreatePlayer(id) {
    if (!id) throw new Error('Invalid player id');
    let p = await Player.findById(id).exec();
    if (!p) { p = new Player({ _id: id }); await p.save(); }
    // Track last seen every time player takes an action
    if (p.registered) { p.lastSeen = Date.now(); }

    const currentTime = now();

    if (p.jailedUntil !== undefined && p.jailedUntil > 0 && p.jailedUntil <= currentTime) {
        p.jailedUntil    = 0;
        p.inJail         = false;
        p.lawyerCallUsed = false; // reset for next sentence
        p.jailWorkDone   = 0;
        p.jailVisitedBy  = [];
        p.prisonGang     = null;  // gang dissolves on release
        p.prisonGangRole = null;
        if (p.health <= 0) p.health = 20;

        // Show overdose penalty report if they OD'd
        if (p.overdosePenaltyLog) {
            // We can't send a WhatsApp message from here directly, so we flag it
            // The penalty log will be prepended to the NEXT command's response
            // via the p.overdosePenaltyLog field — commands check and clear it
            p._pendingOverdoseReport = p.overdosePenaltyLog;
            p.overdosePenaltyLog = null;
        }

        // Discharge fee scales with injury severity: $1,000 (minor) → $50,000 (critical)
        // Severity based on original sentence length
        const origSentenceMs = p.sentenceMs || 0;
        const wasJail        = p.inJail === true;
        let dischargeFee = 0;
        if (!wasJail && origSentenceMs > 0) {
            // Hospital: scale from $1k (≤5min) to $50k (≥30min)
            const sevMins = origSentenceMs / 60000;
            dischargeFee = Math.min(50000, Math.max(1000, Math.floor((sevMins / 30) * 50000)));
        } else if (wasJail && origSentenceMs > 0) {
            // Jail: processing fee scales from $1k (≤8min) to $30k (≥35min)
            const sevMins = origSentenceMs / 60000;
            dischargeFee = Math.min(30000, Math.max(1000, Math.floor((sevMins / 35) * 30000)));
        }
        if (dischargeFee > 0) {
            p.money = Math.max(MIN_WALLET, (p.money || 0) - dischargeFee);
            logFinancial(p, `${wasJail ? 'Jail processing' : 'Hospital discharge'} fee (${Math.round((p.sentenceMs||0)/60000)}min sentence)`, -dischargeFee);
            p._pendingDischargeMsg = `💸 ${wasJail ? '⛓️ Jail processing' : '🏥 Hospital discharge'} fee: *${fmtMoney(dischargeFee)}* charged.`;
        }
        // Reset sentence tracking
        p.sentencedAt = 0;
        p.sentenceMs  = 0;
        p.nurseCallUsed = false; // reset for next hospital stay
    }

    // Auto-land: if flight timer expired, update location
    if (p.travelingTo && p.travelingUntil && p.travelingUntil <= currentTime) {
        p.location = p.travelingTo;
        p.travelingTo = null;
        p.travelingUntil = 0;
    }


    // Ensure inventory and properties are Maps (old accounts may be plain objects)
    if (p.inventory && !(p.inventory instanceof Map)) {
        const inv = new Map(Object.entries(p.inventory));
        p.inventory = inv;
    }
    if (p.properties && !(p.properties instanceof Map)) {
        const props = new Map(Object.entries(p.properties));
        p.properties = props;
    }

    // Auto-migrate legacy location names (e.g. "Torn City" → "Weirdos World")
    const canonical = normLoc(p.location);
    if (canonical !== p.location) p.location = canonical;

    // Rental eviction: if rented home has expired, kick them out immediately
    if (p.rentedHome && p.rentedHomeExpiresAt > 0 && p.rentedHomeExpiresAt <= currentTime) {
        p.rentedHome = null;
        p.rentedHomeExpiresAt = 0;
    }

    // Gear insurance expiry
    if (p.gearInsurance && p.gearInsuranceExpiresAt > 0 && p.gearInsuranceExpiresAt <= currentTime) {
        p.gearInsurance = false;
        p.gearInsuranceExpiresAt = 0;
    }

    // Kidnap auto-release after 24h — frees victim even if kidnapper is offline
    if (p.kidnappedBy && p.kidnappExpiresAt > 0 && p.kidnappExpiresAt <= currentTime) {
        p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0;
        p.ransomDemandedBy = null; p.kidnappExpiresAt = 0;
    }

    // Migrate legacy activeDrug → activeDrugs array
    if (p.activeDrug && (!p.activeDrugs || p.activeDrugs.length === 0)) {
        if (p.drugExpiresAt > currentTime) {
            p.activeDrugs = [{ drug: p.activeDrug, expiresAt: p.drugExpiresAt }];
        }
        p.activeDrug = null;
        p.drugExpiresAt = 0;
    }

    // Clean expired drugs from activeDrugs
    const activeDrugsBefore = (p.activeDrugs || []).length;
    p.activeDrugs = (p.activeDrugs || []).filter(d => d.expiresAt > currentTime);
    if (p.activeDrugs.length !== activeDrugsBefore) p.markModified('activeDrugs');

    // ── OVERDOSE CHECK — fires immediately on load if over the limit ──────────
    // Anyone currently stacking 3+ unique drugs OR 3+ of the same drug ODs now
    if (!p.overdosePenaltyLog) { // don't double-trigger if already OD'd
        const uniqueDrugsNow = new Set((p.activeDrugs||[]).map(d => d.drug));
        const maxSameDose    = Math.max(0, ...[...uniqueDrugsNow].map(drug =>
            (p.activeDrugs||[]).filter(d => d.drug === drug).length
        ));
        if (uniqueDrugsNow.size >= 3 || maxSameDose >= 3) {
            triggerOverdose(p);
            // Will be saved below — penalty log will show on next command
        }
    }

    // Smokebomb special: jailbreak on use, no duration needed
    for (const ad of p.activeDrugs) {
        if (ad.drug === 'smokebomb') { p.jailedUntil = 0; }
    }

    // Crime level decay: -5 per hour
    const hoursSinceDecay = p.lastCrimeLevelDecay ? (currentTime - p.lastCrimeLevelDecay) / 3600000 : 0;
    if (hoursSinceDecay >= 1) {
        const ticks = Math.floor(hoursSinceDecay);
        p.crimeLevel = Math.max(0, (p.crimeLevel || 0) - (5 * ticks));
        p.lastCrimeLevelDecay = currentTime;
    }

    // Auto-heal orphaned faction state (faction deleted but player still linked)
    if (p.faction) {
        const factionExists = await Faction.findById(p.faction).exec().catch(() => null);
        if (!factionExists) {
            p.faction         = null;
            p.lastFactionDues = 0;
            removeFactionPerks(p);
        }
    }

    // Child hunger/happiness decay
    applyChildDecay(p);

    // ── HOURLY ECONOMY DRAINS ─────────────────────────────────────────────────
    await applyHourlyDrains(p);

    const REGEN_TICK_MS = 5 * 60 * 1000;
    // Fix: if no lastUpdate, set it one tick ago so regen fires immediately
    const elapsed = currentTime - (p.lastUpdate || (currentTime - REGEN_TICK_MS));

    if (elapsed >= REGEN_TICK_MS) {
        const rawTicks = Math.floor(elapsed / REGEN_TICK_MS);
        const ticks    = Math.min(rawTicks, 72); // cap at 72 ticks (6 hours) — prevents offline income exploit

        // Effective HP max includes house boost
        const effectiveHpMax = await getEffectiveMaxHP(p);

        if (p.health > 0) p.health = Math.min(effectiveHpMax, p.health + (ticks * 5));
        // In hospital with 0 HP — slow recovery so player can eventually self-discharge
        if (p.health <= 0 && isHospitalized(p) && !p.inJail) {
            p.health = Math.min(effectiveHpMax, (p.health || 0) + (ticks * 3)); // +3 HP per tick in hospital
        }
        p.energy = Math.min(p.maxEnergy, p.energy + (ticks * 5));
        // Nerve regenerates 1 per tick (5 min)
        const maxNerve = 60 + Math.floor((p.level || 1) / 5);
        p.nerve  = Math.min(maxNerve, (p.nerve || 0) + ticks);
        p.maxNerve = maxNerve;

        let income = 0;
        const propEntries = p.properties instanceof Map ? [...p.properties.entries()] : Object.entries(p.properties || {});
        for (let [propId, qty] of propEntries) {
            const shopIt = DEFAULT_SHOP.find(s => s.id === propId);
            if (shopIt && shopIt.incomeRate) income += livePropertyIncome(shopIt.incomeRate, p) * qty * ticks;
        }
        if (income > 0) {
            p.money = capBal((p.money||0) + income);
            logFinancial(p, `Property income (${ticks} tick${ticks===1?'':'s'})`, income);
        }

        // Career salary is NO LONGER passive — player must clockin daily.
        // Check for absences and fire if too many missed days.
        if (p.career?.jobId) {
            const DAY_MS    = 24 * 60 * 60 * 1000;
            const lastClock = p.career.lastClockIn || p.career.hiredAt || currentTime;
            const daysMissed = Math.floor((currentTime - lastClock) / DAY_MS);
            if (daysMissed >= 3 && !p.career.warned) {
                p.career.warned = true;
                p.markModified('career');
                // Will show warning on next command via pendingCareerWarning
                p._pendingCareerWarning = true;
            }
            if (daysMissed >= 5) {
                // FIRED — too many absences
                const company = COMPANIES[p.career.companyId];
                const jobName = company?.name || p.career.jobId;
                p._firedFrom  = jobName;
                p.career      = null;
                p.markModified('career');
            }
        }

        p.lastUpdate = currentTime - (elapsed % REGEN_TICK_MS);
        await p.save();
    }
    return p;
}

// ----------------- Core Commands -----------------

// ── Inline loan deduction for torn.js credit events ──────────────────────────
function deductLoanIfOwed(p, credited, sourceLabel) {
    if (!p.activeLoan || p.activeLoan.owed <= 0) return '';
    const deduct = Math.min(credited, p.activeLoan.owed, Math.max(0, p.money));
    if (deduct <= 0) return '';
    p.money          -= deduct;
    p.activeLoan.owed -= deduct;
    if (p.activeLoan.owed <= 0) {
        p.activeLoan = null;
        return `\n🦈 *Shark update:* ${sourceLabel} paid you ${fmtMoney(credited)}. Auto-deducted *${fmtMoney(deduct)}* — loan *CLEARED!* ✅`;
    }
    return `\n🦈 *Shark update:* ${sourceLabel} paid you ${fmtMoney(credited)}. Auto-deducted *${fmtMoney(deduct)}* — still owe *${fmtMoney(p.activeLoan.owed)}*`;
}

cast({ pattern: 'joinrpg', desc: 'Join the RPG', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        await ensureMongo();
        const id = await getPlayerId(conn, sender);
        let p = await Player.findById(id).exec();

        // If doc exists AND is already registered — block re-registration
        if (p && p.registered) return conn.sendMessage(from, { text: 'You already have an RPG profile. Use *profile* to view it.' }, { quoted: mek });

        const rawName = (args && args.length) ? args.join(' ').trim() : `User_${id.slice(-4)}`;
        if (p) {
            // Ghost account exists (created by being targeted/mentioned) — upgrade it to registered
            p.username   = rawName;
            p.registered = true;
            logAction(p, "Registered RPG Account.");
            await p.save();
        } else {
            p = new Player({ _id: id, username: rawName, registered: true });
            logAction(p, "Created RPG Account.");
            await p.save();
        }
        return conn.sendMessage(from, { text: `🎮 Welcome to *Weirdos World*, *${rawName}*!\nYou can change your name later with: *setname <newname>*\n\nType *profile* to see your stats. Type *guide* for help.` }, { quoted: mek });
    } catch (e) { console.error('joinrpg error', e); }
});

cast({ pattern: 'history', desc: 'View last 20 actions', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const senderId = await getPlayerId(conn, sender);
        const CREATOR_ID = '2348084644182';

        let id = senderId;
        if (senderId === CREATOR_ID) {
            const targetId = await getTargetId(conn, mek, args, 0).catch(() => null);
            if (targetId && targetId !== senderId) id = targetId;
        }

        const p = await getOrCreatePlayer(id);
        if (!p.actionHistory || p.actionHistory.length === 0) {
            return conn.sendMessage(from, { text: `📜 ${id === senderId ? 'Your' : `@${id}'s`} action history is empty.` }, { quoted: mek });
        }
        const label = id === senderId ? `${p.username || p._id}` : `${p.username || p._id} 👑`;
        const hist = [...p.actionHistory].reverse().join('\n');
        return conn.sendMessage(from, { text: `📜 *Action History — ${label}*\n\n${hist}` }, { quoted: mek });
    } catch(e) { console.error(e); }
});

// [statement command handled by economy.js]

cast({ pattern: 'gamestats', desc: 'Dev stats', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if(pId !== '2348084644182') return conn.sendMessage(from, { text: '❌ Access Denied. Creator command only.' }, { quoted: mek });
        
        const totalPlayers = await Player.countDocuments({ registered: true, isChildNpc: { $ne: true } });
        const totalChildNpcs = await Player.countDocuments({ isChildNpc: true });
        const totalFactions = await Faction.countDocuments();
        const totalAuctions = await Auction.countDocuments({ open: true });
        
        const allPlayers = await Player.find({}, 'money');
        let totalMoney = 0;
        allPlayers.forEach(p => totalMoney += (p.money || 0));
        
        return conn.sendMessage(from, { text: `👑 *Game Creator Dashboard*\n\n👥 Registered Players: ${totalPlayers}\n🎓 Active Child NPCs: ${totalChildNpcs}\n🏢 Active Factions: ${totalFactions}\n🔔 Open Auctions: ${totalAuctions}\n💰 Global Economy Cash: ${fmtMoney(totalMoney)}\n🎰 Casino Mega Jackpot: ${fmtMoney(global.casinoJackpot)}` }, { quoted: mek });
    } catch (e) { console.error(e); }
});

// =============================================================================
// COMMANDS: setgamechat / unsetgamechat / gamechatstatus
// Creator-only. Designates (or clears) the group where the RPG game is played.
// The autonomous child NPC tick will ONLY broadcast to this group.
// =============================================================================
cast({ pattern: 'setgamechat', desc: '[Creator] Set this group as the RPG game chat', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId   = await getPlayerId(conn, sender);
        const force = (args[0] || '').toLowerCase() === 'force';
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator only.` }, { quoted: mek });
        if (!from.endsWith('@g.us')) return conn.sendMessage(from, { text: `❌ This command must be used inside a group.` }, { quoted: mek });

        // Already set to THIS group
        if (global.wwGameChat === from) {
            return conn.sendMessage(from, { text: [
                `✅ *Game chat is already set to this group!*`,
                ``,
                `Child NPCs and game broadcasts are already coming here.`,
                `Use *unsetgamechat* to disable, or *gamechatstatus* to check.`,
            ].join('\n') }, { quoted: mek });
        }

        // Already set to a DIFFERENT group — require force
        if (global.wwGameChat && global.wwGameChat !== from && !force) {
            return conn.sendMessage(from, { text: [
                `⚠️ *Game chat is already set to a different group.*`,
                ``,
                `Current: \`${global.wwGameChat}\``,
                ``,
                `Run *setgamechat force* to override and move it here.`,
            ].join('\n') }, { quoted: mek });
        }

        global.wwGameChat = from;
        await saveGameConfig();

        return conn.sendMessage(from, { text: [
            `✅ *This group is now the RPG game chat!*`,
            ``,
            `Child NPCs will broadcast their actions here.`,
            `Game events (global news, etc.) will appear here.`,
            `This setting survives bot restarts automatically.`,
            ``,
            `Use *unsetgamechat* to disable.`,
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('setgamechat error', e); }
});

cast({ pattern: 'unsetgamechat', desc: '[Creator] Remove this group as the RPG game chat', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator only.` }, { quoted: mek });
        if (!global.wwGameChat) return conn.sendMessage(from, { text: `ℹ️ No game chat is currently set.` }, { quoted: mek });
        global.wwGameChat = null;
        await saveGameConfig();
        return conn.sendMessage(from, { text: `✅ RPG game chat cleared. Child NPC broadcasts disabled.` }, { quoted: mek });
    } catch(e) { console.error('unsetgamechat error', e); }
});

cast({ pattern: 'gamechatstatus', desc: '[Creator] Show which group is set as the RPG game chat', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator only.` }, { quoted: mek });

        if (global.wwGameChat) {
            const isThisChat = global.wwGameChat === from;
            return conn.sendMessage(from, { text: [
                `🎮 *RPG Game Chat Status*`,
                ``,
                `Active group: \`${global.wwGameChat}\``,
                isThisChat ? `✅ *This is the current game chat.*` : `ℹ️ The game chat is a different group.`,
                ``,
                `Child NPC broadcasts: *ON*`,
            ].join('\n') }, { quoted: mek });
        } else {
            return conn.sendMessage(from, { text: [
                `🎮 *RPG Game Chat Status*`,
                ``,
                `No game chat set. Child NPC broadcasts are *OFF*.`,
                ``,
                `Run *setgamechat* inside your game group to enable broadcasts.`,
            ].join('\n') }, { quoted: mek });
        }
    } catch(e) { console.error('gamechatstatus error', e); }
});

// ------------- NEW: CREATOR GOD-MODE COOLDOWN WIPE -------------
cast({ pattern: 'cleartimers', desc: '[Creator] Clear timers — all for self, jail/hospital/travel for others', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: '❌ Access Denied. Creator command only.' }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0).catch(() => null);
        const isOther  = targetId && targetId !== pId;

        // ── BASIC clear — hospital, jail, travel only (used for other players) ──
        const clearBasic = async (id) => {
            const p = await getOrCreatePlayer(id);
            if (p.travelingTo) { p.location = p.travelingTo; p.travelingTo = null; p.travelingUntil = 0; }
            p.jailedUntil = 0; p.inJail = false;
            p.jailWorkDone = 0; p.lawyerCallUsed = false;
            p.health  = p.maxHealth || 100;
            p.energy  = p.maxEnergy || 100;
            p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0;
            p.ransomDemandedBy = null; p.kidnappExpiresAt = 0;
            await p.save();
            return p;
        };

        // ── FULL clear — every single timer/cooldown (creator only) ──
        const clearFull = async (id) => {
            const p = await getOrCreatePlayer(id);

            // ── Travel ────────────────────────────────────────────────────────
            if (p.travelingTo) { p.location = p.travelingTo; p.travelingTo = null; p.travelingUntil = 0; }

            // ── Hospital / jail ───────────────────────────────────────────────
            p.jailedUntil = 0; p.inJail = false;
            p.jailWorkDone = 0; p.lawyerCallUsed = false;
            p.health = p.maxHealth || 100;
            p.energy = p.maxEnergy || 100;

            // ── Kidnap ────────────────────────────────────────────────────────
            p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0;
            p.ransomDemandedBy = null; p.kidnappExpiresAt = 0;

            // ── Education ─────────────────────────────────────────────────────
            if (p.education?.course) {
                p.education.startedAt = 0;
                p.education.examReady = true;
                p.markModified('education');
            }

            // ── Career (clockin + promotion) ──────────────────────────────────
            if (p.career) {
                p.career.lastPaidAt      = 0;
                p.career.lastPromotionAt = 0;
                p.career.lastClockIn     = 0;
                p.markModified('career');
            }

            // ── Children — ALL child-level timers ─────────────────────────────
            if (p.children?.length) {
                for (const c of p.children) {
                    c.lastSchool  = 0;
                    c.lastFed     = now();
                    c.lastPlay    = now();
                    c.lastPayday  = 0;
                }
                p.markModified('children');
            }

            // ── Pet — training + feeding ──────────────────────────────────────
            if (p.pet) {
                p.pet = { ...p.pet, lastTrained: 0, lastFed: now() };
            }

            // ── EVERY root-level last* cooldown ───────────────────────────────
            const rootCooldowns = [
                'lastCrime', 'lastWork', 'lastAttack', 'lastDaily',
                'lastHunt', 'lastSearch', 'lastBeg', 'lastBankRob',
                'lastKidnap', 'lastEscapeAttempt', 'lastRob',
                'lastScratch', 'lastIntimacy',
                'lastPropertyTax', 'lastWealthTax', 'lastGearMaintenance',
                'lastFactionDues', 'lastUpdate', 'lastCrimeLevelDecay',
                'lastHeal', 'lastBounty', 'lastAuction', 'lastCareerClockIn',
                'lastHustle', 'lastTutor', 'lastSpy', 'lastSabotage',
                'lastOffshoreTransfer', 'lastVoteAt',
            ];
            for (const k of rootCooldowns) p[k] = 0;

            // ── Faction war timers ────────────────────────────────────────────
            if (p.faction) {
                const fac = await Faction.findById(p.faction).exec().catch(() => null);
                if (fac) {
                    fac.lastWar              = 0;
                    fac.lastFactionCrime     = 0;
                    fac.lastHeist            = 0;
                    fac.lastTerritoryAttack  = 0;
                    await fac.save();
                }
            }

            // ── p.cooldowns object — EVERY key ────────────────────────────────
            const keptStreak = p.cooldowns?.hlStreak || 0;
            const baseCooldowns = {
                // Economy shifts & jobs
                payday: 0, shift: 0, wager: 0, callcops: 0, smuggle: 0,
                hitman: 0, carwash: 0, pickpocket: 0, extort: 0, jailbreak: 0,
                obby: 0, pizzajob: 0, swordfight: 0, duel: 0, warAttack: 0,
                // Torn.js specific keys (different naming convention)
                lastObby: 0, lastHighLow: 0,
                jailwork: 0, trivia: 0, sabotage: 0,
                hlStreak: keptStreak, // keep streak intact — not a timer
            };
            // Also zero all per-item buy cooldowns, daily buy caps, and child cooldowns
            if (p.cooldowns) {
                for (const key of Object.keys(p.cooldowns)) {
                    if (
                        key.startsWith('buy_') ||
                        key.startsWith('buycount_') ||
                        key.startsWith('childTrain_') ||
                        key.startsWith('childEvent_') ||
                        key.startsWith('childAuto_')
                    ) {
                        baseCooldowns[key] = 0;
                    }
                }
            }
            p.cooldowns = baseCooldowns;

            // ── Drugs, crime heat, active brew ────────────────────────────────
            p.activeDrugs = [];
            p.crimeLevel  = 0;
            p.activeBrew  = null;
            p.markModified('activeDrugs');
            p.markModified('cooldowns');

            // ── Cancel pending duels (refund escrowed bets) ───────────────────
            const pendingDuels = await Duel.find({ challengerId: id, status: 'pending' }).exec().catch(() => []);
            for (const d of pendingDuels) {
                d.status = 'expired';
                await d.save();
            }

            await p.save();

            // ── Force-clear economy.js cooldowns via native driver ─────────────
            // economy.js uses a separate MongoClient driver on same weirdo_rpg collection
            // Mongoose save() covers torn.js fields but we must also $unset via native driver
            // to guarantee rob, smuggle, hitman etc. are cleared regardless of driver cache
            try {
                const nativeDb = mongoose.connection.db;
                if (nativeDb) {
                    await nativeDb.collection('weirdo_rpg').updateOne(
                        { _id: id },
                        { $set: {
                            lastRob: 0,
                            'cooldowns.shift': 0,
                            'cooldowns.smuggle': 0,
                            'cooldowns.wager': 0,
                            'cooldowns.hitman': 0,
                            'cooldowns.carwash': 0,
                            'cooldowns.pickpocket': 0,
                            'cooldowns.extort': 0,
                            'cooldowns.payday': 0,
                            'cooldowns.obby': 0,
                            'cooldowns.lastObby': 0,
                            'cooldowns.lastHighLow': 0,
                            'cooldowns.jailwork': 0,
                            'cooldowns.trivia': 0,
                            'cooldowns.pizzajob': 0,
                            'cooldowns.swordfight': 0,
                            'cooldowns.jailbreak': 0,
                        }}
                    );
                }
            } catch(e) { console.error('cleartimers native clear error:', e); }

            return p;
        };

        if (isOther) {
            const p = await clearBasic(targetId);
            return conn.sendMessage(from, {
                text: [
                    `✅ *Timers cleared for @${targetId}*`, ``,
                    `🏥 Hospital/jail cleared — health & energy restored`,
                    `✈️ Travel completed → ${p.location}`,
                    `_Other cooldowns (crime, shift, etc.) are NOT cleared for other players._`
                ].join('\n'),
                mentions: [toJid(targetId)]
            }, { quoted: mek });
        } else {
            const p = await clearFull(pId);
            return conn.sendMessage(from, { text: [
                `👑 *ALL TIMERS CLEARED — CREATOR*`, ``,
                `✅ Hospital/jail cleared | Health & energy restored`,
                `✅ All last* cooldowns reset (crime, rob, hunt, beg, etc.)`,
                `✅ All economy cooldowns reset (shift, smuggle, rob, etc.)`,
                `✅ Clock-in reset | Education exam ready`,
                `✅ Travel completed → ${p.location}`,
                `✅ Children school/feed/play timers reset`,
                `✅ Hustle, spy, tutor, sabotage cooldowns reset`,
                `✅ Buy per-item cooldowns & daily caps cleared`,
                `✅ Pet training & last-fed reset`,
                `✅ Active drugs cleared | Crime heat reset`,
                `✅ Active brew cancelled | Pending duels expired`,
            ].join('\n') }, { quoted: mek });
        }
    } catch(e) { console.error('cleartimers error', e); }
});

cast({ pattern: 'setname', desc: 'Change your username', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const id = await getPlayerId(conn, sender);
        if (!args || !args.length) return conn.sendMessage(from, { text: 'Usage: setname <name>' }, { quoted: mek });
        const p = await getOrCreatePlayer(id);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.`, mentions: [toJid(id)] }, { quoted: mek });

        p.username = args.join(' ').trim();
        logAction(p, `Changed name to ${p.username}`);
        await p.save();
        return conn.sendMessage(from, { text: `✅ Username updated to: *${p.username}*` }, { quoted: mek });
    } catch (e) { console.error('setname error', e); }
});

cast({ pattern: 'profile', desc: 'Show your RPG profile', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const senderId   = await getPlayerId(conn, sender);
        const CREATOR_ID = '2348084644182';
        let id = senderId;
        if (senderId === CREATOR_ID) {
            const targetId = await getTargetId(conn, mek, args, 0).catch(() => null);
            if (targetId && targetId !== senderId) id = targetId;
        }

        const p = await getOrCreatePlayer(id);

        // Overdose report
        if (p._pendingOverdoseReport && id === senderId) {
            const report = p._pendingOverdoseReport;
            p._pendingOverdoseReport = null;
            await p.save();
            await conn.sendMessage(from, { text: report }, { quoted: mek });
        }

        // Fired notification
        if (p._firedFrom && id === senderId) {
            const name = p._firedFrom; p._firedFrom = null; await p.save();
            await conn.sendMessage(from, { text: `🔥 *FIRED* — You were terminated from *${name}* for too many absences. Apply to a new job: *career list*` }, { quoted: mek });
        }

        // Auto-land
        if (p.travelingTo && !isInFlight(p)) { p.location = p.travelingTo; p.travelingTo = null; p.travelingUntil = 0; await p.save(); }

        const nowTs       = now();
        const jailed      = p.jailedUntil && p.jailedUntil > nowTs;
        const inFlight    = isInFlight(p);
        const kidnapped   = isKidnapped(p);

        // Home / HP max
        let displayHpMax = p.maxHealth || 100;
        let homeName = 'The Streets';
        const activeHome = p.rentedHome || p.home;
        if (activeHome && activeHome !== 'streets') {
            const hData = await ShopItem.findOne({ id: activeHome }).exec();
            if (hData) { displayHpMax += hData.hpBoost || 0; homeName = hData.name + (p.rentedHome ? ` (Rented — ${shortTime(p.rentedHomeExpiresAt - nowTs)} left)` : ''); }
        }

        // Inventory
        const inv   = p.inventory instanceof Map ? [...p.inventory.entries()] : Object.entries(p.inventory || {});
        const props = p.properties instanceof Map ? [...p.properties.entries()] : Object.entries(p.properties || {});
        const invText  = inv.filter(([,v])=>v>0).map(([k,v])=>`${k}×${v}`).join(', ') || 'empty';
        const propText = props.filter(([,v])=>v>0).map(([k,v])=>`${k}×${v}`).join(', ') || 'None';
        const cryptoText = p.cryptoPortfolio instanceof Map
            ? ([...p.cryptoPortfolio.entries()].filter(([,v])=>v>0).map(([k,v])=>`${v.toFixed(4)} ${k}`).join(' | ') || 'None')
            : (Object.entries(p.cryptoPortfolio||{}).filter(([,v])=>v>0).map(([k,v])=>`${v.toFixed(4)} ${k}`).join(' | ') || 'None');

        // Drugs
        const activeDrugsNow = (p.activeDrugs||[]).filter(d=>d.expiresAt>nowTs);
        const drugsDisplay   = activeDrugsNow.length ? activeDrugsNow.map(d=>`${d.drug} (${shortTime(d.expiresAt-nowTs)} left)`).join(', ') : 'None';

        // Age
        const born    = p.bornAt || (p.createdAt ? new Date(p.createdAt).getTime() : nowTs);
        const ageHrs  = Math.floor((nowTs - born) / 3600000);
        const ageDays = Math.floor(ageHrs / 24);
        const ageStr  = ageDays > 0 ? `${ageDays}d ${ageHrs%24}h` : `${ageHrs}h`;

        // Degrees
        const LEVEL_NAMES_LOCAL = ['','📜 Certificate','📋 Diploma','🎓 Masters','🏅 PhD'];
        const degreesDisplay = (p.degrees||[]).length
            ? (p.degrees||[]).map(d => { const [cId,l] = d.split('_'); const c = SCHOOL_COURSES?.[cId]; return c ? `${c.icon} ${LEVEL_NAMES_LOCAL[parseInt(l)]} in ${c.name}` : d; }).join('\n   ')
            : 'None';

        // Career
        let careerDisplay = 'Unemployed — use *career list* to find a job';
        if (p.career?.jobId) {
            const company   = COMPANIES?.[p.career.companyId];
            const job       = CAREER_JOBS?.[p.career.jobId];
            const rank      = Math.min(5, p.career.rank || 1);
            const pay       = getCareerDailyPay(p);
            const lastClock = p.career.lastClockIn || 0;
            const nextClock = Math.max(0, 24*60*60*1000 - (nowTs - lastClock));
            const daysAtRank = p.career.daysAtRank || 0;
            const promoDays  = job?.promotionDays?.[rank-1];
            const promoStr   = rank >= 5 ? 'Max rank (Director)' : promoDays ? `${daysAtRank}/${promoDays} days to ${JOB_RANK_NAMES[rank]}` : '';
            careerDisplay = [
                `${company?.icon||'💼'} *${JOB_RANK_NAMES[rank-1]} ${job?.name||p.career.jobId}*`,
                `   🏢 Company: ${company?.name || p.career.companyId || 'Unknown'} (${company?.city||''})`,
                `   💰 Daily pay: ${pay > 0 ? fmtMoney(pay) : 'No company data — resign and reapply'}`,
                `   📅 Days worked: ${p.career.daysWorked||0} | At rank: ${daysAtRank} days`,
                promoStr ? `   📈 Promotion: ${promoStr}` : null,
                nextClock > 0 ? `   ⏰ Next clock-in: ${shortTime(nextClock)}` : `   ✅ Clock-in ready — type *clockin*`,
            ].filter(Boolean).join('\n');
        }

        // Loans
        let loanDisplay = 'None';
        if (p.activeLoan?.owed > 0) {
            const overdue = nowTs - (p.activeLoan.takenAt||0) > 2*60*60*1000;
            loanDisplay = `🦈 Owes *${fmtMoney(p.activeLoan.owed)}* to loan shark${overdue ? ' ⚠️ OVERDUE' : ''}`;
        }

        // Tax
        const taxDisplay = [];
        if ((p.taxOwed||0) > 0)        taxDisplay.push(`🏛️ Tax owed: ${fmtMoney(p.taxOwed)}`);
        if ((p.taxableIncome||0) > 0)  taxDisplay.push(`📊 Unreported income: ${fmtMoney(p.taxableIncome)}`);
        if (p.underAudit && p.auditExpiresAt > nowTs) taxDisplay.push(`🚨 UNDER AUDIT (${shortTime(p.auditExpiresAt-nowTs)} left)`);
        if ((p.taxEvasionStrikes||0) > 0) taxDisplay.push(`⚠️ Tax strikes: ${p.taxEvasionStrikes}/3`);

        // Faction
        let factionDisplay = 'None';
        if (p.faction) {
            const f = await Faction.findById(p.faction).exec().catch(()=>null);
            if (f) factionDisplay = `${f.name} (Level ${f.level||1}) — ${f.members.includes(String(id)) ? (f.owner===String(id)?'👑 Owner': f.officers?.includes(String(id))?'⭐ Officer':'Member') : 'Member'}`;
        }

        // Pet
        const petDisplay = p.pet?.type ? `${p.pet.nickname||p.pet.type} (Lv${p.pet.level||1}) — ${p.pet.injured?'🩹 Injured':'❤️ Healthy'}` : 'None';

        // Children
        // Collect all children (own + co-parented via spouse/exes)
        let allKids = [...(p.children||[])];
        const profileCoParents = [...new Set([p.spouse,...((p.exes||[]).map(e=>e.id))].filter(Boolean))];
        for (const coId of profileCoParents) {
            const co = await getOrCreatePlayer(coId).catch(()=>null);
            if (!co) continue;
            for (const c of (co.children||[])) {
                if ((c.parentIds||[]).includes(id) && !allKids.find(k=>k.name===c.name&&k.bornAt===c.bornAt)) allKids.push(c);
            }
        }
        const childDisplay = allKids.length
            ? allKids.map(c=>{ const age=Math.floor((nowTs-c.bornAt)/3600000); const custTag=c.custodyWith?(c.custodyWith===id?'🏠':` @${c.custodyWith}`):'👨‍👩‍👧'; return `${c.name} (${Math.floor(age/24)}d) ${custTag} — ❤️${c.health} 🍽️${c.hunger} 😊${c.happiness} 🎒${SCHOOL_STAGES?.[c.schoolLevel||0]||'Infant'}`; }).join('\n   ')
            : 'None';

        // Net worth
        const propWorth = props.reduce((t,[k,qty]) => {
            // Use base price (what player actually paid), not inflated market price
            const basePrice = SHOP_BASE_PRICES[k] ?? (DEFAULT_SHOP.find(x=>x.id===k)?.price || 0);
            return t + basePrice * qty;
        }, 0);
        const netWorth  = (p.money||0) + (p.bank||0) + propWorth;

        // Gear summary
        const gearSlots = [
            ['🔫 Weapon', p.equippedWeapon], ['🛡 Body', p.equippedArmor],
            ['⛑️ Head', p.equippedHelmet], ['🥊 Hands', p.equippedGloves],
            ['🦿 Legs', p.equippedKneePads], ['👢 Feet', p.equippedBoots],
        ];
        const gearLine = gearSlots.map(([label, id]) => {
            if (!id) return `${label}: —`;
            const g = DEFAULT_SHOP.find(s=>s.id===id);
            return `${label}: ${id}${g ? ` (+${g.atkBonus||g.defBonus||0})` : ''}`;
        }).join(' | ');

        const lines = [
            `╔══ 👤 *${p.username||'Unknown'}* ══╗`,
            p.isChildNpc ? `🎓 Child NPC | Parent ID: ${p.parentId||'?'} | ${p.childGender==='M'?'👦 Male':'👧 Female'}` : null,
            `📛 ID: ${p._id.startsWith('child_') ? p._id : `@${p._id}`}`,
            `🎖️ ${getTitle(p.level||1)} | Level ${p.level||1} | EXP: ${p.exp||0}/${xpToLevel(p.level||1)}`,
            p.prestigeLevel > 0 ? `⭐ Prestige: P${p.prestigeLevel}` : null,
            `🎂 Age: ${ageStr} | 💀 Deaths: ${p.deathCount||0}`,
            p.lastSeen && (senderId !== id || id === p._id) ? `🕐 Last seen: ${p.lastSeen > Date.now()-60000 ? 'Just now' : shortTime(Date.now()-p.lastSeen) + ' ago'}` : null,
            `📍 Location: ${inFlight ? `${p.location} ✈️→ ${p.travelingTo} (${shortTime(p.travelingUntil-nowTs)})` : p.location}`,
            `🏠 Home: ${homeName}`,
            ``,
            `╠══ 💰 *FINANCES* ══╣`,
            `👛 Wallet: ${(p.money||0) < 0 ? '🔴' : ''} ${fmtMoney(p.money||0)}${(p.money||0) < 0 ? ' ⚠️ IN DEBT' : ''}`,
            `🏦 Bank: ${fmtMoney(p.bank||0)}`,
            (p.offshoreBank||0) > 0 ? `🏝️ Offshore (${p.offshoreCity||'?'}): ${fmtMoney(p.offshoreBank||0)}` : null,
            (p.jointBankBalance||0) > 0 ? `💑 Joint Bank: ${fmtMoney(p.jointBankBalance||0)}` : null,
            `🏦 Debt: ${p.debt > 0 ? `-${fmtMoney(p.debt)}` : 'None'}`,
            `💸 Loan: ${loanDisplay}`,
            taxDisplay.length ? taxDisplay.join(' | ') : null,
            `📈 Net Worth: ~${fmtMoney(netWorth)}`,
            `🪙 Crypto: ${cryptoText}`,
            ``,
            `╠══ ❤️ *STATUS* ══╣`,
            `HP: ${p.health}/${displayHpMax}${jailed ? ` 🏥 (${shortTime(p.jailedUntil-nowTs)})` : ''} | ⚡ Energy: ${p.energy}/${p.maxEnergy||100}`,
            `😤 Nerve: ${p.nerve||60}/${p.maxNerve||60} (regens 1/5min — used for crimes)`,
            `🔥 Crime Heat: ${crimeLevelBar(p.crimeLevel||0)}${(p.crimeLevel||0) >= 80 ? " 🚨 WANTED" : (p.crimeLevel||0) >= 50 ? " ⚠️ Suspicious" : ""}`,
            `💊 Drugs: ${drugsDisplay}`,
            (p.addictionLevel||0) > 0 ? `🧨 Addiction: *${['','Mild','Moderate','Heavy','Severe','Terminal'][p.addictionLevel||0]}* — ${p.addictionDrug||'unknown'} | STR/DEF -${(p.addictionLevel||0)*2} | *rehab enter* to treat` : null,
            (p.inRehab && (p.rehabUntil||0) > nowTs) ? `🏥 IN REHAB — out in ${shortTime((p.rehabUntil||0)-nowTs)}` : null,
            kidnapped ? `🔒 KIDNAPPED by @${p.kidnappedBy}${p.ransomAmount>0?` — Ransom: ${fmtMoney(p.ransomAmount)}`:''}` : null,
            ``,
            `╠══ ⚔️ *COMBAT* ══╣`,
            `💪 STR: ${p.strength} | 🛡 DEF: ${p.defense} | 💨 SPD: ${p.speed} | 🎯 DEX: ${p.dexterity}`,
            `🧠 Intel: ${p.intelligence||1} | 💪 Labor: ${p.manualLabor||0} | 🏃 Endurance: ${p.endurance||0} | 💥 Crimes: ${p.crimesDone||0}`,
            `${gearLine}`,
            `📦 Ammo: ${p.ammo||0}${p.gearInsurance?` | 🛡️ Gear Insured`:``}`,
            `⚔️ Battles: ${p.attacksWon||0}W / ${p.attacksLost||0}L | Defends: ${p.defendsWon||0}W / ${p.defendsLost||0}L`,
            ``,
            `╠══ 🎓 *EDUCATION & CAREER* ══╣`,
            `🧠 Intelligence: ${p.intelligence||1}`,
            `🎓 Degrees:\n   ${degreesDisplay}`,
            `💼 Career: ${careerDisplay}`,
            ``,
            `╠══ 🏢 *SOCIAL* ══╣`,
            `💍 ${p.spouse ? `${p.marriageRole === 'husband' ? '👑 Husband' : '💍 Wife'} → Spouse: @${p.spouse}${p.marriedAt ? ` (married ${Math.floor((nowTs - p.marriedAt)/(24*60*60*1000))}d ago)` : ''}` : 'Single'}`,
            (p.exes||[]).length ? `💔 Exes: ${p.exes.map(e=>`@${e.id} (${e.role})`).join(', ')}` : null,
            `🐾 Pet: ${petDisplay}`,
            `👶 Children (${allKids.length}):\n   ${childDisplay}`,
            `🏢 Faction: ${factionDisplay}`,
            ``,
            `╠══ 🏠 *ASSETS* ══╣`,
            `🏙️ Properties: ${propText}`,
            `🎒 Inventory: ${invText}`,
            `🚗 Cars: ${(p.cars||[]).length ? (p.cars||[]).map(c=>`${c.name}${c.id===p.activeCar?' ⭐':''}`).join(', ') : 'None'}`,
            ``,
            `╠══ 📊 *STATISTICS* ══╣`,
            `💰 Total earned: ${fmtMoney(p.totalEarned||0)} | Spent: ${fmtMoney(p.moneySpent||0)}`,
            `🏛️ Tax paid: ${fmtMoney(p.taxPaid||0)} | Races won: ${p.racesWon||0}`,
            `🎯 Missions: ${(p.missionsCompleted||[]).length}/${MISSIONS.length} | 🏅 Achievements: ${(p.achievements||[]).length}/50+`,
            `📅 Daily challenges done: ${(p.dailyChallengesCompleted||0)} | 🔗 Referrals: ${p.referralCount||0}`,
            (p.leaguePoints||0) > 0 ? `🥊 League Points: ${p.leaguePoints||0} | Tournament Wins: ${p.leagueWins||0}` : null,
            (p.ownsCasino) ? `🎰 Casino Owner | Edge: ${((p.casinoHouseEdge||0.05)*100).toFixed(0)}% | Earned: ${fmtMoney(p.casinoEarnings||0)}` : null,
            `🏅 Titles: ${(p.titles||[]).length?p.titles.join(' | '):'None'}`,
            `╚${'═'.repeat(20)}╝`,
        ].filter(s => s !== null && s !== undefined);

        const mentions = [toJid(p._id)];
        if (p.spouse) mentions.push(toJid(p.spouse));
        if (kidnapped) mentions.push(toJid(p.kidnappedBy));

        // Auto-award any pending missions/achievements
        const missionNotif  = await awardMissions(p);
        const achievNotif   = await awardAchievements(p);
        if (missionNotif || achievNotif) await p.save();
        return conn.sendMessage(from, { text: lines.join('\n') + (missionNotif||'') + (achievNotif||''), mentions }, { quoted: mek });
    } catch (e) { console.error('profile error', e); }
});

// =============================================================================
// COMMAND: compare — Side-by-side full stats comparison between two players
// =============================================================================
cast({ pattern: 'compare', desc: 'compare @player1 @player2 — Full stats comparison', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const senderId = await getPlayerId(conn, sender);
        // Get two targets from mentions/args
        const mentions = mek.message?.extendedTextMessage?.contextInfo?.mentionedJid || [];
        let id1, id2;
        if (mentions.length >= 2) {
            id1 = await getPlayerId(conn, mentions[0]);
            id2 = await getPlayerId(conn, mentions[1]);
        } else if (mentions.length === 1) {
            id1 = senderId;
            id2 = await getPlayerId(conn, mentions[0]);
        } else if (args.length >= 2) {
            id1 = await getPlayerId(conn, args[0]);
            id2 = await getPlayerId(conn, args[1]);
        } else if (args.length === 1) {
            id1 = senderId;
            id2 = await getPlayerId(conn, args[0]);
        } else {
            return conn.sendMessage(from, { text: `Usage: *compare @player1 @player2*\nOr: *compare @player* (compares against yourself)` }, { quoted: mek });
        }
        if (!id1 || !id2) return conn.sendMessage(from, { text: `❌ Couldn't resolve both players. Tag them properly.` }, { quoted: mek });
        if (id1 === id2) return conn.sendMessage(from, { text: `❌ Can't compare a player to themselves.` }, { quoted: mek });

        const [a, b] = await Promise.all([getOrCreatePlayer(id1), getOrCreatePlayer(id2)]);
        const nameA = a.username || `@${id1}`;
        const nameB = b.username || `@${id2}`;

        // Helper: compare a numeric stat, mark winner with ✅, loser with ❌, tie with 🟰
        function cmp(va, vb, fmt) {
            const fa = fmt ? fmt(va) : va.toLocaleString();
            const fb = fmt ? fmt(vb) : vb.toLocaleString();
            if (va > vb) return [`✅ ${fa}`, `❌ ${fb}`];
            if (vb > va) return [`❌ ${fa}`, `✅ ${fb}`];
            return [`🟰 ${fa}`, `🟰 ${fb}`];
        }

        const nw = pl => (pl.money||0) + (pl.bank||0);

        const lines = [
            `⚔️ *PLAYER COMPARISON*`,
            ``,
            `         *${nameA}*  vs  *${nameB}*`,
            ``,
            `━━━━━━━ 💰 WEALTH ━━━━━━━`,
        ];
        const addRow = (label, va, vb, fmt) => {
            const [sa, sb] = cmp(va||0, vb||0, fmt);
            lines.push(`${label}\n  ${nameA}: ${sa}\n  ${nameB}: ${sb}`);
        };

        addRow(`💵 Cash`,        a.money||0,         b.money||0,         fmtMoney);
        addRow(`🏦 Bank`,        a.bank||0,           b.bank||0,          fmtMoney);
        addRow(`💎 Net Worth`,   nw(a),               nw(b),              fmtMoney);
        addRow(`💸 Total Earned`,a.totalEarned||0,    b.totalEarned||0,   fmtMoney);
        addRow(`🏛️ Tax Paid`,    a.taxPaid||0,        b.taxPaid||0,       fmtMoney);

        lines.push(``, `━━━━━━━ ⭐ LEVEL & XP ━━━━━━━`);
        addRow(`⭐ Level`,       a.level||1,          b.level||1);
        addRow(`🔷 XP`,         a.exp||0,             b.exp||0);
        addRow(`🏋️ Total Trains`,a.totalTrains||0,    b.totalTrains||0);

        lines.push(``, `━━━━━━━ 💪 COMBAT STATS ━━━━━━━`);
        addRow(`⚔️ Strength`,    a.strength||0,       b.strength||0);
        addRow(`🛡️ Defense`,     a.defense||0,        b.defense||0);
        addRow(`💨 Speed`,       a.speed||0,          b.speed||0);
        addRow(`🎯 Dexterity`,   a.dexterity||0,      b.dexterity||0);
        addRow(`🧠 Intelligence`,a.intelligence||0,   b.intelligence||0);
        addRow(`❤️ Max HP`,      a.maxHealth||100,    b.maxHealth||100);
        addRow(`❤️ Current HP`,  a.health||0,         b.health||0);

        lines.push(``, `━━━━━━━ ⚔️ COMBAT RECORD ━━━━━━━`);
        addRow(`🥊 Attacks Won`, a.attacksWon||0,     b.attacksWon||0);
        addRow(`💀 Attacks Lost`,a.attacksLost||0,    b.attacksLost||0);
        const ratioA = a.attacksWon && a.attacksLost ? (a.attacksWon/(a.attacksLost||1)).toFixed(2) : (a.attacksWon||0).toFixed(2);
        const ratioB = b.attacksWon && b.attacksLost ? (b.attacksWon/(b.attacksLost||1)).toFixed(2) : (b.attacksWon||0).toFixed(2);
        addRow(`📊 K/D Ratio`,   parseFloat(ratioA),  parseFloat(ratioB), v => v.toFixed(2));
        addRow(`🏆 Bounties Collected`, a.bountiesCollected||0, b.bountiesCollected||0);
        addRow(`🏅 League Points`,a.leaguePoints||0,  b.leaguePoints||0);
        addRow(`🥇 League Wins`, a.leagueWins||0,     b.leagueWins||0);

        lines.push(``, `━━━━━━━ 🦹 CRIME RECORD ━━━━━━━`);
        addRow(`🔪 Crimes Done`, a.crimesDone||0,     b.crimesDone||0);
        addRow(`🔥 Crime Level`, a.crimeLevel||0,     b.crimeLevel||0);
        addRow(`🚔 Times Jailed`,a.timesJailed||0,    b.timesJailed||0);
        addRow(`💸 Fines Paid`,  a.finesPaid||0,      b.finesPaid||0,     fmtMoney);

        lines.push(``, `━━━━━━━ 💼 WORK & CAREER ━━━━━━━`);
        addRow(`🔨 Jobs Done`,   a.jobsDone||0,       b.jobsDone||0);
        addRow(`🏭 Manual Labor`,a.manualLabor||0,    b.manualLabor||0);
        addRow(`🎓 Degrees`,     (a.degrees||[]).length, (b.degrees||[]).length);
        lines.push(`📋 A Degrees: ${(a.degrees||[]).join(', ')||'None'}`);
        lines.push(`📋 B Degrees: ${(b.degrees||[]).join(', ')||'None'}`);

        lines.push(``, `━━━━━━━ 🏘️ ASSETS ━━━━━━━`);
        addRow(`🏠 Properties`,  (a.properties||[]).length, (b.properties||[]).length);
        addRow(`🚗 Cars`,        (a.cars||[]).length, (b.cars||[]).length);
        addRow(`🐾 Has Pet`,     a.pet?.type ? 1 : 0, b.pet?.type ? 1 : 0, v => v ? '✔️' : '✖️');

        lines.push(``, `━━━━━━━ 🎰 GAMBLING ━━━━━━━`);
        addRow(`🎰 Casino Wins`, a.casinoWins||0,     b.casinoWins||0);
        addRow(`💸 Money Spent`, a.moneySpent||0,     b.moneySpent||0,    fmtMoney);
        addRow(`🏇 Race Wins`,   a.racesWon||0,       b.racesWon||0);

        lines.push(``, `━━━━━━━ 👨‍👩‍👧 FAMILY & SOCIAL ━━━━━━━`);
        lines.push(`💍 A Spouse: ${a.spouse ? `@${a.spouse}` : 'None'}`);
        lines.push(`💍 B Spouse: ${b.spouse ? `@${b.spouse}` : 'None'}`);
        addRow(`👶 Children`,    (a.children||[]).length, (b.children||[]).length);
        addRow(`🌍 Cities Visited`, (a.citiesVisited||[]).length, (b.citiesVisited||[]).length);
        lines.push(`🏢 A Faction: ${a.faction||'None'}`);
        lines.push(`🏢 B Faction: ${b.faction||'None'}`);
        addRow(`🎖️ Notoriety`,   a.notoriety||0,      b.notoriety||0);
        addRow(`✈️ Travels`,     a.travels||0,        b.travels||0);

        lines.push(``, `━━━━━━━━━━━━━━━━━━━━━━━`);

        const mentionIds = [toJid(id1), toJid(id2)];
        return conn.sendMessage(from, { text: lines.join('\n'), mentions: mentionIds }, { quoted: mek });
    } catch(e) { console.error('compare error', e); }
});
cast({ pattern: 'gamble', desc: 'Casino Games', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.`, mentions: [toJid(p._id)] }, { quoted: mek });
        
        const game = (args[0] || '').toLowerCase();
        const amount = parseInt(args[1]);

        if (!game || isNaN(amount) || amount <= 0) {
            let txt = `🎰 *THE DIAMOND CASINO* 🎰\n`;
            txt += `💸 *MEGA JACKPOT: ${fmtMoney(global.casinoJackpot)}*\n`;
            txt += `_Welcome high roller. Pick your poison._\n\n`;
            txt += `🎰 *1. Slots* — x2, x5, JACKPOT\n> gamble slots <amount>\n\n`;
            txt += `🪙 *2. Coinflip* — x2 payout\n> gamble coinflip <amount> <heads/tails>\n\n`;
            txt += `🏁 *3. Horse Racing* — 1st/2nd/3rd payouts\n> gamble horse <amount> <1-5>\n\n`;
            txt += `🎡 *4. Roulette* — x2 color, x14 green + JACKPOT\n> gamble roulette <amount> <red/black/green>\n\n`;
            txt += `🃏 *5. High/Low* — guess higher or lower (x2) | 5-streak = jackpot bonus\n> highlow <amount> <higher/lower>\n\n`;
            txt += `🃏 *6. Blackjack* — beat the dealer to 21 (natural pays x2.5)\n> blackjack <amount> → then: blackjack hit | blackjack stand\n\n`;
            txt += `🎲 *7. Dice Poker* — roll 5 dice for poker hands (pair=x1.25, five-of-a-kind=x10)\n> dicegame <amount>\n`;
            return conn.sendMessage(from, { text: txt }, { quoted: mek });
        }

        if (p.money < amount) return conn.sendMessage(from, { text: `You don't have enough money. Your balance: ${fmtMoney(p.money)}` }, { quoted: mek });

        p.money -= amount; 
        p.moneySpent += amount; 
        let winAmount = 0;
        let resultMsg = '';

        if (game === 'slots') {
            const symbols = ['🍎', '🍒', '🍇', '💎', '7️⃣'];
            const r1 = symbols[Math.floor(Math.random() * symbols.length)];
            const r2 = symbols[Math.floor(Math.random() * symbols.length)];
            const r3 = symbols[Math.floor(Math.random() * symbols.length)];
            
            resultMsg = `🎰 *SLOTS* 🎰\n┏━━━━━━━━━━━┓\n┃ ${r1} | ${r2} | ${r3} ┃\n┗━━━━━━━━━━━┛\n\n`;
            
            if (r1 === '7️⃣' && r2 === '7️⃣' && r3 === '7️⃣') {
                winAmount = (amount * 10) + global.casinoJackpot;
                resultMsg += `🚨 *MEGA JACKPOT!!!* 🚨\nYou hit three 7s and won ${fmtMoney(winAmount)}!`;
                global.casinoJackpot = 50000; 
            } else if (r1 === r2 && r2 === r3) {
                winAmount = Math.floor(amount * 3);
                resultMsg += `🎉 *JACKPOT!* You hit 3 of a kind and won ${fmtMoney(winAmount)}!`;
            } else if (r1 === r2 || r2 === r3 || r1 === r3) {
                winAmount = Math.floor(amount * 1.5);
                resultMsg += `Nice! You hit 2 of a kind and won ${fmtMoney(winAmount)}!`;
            } else {
                resultMsg += `Bust. You lost your bet of ${fmtMoney(amount)}.`;
                global.casinoJackpot += Math.floor(amount * 0.1); 
            }
        } 
        
        else if (game === 'coinflip') {
            const guess = (args[2] || '').toLowerCase();
            if (guess !== 'heads' && guess !== 'tails') return conn.sendMessage(from, { text: `Usage: gamble coinflip <amount> <heads/tails>` }, { quoted: mek });
            
            const flip = Math.random() < 0.47 ? guess : (guess === 'heads' ? 'tails' : 'heads'); // 47% player win
            const emoji = flip === 'heads' ? '🌕' : '🌑';
            resultMsg = `🪙 *COINFLIP* 🪙\nTossing the coin... ⬆️🪙⬇️\nIt landed on: ${emoji} *${flip.toUpperCase()}*\n\n`;
            
            if (guess === flip) {
                winAmount = Math.floor(amount * 1.85);
                resultMsg += `You won ${fmtMoney(winAmount)}!`;
            } else {
                resultMsg += `You lost your bet of ${fmtMoney(amount)}.`;
                global.casinoJackpot += Math.floor(amount * 0.1);
            }
        } 
        
        else if (game === 'horse') {
            const guess = parseInt(args[2]);
            if (isNaN(guess) || guess < 1 || guess > 5) return conn.sendMessage(from, { text: `Usage: gamble horse <amount> <1-5>` }, { quoted: mek });
            
            let horses = [1, 2, 3, 4, 5].sort(() => Math.random() - 0.5);
            const first = horses[0];
            const second = horses[1];
            const third = horses[2];

            let track = `🏁 *HORSE RACING* 🏁\n`;
            for(let i=1; i<=5; i++) {
                if(i === first) track += `[${i}] 🏁 🏇💨 ---------------- \n`;
                else if(i === second) track += `[${i}] --- 🏁 🏇💨 ------------- \n`;
                else if(i === third) track += `[${i}] ------ 🏁 🏇💨 ---------- \n`;
                else track += `[${i}] ----------- 🏁 🏇💨 ----- \n`;
            }

            resultMsg = track + `\n`;
            
            if (guess === first) {
                winAmount = Math.floor(amount * 2.5);
                resultMsg += `🥇 1ST PLACE! Your horse won! You take home ${fmtMoney(winAmount)}!`;
            } else if (guess === second) {
                winAmount = Math.floor(amount * 1.5);
                resultMsg += `🥈 2ND PLACE! A solid run. You take home ${fmtMoney(winAmount)}!`;
            } else if (guess === third) {
                winAmount = Math.floor(amount * 0.25); // Get quarter back
                resultMsg += `🥉 3RD PLACE! Barely made the podium. You salvaged ${fmtMoney(winAmount)} of your bet.`;
            } else {
                resultMsg += `❌ Your horse ate dust. You lost ${fmtMoney(amount)}.`;
                global.casinoJackpot += Math.floor(amount * 0.1);
            }
        } 
        
        else if (game === 'roulette') {
            const guess = (args[2] || '').toLowerCase();
            if (guess !== 'red' && guess !== 'black' && guess !== 'green') return conn.sendMessage(from, { text: `Usage: gamble roulette <amount> <red/black/green>` }, { quoted: mek });
            
            const roll = Math.random();
            let land = 'green'; let landEmoji = '🟢';
            if (roll < 0.473) { land = 'red'; landEmoji = '🔴'; }
            else if (roll < 0.946) { land = 'black'; landEmoji = '⚫'; }
            
            resultMsg = `🎡 *ROULETTE* 🎡\nThe wheel spins... 🔴⚫🟢⚫🔴\nThe ball drops on: ${landEmoji} *${land.toUpperCase()}*\n\n`;
            
            if (guess === land) {
                if (land === 'green') {
                    winAmount = (amount * 8) + Math.floor(global.casinoJackpot * 0.25);
                    resultMsg += `🚨 *GREEN!* You won ${fmtMoney(winAmount)} (Includes 25% of the Mega Jackpot)!`;
                    global.casinoJackpot = Math.floor(global.casinoJackpot * 0.75);
                } else {
                    winAmount = Math.floor(amount * 1.7);
                    resultMsg += `Winner! You take home ${fmtMoney(winAmount)}!`;
                }
            } else {
                resultMsg += `Ouch. The house takes your ${fmtMoney(amount)}.`;
                global.casinoJackpot += Math.floor(amount * 0.1);
            }
        } 
        
        else if (game === 'rr') {
            p.money += amount; p.moneySpent -= amount;
            return conn.sendMessage(from, { text: `🔫 Russian Roulette has been *permanently closed* by the house.

Try: slots | coinflip | horse | roulette` }, { quoted: mek });
        }

        else {
            p.money += amount; 
            p.moneySpent -= amount;
            return conn.sendMessage(from, { text: `Invalid game. Type 'gamble' to see the list.` }, { quoted: mek });
        }

        p.money += winAmount;

        // ── IMMEDIATE WIN TAX + WIN CAP ───────────────────────────────────────
        // Cap: no single gamble win can exceed $50B profit (still huge, not game-breaking)
        const MAX_GAMBLE_PROFIT = 50_000_000_000;
        if (winAmount > MAX_GAMBLE_PROFIT) {
            const excess = winAmount - MAX_GAMBLE_PROFIT;
            p.money -= excess;
            winAmount = MAX_GAMBLE_PROFIT;
            resultMsg += `\n⚠️ *House Rule: Win capped at ${fmtMoney(MAX_GAMBLE_PROFIT)}.*`;
        }

        // Apply tax immediately on profit — don't wait for the IRS cycle
        const profit = Math.max(0, winAmount - amount);
        if (profit > 0) {
            addTaxableIncome(p, profit);
            // Instant deduction of a portion — rest tracked for IRS cycle
            const INSTANT_TAX_RATE = profit >= 1_000_000_000 ? 0.30   // $1B+ win → 30% instant
                                   : profit >= 100_000_000  ? 0.25   // $100M+ win → 25% instant
                                   : profit >= 10_000_000   ? 0.20   // $10M+ win → 20% instant
                                   : profit >= 1_000_000    ? 0.15   // $1M+ win → 15% instant
                                   : 0.08;                            // under $1M → 8% instant
            const instantTax = Math.floor(profit * INSTANT_TAX_RATE);
            if (instantTax > 0) {
                p.money = Math.max(0, p.money - instantTax);
                p.taxPaid = (p.taxPaid || 0) + instantTax;
                resultMsg += `\n🏛️ *Instant tax (${(INSTANT_TAX_RATE*100).toFixed(0)}%): -${fmtMoney(instantTax)}* — Net profit: ${fmtMoney(profit - instantTax)}`;
            }
        }

        logAction(p, `Played Casino (${game}) -> ${winAmount > 0 ? '+'+fmtMoney(winAmount) : '-'+fmtMoney(amount)}`);
        if (winAmount > 0) logFinancial(p, `Gamble win (${game})`, winAmount - amount);

        // Butterfly effect: tick challenge, track earnings, check achievements
        tickChallenge(p, 'gambles', 1);
        if (winAmount > 0) {
            p.totalEarned = (p.totalEarned||0) + winAmount;
            awardAchievements(p);
        }
        const titleMsg = checkTitles(p);
        await p.save();
        
        return conn.sendMessage(from, { text: resultMsg + titleMsg }, { quoted: mek });
    } catch (e) { console.error('gamble error', e); }
});

// ------------- Liquidation System -------------
cast({ pattern: 'sellproperty', desc: 'Sell property back to store', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });

        const propId = (args && args[0]) ? args[0].toLowerCase() : null;
        const qty = Math.max(1, parseInt((args && args[1])||'1') || 1);

        if (!propId) return conn.sendMessage(from, { text: 'Usage: sellproperty <property_id> [qty]' }, { quoted: mek });

        const ownedQty = p.properties.get(propId) || 0;
        if (ownedQty < qty) return conn.sendMessage(from, { text: `You don't own ${qty}x ${propId}.` }, { quoted: mek });

        const shopIt = DEFAULT_SHOP.find(s => s.id === propId);
        if (!shopIt || (shopIt.type !== 'property' && shopIt.type !== 'house')) return conn.sendMessage(from, { text: `This is not a valid property.` }, { quoted: mek });

        const sellValue = Math.floor(shopIt.price * 0.75) * qty;

        p.properties.set(propId, ownedQty - qty);
        p.money += sellValue;
        if (p.home === propId && p.properties.get(propId) === 0) p.home = 'streets';

        logAction(p, `Sold property ${propId}x${qty} for ${fmtMoney(sellValue)}`);
        await p.save();

        return conn.sendMessage(from, { text: `🏦 You sold your ${shopIt.name} (x${qty}) to the bank for ${fmtMoney(sellValue)} (75% value).` }, { quoted: mek });
    } catch(e) { console.error(e); }
});

cast({ pattern: 'sellitem', desc: 'Sell items or animals', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });

        const itemId = (args && args[0]) ? args[0].toLowerCase() : null;
        const qty = Math.max(1, parseInt((args && args[1])||'1') || 1);

        if (!itemId) return conn.sendMessage(from, { text: 'Usage: sellitem <item_id> [qty]' }, { quoted: mek });

        const ownedQty = p.inventory.get(itemId) || 0;
        if (ownedQty < qty) return conn.sendMessage(from, { text: `You don't have ${qty}x ${itemId} in your inventory.` }, { quoted: mek });

        let itemPrice = 0;
        let itemName = itemId;
        
        const preyData = PREY_LIST.find(p => p.id === itemId);
        if (preyData) {
            // Prey prices fluctuate with economy — good economy = better black market prices
            const preyMult = 0.6 + (global.ECON_INDEX ?? 1.0) * 0.4;
            itemPrice = Math.ceil(preyData.price * preyMult) * qty;
            itemName = preyData.name;
        } else {
            const shopIt = DEFAULT_SHOP.find(s => s.id === itemId);
            if (shopIt) {
                // Resale at 50% of live market price
                itemPrice = Math.floor(livePrice({ id: itemId, price: shopIt.price }) * 0.50) * qty;
                itemName = shopIt.name;
            } else {
                return conn.sendMessage(from, { text: `This item has no resale value.` }, { quoted: mek });
            }
        }

        p.inventory.set(itemId, ownedQty - qty);
        p.money += itemPrice;
        
        if (p.equippedWeapon === itemId && p.inventory.get(itemId) === 0) p.equippedWeapon = null;
        if (p.equippedArmor === itemId && p.inventory.get(itemId) === 0) p.equippedArmor = null;

        logAction(p, `Sold item ${itemName}x${qty} for ${fmtMoney(itemPrice)}`);
        await p.save();

        return conn.sendMessage(from, { text: `🛒 You sold ${qty}x ${itemName} for ${fmtMoney(itemPrice)}!` }, { quoted: mek });
    } catch(e) { console.error(e); }
});

// ------------- Immersive Mechanics -------------
cast({ pattern: 'hunt', desc: 'Hunt animals in your region', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });

        const elapsed = now() - (p.lastHunt || 0);
        const cooldown = 5 * 60 * 1000; 
        if (elapsed < cooldown) return conn.sendMessage(from, { text: `Wait ${shortTime(cooldown - elapsed)} before hunting again.` }, { quoted: mek }); 
        
        if (p.energy < 15) return conn.sendMessage(from, { text: `Not enough energy to hunt. 15 required.` }, { quoted: mek }); 

        p.energy -= 15;
        p.lastHunt = now();

        const regionPrey = PREY_LIST.filter(a => a.region === normLoc(p.location));
        if (regionPrey.length === 0) return conn.sendMessage(from, { text: `There is nothing to hunt in ${p.location}.` }, { quoted: mek });

        const target = regionPrey[Math.floor(Math.random() * regionPrey.length)];

        const playerPower = p.speed + p.strength + p.dexterity + (p.huntingSkill * 2);
        const hitChance = playerPower / (playerPower + target.difficulty);

        if (Math.random() < hitChance) {
            p.inventory.set(target.id, (p.inventory.get(target.id) || 0) + 1);
            p.huntingSkill += 1;
            const xp = 10 + Math.floor(Math.random() * 20);
            p.exp += xp;
            p.manualLabor = (p.manualLabor||0) + 2;
            p.endurance   = (p.endurance||0) + 1;
            tickChallenge(p, 'hunts', 1);
            const leveled = await tryLevelUp(p);
            logAction(p, `Hunted a ${target.name}`);
            await p.save();

            return conn.sendMessage(from, { text: `🏹 *HUNT SUCCESS!*\nYou stalked and killed a *${target.name}*!\n\n🎒 Added to inventory.\n📈 Hunting Skill +1\n✨ +${xp} EXP${leveled ? `\n🎉 Leveled up! Now level ${p.level}` : ''}\n\n*Tip:* Use 'sellitem ${target.id}' to sell it for ${fmtMoney(Math.ceil(target.price * (0.6 + (global.ECON_INDEX ?? 1.0) * 0.4)))} (market rate).` }, { quoted: mek });
        } else {
            const damage = Math.floor(5 + (target.difficulty * 0.05 * Math.random()));
            p.health = Math.max(0, p.health - damage);
            
            let failMsg = `🏹 *HUNT FAILED!*\nThe *${target.name}* outsmarted you. You took ${damage} damage tripping in the wild.`;
            
            if (p.health <= 0) {
                p.jailedUntil = now() + (10 * 60 * 1000);
                p.inJail = false;
                p.health = 0;
                failMsg += `\n🚑 You were severely injured and hospitalized for 10 minutes.`;
            }
            
            logAction(p, `Failed hunt for ${target.name}`);
            await p.save();
            return conn.sendMessage(from, { text: failMsg }, { quoted: mek });
        }
    } catch(e) { console.error(e); }
});

cast({ pattern: 'search', desc: 'Search area for loot', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });

        const elapsed = now() - (p.lastSearch || 0);
        const cooldown = 3 * 60 * 1000; 
        if (elapsed < cooldown) return conn.sendMessage(from, { text: `Wait ${shortTime(cooldown - elapsed)} before searching again.` }, { quoted: mek }); 
        
        if (p.energy < 5) return conn.sendMessage(from, { text: `Not enough energy to search. 5 required.` }, { quoted: mek }); 

        p.energy -= 5;
        p.lastSearch = now();

        const roll = Math.random();
        if (roll < 0.50) {
            const foundCash = Math.floor(10 + Math.random() * 90);
            p.money += foundCash;
            logAction(p, `Searched and found ${fmtMoney(foundCash)}`);
            await p.save();
            return conn.sendMessage(from, { text: `🗑️ You searched the area and found a dropped wallet with ${fmtMoney(foundCash)}!` }, { quoted: mek });
        } else if (roll < 0.70) {
            const items = ['medkit', 'energydrink', 'bullets'];
            const item = items[Math.floor(Math.random() * items.length)];
            p.inventory.set(item, (p.inventory.get(item) || 0) + 1);
            logAction(p, `Searched and found 1x ${item}`);
            await p.save();
            return conn.sendMessage(from, { text: `🗑️ You dug through an alleyway and found 1x *${item}*!` }, { quoted: mek });
        } else {
            logAction(p, `Searched and found nothing`);
            await p.save();
            return conn.sendMessage(from, { text: `🗑️ You searched the area but only found garbage.` }, { quoted: mek });
        }
    } catch(e) { console.error(e); }
});

cast({ pattern: 'beg', desc: 'Beg for money on the streets', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });

        const elapsed = now() - (p.lastBeg || 0);
        const cooldown = 2 * 60 * 1000; 
        if (elapsed < cooldown) return conn.sendMessage(from, { text: `Wait ${shortTime(cooldown - elapsed)} before begging again. Have some dignity.` }, { quoted: mek }); 
        
        p.lastBeg = now();
        p.timesBegged = (p.timesBegged || 0) + 1;

        if (Math.random() < 0.20) {
            const dmg = Math.floor(Math.random() * 15) + 5;
            p.health = Math.max(0, p.health - dmg);
            let msg = `🛑 You asked the wrong person for money. A grumpy local beat you up! You lost ${dmg} HP.`;
            if (p.health <= 0) {
                p.jailedUntil = now() + (5 * 60 * 1000);
                p.inJail = false;
                msg += `\n🚑 You were sent to the hospital.`;
            }
            await p.save();
            return conn.sendMessage(from, { text: msg }, { quoted: mek });
        }

        const gross = Math.floor(Math.random() * 1500) + 500; // max $2000, avg ~$1250
        const { net: amount, vat } = applyVAT(gross);
        p.money = capBal((p.money||0) + amount);
        p.totalEarned = (p.totalEarned||0) + amount;
        const begLoanMsg = deductLoanIfOwed(p, amount, 'Begging');
        logFinancial(p, `Begging on streets of ${p.location}`, amount);
        const titleMsg = checkTitles(p);
        await p.save();
        return conn.sendMessage(from, { text: `🤲 You begged on the streets of ${p.location} and received ${fmtMoney(gross)} (−${fmtMoney(vat)} VAT) = *${fmtMoney(amount)}*.${begLoanMsg}` + titleMsg }, { quoted: mek });
    } catch(e) { console.error(e); }
});

cast({ pattern: 'bankrob', desc: 'Attempt to rob the central bank (High Risk)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });

        const elapsed = now() - (p.lastBankRob || 0);
        const cooldown = 60 * 60 * 1000; // 1 hour
        if (elapsed < cooldown) return conn.sendMessage(from, { text: `The banks are on high alert. Wait ${shortTime(cooldown - elapsed)}.` }, { quoted: mek }); 
        
        if (p.energy < 50) return conn.sendMessage(from, { text: `Not enough energy. 50 required to orchestrate a bank heist.` }, { quoted: mek }); 
        
        const guns = ['pistol', 'taser', 'ar15', 'goldengun', 'deagle', 'musket', 'precisionrifle'];
        if (!guns.includes(p.equippedWeapon)) return conn.sendMessage(from, { text: `You can't rob a bank without a firearm equipped!` }, { quoted: mek });
        if (p.ammo <= 0) return conn.sendMessage(from, { text: `Your gun has no ammo! Are you crazy?` }, { quoted: mek });

        p.energy -= 50;
        p.ammo -= 1;
        p.lastBankRob = now();
        p.crimeLevel = Math.min(100, (p.crimeLevel || 0) + 30); // bank robbery is very hot

        const power = p.strength + p.speed + p.dexterity;
        const successChance = Math.min(0.40, 0.10 + (power / 1000)); 

        if (Math.random() < successChance) {
            const gross = Math.floor(10000 + Math.random() * 40000);
            const { net: loot, vat } = applyVAT(gross);
            p.money += loot;
            addTaxableIncome(p, loot);
            p.banksRobbed = (p.banksRobbed || 0) + 1;
            p.exp += 150;
            const leveled = await tryLevelUp(p);
            const titleMsg = checkTitles(p);
            logAction(p, `Robbed a bank for ${fmtMoney(loot)}`);
            logFinancial(p, `Bank robbery`, loot);
            logGlobal('🏦', `*${p.username || p._id}* ROBBED THE BANK and escaped with ${fmtMoney(loot)}!`);
            await p.save();
            return conn.sendMessage(from, { text: `🏦 *BANK HEIST SUCCESSFUL!*\nYou stormed the vault and escaped with ${fmtMoney(gross)} — after 🏛️ VAT (12%): *${fmtMoney(loot)} net*!\n\n✨ +150 EXP${leveled ? `\n🎉 Leveled up! Now level ${p.level}` : ''}${titleMsg}` }, { quoted: mek });
        } else {
            let fine = Math.floor(p.money * 0.25) + 50000; // Steep fine ensures debt for brokies
            if (p.money < fine) {
                p.debt += (fine - p.money);
                p.money = 0;
            } else {
                p.money -= fine;
            }
            p.jailedUntil = now() + (60 * 60 * 1000);
            p.inJail = false;
            p.health = 0;
            const lostWpn = p.equippedWeapon;
            p.equippedWeapon = null; 
            logAction(p, `Failed bank heist`);
            await p.save();
            return conn.sendMessage(from, { text: `🚨 *BANK HEIST FAILED!*\nThe SWAT team surrounded the building. You were shot, your ${lostWpn} was confiscated, and you were fined ${fmtMoney(fine)}.\n\n📉 Check your profile. If you couldn't pay the fine, you are now in DEBT!\n🚔 Sent to MAXIMUM SECURITY PRISON for 1 hour.` }, { quoted: mek });
        }
    } catch(e) { console.error(e); }
});

// ------------- Bounty System -------------
cast({ pattern: 'bounty', desc: 'Bounty commands', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const action = (args && args[0]) ? args[0].toLowerCase() : null;
        const pId = await getPlayerId(conn, sender);

        if (!action) return conn.sendMessage(from, { text: 'Usage: bounty <list|set> [args]' }, { quoted: mek });

        if (action === 'list') {
            const bounties = await Bounty.find({ amount: { $gt: 0 } }).sort({ amount: -1 }).limit(15).exec();
            if (!bounties.length) return conn.sendMessage(from, { text: '📋 The bounty board is currently empty. Nobody is wanted.' }, { quoted: mek });
            
            let txt = `☠️ *GLOBAL BOUNTY BOARD* ☠️\n_(Kill these players to claim the cash)_\n\n`;
            let mentionsArray = [];
            bounties.forEach(b => {
                txt += `🎯 Target: *@${b.targetId}*\n💰 Reward: ${fmtMoney(b.amount)}\n\n`;
                mentionsArray.push(toJid(b.targetId));
            });
            return conn.sendMessage(from, { text: txt, mentions: mentionsArray }, { quoted: mek });
        }

        if (action === 'set') {
            const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
            const targetId = await getTargetId(conn, mek, args, 1);
            const amount = parseInt(args[2] || args[args.length - 1]); 

            if (!targetId || isNaN(amount) || amount <= 0) {
                return conn.sendMessage(from, { text: 'Usage: bounty set @user <amount>' }, { quoted: mek });
            }

            if (targetId === pId) return conn.sendMessage(from, { text: `You can't put a bounty on yourself.` }, { quoted: mek });
            if (p.money < amount) return conn.sendMessage(from, { text: `You don't have ${fmtMoney(amount)}.` }, { quoted: mek });

            p.money -= amount;
            p.moneySpent += amount;
            logAction(p, `Placed ${fmtMoney(amount)} bounty on @${targetId}`);
            
            let b = await Bounty.findOne({ targetId: targetId });
            if (!b) b = new Bounty({ targetId: targetId, amount: 0 });
            b.amount += amount;
            
            const titleMsg = checkTitles(p);
            await p.save();
            await b.save();

            return conn.sendMessage(from, { text: `☠️ *@${pId}* just placed a ${fmtMoney(amount)} bounty on *@${targetId}*! Total reward is now ${fmtMoney(b.amount)}.` + titleMsg, mentions: [toJid(pId), toJid(targetId)] }, { quoted: mek });
        }
    } catch(e) { console.error(e); }
});

// ------------- Real Estate Rentals -------------
cast({ pattern: 'rentout', desc: 'Rent out a property you own', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        if (args.length < 3) return conn.sendMessage(from, { text: 'Usage: rentout <property_id> <price> <hours>' }, { quoted: mek });
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        
        const propId = args[0].toLowerCase();
        const price = parseInt(args[1]);
        const hours = parseInt(args[2]);

        if (price <= 0 || hours <= 0) return conn.sendMessage(from, { text: 'Price and hours must be greater than 0.' }, { quoted: mek });
        
        const qty = p.properties.get(propId) || 0;
        if (qty <= 0) return conn.sendMessage(from, { text: `You don't own a ${propId}.` }, { quoted: mek });

        p.properties.set(propId, qty - 1); 
        logAction(p, `Listed ${propId} for rent for ${fmtMoney(price)}/hr`);
        await p.save();

        const rental = new Rental({
            rentalId: `R-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
            propertyId: propId, ownerId: pId, price: price, durationMs: hours * 60 * 60 * 1000, active: true
        });
        await rental.save();

        return conn.sendMessage(from, { text: `✅ You listed your ${propId} for rent! ID: ${rental.rentalId} | Price: ${fmtMoney(price)} | Duration: ${hours}h` }, { quoted: mek });
    } catch(e) { console.error(e); }
});

cast({ pattern: 'rentals', desc: 'View available properties to rent', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const available = await Rental.find({ active: true, renterId: null }).limit(10).exec();
        if (!available.length) return conn.sendMessage(from, { text: 'No properties are currently listed for rent.' }, { quoted: mek });
        
        let txt = available.map(r => `🔑 *${r.rentalId}* | ${r.propertyId}\n💰 Cost: ${fmtMoney(r.price)} | ⏱️ Duration: ${r.durationMs / (60*60*1000)}h`).join('\n\n');
        return conn.sendMessage(from, { text: `🏢 *Real Estate Market*\n\n${txt}\n\n*Command:* rent <rentalId>` }, { quoted: mek });
    } catch(e) { console.error(e); }
});

cast({ pattern: 'rent', desc: 'Rent a listed property', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        if (!args[0]) return conn.sendMessage(from, { text: 'Usage: rent <rentalId>' }, { quoted: mek });
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        
        const rental = await Rental.findOne({ rentalId: args[0].toUpperCase(), active: true, renterId: null }).exec();
        if (!rental) return conn.sendMessage(from, { text: 'Rental not found or already taken.' }, { quoted: mek });

        if (p.money < rental.price) return conn.sendMessage(from, { text: `Not enough money. Costs ${fmtMoney(rental.price)}` }, { quoted: mek });

        p.money -= rental.price;
        p.moneySpent += rental.price;
        p.rentedHome = rental.propertyId;
        p.rentedHomeExpiresAt = now() + rental.durationMs;
        logAction(p, `Rented ${rental.propertyId} for ${fmtMoney(rental.price)}`);
        
        const titleMsg = checkTitles(p);
        await p.save();

        const owner = await Player.findById(rental.ownerId);
        if (owner) { owner.money += rental.price; await owner.save(); }

        rental.renterId = pId;
        rental.expiresAt = p.rentedHomeExpiresAt;
        await rental.save();

        return conn.sendMessage(from, { text: `🏡 You rented a ${rental.propertyId} for ${rental.durationMs/(60*60*1000)} hours! It is now set as your active home.` + titleMsg }, { quoted: mek });
    } catch(e) { console.error(e); }
});

// ------------- Travel System -------------
cast({ pattern: 'travel', desc: 'Travel to a new country', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 You're kidnapped. You can't travel until free.` }, { quoted: mek });

        // Already in-flight — show status
        if (isInFlight(p)) {
            return conn.sendMessage(from, { text: `✈️ *Already in-flight!*\nDestination: *${p.travelingTo}*\nLanding in: ${shortTime(p.travelingUntil - now())}\n\n_All actions are blocked until you land._` }, { quoted: mek });
        }

        // Check if flight just landed (update location)
        if (p.travelingTo && !isInFlight(p)) {
            p.location = p.travelingTo;
            p.travelingTo = null;
            p.travelingUntil = 0;
            await p.save();
        }

        if (!args[0]) {
            const fromCity = normLoc(p.location) || 'Weirdos World';
            const listTimes = { 'Weirdos World': { 'Mexico': 22, 'London': 12, 'Japan': 35, 'Switzerland': 14, 'Dubai': 18, 'New York': 20, 'Paris': 13, 'Lagos': 5, 'Moscow': 16, 'Sydney': 40, 'Rio de Janeiro': 25 }, 'Lagos': { 'Mexico': 22, 'London': 12, 'Japan': 35, 'Switzerland': 14, 'Dubai': 18, 'New York': 20, 'Paris': 13, 'Weirdos World': 5, 'Moscow': 16, 'Sydney': 40, 'Rio de Janeiro': 25 }, 'Mexico': { 'Weirdos World': 22, 'Lagos': 22, 'London': 18, 'Japan': 20, 'Switzerland': 17, 'Dubai': 25, 'New York': 8, 'Paris': 17, 'Moscow': 23, 'Sydney': 32, 'Rio de Janeiro': 12 }, 'London': { 'Weirdos World': 12, 'Lagos': 12, 'Mexico': 18, 'Japan': 28, 'Switzerland': 5, 'Dubai': 14, 'New York': 15, 'Paris': 4, 'Moscow': 10, 'Sydney': 38, 'Rio de Janeiro': 20 }, 'Japan': { 'Weirdos World': 35, 'Lagos': 35, 'Mexico': 20, 'London': 28, 'Switzerland': 26, 'Dubai': 22, 'New York': 25, 'Paris': 27, 'Moscow': 18, 'Sydney': 18, 'Rio de Janeiro': 38 }, 'Switzerland': { 'Weirdos World': 14, 'Lagos': 14, 'Mexico': 17, 'London': 5, 'Japan': 26, 'Dubai': 12, 'New York': 14, 'Paris': 4, 'Moscow': 9, 'Sydney': 36, 'Rio de Janeiro': 19 }, 'Dubai': { 'Weirdos World': 18, 'Lagos': 18, 'Mexico': 25, 'London': 14, 'Japan': 22, 'Switzerland': 12, 'New York': 20, 'Paris': 13, 'Moscow': 10, 'Sydney': 28, 'Rio de Janeiro': 28 }, 'New York': { 'Weirdos World': 20, 'Lagos': 20, 'Mexico': 8, 'London': 15, 'Japan': 25, 'Switzerland': 14, 'Dubai': 20, 'Paris': 14, 'Moscow': 18, 'Sydney': 35, 'Rio de Janeiro': 13 }, 'Paris': { 'Weirdos World': 13, 'Lagos': 13, 'Mexico': 17, 'London': 4, 'Japan': 27, 'Switzerland': 4, 'Dubai': 13, 'New York': 14, 'Moscow': 9, 'Sydney': 37, 'Rio de Janeiro': 20 }, 'Moscow': { 'Weirdos World': 16, 'Lagos': 16, 'Mexico': 23, 'London': 10, 'Japan': 18, 'Switzerland': 9, 'Dubai': 10, 'New York': 18, 'Paris': 9, 'Sydney': 30, 'Rio de Janeiro': 26 }, 'Sydney': { 'Weirdos World': 40, 'Lagos': 40, 'Mexico': 32, 'London': 38, 'Japan': 18, 'Switzerland': 36, 'Dubai': 28, 'New York': 35, 'Paris': 37, 'Moscow': 30, 'Rio de Janeiro': 42 }, 'Rio de Janeiro': { 'Weirdos World': 25, 'Lagos': 25, 'Mexico': 12, 'London': 20, 'Japan': 38, 'Switzerland': 19, 'Dubai': 28, 'New York': 13, 'Paris': 20, 'Moscow': 26, 'Sydney': 42 } };
            const myTimes = listTimes[fromCity] || listTimes['Weirdos World'];
            const destList = LOCATIONS.filter(l => normLoc(l.name) !== normLoc(p.location));
            let txt = destList.map(l => {
                const mins = myTimes[l.name] || 20;
                const blocked = isTravelBlocked(l.name) ? ' 🌩️ BLOCKED' : '';
                return `✈️ *${l.name}* (${l.id}) — Ticket: ${fmtMoney(iC(l.cost))} | ~${mins} min${blocked}`;
            }).join('\n');
            return conn.sendMessage(from, { text: `🗺️ *Travel Agency*\nCurrent Location: *${p.location}*\n\n${txt}\n\nUsage: travel <location_id>` }, { quoted: mek });
        }

        // Resolve aliases: ww/torn/torncity/weirdosworld/home → ww, swiss/switzerland → swiss
        const RAW = args[0].toLowerCase().replace(/[\s_-]/g, '');
        const ALIAS = {
            torn: 'ww', torncity: 'ww', weirdosworld: 'ww', weirdos: 'ww', home: 'ww', ww: 'ww',
            mexico: 'mexico', mex: 'mexico',
            london: 'london', uk: 'london', england: 'london',
            japan: 'japan', jp: 'japan', tokyo: 'japan',
            switzerland: 'swiss', swiss: 'swiss', zurich: 'swiss', switz: 'swiss'
        };
        const resolvedId = ALIAS[RAW] || RAW;
        const dest = LOCATIONS.find(l => l.id === resolvedId);
        if (!dest) return conn.sendMessage(from, { text: 'Invalid location ID.' }, { quoted: mek });
        if (normLoc(p.location) === normLoc(dest.name)) return conn.sendMessage(from, { text: `You are already in ${dest.name}.` }, { quoted: mek });

        // Weather check — severe weather blocks flights
        const weatherWarn = travelWarning(dest.name);
        if (isTravelBlocked(dest.name)) return conn.sendMessage(from, { text: weatherWarn }, { quoted: mek });

        if (p.money < iC(dest.cost)) return conn.sendMessage(from, { text: `You can't afford a ticket. Costs ${fmtMoney(iC(dest.cost))}.` }, { quoted: mek });
        
        // Flight duration: based on real-world proximity between cities
        // Base times (minutes) from Weirdos World (Nigeria hub). Matrix is symmetric.
        const FLIGHT_TIMES = {
            'Weirdos World': { 'Mexico': 22, 'London': 12, 'Japan': 35, 'Switzerland': 14, 'Dubai': 18, 'New York': 20, 'Paris': 13, 'Lagos': 5, 'Moscow': 16, 'Sydney': 40, 'Rio de Janeiro': 25 },
            'Lagos':         { 'Mexico': 22, 'London': 12, 'Japan': 35, 'Switzerland': 14, 'Dubai': 18, 'New York': 20, 'Paris': 13, 'Weirdos World': 5, 'Moscow': 16, 'Sydney': 40, 'Rio de Janeiro': 25 },
            'Mexico':        { 'Weirdos World': 22, 'Lagos': 22, 'London': 18, 'Japan': 20, 'Switzerland': 17, 'Dubai': 25, 'New York': 8, 'Paris': 17, 'Moscow': 23, 'Sydney': 32, 'Rio de Janeiro': 12 },
            'London':        { 'Weirdos World': 12, 'Lagos': 12, 'Mexico': 18, 'Japan': 28, 'Switzerland': 5, 'Dubai': 14, 'New York': 15, 'Paris': 4, 'Moscow': 10, 'Sydney': 38, 'Rio de Janeiro': 20 },
            'Japan':         { 'Weirdos World': 35, 'Lagos': 35, 'Mexico': 20, 'London': 28, 'Switzerland': 26, 'Dubai': 22, 'New York': 25, 'Paris': 27, 'Moscow': 18, 'Sydney': 18, 'Rio de Janeiro': 38 },
            'Switzerland':   { 'Weirdos World': 14, 'Lagos': 14, 'Mexico': 17, 'London': 5, 'Japan': 26, 'Dubai': 12, 'New York': 14, 'Paris': 4, 'Moscow': 9, 'Sydney': 36, 'Rio de Janeiro': 19 },
            'Dubai':         { 'Weirdos World': 18, 'Lagos': 18, 'Mexico': 25, 'London': 14, 'Japan': 22, 'Switzerland': 12, 'New York': 20, 'Paris': 13, 'Moscow': 10, 'Sydney': 28, 'Rio de Janeiro': 28 },
            'New York':      { 'Weirdos World': 20, 'Lagos': 20, 'Mexico': 8, 'London': 15, 'Japan': 25, 'Switzerland': 14, 'Dubai': 20, 'Paris': 14, 'Moscow': 18, 'Sydney': 35, 'Rio de Janeiro': 13 },
            'Paris':         { 'Weirdos World': 13, 'Lagos': 13, 'Mexico': 17, 'London': 4, 'Japan': 27, 'Switzerland': 4, 'Dubai': 13, 'New York': 14, 'Moscow': 9, 'Sydney': 37, 'Rio de Janeiro': 20 },
            'Moscow':        { 'Weirdos World': 16, 'Lagos': 16, 'Mexico': 23, 'London': 10, 'Japan': 18, 'Switzerland': 9, 'Dubai': 10, 'New York': 18, 'Paris': 9, 'Sydney': 30, 'Rio de Janeiro': 26 },
            'Sydney':        { 'Weirdos World': 40, 'Lagos': 40, 'Mexico': 32, 'London': 38, 'Japan': 18, 'Switzerland': 36, 'Dubai': 28, 'New York': 35, 'Paris': 37, 'Moscow': 30, 'Rio de Janeiro': 42 },
            'Rio de Janeiro':{ 'Weirdos World': 25, 'Lagos': 25, 'Mexico': 12, 'London': 20, 'Japan': 38, 'Switzerland': 19, 'Dubai': 28, 'New York': 13, 'Paris': 20, 'Moscow': 26, 'Sydney': 42 },
        };
        const currentCity = normLoc(p.location) || 'Weirdos World';
        const timeTable = FLIGHT_TIMES[currentCity] || FLIGHT_TIMES['Weirdos World'];
        const baseMinutes = timeTable[dest.name] || 20;
        const jitter = Math.floor(Math.random() * 5) - 2; // ±2 min variance
        const weather      = global.cityWeather?.[dest.name] || '☀️ Clear';
        const weatherDelay = WEATHER_SEVERITY[weather] >= 2 ? Math.floor(Math.random() * 8) : 0;
        const flightMinutes = Math.max(3, baseMinutes + jitter + weatherDelay);
        const flightMs = flightMinutes * 60 * 1000;

        p.money -= iC(dest.cost);
        p.moneySpent += iC(dest.cost);
        p.travelingTo = dest.name;
        p.travelingUntil = now() + flightMs;
        // Track cities visited for achievements/missions
        const citiesVisited = p.citiesVisited || [];
        if (!citiesVisited.includes(dest.name)) {
            p.citiesVisited = [...citiesVisited, dest.name];
        }
        tickChallenge(p, 'travels', 1);
        // Location stays as current city until landing
        logAction(p, `Departed for ${dest.name} (${flightMinutes}min flight)`);
        logFinancial(p, `Flight ticket to ${dest.name}`, -iC(dest.cost));
        
        await p.save();
        return conn.sendMessage(from, {
            text: `🛫 *Boarding now!*\n\nDestination: *${dest.name}*\nFlight Duration: *${flightMinutes} minutes*${weatherDelay > 0 ? ` (${weatherDelay}min weather delay)` : ''}\nTicket: ${fmtMoney(iC(dest.cost))}\nWeather at destination: ${weather}\n\n⚠️ All actions are blocked while in-flight.\nUse *travel* to check landing status.`
        }, { quoted: mek });
    } catch(e) { console.error(e); }
});

// ------------- Marriage System -------------
async function handleMarryCmd(conn, mek, m, { sender, from, args }) {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (p.spouse) return conn.sendMessage(from, { text: `You are already married to @${p.spouse}! Divorce first.` }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId || targetId === pId) return conn.sendMessage(from, { text: [
            `Usage: marry @player [husband|wife]`,
            ``,
            `• marry @player          — you propose as the husband (default)`,
            `• marry @player wife     — you propose as the wife`,
            ``,
            `The other person's role is set automatically as the opposite.`
        ].join('\n') }, { quoted: mek });

        const t = await getOrCreatePlayer(targetId);
        if (t.spouse) return conn.sendMessage(from, { text: `@${targetId} is already married!` }, { quoted: mek });
        if (t.pendingProposal) return conn.sendMessage(from, { text: `@${targetId} already has a pending proposal.` }, { quoted: mek });

        // Proposer can declare their own role — defaults to husband
        const roleArg = args.find(a => a.toLowerCase() === 'wife' || a.toLowerCase() === 'husband');
        const proposerRole = roleArg ? roleArg.toLowerCase() : 'husband';
        const accepterRole = proposerRole === 'husband' ? 'wife' : 'husband';

        // Store pending proposal with role info: "proposerId:proposerRole"
        t.pendingProposal = `${pId}:${proposerRole}`;
        await t.save();

        const proposerLabel = proposerRole === 'husband' ? '👑 Husband' : '💍 Wife';
        const accepterLabel = accepterRole === 'husband' ? '👑 Husband' : '💍 Wife';

        return conn.sendMessage(from, {
            text: [
                `💍 *MARRIAGE PROPOSAL*`,
                ``,
                `@${pId} has proposed to @${targetId}!`,
                ``,
                `${proposerLabel}: @${pId}`,
                `${accepterLabel}: @${targetId}`,
                ``,
                `@${targetId} — type *accept* to say yes 💒`,
                `_You have 30 minutes to respond._`
            ].join('\n'),
            mentions: [toJid(pId), toJid(targetId)]
        }, { quoted: mek });
    } catch (e) { console.error('marry error', e); }
}
cast({ pattern: 'marry',   desc: 'Propose marriage to a player',  category: 'rpg', filename: __filename }, handleMarryCmd);
cast({ pattern: 'propose', desc: 'Propose marriage to a player',  category: 'rpg', filename: __filename }, handleMarryCmd);

cast({ pattern: 'accept', desc: 'Accept a marriage proposal', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted.` }, { quoted: mek });
        if (!p.pendingProposal) return conn.sendMessage(from, { text: `You have no pending proposals. Someone needs to propose to you first with: marry @you` }, { quoted: mek });
        if (p.spouse) return conn.sendMessage(from, { text: `You are already married.` }, { quoted: mek });

        // pendingProposal format: "proposerId:proposerRole" (new) or just "proposerId" (legacy)
        const parts        = p.pendingProposal.split(':');
        const proposerId   = parts[0];
        const proposerRole = parts[1] || 'husband'; // default husband for legacy records
        const accepterRole = proposerRole === 'husband' ? 'wife' : 'husband';

        const partner = await getOrCreatePlayer(proposerId);
        if (!partner) return conn.sendMessage(from, { text: `Proposer account not found.` }, { quoted: mek });

        p.spouse        = partner._id;
        p.marriageRole  = accepterRole;
        p.marriedAt     = now();
        p.pendingProposal = null;

        partner.spouse       = p._id;
        partner.marriageRole = proposerRole;
        partner.marriedAt    = now();

        const husband = proposerRole === 'husband' ? partner : p;
        const wife    = proposerRole === 'husband' ? p       : partner;

        logAction(p,       `Married @${partner._id} (${accepterRole})`);
        logAction(partner, `Married @${p._id} (${proposerRole})`);
        logGlobal('💒', `*${husband.username || husband._id}* (husband) and *${wife.username || wife._id}* (wife) just got married!`);

        await p.save();
        await partner.save();

        return conn.sendMessage(from, {
            text: [
                `💒 *MARRIED!*`,
                ``,
                `👑 Husband: @${husband._id}`,
                `💍 Wife:    @${wife._id}`,
                ``,
                `Congratulations! You are now officially bound together.`,
                ``,
                `⚠️ _Warning: Divorce means the wife receives 50% of both players' combined total assets._`
            ].join('\n'),
            mentions: [toJid(p._id), toJid(partner._id)]
        }, { quoted: mek });
    } catch (e) { console.error('accept error', e); }
});

cast({ pattern: 'divorce', desc: 'Divorce your spouse (wife takes 50% of combined assets)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted.` }, { quoted: mek });
        if (!p.spouse) return conn.sendMessage(from, { text: `You are not married.` }, { quoted: mek });

        const ex    = await getOrCreatePlayer(p.spouse);
        const exId  = ex._id;

        // ── Short marriage protection — under 7 days, no settlement ──────────
        const marriedDuration = now() - (p.marriedAt || 0);
        const MIN_MARRIAGE_MS  = 7 * 24 * 60 * 60 * 1000; // 7 days
        const noSettlement     = marriedDuration < MIN_MARRIAGE_MS;
        const daysMarried      = Math.floor(marriedDuration / (24*60*60*1000));

        // Identify husband and wife
        const husband = p.marriageRole === 'husband' ? p   : ex;
        const wife    = p.marriageRole === 'wife'    ? p   : ex;

        // ── Calculate combined total assets ───────────────────────────────────
        // Wallet + Bank for both players
        let combinedCash = (husband.money || 0) + (husband.bank || 0)
                         + (wife.money    || 0) + (wife.bank    || 0);

        // Property values — look up each property in DEFAULT_SHOP
        function getPropertyValue(player) {
            let total = 0;
            const props = player.properties;
            if (!props) return 0;
            const entries = props instanceof Map ? [...props.entries()] : Object.entries(props);
            for (const [propId, qty] of entries) {
                if (!qty || qty <= 0) continue;
                const shopItem = DEFAULT_SHOP.find(s => s.id === propId);
                if (shopItem) total += shopItem.price * qty;
            }
            return total;
        }

        const husbandPropValue = getPropertyValue(husband);
        const wifePropValue    = getPropertyValue(wife);
        const combinedTotal    = combinedCash + husbandPropValue + wifePropValue;

        // ── Court ruling — based on marriage duration and who files ──────────
        // < 7 days:  no settlement (anti-exploit)
        // 7–30 days: 20% to petitioner's ex
        // 1–6 months: 30%
        // 6+ months:  40%
        // Filing party gets slightly less (courts penalise the initiator)
        let settlementPct = 0;
        if (noSettlement) {
            settlementPct = 0;
        } else if (daysMarried < 30) {
            settlementPct = 0.20;
        } else if (daysMarried < 180) {
            settlementPct = 0.30;
        } else {
            settlementPct = 0.40;
        }

        // Who gets paid? The person who DIDN'T file for divorce (the ex)
        // If the husband files, wife gets settlement from husband
        // If the wife files, husband gets settlement from wife
        const filer      = p; // person who ran /divorce
        const recipient  = ex; // the other person
        const filerRole  = p.marriageRole || 'husband';

        // Settlement comes from filer's assets
        const combinedFilerAssets = (filer.money||0) + (filer.bank||0) + getPropertyValue(filer);
        const transferAmount      = noSettlement ? 0 : Math.floor(combinedFilerAssets * settlementPct);

        // Apply transfer: drain filer wallet→bank→liquidate props
        let toTake = transferAmount;
        const fromWallet2 = Math.min(filer.money||0, toTake);
        filer.money = (filer.money||0) - fromWallet2;
        toTake -= fromWallet2;
        if (toTake > 0) {
            const fromBank2 = Math.min(filer.bank||0, toTake);
            filer.bank = (filer.bank||0) - fromBank2;
            toTake -= fromBank2;
        }
        recipient.money = (recipient.money||0) + transferAmount;
        const wifeCurrentTotal = 0; // unused now — kept for compat below

        const wifeEndTotal = (recipient.money||0) + (recipient.bank||0);

        // ── Record in exes list for both players ─────────────────────────────
        p.exes  = p.exes  || [];
        ex.exes = ex.exes || [];
        p.exes.push({  id: exId,       role: p.marriageRole  || 'unknown', divorcedAt: now() });
        ex.exes.push({ id: pId,        role: ex.marriageRole || 'unknown', divorcedAt: now() });

        // ── Clear marriage fields ─────────────────────────────────────────────
        p.spouse   = null; p.marriageRole = null; p.marriedAt = 0;
        ex.spouse  = null; ex.marriageRole = null; ex.marriedAt = 0;

        logAction(p,  `Divorced @${exId}`);
        logAction(ex, `Divorced by @${pId}`);
        logFinancial(filer,     `Divorce settlement paid out`, -transferAmount);
        logFinancial(recipient, `Divorce settlement received`, transferAmount);
        logGlobal('💔', `*${filer.username||pId}* divorced *${recipient.username||exId}*${noSettlement ? ' (no settlement — married < 7 days)' : `. ${recipient.username||exId} received ${fmtMoney(transferAmount)}.`}`);

        await p.save();
        await ex.save();

        const titleMsg = checkTitles(p);
        return conn.sendMessage(from, {
            text: [
                `💔 *DIVORCE FINALISED*`, ``,
                `Filed by: @${pId} | Ex: @${exId}`,
                `Married for: *${daysMarried} day${daysMarried===1?'':'s'}*`, ``,
                noSettlement
                    ? `⚖️ *No settlement* — marriage under 7 days. Court dismissed.`
                    : [
                        `⚖️ *Court ruling (${(settlementPct*100).toFixed(0)}% settlement):*`,
                        `   Based on ${daysMarried} days married`,
                        `   @${exId} receives: *${fmtMoney(transferAmount)}*`,
                        `   From @${pId}'s assets`,
                      ].join('\n'),
            ].join('\n'),
            mentions: [toJid(pId), toJid(exId)]
        }, { quoted: mek });
    } catch (e) { console.error('divorce error', e); }
});


// ------------- Crime & Work System -------------
cast({ pattern: 'crime', desc: 'Attempt a crime', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        
        if (isHospitalized(p)) {
            return conn.sendMessage(from, { text: `🚑 *@${p._id}*, action restricted. You are hospitalized/jailed.`, mentions: [toJid(p._id)] }, { quoted: mek });
        }
        if (isKidnapped(p)) {
            return conn.sendMessage(from, { text: `🔒 You are kidnapped by @${p.kidnappedBy}. Use 'payransom' or 'escape' to get free.`, mentions: [toJid(p._id)] }, { quoted: mek });
        }
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });

        // Show menu if no crime specified
        if (!args || !args.length || !args[0]) {
            const { min: pMin, max: pMax } = liveCrimeReward(CRIMES[0].rewardMin, CRIMES[0].rewardMax);
            const lines = [`🦹 *CRIMES*`, ``, `Choose a crime:`, ``];
            for (const c of CRIMES) {
                const { min, max } = liveCrimeReward(c.rewardMin, c.rewardMax);
                const cdKey = `crime_${c.id}`;
                const lastT = p.cooldowns?.[cdKey] || p.lastCrime || 0;
                const cdLeft = c.cooldownMs - (now() - lastT);
                const status = cdLeft > 0 ? `⏳ ${shortTime(cdLeft)}` : `✅ Ready`;
                lines.push(`• *${c.name}* (crime ${c.id}) — ${fmtMoney(min)}–${fmtMoney(max)} | ${status}`);
            }
            lines.push(``, `Usage: *crime <id>* (e.g. crime pickpocket)`);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }

        let crime = CRIMES.find(c => c.id === args[0].toLowerCase());
        if (!crime) {
            return conn.sendMessage(from, { text: `❌ Unknown crime "${args[0]}".\nOptions: ${CRIMES.map(c=>c.id).join(', ')}` }, { quoted: mek });
        }

        // Per-crime cooldown key so each crime has its own timer
        const crimeCdKey = `crime_${crime.id}`;
        if (!p.cooldowns) p.cooldowns = {};
        const lastThisCrime = p.cooldowns[crimeCdKey] || 0;
        const elapsed = now() - lastThisCrime;
        if (elapsed < crime.cooldownMs) return conn.sendMessage(from, { text: `⏳ *${crime.name}* on cooldown. Wait ${shortTime(crime.cooldownMs - elapsed)}.` }, { quoted: mek });
        if (p.energy < crime.energy) return conn.sendMessage(from, { text: `Not enough energy. ${crime.energy} required.` }, { quoted: mek }); 
        
        p.energy -= crime.energy;
        // Crimes use nerve too (half the crime energy as nerve cost)
        const nerveCost = Math.ceil(crime.energy / 2);
        if ((p.nerve || 0) < nerveCost) return conn.sendMessage(from, { text: `😰 Not enough nerve. Need ${nerveCost} nerve. You have ${p.nerve || 0}/${p.maxNerve || 60}. Regens 1 per 5 minutes.` }, { quoted: mek });
        p.nerve = Math.max(0, (p.nerve || 60) - nerveCost);
        p.lastCrime = now(); 
        const crimDegBonus = (p.degrees||[]).some(d=>d.startsWith('criminology_')) ? 0.10 : 0;
        const failChance = Math.max(0, crime.failChance - Math.min(0.2, p.dexterity * 0.01) - crimDegBonus); 
        
        let eventMsg = "";
        if (Math.random() < 0.15) {
            if (Math.random() < 0.5) {
                const found = Math.floor(100 + Math.random() * 500);
                p.money += found;
                eventMsg = `\n🍀 *Random Event:* You found a dropped wallet with ${fmtMoney(found)} while running away!`;
            } else {
                const mugDmg = Math.floor(10 + Math.random() * 20);
                p.health = Math.max(0, p.health - mugDmg);
                eventMsg = `\n💀 *Random Event:* Rival gang members spotted you. You took ${mugDmg} damage escaping!`;
                if (p.health <= 0) {
                    p.jailedUntil = now() + (3*60*1000);
                    p.inJail = false;
                    p.health = 0;
                    logAction(p, `Died during ${crime.name} (Rival Gang)`);
                    await p.save();
                    return conn.sendMessage(from, { text: `❌ *@${p._id}* died to a rival gang during the crime. Hospitalized!${eventMsg}`, mentions: [toJid(p._id)] }, { quoted: mek });
                }
            }
        }

        if (Math.random() < failChance) { 
            const damage = Math.floor(5 + Math.random()*25); 
            p.health = Math.max(0, p.health - damage); 
            
            const fine = Math.max(50, Math.floor(p.money * (0.05 + Math.random() * 0.15))); 
            p.money -= fine; 
            
            let confiscateMsg = '';
            if (p.health <= 0) { 
                p.jailedUntil = now() + (10*60*1000); 
                p.health = 0;
                if (p.equippedWeapon && Math.random() < 0.3) {
                    confiscateMsg = `\n🚓 The cops confiscated your ${p.equippedWeapon}!`;
                    p.equippedWeapon = null;
                }
            } 
            logAction(p, `Failed crime: ${crime.name} (-${fmtMoney(fine)})`);
            await p.save(); 
            return conn.sendMessage(from, { text: `❌ *@${p._id}* failed ${crime.name}\n- Health: -${damage}\n- Fine: ${fmtMoney(fine)}${p.jailedUntil && p.jailedUntil>now() ? `\n🚑 Jailed/Hospitalized for ${shortTime(p.jailedUntil - now())}` : ''}${confiscateMsg}${eventMsg}`, mentions: [toJid(p._id)] }, { quoted: mek }); 
        } else { 
            const { min: cMin, max: cMax } = liveCrimeReward(crime.rewardMin, crime.rewardMax);
            const gross = Math.floor(cMin + Math.random()*(cMax - cMin)); 
            const xp = Math.floor(5 + Math.random()*15); // no stat scaling
            const { net: reward, vat } = applyVAT(gross);
            p.money = capBal((p.money||0) + reward);
            const crimeLoanMsg = deductLoanIfOwed(p, reward, crime.name);
            payReferralCut(p, reward).catch(()=>{});
            addTaxableIncome(p, reward);
            p.exp         += xp;
            p.crimesCommitted = (p.crimesCommitted||0) + 1;
            p.crimesDone      = (p.crimesDone||0) + 1;
            p.intelligence    = Math.min(9999, (p.intelligence||1) + 1);
            p.totalEarned     = (p.totalEarned||0) + reward;
            p.crimeLevel      = Math.min(100, (p.crimeLevel||0) + Math.floor(5 + (crime.energy/5)));
            tickChallenge(p, 'crimes', 1);
            tickChallenge(p, 'earned', reward);
            const leveled = await tryLevelUp(p); 
            logAction(p, `Committed crime: ${crime.name} (+${fmtMoney(reward)})`);
            logFinancial(p, `Crime: ${crime.name}`, reward);
            logGlobal('🦹', `*${p.username || p._id}* pulled off a *${crime.name}* and walked away with ${fmtMoney(reward)}.`);
            const titleMsg = checkTitles(p);
            await p.save(); 
            return conn.sendMessage(from, { text: `✅ *@${p._id}* successfully committed ${crime.name}\nGross: ${fmtMoney(gross)} | VAT: -${fmtMoney(vat)} | *Net: ${fmtMoney(reward)}*\n+${xp} EXP${leveled ? `\n🎉 Leveled up! Now level ${p.level}` : ''}${eventMsg}${titleMsg}${crimeLoanMsg || ''}`, mentions: [toJid(p._id)] }, { quoted: mek }); 
        } 
    } catch (e) { console.error('crime error', e); }
});

cast({ pattern: 'work', desc: 'Do a job for safe money', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek }); 
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 You are being held captive. Use 'escape' or 'payransom' to get free.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });
        
        const job = JOBS[Math.floor(Math.random()*JOBS.length)]; 
        const elapsed = now() - (p.lastWork || 0); 
        if (elapsed < job.cooldownMs) return conn.sendMessage(from, { text: `Wait ${shortTime(job.cooldownMs - elapsed)} before working again.` }, { quoted: mek }); 
        if (p.energy < job.energy) return conn.sendMessage(from, { text: `Not enough energy. ${job.energy} required.` }, { quoted: mek }); 
        
        p.energy -= job.energy; 
        p.lastWork = now(); 
        
        // Live wages fluctuate with the labour market index
        const { min: liveMin, max: liveMax } = liveJobPay(job.rewardMin, job.rewardMax);
        const gross = Math.floor(liveMin + Math.random()*(liveMax - liveMin)); 
        const { net: reward, vat } = applyVAT(gross);
        const wageLabel = global.WAGE_INDEX > 1.15 ? ' 📈 (high wages)' : global.WAGE_INDEX < 0.85 ? ' 📉 (low wages)' : '';
        const xp = 4 + Math.floor(Math.random()*8); 
        p.money += reward;
        addTaxableIncome(p, reward);
        p.exp += xp;
        p.jobsDone     += 1;
        p.totalEarned   = (p.totalEarned||0) + reward;
        p.manualLabor   = (p.manualLabor||0) + 1;
        tickChallenge(p, 'shifts', 1);
        tickChallenge(p, 'earned', reward);

        let eventMsg = "";
        if (Math.random() < 0.15) {
            const muggerPower = 10 + (p.level * 2);
            let myPower = p.strength + p.speed;
            if (p.equippedWeapon && p.ammo > 0) myPower += 20;

            if (myPower > muggerPower) {
                const loot = 200 + (p.level * 10);
                p.money += loot;
                eventMsg = `\n👊 *Random Event:* A mugger attacked you at work, but you beat them up and took ${fmtMoney(loot)}!`;
            } else {
                const loss = Math.max(50, Math.floor(p.money * (0.05 + Math.random() * 0.15)));
                p.money -= loss;
                p.health = Math.max(0, p.health - 20);
                eventMsg = `\n💀 *Random Event:* You were mugged at work and lost ${fmtMoney(loss)}!`;
                if(p.health <= 0) { p.jailedUntil = now() + (3*60*1000); p.inJail = false; }
            }
        }
        
        const leveled = await tryLevelUp(p); 
        logAction(p, `Worked as ${job.name} (+${fmtMoney(reward)})`);
        logFinancial(p, `Job: ${job.name}`, reward);
        logGlobal('💼', `*${p.username || p._id}* worked as ${job.name} and earned ${fmtMoney(reward)}.`);
        const titleMsg = checkTitles(p);
        await p.save(); 
        return conn.sendMessage(from, { text: `🧑‍🔧 *@${p._id}* worked as ${job.name}${wageLabel}\nGross: ${fmtMoney(gross)} | 🏛️ VAT (12%): -${fmtMoney(vat)} | *Net: ${fmtMoney(reward)}*\n+${xp} EXP | Energy -${job.energy}${leveled ? `\n🎉 Level up! Now level ${p.level}` : ''}${eventMsg}${titleMsg}`, mentions: [toJid(p._id)] }, { quoted: mek }); 
    } catch (e) { console.error('work error', e); }
});

cast({ pattern: 'train', desc: 'Train a stat', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        await checkOverdoseReport(p, conn, from, mek);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek }); 
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });
        
        const stat = (args && args[0]) ? args[0].toLowerCase() : null;
        const map = { str:'strength', def:'defense', spd:'speed', dex:'dexterity' };
        if (!stat || !map[stat]) return conn.sendMessage(from, { text: 'Usage: train <str|def|spd|dex>' }, { quoted: mek }); 
        const target = map[stat]; 
        
        if (p.energy < 10) return conn.sendMessage(from, { text: `Not enough energy. 10 required.` }, { quoted: mek }); 
        p.energy -= 10; 
        
        let baseGain = 1 + Math.floor(Math.random()*2); 
        // Level scaling: +10% per level, so level 10 = 2x, level 20 = 3x
        const levelMult = 1 + ((p.level - 1) * 0.10);
        // Prestige bonus: +5% per prestige level
        const prestigeMult = 1 + ((p.prestigeLevel || 0) * 0.05);
        baseGain = Math.max(1, Math.floor(baseGain * levelMult * prestigeMult));
        
        let homeBonus = 0;
        let activeHome = p.rentedHome || p.home;
        if (activeHome !== 'streets') {
            const hData = await ShopItem.findOne({ id: activeHome }).exec();
            if (hData) homeBonus = hData.trainBoost || 0;
        }

        let gain = baseGain + homeBonus;

        // ── DRUG STACKING: compute combined multiplier from all active drugs ──
        const nowTs = now();
        const activeDrugsNow = (p.activeDrugs || []).filter(d => d.expiresAt > nowTs);
        let totalTrainMult = 1.0;
        let totalHpPenalty = 0;
        let drugEffectStr = '';

        for (const ad of activeDrugsNow) {
            const ef = DRUG_EFFECTS[ad.drug];
            if (ef && ef.trainMult > 1) {
                // Diminishing returns: each additional drug stack adds half the previous bonus
                const bonus = (ef.trainMult - 1);
                const alreadyStacked = totalTrainMult - 1.0;
                totalTrainMult += bonus * (1 / (1 + alreadyStacked)); // diminishing
            }
            if (ef) {
                if (ef.hpPenalty > 0) totalHpPenalty += ef.hpPenalty;
                else if (ef.hpPenalty === -1) totalHpPenalty += Math.floor(Math.random() * 25) + 5;
            }
        }
        // Hard cap: drug stacking can never give more than 3x total train multiplier
        totalTrainMult = Math.min(3.0, totalTrainMult);

        if (totalTrainMult > 1.0) {
            gain = Math.floor(gain * totalTrainMult);
            const drugNames = activeDrugsNow.map(d => d.drug).join(' + ');
            drugEffectStr = `\n💊 *Drug Stack [${drugNames}]:* x${totalTrainMult.toFixed(1)} multiplier!`;
            if (totalHpPenalty > 0) {
                p.health = Math.max(1, p.health - totalHpPenalty);
                drugEffectStr += ` (-${totalHpPenalty} HP)`;
            }
        }

        // Gym membership: 2× gains + bonus XP
        const gymMult = getGymMultiplier(p);
        if (gymMult > 1) gain = Math.floor(gain * gymMult);
        const gymStr  = gymMult > 1 ? ` 🏋️ *Gym 2×!*` : '';
        const xpBonus = gymMult > 1 ? 5 : 0;

        p[target]      = (p[target]||0) + gain;
        p.endurance    = (p.endurance||0) + 1;
        p.totalTrains  = (p.totalTrains||0) + 1;
        p.manualLabor  = (p.manualLabor||0) + Math.ceil(gain/10);
        const xp = 3 + Math.floor(Math.random()*4) + xpBonus;
        p.exp += xp;
        tickChallenge(p, 'trains', 1);
        tickChallenge(p, 'energy', 10);
        const leveled = await tryLevelUp(p);
        logAction(p, `Trained ${target} (+${gain})`);
        await p.save(); 
        
        return conn.sendMessage(from, { text: `🏋 *@${p._id}* trained ${target} +${gain}${homeBonus > 0 ? ` (Home +${homeBonus})` : ''}${drugEffectStr}${gymStr}\n+${xp} EXP | Energy -10${leveled ? `\n🎉 Level up! Now level ${p.level}` : ''}`, mentions: [toJid(p._id)] }, { quoted: mek }); 
    } catch (e) { console.error('train error', e); }
});

// =============================================================================
// COMMAND: obby — Obstacle course that trains endurance and labor stats
// Endurance: increases max HP cap. Labor: boosts property income and crafting.
// 45 min cooldown. Costs energy. Location-specific courses.
// =============================================================================
const OBBY_COURSES = {
    'Weirdos World': { name: 'WW City Rooftops',   difficulty: 1, energyCost: 20, endGain: [1,2], labGain: [0,1], xp: 25, reward: null },
    'Lagos':         { name: 'Lagos Street Hustle Course', difficulty: 2, energyCost: 25, endGain: [1,3], labGain: [1,2], xp: 35, reward: null },
    'Mexico':        { name: 'Mexico Jungle Run',   difficulty: 3, energyCost: 30, endGain: [2,4], labGain: [1,2], xp: 50, reward: 'medkit' },
    'London':        { name: 'London Rooftop Relay', difficulty: 3, energyCost: 30, endGain: [2,4], labGain: [1,3], xp: 50, reward: null },
    'New York':      { name: 'NYC Subway Gauntlet',  difficulty: 4, energyCost: 35, endGain: [2,5], labGain: [2,3], xp: 65, reward: null },
    'Paris':         { name: 'Paris Catacombs Run',  difficulty: 4, energyCost: 35, endGain: [3,5], labGain: [2,3], xp: 65, reward: 'energydrink' },
    'Dubai':         { name: 'Dubai Tower Climb',    difficulty: 5, energyCost: 40, endGain: [3,6], labGain: [2,4], xp: 80, reward: 'medkit' },
    'Japan':         { name: 'Tokyo Ninja Circuit',  difficulty: 5, energyCost: 40, endGain: [4,7], labGain: [3,5], xp: 90, reward: null },
    'Switzerland':   { name: 'Swiss Alpine Ascent',  difficulty: 6, energyCost: 50, endGain: [5,9], labGain: [4,6], xp: 120, reward: 'energydrink' },
};

cast({ pattern: 'obby', desc: 'obby — Run an obstacle course (trains endurance + labor)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🏥 Can't run an obstacle course from hospital.` }, { quoted: mek });
        if (isInFlight(p))     return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });
        if (isKidnapped(p))    return conn.sendMessage(from, { text: `🔒 You're kidnapped. Escape first.` }, { quoted: mek });

        const CD = 45 * 60 * 1000;
        const lastObby = p.cooldowns?.lastObby || 0;
        if (now() - lastObby < CD) {
            return conn.sendMessage(from, { text: `⏳ Catching your breath. Next obby in *${shortTime(CD - (now() - lastObby))}*.` }, { quoted: mek });
        }

        const city   = normLoc(p.location);
        const course = OBBY_COURSES[city] || OBBY_COURSES['Weirdos World'];

        if ((p.energy || 0) < course.energyCost) {
            return conn.sendMessage(from, { text: `⚡ Need *${course.energyCost} energy* for this course. You have ${p.energy}.` }, { quoted: mek });
        }

        p.energy -= course.energyCost;
        p.cooldowns = p.cooldowns || {};
        p.cooldowns.lastObby = now();
        p.markModified('cooldowns');

        // Failure chance based on difficulty vs speed+dexterity
        const athleticism = (p.speed || 1) + (p.dexterity || 1);
        const failChance  = Math.max(0.05, (course.difficulty * 0.10) - (athleticism / 200));
        const failed      = Math.random() < failChance;

        if (failed) {
            // Fail: lose HP, no gains
            const hpLoss = course.difficulty * 5;
            p.health = Math.max(1, (p.health || 100) - hpLoss);
            await p.save();
            return conn.sendMessage(from, { text: [
                `😬 *OBBY FAILED — ${course.name}*`,``,
                `You wiped out mid-course! -${hpLoss} HP`,
                `HP: ${p.health}/${p.maxHealth || 100}`,``,
                `_Build your Speed & Dexterity to reduce fail chance._`,
                `Next attempt in 45 min.`
            ].join('\n') }, { quoted: mek });
        }

        // Success: gain endurance and labor
        const endGain = course.endGain[0] + Math.floor(Math.random() * (course.endGain[1] - course.endGain[0] + 1));
        const labGain = course.labGain[0] + Math.floor(Math.random() * (course.labGain[1] - course.labGain[0] + 1));

        p.endurance = (p.endurance || 0) + endGain;
        p.labor     = (p.labor || 0) + labGain;
        p.exp       = (p.exp || 0) + course.xp;
        p.totalTrains = (p.totalTrains || 0) + 1;

        // Every 5 endurance points = +1 permanent max HP
        const newHpBonus = Math.floor(p.endurance / 5);
        const oldHpBonus = Math.floor(((p.endurance - endGain) / 5));
        if (newHpBonus > oldHpBonus) {
            const hpUp = (newHpBonus - oldHpBonus);
            p.maxHealth = (p.maxHealth || 100) + hpUp; // no cap — never reduce existing maxHealth
        }

        // Reward item drop
        let rewardMsg = '';
        if (course.reward) {
            const inv = p.inventory instanceof Map ? p.inventory : new Map(Object.entries(p.inventory || {}));
            inv.set(course.reward, (inv.get(course.reward) || 0) + 1);
            p.inventory = inv;
            p.markModified('inventory');
            rewardMsg = `\n🎁 Found: *${course.reward}*!`;
        }

        // Level up check
        const xpNeeded = p.level * 100;
        let levelMsg   = '';
        if ((p.exp || 0) >= xpNeeded) {
            p.level = (p.level || 1) + 1;
            levelMsg = `\n🎉 *Level up! Now Level ${p.level}!*`;
        }

        await p.save();
        return conn.sendMessage(from, { text: [
            `🏃 *OBBY COMPLETE — ${course.name}*`,``,
            `_Obby trains STATS, not cash. No money reward._`,``,
            `💪 Endurance +${endGain} → *${p.endurance}*`,
            `⚒️ Labor +${labGain} → *${p.labor}*`,
            `+${course.xp} XP | ⚡ -${course.energyCost} energy`,
            newHpBonus > oldHpBonus ? `❤️ Max HP increased to *${p.maxHealth}*!` : `_(Every 5 endurance = +1 Max HP — at ${5 - (p.endurance % 5)} more)_`,
            rewardMsg, levelMsg,``,
            `Next course in *45 min*`
        ].filter(Boolean).join('\n') }, { quoted: mek });
    } catch(e) { console.error('obby error', e); }
});

// ------------- Advanced Combat System -------------
cast({ pattern: 'attack', desc: 'Attack another player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const attackerId = await getPlayerId(conn, sender); 
        const targetId = await getTargetId(conn, mek, args, 0); 
        
        if (!targetId || targetId === attackerId) return conn.sendMessage(from, { text: 'Invalid target. Tag someone properly.' }, { quoted: mek }); 
        
        const atk = await getOrCreatePlayer(attackerId); 
        const def = await getOrCreatePlayer(targetId); 
        
        if (isHospitalized(atk)) return conn.sendMessage(from, { text: `🚑 *${atk.username || atk._id}*, you cannot attack while hospitalized/jailed!`, mentions: [toJid(atk._id)] }, { quoted: mek }); 
        if (isHospitalized(def)) return conn.sendMessage(from, { text: `Target is currently hospitalized/jailed.` }, { quoted: mek }); 
        if (isKidnapped(atk)) return conn.sendMessage(from, { text: `🔒 You are kidnapped. Use 'escape' or 'payransom' first.` }, { quoted: mek });
        if (isKidnapped(def)) return conn.sendMessage(from, { text: `That player is currently being held captive. Find the kidnapper instead.` }, { quoted: mek });
        if (isInFlight(atk)) return conn.sendMessage(from, { text: flightMsg(atk) }, { quoted: mek });
        if (isInFlight(def)) return conn.sendMessage(from, { text: `That player is currently in-flight and unreachable.` }, { quoted: mek });
        
        if (normLoc(atk.location) !== normLoc(def.location)) return conn.sendMessage(from, { text: `🌍 *${atk.username || atk._id}*, you cannot attack *${def.username || def._id}*. You are in ${normLoc(atk.location)}, but they are in ${normLoc(def.location)}.`, mentions: [toJid(atk._id), toJid(def._id)] }, { quoted: mek });

        const atkElapsed = now() - (atk.lastAttack || 0); 
        if (atkElapsed < 30*1000) return conn.sendMessage(from, { text: `Wait ${shortTime(30*1000 - atkElapsed)} before attacking again.` }, { quoted: mek }); 
        if (atk.energy < 15) return conn.sendMessage(from, { text: `Not enough energy to attack. 15 required.` }, { quoted: mek }); 

        atk.energy -= 15; 
        atk.lastAttack = now();
        atk.crimeLevel = Math.min(100, (atk.crimeLevel || 0) + 20);

        // ── GEAR BONUSES (all equipped slots) ────────────────────────────────
        const atkGear = getGearBonuses(atk);
        const defGear = getGearBonuses(def);

        let atkAmmoUsed = '';
        if (atk.equippedWeapon && atk.ammo > 0) { atk.ammo -= 1; atkAmmoUsed = ` (Used ${atk.equippedWeapon})`; }
        else if (atk.equippedWeapon && atk.ammo <= 0) atkAmmoUsed = ` (Weapon empty, fists used)`;

        let defAmmoUsed = '';
        if (def.equippedWeapon && def.ammo > 0) { def.ammo -= 1; defAmmoUsed = ` (Fired back with ${def.equippedWeapon})`; }
        else if (def.equippedWeapon && def.ammo <= 0) defAmmoUsed = ` (Countered with fists)`;

        // Effective stats = base stat + gear bonuses + LEVEL SCALING
        // Level contributes heavily — higher level players scale infinitely, no cap
        // Level has NO effect on combat — pure stats only (allows "false levelers")
        const atkStr = (atk.strength || 1) + atkGear.strBonus;
        const atkDef = (atk.defense  || 1) + atkGear.defBonus;
        const atkSpd = (atk.speed    || 1) + atkGear.spdBonus;
        const atkDex = (atk.dexterity|| 1) + atkGear.dexBonus;
        const atkWpn = atkGear.atkBonus;

        const defStr = (def.strength || 1) + defGear.strBonus;
        const defDef = (def.defense  || 1) + defGear.defBonus;
        const defSpd = (def.speed    || 1) + defGear.spdBonus;
        const defDex = (def.dexterity|| 1) + defGear.dexBonus;
        const defWpn = defGear.atkBonus;

        // Power Math — all four stats contribute to both offense and defense
        // Offense:  Str 45% (raw power) + Dex 25% (precision) + Spd 20% (aggression) + Def 10% (pressure)
        // Defense:  Def 50% (resilience) + Str 20% (bracing) + Dex 20% (evasion) + Spd 10% (footwork)
        // Weapon multiplier amplifies total offense. Health penalty kicks in below 50% HP.
        // HP factor: at 100% HP = 1.0, at 50% = 0.5, at 10% = 0.2, at 0% = 0.2 floor
        // Low HP means genuinely weaker — no longer capped at 0.5 minimum
        // Addiction weakens fighters
        const atkAddPenalty = 1 - Math.min(0.40, (atk.addictionLevel||0) * 0.08);
        const defAddPenalty = 1 - Math.min(0.40, (def.addictionLevel||0) * 0.08);
        const atkHealthFactor = Math.max(0.20, atk.health / (atk.maxHealth || 100)) * atkAddPenalty;
        const defHealthFactor = Math.max(0.20, def.health / (def.maxHealth || 100)) * defAddPenalty;

        const atkOffense = (atkStr * 0.45 + atkDex * 0.25 + atkSpd * 0.20 + atkDef * 0.10)
                         * (1 + (atkWpn / 50))
                         * atkHealthFactor;

        const atkDefense = (atkDef * 0.50 + atkStr * 0.20 + atkDex * 0.20 + atkSpd * 0.10);

        const defOffense = (defStr * 0.45 + defDex * 0.25 + defSpd * 0.20 + defDef * 0.10)
                         * (1 + (defWpn / 50))
                         * defHealthFactor;

        const defDefense = (defDef * 0.50 + defStr * 0.20 + defDex * 0.20 + defSpd * 0.10);

        let result = `⚔️ *${atk.username || atk._id}* (@${atk._id}) attacked *${def.username || def._id}* (@${def._id})! ⚔️\n\n`;

        // ── DAMAGE FORMULA ────────────────────────────────────────────────────
        // TWO NUMBERS:
        //   hpDmg    — actual HP removed (% of target's max HP, keeps fights balanced)
        //   displayDmg — what gets shown in chat (scales with raw power, so dominant
        //                players see 50,000+ damage instead of a pathetic "100")
        // At ratio < 5 they're the same. At ratio ≥ 10 the display number is the
        // attacker's raw offense output so you see your true power reflected.
        function calcDmg(offensePower, defensePower, targetMaxHp, dexBonus) {
            const ratio  = offensePower / Math.max(1, defensePower);
            const rng    = 0.82 + Math.random() * 0.36;

            // HP removal percentage — determines fight length
            const pct = ratio >= 20 ? 1.0
                      : ratio >= 10 ? 0.60 + ((ratio-10) / 10)  * 0.40
                      : ratio >= 5  ? 0.35 + ((ratio-5)  / 5)   * 0.25
                      : ratio >= 2  ? 0.18 + ((ratio-2)  / 3)   * 0.17
                      : Math.max(0.05, 0.04 + (ratio - 0.5) * 0.093);

            const hpDmg = Math.floor(targetMaxHp * pct * rng);

            // Displayed number — uses raw offense when dominant so numbers are impressive
            let displayDmg;
            if (ratio >= 10) {
                // Full raw power output — a max player sees numbers like 80,000+
                displayDmg = Math.floor(offensePower * 0.22 * rng);
            } else if (ratio >= 5) {
                // Blend smoothly between hp-based and power-based
                const t = (ratio - 5) / 5;
                displayDmg = Math.floor(hpDmg * (1 - t) + (offensePower * 0.22 * rng) * t);
            } else {
                displayDmg = hpDmg;
            }

            const critRoll = Math.random() < (dexBonus / (dexBonus + 200));
            if (critRoll) {
                const critMult = 1.20 + Math.random() * 0.30;
                return { dmg: Math.floor(displayDmg * critMult), hpDmg: Math.floor(hpDmg * critMult), crit: true };
            }
            return { dmg: displayDmg, hpDmg, crit: false };
        }

        // Track total damage dealt to each player (for hospital duration)
        let totalDmgOnDef = 0;
        let totalDmgOnAtk = 0;

        // Hospital duration — based on how hard the victim was hit relative to their max HP
        // Barely KO'd (10% HP dealt) → ~7 min | Exact KO (100%) → 30 min | Overkill → 60 min max
        function hospitalTime(rawDmg, victimMaxHp) {
            const ratio = rawDmg / Math.max(1, victimMaxHp);
            return Math.min(30, Math.max(2, 2 + Math.floor(ratio * 28))); // max 30 min
        }

        // Attack Phase
        const atkHitChance = Math.max(0.1, Math.min(0.95, 0.5 + ((atkSpd - defDex) / (atkSpd + defDex + 1))));
        let atkDmg = 0;
        if (Math.random() <= atkHitChance) {
            const { dmg, hpDmg, crit } = calcDmg(atkOffense, defDefense, def.maxHealth || 100, atkDex);
            atkDmg = dmg;

            // ── Bodyguard: absorbs 50% of damage if active ───────────────────
            let actualHpDmg = hpDmg;
            if (def.protectedBy && (def.protectedBy !== defId)) {
                const bg = await getOrCreatePlayer(def.protectedBy).catch(() => null);
                if (bg && (bg.bodyguardExpires || 0) > now() && !isHospitalized(bg)) {
                    const absorbed = Math.floor(hpDmg * 0.50);
                    actualHpDmg   = hpDmg - absorbed;
                    bg.health     = Math.max(0, bg.health - absorbed);
                    if (bg.health <= 0) { bg.jailedUntil = now() + 5*60*1000; bg.inJail = false; bg.bodyguardFor = null; bg.bodyguardExpires = 0; def.protectedBy = null; }
                    await bg.save();
                    result += `🛡️ *@${bg._id} bodyguard absorbed ${absorbed} damage!*\n`;
                } else {
                    def.protectedBy = null; // expired
                }
            }

            totalDmgOnDef += actualHpDmg;
            if (crit) result += `*CRITICAL HIT!* `;
            def.health = Math.max(0, def.health - actualHpDmg);
            result += `💥 You dealt *${atkDmg.toLocaleString()} damage* to the defender!${atkAmmoUsed}\n`;
        } else {
            result += `💨 *MISS!* Your opponent was too quick. You missed your attack!\n`;
        }

        // ── ATTACKER'S PET strikes after the player ───────────────────────────
        const atkPetData = getPetCombatData(atk);
        if (atkPetData) {
            // Pet damage is FLAT based on scaled power — not % of HP
            // This ensures a Lv100 pet always vastly outperforms a Lv1 pet
            const petDmg    = Math.floor(atkPetData.power * (0.8 + Math.random() * 0.4));
            const petHpDmg  = Math.floor((def.maxHealth || 100) * Math.min(0.05, atkPetData.power / 50000));
            const actualDmg = Math.max(petDmg, petHpDmg);
            totalDmgOnDef  += actualDmg;
            def.health      = Math.max(0, def.health - actualDmg);
            result += `${atkPetData.icon} *${atkPetData.name}* ${atkPetData.atkLine} dealing *${actualDmg.toLocaleString()} damage*!\n`;
        }

        // Counter-attack Phase
        const defHitChance = Math.max(0.05, Math.min(0.8, 0.4 + ((defSpd - atkDex) / (defSpd + atkDex + 1))));
        let defDmg = 0;
        if (Math.random() <= defHitChance) {
            const { dmg, hpDmg: defHpDmg, crit } = calcDmg(defOffense, atkDefense, atk.maxHealth || 100, defDex);
            defDmg = dmg;
            totalDmgOnAtk += defHpDmg;
            if (crit) result += `*CRITICAL COUNTER!* `;
            atk.health = Math.max(0, atk.health - defHpDmg);
            result += `🩸 They counter-attacked and dealt *${defDmg.toLocaleString()} damage* to you!${defAmmoUsed}\n`;
        } else {
            result += `🛡️ They tried to counter-attack but missed!\n`;
        }

        // ── DEFENDER'S PET retaliates to protect its owner ────────────────────
        const defPetData = getPetCombatData(def);
        if (defPetData) {
            // Same flat formula — pet level is the only thing that should matter
            const petDmg    = Math.floor(defPetData.power * (0.8 + Math.random() * 0.4));
            const petHpDmg  = Math.floor((atk.maxHealth || 100) * Math.min(0.05, defPetData.power / 50000));
            const actualDmg = Math.max(petDmg, petHpDmg);
            totalDmgOnAtk  += actualDmg;
            atk.health      = Math.max(0, atk.health - actualDmg);
            result += `${defPetData.icon} *${defPetData.name}* ${defPetData.defLine} dealing *${actualDmg.toLocaleString()} damage* to you!\n`;
        }

        result += `\n`;

        // Resolution Phase
        if (def.health <= 0 && atk.health > 0) {
            const stealPct = 0.05 + (Math.random() * 0.05); 
            let stealGross = Math.max(0, Math.min(def.money, Math.floor(def.money * stealPct))); 
            if (stealGross < 50 && def.money >= 50) stealGross = 50;
            const { net: steal, vat: stealVat } = applyVAT(stealGross);
            def.money = Math.max(0, def.money - stealGross); 
            atk.money = capBal((atk.money||0) + steal);
            atk.exp += 15 + Math.floor(Math.random()*15);
            atk.peopleMugged += 1;
            atk.attacksWon  = (atk.attacksWon||0) + 1;
            atk.totalEarned = (atk.totalEarned||0) + steal;
            def.defendsLost = (def.defendsLost||0) + 1;
            def.timesJailed = (def.timesJailed||0) + 1;
            tickChallenge(atk, 'wins', 1);
            tickChallenge(atk, 'earned', steal);
            const defHospMins = hospitalTime(totalDmgOnDef, def.maxHealth || 100);
            def.jailedUntil = now() + (defHospMins * 60 * 1000); def.inJail = false; def.health = 0; def.sentencedAt = now(); def.sentenceMs = defHospMins * 60 * 1000;
            result += `💀 *VICTORY!* You knocked them out and took ${fmtMoney(stealGross)} (−${fmtMoney(stealVat)} VAT) = *${fmtMoney(steal)} net*!\n🚑 Defender hospitalized for *${defHospMins} minute${defHospMins===1?'':'s'}*.`;
            
            const bounty = await Bounty.findOne({ targetId: def._id });
            if (bounty && bounty.amount > 0) {
                atk.money += bounty.amount;
                result += `\n💰 *BOUNTY CLAIMED!* You collected the ${fmtMoney(bounty.amount)} hit on their head!`;
                logAction(atk, `Claimed ${fmtMoney(bounty.amount)} bounty on @${def._id}`);
                await Bounty.deleteOne({ targetId: def._id });
            }
            logAction(atk, `Defeated @${def._id} and stole ${fmtMoney(steal)}`);
            const attackLoanMsg = deductLoanIfOwed(atk, steal, 'Attack loot');
            // Auto-collect Bounty2 if exists
            Bounty2.findOne({ targetId: def._id.toString(), claimed: false }).then(async b2 => {
                if (!b2) return;
                b2.claimed = true; b2.claimedBy = atk._id.toString(); await b2.save();
                atk.money = capBal((atk.money||0) + b2.amount);
                addTaxableIncome(atk, b2.amount);
                if (!(atk.achievements||[]).includes('ach_bounty_collect')) { atk.achievements = [...(atk.achievements||[]), 'ach_bounty_collect']; }
                logGlobal('🎯', `*${atk.username||atk._id}* collected *${fmtMoney(b2.amount)}* bounty on @${def._id}!`);
                await atk.save();
            }).catch(()=>{});
            // Award achievements (non-blocking)
            awardAchievements(atk); awardMissions(atk).catch(()=>{});
            logAction(def, `Mugged by @${atk._id} (-${fmtMoney(steal)})`);
            logFinancial(atk, `Attack win vs @${def._id}`, steal);
            logFinancial(def, `Mugged by @${atk._id}`, -steal);
            logGlobal('⚔️', `*${atk.username || atk._id}* knocked out *${def.username || def._id}* and stole ${fmtMoney(steal)}!`);
            // Gear loss on defender death — uninsured players lose random equipped gear
            if (!def.gearInsurance) {
                const defSlots = ['equippedWeapon','equippedArmor','equippedHelmet','equippedGloves','equippedKneePads','equippedBoots'].filter(s => def[s]);
                if (defSlots.length > 0 && Math.random() < 0.4) {
                    const lostSlot = defSlots[Math.floor(Math.random() * defSlots.length)];
                    const lostItem = def[lostSlot];
                    def[lostSlot] = null;
                    result += `\n🔱 *Gear Lost!* @${def._id} lost their *${lostItem}* (no insurance!)`;
                }
            } else {
                result += `\n🛡️ @${def._id}'s insurance protected their gear.`;
            }
        } else if (atk.health <= 0 && def.health > 0) {
            const stealPct = 0.05 + (Math.random() * 0.05); 
            let steal = Math.max(0, Math.min(atk.money, Math.floor(atk.money * stealPct))); 
            if (steal < 50 && atk.money >= 50) steal = 50;
            atk.money = Math.max(0, atk.money - steal); 
            def.money = capBal((def.money||0) + steal);
            def.exp += 15 + Math.floor(Math.random()*15);
            def.peopleMugged += 1;
            def.defendsWon  = (def.defendsWon  || 0) + 1;
            atk.attacksLost = (atk.attacksLost || 0) + 1;
            const atkHospMins = hospitalTime(totalDmgOnAtk, atk.maxHealth || 100);
            atk.jailedUntil = now() + (atkHospMins * 60 * 1000); atk.inJail = false; atk.health = 0; atk.sentencedAt = now(); atk.sentenceMs = atkHospMins * 60 * 1000;
            result += `💀 *DEFEAT!* You were overpowered! They knocked you out in self-defense and stole ${fmtMoney(steal)}!\n🚑 You are hospitalized for *${atkHospMins} minute${atkHospMins===1?'':'s'}*.`;
            // 5% death chance on attack defeat
            const diedFromAttack = await rollDeathChance(atk, conn, from, mek, 'combat');
            if (diedFromAttack) { await def.save(); return; }
            
            const bounty = await Bounty.findOne({ targetId: atk._id });
            if (bounty && bounty.amount > 0) {
                def.money += bounty.amount;
                result += `\n💰 *YOUR BOUNTY CLAIMED!* They collected the ${fmtMoney(bounty.amount)} hit on your head!`;
                logAction(def, `Claimed ${fmtMoney(bounty.amount)} bounty on @${atk._id} in self-defense!`);
                await Bounty.deleteOne({ targetId: atk._id });
            }
            logAction(def, `Defended against @${atk._id} and stole ${fmtMoney(steal)}`);
            logAction(atk, `Killed attacking @${def._id} (-${fmtMoney(steal)})`);

        } else if (atk.health <= 0 && def.health <= 0) {
            const mutAtkMins = hospitalTime(totalDmgOnAtk, atk.maxHealth || 100);
            const mutDefMins = hospitalTime(totalDmgOnDef, def.maxHealth || 100);
            atk.jailedUntil = now() + (mutAtkMins*60*1000); atk.inJail=false; atk.health=0; atk.sentencedAt=now(); atk.sentenceMs=mutAtkMins*60*1000;
            def.jailedUntil = now() + (mutDefMins*60*1000); def.inJail=false; def.health=0; def.sentencedAt=now(); def.sentenceMs=mutDefMins*60*1000;
            result += `💀 *MUTUAL DESTRUCTION!* Both knocked out!\n🚑 You: ${mutAtkMins} min hospital | Them: ${mutDefMins} min hospital.`;
            atk.attacksLost   = (atk.attacksLost  || 0) + 1;
            def.defendsLost   = (def.defendsLost   || 0) + 1;
            logAction(atk, `Mutual knockout with @${def._id}`);
            logAction(def, `Mutual knockout with @${atk._id}`);
        } else {
            result += `Status: You have ${atk.health} HP left | They have ${def.health} HP left.`;
            atk.attacksFailed = (atk.attacksFailed || 0) + 1;
            logAction(atk, `Attacked @${def._id} (Traded hits)`);
            logAction(def, `Defended against @${atk._id}`);
        }
        
        await tryLevelUp(atk);
        await tryLevelUp(def);
        const titleMsg1 = checkTitles(atk);
        const titleMsg2 = checkTitles(def);
        await atk.save(); await def.save(); 
        
        return conn.sendMessage(from, { text: result + titleMsg1, mentions: [toJid(atk._id), toJid(def._id)] }, { quoted: mek }); 
    } catch (e) { console.error('attack error', e); }
});

// ------------- Shop & Inventory -------------
cast({ pattern: 'shop', desc: 'View shop items', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
        const page = Math.max(1, parseInt(args && args[0]) || 1);
        const limit = 8;
        const skip = (page-1) * limit;
        
        const items = await ShopItem.find({ region: { $in: ['All', normLoc(p.location)] } }).skip(skip).limit(limit).exec();
        if (!items.length) return conn.sendMessage(from, { text: 'No shop items found on this page for this region.' }, { quoted: mek }); 
        
        const txt = items.map(it => {
            const live  = livePrice({ id: it.id, price: it.price });
            const mult  = global.MARKET_PRICES?.[it.id] ?? 1.0;
            const arrow = mult > 1.10 ? '📈' : mult < 0.90 ? '📉' : '➡️';
            const pctStr = mult >= 1.005 ? `+${((mult-1)*100).toFixed(0)}%` : mult <= 0.995 ? `${((mult-1)*100).toFixed(0)}%` : `±0%`;
            return `🛒 *${it.id}* - ${it.name}\n 📜 ${it.description}\n 💰 ${fmtMoney(live)} ${arrow} ${pctStr} | 📦 Stock: ${it.stock}/${it.maxStock}`;
        }).join('\n\n');

        const nextTick = Math.max(0, 20*60*1000 - (Date.now() - (global.LAST_MARKET_UPDATE || Date.now())));
        return conn.sendMessage(from, { text: [
            `🛍 *${p.location} Shop — Page ${page}*`,
            `${econLabel()} | Next price update: ${nextTick > 0 ? Math.ceil(nextTick/60000)+'min' : 'soon'}`,
            ``,
            txt,
            ``,
            `*Command:* buy <itemId> [qty]`
        ].join('\n') }, { quoted: mek }); 
    } catch (e) { console.error('shop error', e); }
});

cast({ pattern: 'buy', desc: 'Buy an item', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender)); 
        const item = (args && args[0]) ? args[0].toLowerCase() : null;

        if (isHospitalized(p) && item !== 'medkit') {
            return conn.sendMessage(from, { text: `Action restricted. Hospital/Jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        }

        // ── Per-item buy cooldown — prevents spam purchasing ──────────────────
        // Consumables: 2 min cooldown. Weapons/armor: 5 min. Properties: 10 min.
        const BUY_COOLDOWN_MS = { consumable: 2*60*1000, drug: 3*60*1000, weapon: 5*60*1000, armor: 5*60*1000, property: 10*60*1000, house: 10*60*1000, ammo: 60*1000 };
        const qty = Math.min(10, Math.max(1, parseInt((args && args[1])||'1') || 1)); // cap qty at 10 per buy

        if (!item) return conn.sendMessage(from, { text: 'Usage: buy <itemId> [qty]' }, { quoted: mek }); 
        
        const shopIt = await ShopItem.findOne({ id: item }).exec(); 
        if (!shopIt) return conn.sendMessage(from, { text: 'Item not found.' }, { quoted: mek }); 
        if (shopIt.region !== 'All' && shopIt.region !== normLoc(p.location)) return conn.sendMessage(from, { text: `You must travel to ${shopIt.region} to buy this.` }, { quoted: mek });
        if (shopIt.stock < qty) return conn.sendMessage(from, { text: `Only ${shopIt.stock} left in stock.` }, { quoted: mek }); 

        // Check per-item cooldown
        const cdMs    = BUY_COOLDOWN_MS[shopIt.type] || 2*60*1000;
        const cdKey   = `buy_${item}`;
        const lastBuy = p.cooldowns?.[cdKey] || 0;
        const cdLeft  = cdMs - (now() - lastBuy);
        if (cdLeft > 0) return conn.sendMessage(from, { text: `⏳ You just bought ${shopIt.name}. Wait ${shortTime(cdLeft)} before buying again.` }, { quoted: mek });
        
        // Live price: base × inflation × current market drift for this item
        const unitPrice = livePrice({ id: item, price: shopIt.price });
        const cost = unitPrice * qty;

        // ── Crypto payment option ─────────────────────────────────────────────
        // Usage: buy <item> [qty] [coinTicker]  e.g.  buy medkit 3 BTC
        const cryptoArg = args[2] ? args[2].toUpperCase() : null;
        const validCoin = cryptoArg && global.market?.[cryptoArg] ? cryptoArg : null;

        if (validCoin) {
            // Crypto payment: convert cost to coin amount
            const coinPrice   = global.market[validCoin];
            const coinAmount  = cost / coinPrice;
            const ownedCrypto = p.cryptoPortfolio instanceof Map
                ? (p.cryptoPortfolio.get(validCoin) || 0)
                : ((p.cryptoPortfolio || {})[validCoin] || 0);
            if (ownedCrypto < coinAmount) {
                return conn.sendMessage(from, { text: [
                    `❌ Not enough *${validCoin}*.`,
                    `Need: ${coinAmount.toFixed(6)} ${validCoin} (≈ ${fmtMoney(cost)})`,
                    `You have: ${ownedCrypto.toFixed(6)} ${validCoin}`,
                    ``,
                    `Pay with cash: just use *buy ${item} ${qty}*`,
                ].join('\n') }, { quoted: mek });
            }
            // Deduct crypto
            if (p.cryptoPortfolio instanceof Map) {
                p.cryptoPortfolio.set(validCoin, ownedCrypto - coinAmount);
            } else {
                p.cryptoPortfolio = p.cryptoPortfolio || {};
                p.cryptoPortfolio[validCoin] = ownedCrypto - coinAmount;
            }
            p.moneySpent += cost; // track for stats
            logFinancial(p, `Shop (crypto ${validCoin}): ${qty}x ${shopIt.name}`, -cost);
        } else {
            // Cash payment (default)
            if (p.money < cost) return conn.sendMessage(from, { text: [
                `Not enough money. Total cost: ${fmtMoney(cost)}`,
                `_Tip: pay with crypto — buy ${item} ${qty} <COIN> (e.g. BTC, ETH)_`
            ].join('\n') }, { quoted: mek });
            p.money -= cost;
            p.moneySpent += cost;
        }

        shopIt.stock -= qty;
        // Set cooldown
        if (!p.cooldowns) p.cooldowns = {};
        p.cooldowns[cdKey] = now();
        p.markModified('cooldowns');
        
        logAction(p, `Bought ${qty}x ${shopIt.name}${validCoin ? ` (paid ${(cost/global.market[validCoin]).toFixed(6)} ${validCoin})` : ''}`);
        tickChallenge(p, 'purchases', qty);

        const titleMsg = checkTitles(p);

        if (shopIt.type === 'property' || shopIt.type === 'house') {
            // ── Property ownership limits ─────────────────────────────────────
            const currentOwned   = p.properties.get(item) || 0;
            const perTypeLimit   = PROPERTY_LIMITS[item] ?? PROPERTY_LIMITS._default;
            if (currentOwned + qty > perTypeLimit) {
                p.money += cost; p.moneySpent -= cost; // refund
                return conn.sendMessage(from, { text: [
                    `❌ *Property Limit Reached*`,
                    `You can only own *${perTypeLimit}x ${shopIt.name}*.`,
                    `You currently own: ${currentOwned}`,
                    ``,
                    `_Limits exist to prevent monopolisation. Sell some first: *sellproperty ${item}*_`
                ].join('\n') }, { quoted: mek });
            }
            const propEntries = p.properties instanceof Map ? [...p.properties.entries()] : Object.entries(p.properties || {});
            const totalOwned  = propEntries.reduce((t,[,v]) => t + (v||0), 0);
            const totalLimit  = maxTotalProperties(p.level || 1);
            if (totalOwned + qty > totalLimit) {
                p.money += cost; p.moneySpent -= cost;
                return conn.sendMessage(from, { text: [
                    `❌ *Total Property Limit Reached*`,
                    `At Level ${p.level}, you can own a maximum of *${totalLimit} properties* total.`,
                    `You currently own: ${totalOwned}`,
                    ``,
                    `_Level up to unlock more slots (max 30 at Level 50+)._`,
                    `_Sell properties: *sellproperty <id>*_`
                ].join('\n') }, { quoted: mek });
            }
            p.properties.set(item, currentOwned + qty);
            await p.save(); await shopIt.save();
            return conn.sendMessage(from, { text: `🏙️ Purchased ${shopIt.name} x${qty} for ${fmtMoney(cost)}. Use *movein ${item}* to set it as your home!\n📊 Properties owned: ${totalOwned + qty}/${totalLimit}` + titleMsg }, { quoted: mek }); 
        } else {
            // Daily buy cap: drugs max 5/day, consumables max 20/day, weapons max 3/day
            const dailyCapKey = `buycount_${item}_${new Date().toISOString().split('T')[0]}`;
            const currentDayCount = p.cooldowns?.[dailyCapKey] || 0;
            const dailyCap = shopIt.type === 'drug' ? 5 : shopIt.type === 'weapon' || shopIt.type === 'armor' ? 3 : 20;
            if (currentDayCount + qty > dailyCap) {
                p.money += cost; p.moneySpent -= cost; shopIt.stock += qty; // refund
                p.cooldowns[`buy_${item}`] = 0; p.markModified('cooldowns');
                return conn.sendMessage(from, { text: `❌ *Daily buy limit reached*\nYou can only buy *${dailyCap}x ${shopIt.name}* per day.\nBought today: ${currentDayCount}/${dailyCap}` }, { quoted: mek });
            }
            p.cooldowns[dailyCapKey] = currentDayCount + qty;
            p.markModified('cooldowns');
            p.inventory.set(item, (p.inventory.get(item) || 0) + qty);
            await p.save(); await shopIt.save(); 
            return conn.sendMessage(from, { text: `🛍 Bought ${shopIt.name} x${qty} for ${fmtMoney(cost)}. Use it with: use ${item}\n📦 Daily limit: ${currentDayCount + qty}/${dailyCap}` + titleMsg }, { quoted: mek }); 
        }
    } catch (e) { console.error('buy error', e); }
});

cast({ pattern: 'movein', desc: 'Move into a house you own', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const houseId = (args && args[0]) ? args[0].toLowerCase() : null;
        if (!houseId) return conn.sendMessage(from, { text: `Usage: movein <house_id>\nYour properties: use 'profile' to see what you own.` }, { quoted: mek });

        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
        const owned = p.properties.get(houseId) || 0;
        if (owned <= 0) return conn.sendMessage(from, { text: `❌ You don't own a *${houseId}*. Buy it from the shop first.` }, { quoted: mek });

        const shopIt = await ShopItem.findOne({ id: houseId }).exec();
        if (!shopIt || shopIt.type !== 'house') {
            // Show what houses they actually own
            const ownedHouses = DEFAULT_SHOP.filter(s => s.type === 'house' && ((p.properties instanceof Map ? p.properties.get(s.id) : (p.properties||{})[s.id]) || 0) > 0);
            if (ownedHouses.length > 0) {
                return conn.sendMessage(from, { text: [`❌ *${houseId}* is not a house (it may be an income property).`, ``, `Your houses:`, ...ownedHouses.map(h => `• *${h.id}* — ${h.name} (+${h.hpBoost||0} HP)`), ``, `Usage: *movein <house_id>*`].join('\n') }, { quoted: mek });
            }
            return conn.sendMessage(from, { text: [`❌ *${houseId}* is not a liveable house.`, ``, `Houses you can buy: *shack, hideout, condo, townhouse, penthouse, ryokan, cartel mansion* etc.`, `Browse: *shop houses*`].join('\n') }, { quoted: mek });
        }

        const oldHome = p.home;
        p.home = houseId;
        // Apply new HP boost (remove old, add new)
        if (oldHome && oldHome !== 'streets' && oldHome !== houseId) {
            const oldData = await ShopItem.findOne({ id: oldHome }).exec();
            if (oldData) p.maxHealth = Math.max(100, p.maxHealth - (oldData.hpBoost || 0));
        }
        if (oldHome !== houseId) p.maxHealth += (shopIt.hpBoost || 0);

        logAction(p, `Moved into ${shopIt.name}`);
        await p.save();
        return conn.sendMessage(from, {
            text: `🏠 You moved into *${shopIt.name}*!\n+${shopIt.hpBoost || 0} Max HP | +${shopIt.trainBoost || 0} Train Boost applied.`
        }, { quoted: mek });
    } catch (e) { console.error('movein error', e); }
});

cast({ pattern: 'use', desc: 'Use an item (use <item> [qty])', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const item = (args && args[0]) ? args[0].toLowerCase() : null;
        if (!item) return conn.sendMessage(from, { text: 'Usage: use <item_id> [quantity]\nExamples: use medkit 3 | use steroid 2 | use kevlar' }, { quoted: mek });

        const useQty = Math.max(1, parseInt(args[1]) || 1);
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender)); 
        
        // ── Jail/Hospital use restrictions ───────────────────────────────────
        if (isHospitalized(p)) {
            if (isInJail(p)) {
                // IN JAIL — almost nothing works here
                const jailAllowed = ['smokebomb']; // only smokebomb (40% chance, no discharge)
                if (!jailAllowed.includes(item)) {
                    return conn.sendMessage(from, { text: [
                        `⛓️ You're in *jail* — you can't use items here.`,
                        ``,
                        `Jail options: *jailwork* | *lawyercall* | *callawyer @friend* | *bailout* | *jailbreak*`,
                        `_Medkits are for hospital, not jail._`
                    ].join('\n') }, { quoted: mek });
                }
            } else {
                // IN HOSPITAL — allow medkits, energy drinks, and all consumable/healing items
                const hospAllowed = ['medkit', 'xanax', 'healingspa', 'firstaidkit', 'mega_medkit', 'energydrink', 'bandage', 'morphine'];
                // Also allow anything with heal in the name
                if (!hospAllowed.includes(item) && !item.includes('medkit') && !item.includes('heal') && !item.includes('kit')) {
                    return conn.sendMessage(from, { text: `Action restricted. In hospital for ${shortTime(p.jailedUntil - now())}. Only medkits and healing items work here.` }, { quoted: mek });
                }
            }
        }

        const owned = p.inventory.get(item) || 0;
        if (owned <= 0) return conn.sendMessage(from, { text: `You don't have any ${item}.` }, { quoted: mek }); 
        if (owned < useQty) return conn.sendMessage(from, { text: `You only have ${owned}x ${item}. Can't use ${useQty}.` }, { quoted: mek });

        const shopIt = await ShopItem.findOne({ id: item }).exec(); 
        if (!shopIt) {
            const preyCheck = PREY_LIST.find(pr => pr.id === item);
            if (preyCheck) return conn.sendMessage(from, { text: `You cannot 'use' an animal. Try 'sellitem ${item}' to make money off it.` }, { quoted: mek });
            return conn.sendMessage(from, { text: 'This item cannot be used.' }, { quoted: mek }); 
        }

        // ── WEAPON EQUIP ──────────────────────────────────────────────────────
        if (shopIt.type === 'weapon') {
            if (p.equippedWeapon) p.inventory.set(p.equippedWeapon, (p.inventory.get(p.equippedWeapon) || 0) + 1); 
            p.equippedWeapon = item;
            p.inventory.set(item, owned - 1);
            const r = shopIt.rarity || 'common';
            logAction(p, `Equipped weapon: ${shopIt.name}`);
            await p.save();
            return conn.sendMessage(from, { text: `🔫 ${RARITY_LABEL[r] || ''} Equipped *${shopIt.name}* (${r}) — +${shopIt.atkBonus || 0} Atk` }, { quoted: mek }); 
        }

        // ── GEAR / ARMOR EQUIP ────────────────────────────────────────────────
        if (shopIt.type === 'armor') {
            const slot = shopIt.gearSlot || 'body';
            const slotField = GEAR_SLOT_FIELD[slot] || 'equippedArmor';
            const currentlyEquipped = p[slotField];
            if (currentlyEquipped) p.inventory.set(currentlyEquipped, (p.inventory.get(currentlyEquipped) || 0) + 1);
            p[slotField] = item;
            p.inventory.set(item, owned - 1);
            const r = shopIt.rarity || 'common';
            const bonuses = [
                shopIt.defBonus ? `+${shopIt.defBonus} Def` : null,
                shopIt.strBonus ? `+${shopIt.strBonus} Str` : null,
                shopIt.spdBonus ? `+${shopIt.spdBonus} Spd` : null,
                shopIt.dexBonus ? `+${shopIt.dexBonus} Dex` : null,
            ].filter(Boolean).join(', ');
            logAction(p, `Equipped gear: ${shopIt.name} [${slot}]`);
            await p.save();
            return conn.sendMessage(from, { text: `🛡 ${RARITY_LABEL[r] || ''} Equipped *${shopIt.name}* (${r}) in [${slot}] slot — ${bonuses}` }, { quoted: mek }); 
        }

        // ── AMMO ──────────────────────────────────────────────────────────────
        if (shopIt.type === 'ammo') {
            p.ammo += 20 * useQty; 
            p.inventory.set(item, owned - useQty);
            await p.save();
            return conn.sendMessage(from, { text: `📦 Loaded ${useQty} box(es) of ammo (+${20 * useQty}). Total: ${p.ammo} bullets.` }, { quoted: mek }); 
        }

        // ── DRUGS (multi-use) ─────────────────────────────────────────────────
        if (shopIt.type === 'drug') {
            const ef = DRUG_EFFECTS[item];
            if (!ef) return conn.sendMessage(from, { text: `This drug has no effect data.` }, { quoted: mek });

            let totalHpPenalty = 0;
            let totalEnergyBoost = 0;
            let healed = false;
            let jailbreak = false;
            let lines = [];

            const effMaxHP = await getEffectiveMaxHP(p);

            // ── DRUG STACK LIMITS ──────────────────────────────────────────────
            // Max 2 different drugs active at once. 3rd type = instant overdose.
            const currentStack = (p.activeDrugs || []).filter(d => d.expiresAt > now());
            const uniqueDrugsActive = new Set(currentStack.map(d => d.drug));

            // Trying to add a 3rd unique drug type — overdose immediately
            if (!uniqueDrugsActive.has(item) && uniqueDrugsActive.size >= 2) {
                triggerOverdose(p);
                await p.save();
                return conn.sendMessage(from, {
                    text: [
                        `☠️ *OVERDOSE!*`,
                        ``,
                        `You tried to add *${item}* on top of *${[...uniqueDrugsActive].join(' + ')}* — your body couldn't handle it.`,
                        ``,
                        `🚑 You've been rushed to hospital for *60 minutes*.`,
                        `💊 All drugs wiped from your system.`,
                        ``,
                        `When you wake up, type any command to see what you lost.`
                    ].join('\n')
                }, { quoted: mek });
            }

            // Max 2 doses of the same drug — 3rd dose = overdose
            const sameInStack = currentStack.filter(d => d.drug === item).length;
            if (sameInStack >= 2) {
                triggerOverdose(p);
                await p.save();
                return conn.sendMessage(from, {
                    text: [
                        `☠️ *OVERDOSE!*`,
                        ``,
                        `You took a *3rd dose of ${item}* — tolerance broke and your organs gave out.`,
                        ``,
                        `🚑 You've been rushed to hospital for *60 minutes*.`,
                        `💊 All drugs wiped from your system.`,
                        ``,
                        `When you wake up, type any command to see what you lost.`
                    ].join('\n')
                }, { quoted: mek });
            }

            for (let i = 0; i < useQty; i++) {
                p.drugsUsed += 1;
                if (ef.jailbreak) { jailbreak = true; continue; }
                if (ef.healFull) { healed = true; }
                if (ef.energyBoost >= 999) totalEnergyBoost = 999;
                else if (ef.energyBoost > 0) totalEnergyBoost += ef.energyBoost;
                const penalty = ef.hpPenalty === -1 ? (5 + Math.floor(Math.random() * 26)) : (ef.hpPenalty || 0);
                totalHpPenalty += penalty;
                const expiresAt = now() + (ef.durationMs || 3600000);
                p.activeDrugs.push({ drug: item, expiresAt });
                // Addiction tracking
                if (!p.addictionDrug) p.addictionDrug = item;
                if (p.addictionDrug === item) {
                    const drugCountKey = 'drugCount_' + item;
                    p[drugCountKey] = (p[drugCountKey]||0) + 1;
                    const uses = p[drugCountKey];
                    const THRESH = [0,5,15,30,60,100];
                    for (let lv = THRESH.length-1; lv >= 1; lv--) {
                        if (uses >= THRESH[lv]) { p.addictionLevel = lv; break; }
                    }
                }
                tickChallenge(p, 'drugUses', 1);
            }

            p.markModified('activeDrugs');
            p.inventory.set(item, owned - useQty);

            if (jailbreak) {
                // Smokebomb no longer guarantees exit — it gives a 40% chance of reduction
                // To fully escape jail use: jailbreak, lawyercall, or bailout
                if (Math.random() < 0.40) {
                    const smokeSaved = Math.min(p.jailedUntil - now(), 15 * 60 * 1000);
                    p.jailedUntil -= smokeSaved;
                    await p.save();
                    return conn.sendMessage(from, { text: `💨 *Smoke Bomb!* The guards lost sight of you briefly — sentence cut by ${shortTime(smokeSaved)}.\n⛓️ Still in for ${shortTime(Math.max(0, p.jailedUntil - now()))}. Use *jailbreak* or *lawyercall* to fully escape.` }, { quoted: mek });
                } else {
                    await p.save();
                    return conn.sendMessage(from, { text: `💨 *Smoke Bomb!* Guards saw through the smoke. Still in for ${shortTime(Math.max(0, p.jailedUntil - now()))}.` }, { quoted: mek });
                }
            }

            if (healed) p.health = effMaxHP;
            if (totalEnergyBoost >= 999) p.energy = p.maxEnergy;
            else if (totalEnergyBoost > 0) p.energy = Math.min(p.maxEnergy, p.energy + totalEnergyBoost);

            // Apply HP penalty — if it exceeds current HP, hospitalise immediately
            const newHp = p.health - totalHpPenalty;
            if (newHp <= 0 && useQty > 1) {
                p.health = 0;
                p.jailedUntil = now() + (15 * 60 * 1000);
                lines.push(`💀 *OVERDOSE!* The combined effects were too much. You've been rushed to hospital for 15 minutes!`);
            } else {
                p.health = Math.max(1, newHp);
                lines.push(`💊 Took *${shopIt.name} x${useQty}* — -${totalHpPenalty} HP total penalty`);
            }

            const stack = p.activeDrugs.filter(d => d.expiresAt > now());
            const stackStr = stack.length > 0 ? `\n🧪 Active: ${stack.map(d => d.drug).join(' + ')}` : '';
            lines.push(`❤️ HP: ${p.health}/${effMaxHP} | ⚡ Energy: ${p.energy}/${p.maxEnergy}${stackStr}`);

            const titleMsg = checkTitles(p);
            await p.save();
            return conn.sendMessage(from, { text: lines.join('\n') + titleMsg }, { quoted: mek }); 
        }

        // ── CONSUMABLES (medkit, energy drink, gear insurance, etc.) ─────────────
        const effMaxHP2 = await getEffectiveMaxHP(p);
        let totalHeal = 0, totalEnergy = 0;
        let hospitalDischarged = false;

        // Special case: gear insurance
        if (item === 'gearinsurance') {
            p.inventory.set(item, owned - useQty);
            p.gearInsurance = true;
            // Insurance lasts 24h — store expiry in a temp field
            p.gearInsuranceExpiresAt = now() + (24 * 60 * 60 * 1000);
            await p.save();
            return conn.sendMessage(from, { text: `🛡️ *Gear Insurance Active!*\nYour equipped gear is protected from loss for 24 hours.` }, { quoted: mek });
        }

        for (let i = 0; i < useQty; i++) {
            if (shopIt.heal > 0) totalHeal += shopIt.heal;
            if (shopIt.energy > 0) totalEnergy += shopIt.energy;
        }

        p.inventory.set(item, owned - useQty);
        if (totalHeal > 0) {
            const nursingBonus = item === 'medkit' && (p.degrees||[]).some(d=>d.startsWith('nursing_')) ? 20 * useQty : 0;

            if (item === 'medkit' && isHospitalized(p)) {
                if (p.inJail) {
                    p.inventory.set(item, (p.inventory.get(item)||0) + useQty); // refund
                    await p.save();
                    return conn.sendMessage(from, { text: `⛓️ You're in *jail*, not hospital. Medkits don't work here.\nUse: *jailwork*, *lawyercall*, *bailout*, or wait.` }, { quoted: mek });
                }
                // Hospital: 5-10 HP per kit, discharge when ≥ 40 HP
                totalHeal = Math.floor(5 + Math.random() * 6) + nursingBonus;
            } else {
                totalHeal += nursingBonus;
            }

            p.health = Math.min(effMaxHP2, (p.health || 0) + totalHeal);

            if (item === 'medkit' && !p.inJail && p.health >= 40 && isHospitalized(p)) {
                hospitalDischarged = true;
                p.jailedUntil   = 0;
                p.inJail        = false;
                p.nurseCallUsed = false;
                p.sentenceMs    = 0;
            }
        }
        if (totalEnergy > 0) p.energy = Math.min(p.maxEnergy, p.energy + totalEnergy);

        logAction(p, `Used ${useQty}x ${shopIt.name}`);
        await p.save();
        const dischargeNote = hospitalDischarged ? '\n🚑 *Discharged from hospital!*' : (item === 'medkit' && isHospitalized(p) && !p.inJail) ? `\n❤️ HP: ${p.health}/${effMaxHP2} — need *40 HP* to leave. Use more medkits.` : '';
        return conn.sendMessage(from, { text: `✅ Used ${shopIt.name} x${useQty}. +${totalHeal} HP${totalEnergy > 0 ? `, +${totalEnergy} Energy` : ''}\n❤️ ${p.health}/${effMaxHP2} | ⚡ ${p.energy}/${p.maxEnergy}${dischargeNote}` }, { quoted: mek }); 

    } catch (e) { console.error('use error', e); }
});

// ------------- Kidnapping System -------------

cast({ pattern: 'kidnap', desc: 'Kidnap another player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const atkId = await getPlayerId(conn, sender);
        const atk = await getOrCreatePlayer(atkId);

        if (isHospitalized(atk)) return conn.sendMessage(from, { text: `🚑 You can't kidnap from jail/hospital.` }, { quoted: mek });
        if (isKidnapped(atk)) return conn.sendMessage(from, { text: `🔒 You're kidnapped yourself! Escape first.` }, { quoted: mek });
        if (isInFlight(atk)) return conn.sendMessage(from, { text: `✈️ Can't kidnap while in-flight.` }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId) return conn.sendMessage(from, { text: `Usage: kidnap @player` }, { quoted: mek });
        if (targetId === atkId) return conn.sendMessage(from, { text: `You can't kidnap yourself.` }, { quoted: mek });

        const victim = await getOrCreatePlayer(targetId);
        if (isHospitalized(victim)) return conn.sendMessage(from, { text: `That player is already in hospital/jail.` }, { quoted: mek });
        if (isKidnapped(victim)) return conn.sendMessage(from, { text: `That player is already kidnapped by someone else.` }, { quoted: mek });
        if (isInFlight(victim)) return conn.sendMessage(from, { text: `Can't kidnap someone mid-flight.` }, { quoted: mek });

        // ── SAME CITY REQUIRED ─────────────────────────────────────────────
        const atkCity  = normLoc(atk.location);
        const vicCity  = normLoc(victim.location);
        if (atkCity !== vicCity) {
            return conn.sendMessage(from, { text: `🌍 You're in *${atkCity}* — target is in *${vicCity}*. Travel there first.` }, { quoted: mek });
        }

        if (!atk.equippedWeapon) return conn.sendMessage(from, { text: `🔫 You need a weapon equipped to kidnap. Equip one first.` }, { quoted: mek });
        if (atk.energy < 40) return conn.sendMessage(from, { text: `⚡ Not enough energy. Kidnapping costs 40 energy.` }, { quoted: mek });

        // Use dedicated lastKidnap cooldown — doesn't block attack command
        const KIDNAP_COOLDOWN = 4 * 60 * 60 * 1000;
        const elapsed = now() - (atk.lastKidnap || 0);
        if (elapsed < KIDNAP_COOLDOWN) return conn.sendMessage(from, { text: `⏳ Kidnap cooldown: ${shortTime(KIDNAP_COOLDOWN - elapsed)} left.` }, { quoted: mek });

        // Strength-based outcome including all gear + level scaling + pet power
        const atkLvlM = 1; // Level removed from combat — pure stats
        const vicLvlM = 1;
        const atkGear   = getGearBonuses(atk);
        const vicGear   = getGearBonuses(victim);
        const atkPetC   = getPetCombatData(atk);
        const vicPetC   = getPetCombatData(victim);
        const atkPower  = ((atk.strength || 1) + (atk.speed || 1) + atkGear.strBonus + atkGear.spdBonus + atkGear.atkBonus + (atkPetC ? atkPetC.power : 0)) * atkLvlM;
        const defPower  = ((victim.strength || 1) + (victim.defense || 1) + vicGear.defBonus + vicGear.strBonus + (victim.equippedArmor ? 15 : 0) + (vicPetC ? vicPetC.power * 0.8 : 0)) * vicLvlM;
        const successChance = Math.min(0.85, Math.max(0.15, 0.35 + 0.5 * (atkPower - defPower) / Math.max(defPower, 1)));

        atk.energy -= 40;
        atk.lastKidnap = now();
        atk.crimeLevel = Math.min(100, (atk.crimeLevel || 0) + 35);

        // Pet flavour lines for kidnap attempt
        let kidnapPetLines = '';
        if (atkPetC) kidnapPetLines += `\n${atkPetC.icon} Your *${atkPetC.name}* helped corner the target!`;
        if (vicPetC) kidnapPetLines += `\n${vicPetC.icon} Their *${vicPetC.name}* fought to defend them!`;

        if (Math.random() < successChance) {
            victim.kidnappedBy = atkId;
            victim.kidnappedAt = now();
            victim.ransomAmount = 0;
            victim.ransomDemandedBy = null;
            // Auto-release after 24 hours — stored as kidnap expiry
            victim.kidnappExpiresAt = now() + (24 * 60 * 60 * 1000);
            logAction(atk, `Kidnapped ${victim.username || targetId}`);
            logAction(victim, `Kidnapped by @${atkId}`);
            await atk.save();
            await victim.save();
            logGlobal('🔒', `*${atk.username || atkId}* KIDNAPPED *${victim.username || targetId}*! Held for ransom.`);
            return conn.sendMessage(from, {
                text: `🔒 *Kidnapping successful!*\n\n@${targetId} is your captive.${kidnapPetLines}\n⚠️ Crime Heat +35\n\nNext steps:\n• *demandransom @${targetId} <amount>* — set a ransom\n• *release @${targetId}* — let them go\n\nAuto-release in 24h if no ransom is paid.`,
                mentions: [toJid(targetId)]
            }, { quoted: mek });
        } else {
            const jailTime = 30 * 60 * 1000;
            atk.health = Math.max(1, atk.health - 15);
            atk.jailedUntil = now() + jailTime;
            logAction(atk, `Failed kidnap of ${victim.username || targetId}, caught by police`);
            await atk.save();
            return conn.sendMessage(from, {
                text: `❌ *Kidnap failed!* @${targetId} fought back — you were caught by police.\n🚔 Jailed ${shortTime(jailTime)}. Lost 15 HP.`,
                mentions: [toJid(targetId)]
            }, { quoted: mek });
        }
    } catch (e) { console.error('kidnap error', e); }
});

cast({ pattern: 'demandransom', desc: 'Set a ransom demand for your captive', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const atkId = await getPlayerId(conn, sender);
        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId) return conn.sendMessage(from, { text: `Usage: demandransom @player <amount>` }, { quoted: mek });

        // Always grab the last purely-numeric arg to avoid picking up a phone number from a tag
        const amountArg = [...args].reverse().find(a => /^\d+$/.test(a));
        const amount = parseInt(amountArg || '0');
        if (!amount || amount < iC(500)) return conn.sendMessage(from, { text: `Ransom must be at least ${fmtMoney(iC(500))}.\nUsage: demandransom @player <amount>` }, { quoted: mek });
        if (amount > iC(5000000)) return conn.sendMessage(from, { text: `Ransom can't exceed ${fmtMoney(iC(5000000))}.` }, { quoted: mek });

        const victim = await getOrCreatePlayer(targetId);
        const atk = await getOrCreatePlayer(atkId);
        if (isHospitalized(atk)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${atk.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
        if (!isKidnapped(victim)) return conn.sendMessage(from, { text: `@${targetId} is not currently kidnapped.`, mentions: [toJid(targetId)] }, { quoted: mek });
        if (victim.kidnappedBy !== atkId) return conn.sendMessage(from, { text: `That player is not your captive.` }, { quoted: mek });

        victim.ransomAmount = amount;
        victim.ransomDemandedBy = atkId;
        await victim.save();

        return conn.sendMessage(from, {
            text: `💰 Ransom of *${fmtMoney(amount)}* demanded from @${targetId}.\nThey can pay with: *payransom*\nOr attempt to: *escape*`,
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch (e) { console.error('demandransom error', e); }
});

cast({ pattern: 'payransom', desc: 'Pay your ransom to be released', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });

        if (!isKidnapped(p)) return conn.sendMessage(from, { text: `You are not kidnapped.` }, { quoted: mek });
        if (!p.ransomAmount || p.ransomAmount <= 0) return conn.sendMessage(from, { text: `No ransom has been set yet. Wait for your captor to run: demandransom @you <amount>` }, { quoted: mek });
        if (p.money < p.ransomAmount) return conn.sendMessage(from, { text: `💸 Can't afford it. Ransom: ${fmtMoney(p.ransomAmount)} | Your cash: ${fmtMoney(p.money)}\nTry: *escape*` }, { quoted: mek });

        const kidnapperId = p.kidnappedBy;
        const kidnapper = await getOrCreatePlayer(kidnapperId);

        const paidAmount = p.ransomAmount;
        p.money -= paidAmount;
        p.moneySpent = (p.moneySpent || 0) + paidAmount;
        kidnapper.money += paidAmount;
        kidnapper.totalEarnings = (kidnapper.totalEarnings || 0) + paidAmount;

        logAction(p, `Paid ransom ${fmtMoney(paidAmount)} to ${kidnapper.username || kidnapperId}`);
        logAction(kidnapper, `Received ransom ${fmtMoney(paidAmount)} from ${p.username || pId}`);
        logFinancial(p, `Ransom paid to @${kidnapperId}`, -paidAmount);
        logFinancial(kidnapper, `Ransom received from @${pId}`, paidAmount);

        p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0; p.ransomDemandedBy = null;

        await p.save();
        await kidnapper.save();

        // Notify kidnapper
        try {
            await conn.sendMessage(from, {
                text: `💰 @${kidnapperId} — your captive *${p.username || pId}* paid the ransom of *${fmtMoney(paidAmount)}*! Money deposited.`,
                mentions: [toJid(kidnapperId)]
            });
        } catch (_) {}

        return conn.sendMessage(from, {
            text: `💸 You paid *${fmtMoney(paidAmount)}* and have been *released*! You're free.\n💰 Cash left: ${fmtMoney(p.money)}`
        }, { quoted: mek });
    } catch (e) { console.error('payransom error', e); }
});

cast({ pattern: 'escape', desc: 'Attempt to escape captivity', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });

        if (!isKidnapped(p)) return conn.sendMessage(from, { text: `You're not being held captive.` }, { quoted: mek });

        // Escape cooldown — can only try once every 5 min
        const ESCAPE_CD = 5 * 60 * 1000;
        const lastEsc = p.lastEscapeAttempt || 0;
        if (now() - lastEsc < ESCAPE_CD) {
            return conn.sendMessage(from, { text: `⏳ Your captor is watching closely. Try again in ${shortTime(ESCAPE_CD - (now() - lastEsc))}.` }, { quoted: mek });
        }
        p.lastEscapeAttempt = now();

        const kidnapper = await getOrCreatePlayer(p.kidnappedBy);

        // Escape power: speed + dex + gear spd/dex bonuses
        const pGear    = getGearBonuses(p);
        const kGear    = getGearBonuses(kidnapper);
        const escapePower = (p.speed || 1) + (p.dexterity || 1) + pGear.spdBonus + pGear.dexBonus + Math.random() * 20;
        const holdPower   = (kidnapper.strength || 1) + (kidnapper.defense || 1) + kGear.strBonus + kGear.defBonus;
        const escapeChance = Math.min(0.75, Math.max(0.10, 0.30 + 0.4 * (escapePower - holdPower) / Math.max(holdPower, 1)));

        if (Math.random() < escapeChance) {
            const escapeDmg = 10;
            p.health = Math.max(1, p.health - escapeDmg);
            const kidnapperIdSaved = p.kidnappedBy;
            p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0; p.ransomDemandedBy = null;
            await p.save();
            logAction(p, `Escaped captivity from ${kidnapper.username || kidnapperIdSaved}`);
            logGlobal('🏃', `*${p.username || pId}* broke free from captivity!`);

            // Notify kidnapper they lost their captive
            try {
                await conn.sendMessage(from, {
                    text: `🏃 @${kidnapperIdSaved} — your captive *${p.username || pId}* has ESCAPED! They're gone.`,
                    mentions: [toJid(kidnapperIdSaved)]
                });
            } catch (_) {}

            return conn.sendMessage(from, { text: `🏃 *You escaped!* Lost ${escapeDmg} HP scrambling away.\n❤️ HP: ${p.health}` }, { quoted: mek });
        } else {
            const beatDmg = Math.floor(15 + Math.random() * 20);
            p.health = Math.max(0, p.health - beatDmg);
            if (p.health <= 0) {
                // KO'd: hospitalize AND clear kidnap — can't be stuck in both states
                p.health = 0;
                p.jailedUntil = now() + 10 * 60 * 1000;
                p.kidnappedBy = null; p.kidnappedAt = 0; p.ransomAmount = 0; p.ransomDemandedBy = null;
                logAction(p, `Beaten unconscious escaping — auto-released from kidnap`);
                await p.save();
                return conn.sendMessage(from, { text: `❌ *Escape failed!* Your captor beat you unconscious.\n🚑 Hospitalized for 10 min. Kidnap ended (you're free but incapacitated).` }, { quoted: mek });
            }
            logAction(p, `Failed escape attempt (-${beatDmg} HP)`);
            await p.save();
            return conn.sendMessage(from, { text: `❌ *Escape failed!* Caught trying to run — beat down by your captor.\n❤️ HP: ${p.health}\n⏳ Wait ${shortTime(ESCAPE_CD)} before trying again.` }, { quoted: mek });
        }
    } catch (e) { console.error('escape error', e); }
});

cast({ pattern: 'release', desc: 'Release your captive', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const atkId = await getPlayerId(conn, sender);
        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId) return conn.sendMessage(from, { text: `Usage: release @player` }, { quoted: mek });

        const victim = await getOrCreatePlayer(targetId);
        if (victim.kidnappedBy !== atkId) return conn.sendMessage(from, { text: `That player is not your captive.` }, { quoted: mek });

        victim.kidnappedBy = null; victim.kidnappedAt = 0; victim.ransomAmount = 0; victim.ransomDemandedBy = null;
        await victim.save();

        return conn.sendMessage(from, {
            text: `✅ You released @${targetId}. They're free to go.`,
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch (e) { console.error('release error', e); }
});

// ------------- Rescue System -------------
cast({ pattern: 'rescue', desc: 'Attempt to rescue a kidnapped player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const rescuerId = await getPlayerId(conn, sender);
        const rescuer = await getOrCreatePlayer(rescuerId);

        if (isHospitalized(rescuer)) return conn.sendMessage(from, { text: `🚑 You can't rescue anyone from jail/hospital.` }, { quoted: mek });
        if (isKidnapped(rescuer)) return conn.sendMessage(from, { text: `🔒 You're kidnapped yourself! Escape first.` }, { quoted: mek });
        if (isInFlight(rescuer)) return conn.sendMessage(from, { text: flightMsg(rescuer) }, { quoted: mek });

        const victimId = await getTargetId(conn, mek, args, 0);
        if (!victimId) return conn.sendMessage(from, { text: `Usage: rescue @player\n\nAttempt to forcefully free a kidnapped player by taking on their captor.` }, { quoted: mek });
        if (victimId === rescuerId) return conn.sendMessage(from, { text: `You can't rescue yourself. Use 'escape' instead.` }, { quoted: mek });

        const victim = await getOrCreatePlayer(victimId);
        if (!isKidnapped(victim)) return conn.sendMessage(from, { text: `@${victimId} is not kidnapped.`, mentions: [toJid(victimId)] }, { quoted: mek });

        const kidnapperId = victim.kidnappedBy;
        if (kidnapperId === rescuerId) return conn.sendMessage(from, { text: `You are the kidnapper — use 'release @player' if you want to free them.` }, { quoted: mek });

        const kidnapper = await getOrCreatePlayer(kidnapperId);

        if (!rescuer.equippedWeapon) return conn.sendMessage(from, { text: `🔫 You need a weapon to storm a kidnapper's hideout.` }, { quoted: mek });
        if (rescuer.energy < 30) return conn.sendMessage(from, { text: `Not enough energy. Rescue costs 30 energy.` }, { quoted: mek });

        // Location check — must be in same city as kidnapper
        if (normLoc(rescuer.location) !== normLoc(kidnapper.location)) {
            return conn.sendMessage(from, {
                text: `🌍 *${rescuer.username || rescuerId}* is in ${rescuer.location} but the kidnapper is in ${kidnapper.location}. Travel there first.`
            }, { quoted: mek });
        }

        rescuer.energy -= 30;
        rescuer.crimeLevel = Math.min(100, (rescuer.crimeLevel || 0) + 10);

        // Combat: rescuer STR+SPD+weapon vs kidnapper STR+DEF+armor
        const weaponBonus = rescuer.equippedWeapon ? 25 : 0;
        const armorBonus  = kidnapper.equippedArmor ? 15 : 0;
        const rescuePower  = (rescuer.strength || 1) + (rescuer.speed || 1) + weaponBonus + Math.random() * 20;
        const kidnappPower = (kidnapper.strength || 1) + (kidnapper.defense || 1) + armorBonus + Math.random() * 15;

        const rescuerWins = rescuePower > kidnappPower;

        if (rescuerWins) {
            // Kidnapper takes a beating
            const dmgToKidnapper = Math.floor(20 + Math.random() * 30);
            kidnapper.health = Math.max(0, kidnapper.health - dmgToKidnapper);
            if (kidnapper.health <= 0) {
                kidnapper.jailedUntil = now() + (15 * 60 * 1000); kidnapper.inJail = true;
                kidnapper.jailWorkDone = 0; kidnapper.lawyerCallUsed = false; kidnapper.sentencedAt = now(); kidnapper.sentenceMs = 15*60*1000;
                kidnapper.health = 0;
            }

            // Rescuer takes minor damage
            const dmgToRescuer = Math.floor(5 + Math.random() * 15);
            rescuer.health = Math.max(1, rescuer.health - dmgToRescuer);

            // Free the victim
            victim.kidnappedBy = null; victim.kidnappedAt = 0;
            victim.ransomAmount = 0; victim.ransomDemandedBy = null;

            logAction(rescuer, `Rescued @${victimId} from @${kidnapperId}`);
            logAction(victim, `Rescued by @${rescuerId} from @${kidnapperId}`);
            logAction(kidnapper, `Raided by @${rescuerId}, lost captive @${victimId}`);
            logGlobal('🦸', `*${rescuer.username || rescuerId}* stormed ${kidnapper.username || kidnapperId}'s hideout and RESCUED *${victim.username || victimId}*!`);

            await rescuer.save();
            await victim.save();
            await kidnapper.save();

            return conn.sendMessage(from, {
                text: [
                    `🦸 *RESCUE SUCCESSFUL!*`,
                    ``,
                    `You fought through ${kidnapper.username || kidnapperId}'s defences and freed @${victimId}!`,
                    `⚔️ Dealt ${dmgToKidnapper} damage to the kidnapper${kidnapper.health <= 0 ? ' — they\'ve been hospitalised!' : ''}`,
                    `❤️ You took ${dmgToRescuer} damage. HP: ${rescuer.health}`,
                    ``,
                    `@${victimId} is now free.`
                ].join('\n'),
                mentions: [toJid(victimId), toJid(kidnapperId)]
            }, { quoted: mek });

        } else {
            // Rescue failed — rescuer gets hurt and possibly jailed
            const dmgToRescuer = Math.floor(25 + Math.random() * 35);
            rescuer.health = Math.max(0, rescuer.health - dmgToRescuer);
            if (rescuer.health <= 0) {
                rescuer.jailedUntil = now() + (10 * 60 * 1000); rescuer.inJail = false; // injured in rescue, hospital
                rescuer.health = 0;
            }

            logAction(rescuer, `Failed rescue of @${victimId} from @${kidnapperId}`);

            await rescuer.save();

            return conn.sendMessage(from, {
                text: [
                    `❌ *RESCUE FAILED!*`,
                    ``,
                    `${kidnapper.username || kidnapperId} was too strong — they fought you off.`,
                    `❤️ You took ${dmgToRescuer} damage. HP: ${rescuer.health}${rescuer.health <= 0 ? '\n🚑 You were knocked out and hospitalised for 10 minutes.' : ''}`,
                    ``,
                    `@${victimId} is still captive. Try again or find allies.`
                ].join('\n'),
                mentions: [toJid(victimId)]
            }, { quoted: mek });
        }
    } catch (e) { console.error('rescue error', e); }
});

// ------------- Global Game Log -------------
cast({ pattern: 'gamelog', desc: 'View the global game event log', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const entries = await GameLog.find().sort({ ts: -1 }).limit(100).exec();
        if (!entries || entries.length === 0) {
            return conn.sendMessage(from, { text: `📋 The game log is empty — nothing has happened yet!` }, { quoted: mek });
        }
        // Show newest-first, numbered
        const lines = entries.map((e, i) => `${i + 1}. ${e.text}`).join('\n');
        return conn.sendMessage(from, {
            text: `📋 *Global Game Log* (last ${entries.length} events)\n\n${lines}`
        }, { quoted: mek });
    } catch (e) { console.error('gamelog error', e); }
});

// ------------- Factions -------------
cast({ pattern: 'faction', desc: 'Faction commands', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const action = (args && args[0]) ? args[0].toLowerCase() : null;
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (!action) return conn.sendMessage(from, { text: [
            `🏢 *FACTION SYSTEM*`, ``,
            `*Basic:*`,
            `  faction create <name> — start a faction ($50k)`,
            `  faction info — view your faction`,
            `  faction invite @player — invite someone`,
            `  faction join <name> — join a faction`,
            `  faction kick @player — remove a member`,
            `  faction leave — leave your faction`,
            `  faction deposit <amount> — add to faction vault`,
            `  faction withdraw <amount> — take from vault`,
            `  faction war <name> — declare war on another faction`,
            ``,
            `*Recruitment:*`,
            `  faction recruit open/close — toggle applications`,
            `  faction recruit apply <name> — apply to a faction`,
            `  faction recruit accept @player — accept applicant`,
            `  faction recruit applicants — view pending`,
            ``,
            `*Events:*`,
            `  faction crime <type> — coordinated crime`,
            `  faction heist plan — browse heist tiers`,
            `  faction heist go <number> — execute heist`,
            `  faction territory view — see city control map`,
            `  faction territory claim <city> — seize territory`,
            ``,
            `*Info:*`,
            `  faction level — XP, rank, perks`,
            `  faction armory — view weapons`,
        ].join('\n') }, { quoted: mek });

        if (action === 'create') { 
            const name = args.slice(1).join(' ').trim(); 
            if (!name) return conn.sendMessage(from, { text: 'Usage: faction create <name>' }, { quoted: mek }); 
            
            if (p.faction) return conn.sendMessage(from, { text: 'You are already in a faction!' }, { quoted: mek });
            if (p.money < 50000) return conn.sendMessage(from, { text: 'Creating a faction costs $50,000.' }, { quoted: mek });
            
            const existingFaction = await Faction.findOne({ name }).exec();
            if (existingFaction) {
                // If orphaned (no valid members) — delete and allow recreation
                const validMembers = await Player.countDocuments({ faction: existingFaction._id }).exec().catch(() => 0);
                if (validMembers === 0 && existingFaction.members.length <= 1) {
                    await Faction.deleteOne({ _id: existingFaction._id }).exec();
                    // Also clean up any players pointing to this faction
                    await Player.updateMany({ faction: existingFaction._id }, { $set: { faction: null, lastFactionDues: 0 } }).exec().catch(()=>{});
                } else {
                    return conn.sendMessage(from, { text: `A faction named *${name}* already exists. Choose a different name.` }, { quoted: mek });
                }
            }
            
            p.money    -= 50000;
            p.moneySpent += 50000;
            const f = new Faction({ name, owner: pId, members: [pId], funds: 0 });
            await f.save();
            p.faction        = f._id;
            p.lastFactionDues = now(); // start the dues clock NOW — no retroactive charge
            logAction(p, `Created Faction: ${name}`);
            logGlobal('🏢', `*${p.username||pId}* founded *${name}*!`);
            const titleMsg = checkTitles(p);
            await p.save();
            return conn.sendMessage(from, { text: [
                `🏢 *${name}* has been founded!`,
                ``,
                `You are the owner. Invite members with: *faction invite @player*`,
                `Dues: $${fmtMoney(FACTION_DUES_BASE)}/hr per member — starts in 1 hour`,
            ].join('\n') + titleMsg }, { quoted: mek });
        }
        
        if (action === 'info') {
            if (!p.faction) return conn.sendMessage(from, { text: [
                `You are not in a faction.`,
                ``,
                `Create one: *faction create <name>* ($50k)`,
                `Browse: *faction join <name>* | Apply: *factionrecruit apply <name>*`
            ].join('\n') }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (!f) {
                // Orphaned state — faction was deleted. Clean up player.
                p.faction = null; p.lastFactionDues = 0; await p.save();
                return conn.sendMessage(from, { text: [
                    `⚠️ Your faction was dissolved or deleted.`,
                    ``,
                    `Create a new one: *faction create <name>* ($50k)`
                ].join('\n') }, { quoted: mek });
            }
            const owner = await Player.findById(f.owner).exec();
            // Load member usernames
            const memberDocs = await Player.find({ _id: { $in: f.members } }, '_id username level').lean().exec();
            const memberMap  = Object.fromEntries(memberDocs.map(m => [m._id, m]));
            const memberList = f.members.map(mid => {
                const mem = memberMap[mid];
                const name = mem ? (mem.username || mid) : mid;
                const lvl  = mem ? ` (Lv${mem.level||1})` : '';
                const role = mid === f.owner ? ' 👑' : (f.officers||[]).includes(mid) ? ' ⭐' : '';
                return `  • ${name}${lvl}${role}`;
            }).join('\n');

            const warCd = f.lastWar ? Math.max(0, (f.lastWar + 24*60*60*1000) - now()) : 0;
            const lines = [
                `🏢 *${f.name}*${f.tag ? ` [${f.tag}]` : ''}`,
                `📍 Territory: ${f.territory || 'None'}`,
                `⭐ Level ${f.level||1} | 🏆 Prestige: ${f.prestige||0}`,
                ``,
                `👥 *Members (${f.members.length}/${f.maxMembers||10}):*`,
                memberList,
                ``,
                `💰 Vault: ${fmtMoney(f.funds||0)} | 🏦 Bank: ${fmtMoney(f.bank||0)}`,
                `⚔️ Wars: ${f.warsWon||0}W / ${f.warsLost||0}L`,
                warCd > 0 ? `⏳ War cooldown: ${shortTime(warCd)}` : `✅ War ready`,
                f.recruiting ? `📢 Recruiting — apply with *factionrecruit apply ${f.name}*` : `🔒 Not recruiting`,
            ].filter(Boolean);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }

        if (action === 'invite') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (f.owner !== pId) return conn.sendMessage(from, { text: 'Only the faction owner can invite members.' }, { quoted: mek });
            const targetId = await getTargetId(conn, mek, args, 1);
            if (!targetId) return conn.sendMessage(from, { text: 'Usage: faction invite @user' }, { quoted: mek });
            
            const t = await getOrCreatePlayer(targetId);
            if (t.faction) return conn.sendMessage(from, { text: 'That player is already in a faction.' }, { quoted: mek });
            
            t.pendingFactionInvite = String(f._id);
            await t.save();
            return conn.sendMessage(from, { text: `📩 *@${pId}* invited *@${targetId}* to join **${f.name}**!\n\n@${targetId}, reply with \`faction join\` to accept.`, mentions: [toJid(pId), toJid(targetId)] }, { quoted: mek });
        }

        if (action === 'join') {
            if (p.faction) return conn.sendMessage(from, { text: 'You are already in a faction.' }, { quoted: mek });
            if (!p.pendingFactionInvite) return conn.sendMessage(from, { text: 'You have no pending faction invites.' }, { quoted: mek });
            
            const f = await Faction.findById(p.pendingFactionInvite).exec();
            if (!f) {
                p.pendingFactionInvite = null; await p.save();
                return conn.sendMessage(from, { text: 'That faction no longer exists.' }, { quoted: mek });
            }
            
            p.faction         = f._id;
            p.lastFactionDues  = now(); // grace clock starts now
            f.members.push(pId);
            p.pendingFactionInvite = null;
            const perkTier = getFactionPerkTier(f.prestige || 0);
            applyFactionPerks(p, perkTier);
            logAction(p, `Joined Faction: ${f.name}`);
            logGlobal('🏢', `*${p.username||pId}* joined *${f.name}*!`);
            await p.save(); await f.save();
            return conn.sendMessage(from, { text: `✅ Joined *${f.name}*!\nRank: ${perkTier.name} — perks applied.\nDues: $${fmtMoney(FACTION_DUES_BASE)}/hr — starts in 1 hour.` }, { quoted: mek });
        }

        if (action === 'kick') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (f.owner !== pId) return conn.sendMessage(from, { text: 'Only the faction owner can kick members.' }, { quoted: mek });
            
            const targetId = await getTargetId(conn, mek, args, 1);
            if (!targetId) return conn.sendMessage(from, { text: 'Usage: faction kick @user' }, { quoted: mek });
            if (targetId === pId) return conn.sendMessage(from, { text: 'You cannot kick yourself.' }, { quoted: mek });
            
            const t = await getOrCreatePlayer(targetId);
            if (String(t.faction) !== String(f._id)) return conn.sendMessage(from, { text: 'That player is not in your faction.' }, { quoted: mek });
            
            t.faction = null;
            f.members = f.members.filter(m => m !== targetId);
            removeFactionPerks(t);

            // Strip Faction Weapons
            for (let [item, qty] of t.borrowedFromFaction.entries()) {
                if (item === 'ammo') {
                    if (t.ammo >= qty) { t.ammo -= qty; f.armory.set('ammo', (f.armory.get('ammo') || 0) + qty); }
                    else { f.armory.set('ammo', (f.armory.get('ammo') || 0) + t.ammo); t.debt += (qty - t.ammo) * 25; t.ammo = 0; }
                } else {
                    let owned = t.inventory.get(item) || 0;
                    if (t.equippedWeapon === item) { owned += 1; t.equippedWeapon = null; }
                    if (t.equippedArmor === item) { owned += 1; t.equippedArmor = null; }
                    if (owned >= qty) {
                        t.inventory.set(item, owned - qty);
                        f.armory.set(item, (f.armory.get(item) || 0) + qty);
                    } else {
                        t.inventory.set(item, 0);
                        f.armory.set(item, (f.armory.get(item) || 0) + owned);
                        let missing = qty - owned;
                        let shopItem = DEFAULT_SHOP.find(s => s.id === item);
                        if (shopItem) t.debt += missing * shopItem.price;
                    }
                }
            }
            t.borrowedFromFaction.clear();

            await t.save(); await f.save();
            return conn.sendMessage(from, { text: `👢 *@${targetId}* was kicked from the faction. All borrowed weapons have been stripped.`, mentions: [toJid(targetId)] }, { quoted: mek });
        }

        if (action === 'leave') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (f) {
                if (f.owner === pId) return conn.sendMessage(from, { text: 'You are the owner! You cannot leave right now.' }, { quoted: mek });
                f.members = f.members.filter(m => m !== pId);
                
                // Strip Faction Weapons
                for (let [item, qty] of p.borrowedFromFaction.entries()) {
                    if (item === 'ammo') {
                        if (p.ammo >= qty) { p.ammo -= qty; f.armory.set('ammo', (f.armory.get('ammo') || 0) + qty); }
                        else { f.armory.set('ammo', (f.armory.get('ammo') || 0) + p.ammo); p.debt += (qty - p.ammo) * 25; p.ammo = 0; }
                    } else {
                        let owned = p.inventory.get(item) || 0;
                        if (p.equippedWeapon === item) { owned += 1; p.equippedWeapon = null; }
                        if (p.equippedArmor === item) { owned += 1; p.equippedArmor = null; }
                        if (owned >= qty) {
                            p.inventory.set(item, owned - qty);
                            f.armory.set(item, (f.armory.get(item) || 0) + qty);
                        } else {
                            p.inventory.set(item, 0);
                            f.armory.set(item, (f.armory.get(item) || 0) + owned);
                            let missing = qty - owned;
                            let shopItem = DEFAULT_SHOP.find(s => s.id === item);
                            if (shopItem) p.debt += missing * shopItem.price;
                        }
                    }
                }
                p.borrowedFromFaction.clear();
                await f.save();
            }
            p.faction = null;
            logAction(p, `Left Faction`);
            removeFactionPerks(p);
            await p.save();
            return conn.sendMessage(from, { text: 'You left the faction and returned all borrowed weapons.' }, { quoted: mek });
        }

        if (action === 'deposit') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            if (p.underAudit && p.auditExpiresAt > now()) return conn.sendMessage(from, { text: `🚨 Blocked — Under IRS audit. Can't move money to faction.` }, { quoted: mek });
            if ((p.taxOwed||0) > 500000) return conn.sendMessage(from, { text: `🏛️ Blocked — Pay your $${((p.taxOwed||0)/1e6).toFixed(1)}M tax first: *paytax all*` }, { quoted: mek });
            if ((p.activeLoan?.owed||0) > 0) return conn.sendMessage(from, { text: `🦈 Blocked — Pay your loan first: *loan pay all*` }, { quoted: mek });
            const amount = parseInt(args[1]);
            if (isNaN(amount) || amount <= 0) return conn.sendMessage(from, { text: 'Usage: faction deposit <amount>' }, { quoted: mek });
            if (p.money < amount) return conn.sendMessage(from, { text: 'Not enough cash.' }, { quoted: mek });
            
            const f = await Faction.findById(p.faction).exec();
            p.money -= amount;
            f.funds += amount;
            logAction(p, `Deposited ${fmtMoney(amount)} into faction`);
            await p.save(); await f.save();
            return conn.sendMessage(from, { text: `✅ Deposited ${fmtMoney(amount)} into faction funds.` }, { quoted: mek });
        }

        if (action === 'withdraw') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (f.owner !== pId) return conn.sendMessage(from, { text: 'Only the faction owner can withdraw funds.' }, { quoted: mek });
            
            const amount = parseInt(args[1]);
            if (isNaN(amount) || amount <= 0) return conn.sendMessage(from, { text: 'Usage: faction withdraw <amount>' }, { quoted: mek });
            if (f.funds < amount) return conn.sendMessage(from, { text: 'Faction does not have enough funds.' }, { quoted: mek });
            
            f.funds -= amount;
            p.money += amount;
            logAction(p, `Withdrew ${fmtMoney(amount)} from faction`);
            await f.save(); await p.save();
            return conn.sendMessage(from, { text: `✅ Withdrew ${fmtMoney(amount)} from faction funds.` }, { quoted: mek });
        }

        if (action === 'armory') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            if (!f) return conn.sendMessage(from, { text: 'Your faction no longer exists.' }, { quoted: mek });
            
            let armoryTxt = `🛡️ *${f.name} Armory*\n\n`;
            let items = Array.from(f.armory.entries());
            if (items.length === 0) armoryTxt += "The armory is completely empty. Use `faction putarmory <item> <qty>` to stock it.";
            else items.forEach(([k, v]) => armoryTxt += `📦 ${k}: ${v}\n`);
            
            return conn.sendMessage(from, { text: armoryTxt }, { quoted: mek });
        }

        if (action === 'putarmory') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            
            const item = (args[1] || '').toLowerCase();
            const qty = parseInt(args[2]) || 1;
            
            if (!item || qty <= 0) return conn.sendMessage(from, { text: 'Usage: faction putarmory <item_id> <qty>' }, { quoted: mek });
            
            if (item === 'ammo') {
                if (p.ammo < qty) return conn.sendMessage(from, { text: `You don't have ${qty} ammo.` }, { quoted: mek });
                p.ammo -= qty;
                f.armory.set('ammo', (f.armory.get('ammo') || 0) + qty);
            } else {
                let owned = p.inventory.get(item) || 0;
                if (owned < qty) return conn.sendMessage(from, { text: `You don't have ${qty}x ${item} in your inventory.` }, { quoted: mek });
                p.inventory.set(item, owned - qty);
                f.armory.set(item, (f.armory.get(item) || 0) + qty);
            }
            
            logAction(p, `Deposited ${qty}x ${item} to Faction Armory`);
            await p.save(); await f.save();
            return conn.sendMessage(from, { text: `✅ Deposited ${qty}x ${item} into the Faction Armory.` }, { quoted: mek });
        }

        if (action === 'takearmory') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();
            
            const item = (args[1] || '').toLowerCase();
            const qty = parseInt(args[2]) || 1;
            
            if (!item || qty <= 0) return conn.sendMessage(from, { text: 'Usage: faction takearmory <item_id> <qty>' }, { quoted: mek });
            
            let stock = f.armory.get(item) || 0;
            if (stock < qty) return conn.sendMessage(from, { text: `The armory only has ${stock}x ${item}.` }, { quoted: mek });
            
            f.armory.set(item, stock - qty);
            p.borrowedFromFaction.set(item, (p.borrowedFromFaction.get(item) || 0) + qty);
            
            if (item === 'ammo') {
                p.ammo += qty;
            } else {
                p.inventory.set(item, (p.inventory.get(item) || 0) + qty);
            }
            
            logAction(p, `Took ${qty}x ${item} from Faction Armory`);
            await p.save(); await f.save();
            return conn.sendMessage(from, { text: `🔫 You took ${qty}x ${item} from the Faction Armory. \n_Note: If you leave the faction, you must return this or you will go into massive debt!_` }, { quoted: mek });
        }


        if (action === 'war') {
            if (!p.faction) return conn.sendMessage(from, { text: 'You are not in a faction.' }, { quoted: mek });
            const f = await Faction.findById(p.faction).exec();

            const enemyName = args.slice(1).join(' ').trim();
            if (!enemyName) return conn.sendMessage(from, {
                text: [
                    '⚔️ *FACTION GANG WAR*', '',
                    'Usage: faction war <faction name>', '',
                    '• All member stats + gear + level + pets summed into total faction power',
                    '• Winner takes ALL of the loser\'s faction funds',
                    '• +1000 prestige to the winner',
                    '• 12-hour cooldown between wars'
                ].join('\n')
            }, { quoted: mek });

            if (f.owner !== pId) return conn.sendMessage(from, { text: 'Only the faction owner can declare war.' }, { quoted: mek });

            const WAR_COOLDOWN = 12 * 60 * 60 * 1000;
            if (now() - (f.lastWar || 0) < WAR_COOLDOWN)
                return conn.sendMessage(from, { text: `⏳ War cooldown: ${shortTime(WAR_COOLDOWN - (now() - f.lastWar))} remaining.` }, { quoted: mek });

            const escapedName = enemyName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
            const eFac = await Faction.findOne({ name: new RegExp('^' + escapedName + '$', 'i') }).exec();
            if (!eFac) return conn.sendMessage(from, { text: `Faction "${enemyName}" not found.` }, { quoted: mek });
            if (String(eFac._id) === String(f._id)) return conn.sendMessage(from, { text: "You can't declare war on yourself." }, { quoted: mek });

            // ── Calculate total faction combat power ──────────────────────────
            // Every member's full stat formula + gear + level mult + pet power summed
            async function getFacPower(fac) {
                const members = await Player.find({ _id: { $in: fac.members } }).exec();
                let total = 0;
                for (const mb of members) {
                    const lm   = 1; // Level removed from combat
                    const gear = getGearBonuses(mb);
                    const str  = ((mb.strength  || 1) + gear.strBonus) * lm;
                    const def  = ((mb.defense   || 1) + gear.defBonus) * lm;
                    const spd  = ((mb.speed     || 1) + gear.spdBonus) * lm;
                    const dex  = ((mb.dexterity || 1) + gear.dexBonus) * lm;
                    const wpn  = gear.atkBonus;
                    const pet  = getPetCombatData(mb);
                    total += (str*0.45 + dex*0.25 + spd*0.20 + def*0.10) * (1 + wpn/50) + (pet ? pet.power : 0);
                }
                return { total: Math.floor(total), count: members.length };
            }

            const { total: myPow, count: myCount } = await getFacPower(f);
            const { total: enPow, count: enCount } = await getFacPower(eFac);

            // ±15% RNG upset factor — upsets can happen
            const myRoll = myPow * (0.85 + Math.random() * 0.30);
            const enRoll = enPow * (0.85 + Math.random() * 0.30);
            const myWon  = myRoll >= enRoll;

            const winner = myWon ? f    : eFac;
            const loser  = myWon ? eFac : f;
            const loot   = loser.funds || 0;
            loser.funds  = 0;
            winner.funds = (winner.funds || 0) + loot;
            winner.prestige = (winner.prestige || 0) + 1000;
            f.lastWar    = now();
            eFac.lastWar = now();
            await f.save();
            await eFac.save();

            const totalPow = Math.max(1, myPow + enPow);
            const bar = (pow) => {
                const n = Math.min(10, Math.round((pow / totalPow) * 10));
                return '█'.repeat(n) + '░'.repeat(10 - n);
            };
            const pctDiff = Math.abs(myPow - enPow) / totalPow * 100;
            const closeness = pctDiff < 5  ? '🔥 *Razor close! Could have gone either way!*'
                            : pctDiff < 20 ? '💪 A decisive victory.'
                            : '💀 A complete domination.';

            const winLine  = myWon
                ? `🏆 *${f.name} WINS!*\nYour faction crushed ${eFac.name} in the streets!`
                : `💀 *${eFac.name} WINS!*\n${eFac.name} stood their ground and wiped you out!`;
            const lootLine = loot > 0
                ? `💰 *Winner takes all:* ${fmtMoney(loot)} seized from ${loser.name}'s vault`
                : `💸 Loser's vault was empty — only pride was at stake.`;
            const taunt = myWon
                ? `😤 ${eFac.name} — come back when your soldiers are stronger.`
                : `😤 ${f.name} — regroup, train harder, come back.`;

            const warLines = [
                `⚔️ *GANG WAR — ${f.name} vs ${eFac.name}* ⚔️`, ``,
                `🔴 *${f.name}* — ${myCount} soldier${myCount !== 1 ? 's' : ''}`,
                `   ⚡ Power: ${myPow.toLocaleString()}  |  ${bar(myPow)}`, ``,
                `🔵 *${eFac.name}* — ${enCount} soldier${enCount !== 1 ? 's' : ''}`,
                `   ⚡ Power: ${enPow.toLocaleString()}  |  ${bar(enPow)}`, ``,
                `━━━━━━━━━━━━━━━━━━━━━━`, ``,
                closeness, ``, winLine, ``, lootLine,
                `⭐ ${winner.name} gains *+1000 prestige*`, ``, taunt,
            ];

            logGlobal('⚔️', `*${winner.name}* DESTROYED *${loser.name}* in a gang war! ${fmtMoney(loot)} seized.`);
            return conn.sendMessage(from, { text: warLines.join('\n') }, { quoted: mek });
        }


        // ── faction level ────────────────────────────────────────────────────
        if (action === 'level') {
            if (!p.faction) return conn.sendMessage(from, { text: `You're not in a faction.` }, { quoted: mek });
            const fLvl = await Faction.findById(p.faction).exec();
            const lvl = fLvl.level || 1, xp = fLvl.xp || 0;
            const nextXP = lvl < 10 ? FACTION_LEVEL_XP[lvl] : null;
            const xpBar = nextXP ? '█'.repeat(Math.floor(xp/nextXP*10))+'░'.repeat(10-Math.floor(xp/nextXP*10)) : '██████████';
            const PERKS = ['Faction formed','+5 slots','Territory','Bank raid','+10 slots','Heist tier 2','War bonus','Tag','+25 slots','MAX Elite'];
            return conn.sendMessage(from, { text: [
                `🏢 *${fLvl.name} — LEVEL ${lvl}*`, ``,
                `XP: ${xp}${nextXP ? `/${nextXP}` : ' (MAX)'}  ${xpBar}`,
                `Members: ${fLvl.members.length}/${fLvl.maxMembers||10} | Wars: ${fLvl.warsWon||0}W/${fLvl.warsLost||0}L`,
                `Territory: ${fLvl.territory||'None'}`, ``,
                `🌟 *${PERKS[lvl-1]}*`, nextXP ? `Next: ${PERKS[lvl]}` : `Max level!`
            ].join('\n') }, { quoted: mek });
        }

        // ── faction recruit ───────────────────────────────────────────────────
        if (action === 'recruit') {
            const rsub = (args[1] || '').toLowerCase();
            const fr = p.faction ? await Faction.findById(p.faction).exec() : null;
            if (!fr && rsub !== 'apply') return conn.sendMessage(from, { text: `You're not in a faction.` }, { quoted: mek });
            if (rsub === 'open') {
                if (fr?.owner !== pId) return conn.sendMessage(from, { text: `Owner only.` }, { quoted: mek });
                fr.recruiting = true; await fr.save();
                return conn.sendMessage(from, { text: `✅ *${fr.name}* is now recruiting!` }, { quoted: mek });
            }
            if (rsub === 'close') {
                if (fr?.owner !== pId) return conn.sendMessage(from, { text: `Owner only.` }, { quoted: mek });
                fr.recruiting = false; await fr.save();
                return conn.sendMessage(from, { text: `🔒 Recruitment closed.` }, { quoted: mek });
            }
            if (rsub === 'apply') {
                const facName = args.slice(2).join(' ').trim();
                const rTarget = await Faction.findOne({ name: new RegExp('^' + facName.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '$','i') }).exec();
                if (!rTarget) return conn.sendMessage(from, { text: `Faction not found.` }, { quoted: mek });
                if (!rTarget.recruiting) return conn.sendMessage(from, { text: `Not recruiting.` }, { quoted: mek });
                if (p.faction) return conn.sendMessage(from, { text: `Leave your faction first.` }, { quoted: mek });
                if (rTarget.pendingApplicants.includes(pId)) return conn.sendMessage(from, { text: `Already applied.` }, { quoted: mek });
                rTarget.pendingApplicants.push(pId); await rTarget.save();
                return conn.sendMessage(from, { text: `📋 Application sent to *${rTarget.name}*.` }, { quoted: mek });
            }
            if (rsub === 'accept') {
                if (!fr || (fr.owner !== pId && !fr.officers?.includes(pId))) return conn.sendMessage(from, { text: `Officers only.` }, { quoted: mek });
                const rId = await getTargetId(conn, mek, args, 2);
                if (!rId || !fr.pendingApplicants.includes(rId)) return conn.sendMessage(from, { text: `No pending application.` }, { quoted: mek });
                if (fr.members.length >= (fr.maxMembers||10)) return conn.sendMessage(from, { text: `Faction is full.` }, { quoted: mek });
                fr.pendingApplicants = fr.pendingApplicants.filter(x=>x!==rId);
                fr.members.push(rId);
                const newMember = await getOrCreatePlayer(rId);
                newMember.faction = fr._id; await newMember.save();
                await addFactionXP(fr,50); await fr.save();
                return conn.sendMessage(from, { text: `✅ @${rId} accepted!`, mentions:[toJid(rId)] }, { quoted: mek });
            }
            if (rsub === 'applicants') {
                if (!fr || (fr.owner !== pId && !fr.officers?.includes(pId))) return conn.sendMessage(from, { text: `Officers only.` }, { quoted: mek });
                if (!fr.pendingApplicants.length) return conn.sendMessage(from, { text: `No pending applications.` }, { quoted: mek });
                return conn.sendMessage(from, { text: `📋 Pending:\n${fr.pendingApplicants.map(x=>`@${x}`).join('\n')}\n\nAccept: faction recruit accept @player`, mentions:fr.pendingApplicants.map(toJid) }, { quoted: mek });
            }
        }

        // ── faction heist ─────────────────────────────────────────────────────
        if (action === 'heist') {
            if (!p.faction) return conn.sendMessage(from, { text: `You're not in a faction.` }, { quoted: mek });
            const fH = await Faction.findById(p.faction).exec();
            const hsub = (args[1]||'plan').toLowerCase();
            const HT = [
                {name:'Warehouse Robbery',minLvl:1,reward:[100000,400000],energy:20,minMem:2,fail:0.30},
                {name:'Casino Heist',minLvl:2,reward:[500000,2000000],energy:30,minMem:3,fail:0.40},
                {name:'Bank Vault',minLvl:4,reward:[2500000,10000000],energy:40,minMem:4,fail:0.45},
                {name:'Federal Reserve',minLvl:6,reward:[10000000,40000000],energy:50,minMem:5,fail:0.55},
                {name:'Crypto Exchange',minLvl:8,reward:[25000000,100000000],energy:60,minMem:4,fail:0.60},
            ];
            const HCD = 4*60*60*1000;
            if (hsub === 'plan') {
                const lvl = fH.level||1;
                const lines = [`🦹 *FACTION HEISTS — ${fH.name}*`,``];
                HT.forEach((t,i)=>lines.push(`${lvl>=t.minLvl?'✅':'🔒'} *${i+1}. ${t.name}* — ${fmtMoney(t.reward[0])}–${fmtMoney(t.reward[1])} | ${t.minMem}+ members | ${Math.round(t.fail*100)}% fail`));
                lines.push(`\nRun: *faction heist go <number>*`);
                return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
            }
            if (hsub === 'go') {
                if (fH.owner!==pId && !(fH.officers||[]).includes(pId)) return conn.sendMessage(from, { text: `Officers only.` }, { quoted: mek });
                if (now()-(fH.lastHeist||0)<HCD) return conn.sendMessage(from, { text: `⏳ Heist CD: ${shortTime(HCD-(now()-(fH.lastHeist||0)))}` }, { quoted: mek });
                const lvl=fH.level||1; const hIdx=(parseInt(args[2])||1)-1;
                const heist=HT.filter(t=>lvl>=t.minLvl)[hIdx];
                if (!heist) return conn.sendMessage(from, { text: `Invalid selection.` }, { quoted: mek });
                const hAllM=await Player.find({_id:{$in:fH.members},jailedUntil:{$lte:now()}}).exec();
                const hAvail=hAllM.filter(mb=>(mb.energy||0)>=heist.energy&&!isHospitalized(mb));
                if (hAvail.length<heist.minMem) return conn.sendMessage(from, { text: `Need ${heist.minMem} healthy members with ${heist.energy}+ energy. ${hAvail.length} available.` }, { quoted: mek });
                fH.lastHeist=now();
                if (Math.random()>heist.fail) {
                    const gross=Math.floor(heist.reward[0]+Math.random()*(heist.reward[1]-heist.reward[0]));
                    const cut=Math.floor(gross*0.80/hAvail.length);
                    fH.funds+=Math.floor(gross*0.20);
                    for(const mb of hAvail){mb.energy-=heist.energy;mb.money+=cut;addTaxableIncome(mb,cut);await mb.save();}
                    await addFactionXP(fH,200); await fH.save();
                    logGlobal('🦹',`*${fH.name}* pulled off *${heist.name}* netting ${fmtMoney(gross)}!`);
                    return conn.sendMessage(from,{text:[`🦹 *${heist.name} — SUCCESS!*`,`💰 ${fmtMoney(gross)} | 🏢 Faction: ${fmtMoney(Math.floor(gross*0.2))} | 👥 Each: *${fmtMoney(cut)}* | ⭐ +200 XP`].join('\n')},{quoted:mek});
                } else {
                    for(const mb of hAvail){mb.energy=Math.max(0,mb.energy-heist.energy);mb.jailedUntil=now()+30*60*1000;mb.inJail=true;mb.jailWorkDone=0;mb.lawyerCallUsed=false;mb.sentencedAt=now();mb.sentenceMs=30*60*1000;mb.crimeLevel=Math.min(100,(mb.crimeLevel||0)+25);await mb.save();}
                    await fH.save();
                    logGlobal('🚔',`*${fH.name}*'s ${heist.name} FAILED!`);
                    return conn.sendMessage(from,{text:`🚔 *${heist.name} — FAILED!* All jailed 30 minutes.`},{quoted:mek});
                }
            }
        }


        // ── faction crime ─────────────────────────────────────────────────────
        if (action === 'crime') {
            // Re-use the factioncrime command logic by redirecting args
            // Just show help or forward to factioncrime
            const crimeId = (args[1] || '').toLowerCase();
            if (!crimeId) {
                const list = FACTION_CRIMES.map((c,i) => `*${i+1}. ${c.name}* (${c.id})\n   👥 ${c.minMembers}+ members | ⚡${c.energy} energy | 💰 ${fmtMoney(c.rewardMin)}–${fmtMoney(c.rewardMax)} | ⏱️ ${shortTime(c.cooldownMs)}`).join('\n');
                return conn.sendMessage(from, { text: [`🏢 *FACTION CRIMES*`,``,list,``,`Run: *faction crime <id>* e.g. *faction crime smuggling*`,`Or use: *factioncrime <id>*`].join('\n') }, { quoted: mek });
            }
            // Forward to factioncrime handler by mutating args and re-dispatching would be complex
            // Instead just show usage
            return conn.sendMessage(from, { text: `Use: *factioncrime ${crimeId}*` }, { quoted: mek });
        }

        // ── faction territory ─────────────────────────────────────────────────
        if (action === 'territory') {
            if (!p.faction) return conn.sendMessage(from, { text: `You're not in a faction.` }, { quoted: mek });
            const fT = await Faction.findById(p.faction).exec();
            if ((fT.level||1)<3) return conn.sendMessage(from, { text: `Requires Faction Level 3.` }, { quoted: mek });
            const tsub=(args[1]||'view').toLowerCase();
            const TCITIES=['Weirdos World','Mexico','London','Japan','Switzerland','Dubai','New York','Paris','Lagos','Moscow','Sydney','Rio de Janeiro'];
            if (tsub==='view') {
                const aF=await Faction.find({territory:{$ne:null}}).exec();
                const tLines=[`🗺️ *TERRITORY MAP*`,``];
                for(const city of TCITIES){const ctrl=aF.find(fc=>fc.territory===city);tLines.push(ctrl?`🔴 *${city}* — *${ctrl.name}*`:`⬜ *${city}* — unclaimed`);}
                tLines.push(``,fT.territory?`Yours: *${fT.territory}*`:`None claimed.`,`Use: *faction territory claim <city>*`);
                return conn.sendMessage(from,{text:tLines.join('\n')},{quoted:mek});
            }
            if (tsub==='claim') {
                if (fT.owner!==pId) return conn.sendMessage(from, { text: `Owner only.` }, { quoted: mek });
                const TCD2=24*60*60*1000;
                if (now()-(fT.lastTerritoryAttack||0)<TCD2) return conn.sendMessage(from, { text: `⏳ CD: ${shortTime(TCD2-(now()-(fT.lastTerritoryAttack||0)))}` }, { quoted: mek });
                const tcity=TCITIES.find(c=>c.toLowerCase()===args.slice(2).join(' ').trim().toLowerCase());
                if (!tcity) return conn.sendMessage(from, { text: `Unknown city.` }, { quoted: mek });
                fT.lastTerritoryAttack=now();
                const tExist=await Faction.findOne({territory:tcity}).exec();
                if (!tExist){fT.territory=tcity;await addFactionXP(fT,500);await fT.save();logGlobal('🗺️',`*${fT.name}* claimed *${tcity}*!`);return conn.sendMessage(from,{text:`🗺️ *${tcity}* claimed! +500 XP`},{quoted:mek});}
                const tMyM=await Player.find({_id:{$in:fT.members}}).exec();
                const tEnM=await Player.find({_id:{$in:tExist.members}}).exec();
                const tPow=m=>m.reduce((t,mb)=>t+(mb.strength||3)+(mb.defense||3)+(mb.speed||3),0);
                if(tPow(tMyM)*(0.85+Math.random()*0.30)>tPow(tEnM)*(0.85+Math.random()*0.30)){
                    tExist.territory=null;fT.territory=tcity;fT.warsWon=(fT.warsWon||0)+1;tExist.warsLost=(tExist.warsLost||0)+1;
                    await addFactionXP(fT,1000);await fT.save();await tExist.save();
                    logGlobal('🗺️',`*${fT.name}* seized *${tcity}* from *${tExist.name}*!`);
                    return conn.sendMessage(from,{text:`⚔️ *${tcity} SEIZED!* +1000 XP`},{quoted:mek});
                }else{
                    fT.warsLost=(fT.warsLost||0)+1;tExist.warsWon=(tExist.warsWon||0)+1;await fT.save();await tExist.save();
                    return conn.sendMessage(from,{text:`⚔️ Attack failed. ${tExist.name} defended. Try in 24h.`},{quoted:mek});
                }
            }
        }

    } catch (e) { console.error('faction error', e); }
});

// =============================================================================
// FACTION WAR RESOLUTION HELPERS
// =============================================================================
async function resolveWar(myFac, surrendered = false) {
    try {
        if (!myFac.activeWar) return;
        const w     = myFac.activeWar;
        const enemy = await Faction.findById(w.enemyId).exec();
        if (!enemy) { myFac.activeWar = null; await myFac.save(); return; }

        const myScore  = w.score || 0;
        const enScore  = w.enemyScore || 0;
        const myWon    = !surrendered && myScore >= enScore;

        const LOOT_PCT  = 0.25;
        const loser     = myWon ? enemy : myFac;
        const winner    = myWon ? myFac : enemy;
        const lootAmt   = Math.floor(loser.funds * LOOT_PCT);
        loser.funds     = Math.max(0, loser.funds - lootAmt);
        winner.funds   += lootAmt;
        winner.prestige = (winner.prestige || 0) + 500;

        const winnerTopMVP = Object.entries(
            (myWon ? w : enemy.activeWar?.contributions || {})
        ).sort((a,b)=>b[1]-a[1])[0];

        logGlobal('🏆', [
            surrendered
                ? `*${myFac.name}* has surrendered to *${enemy.name}*!`
                : `*FACTION WAR OVER!* 🔴 ${myFac.name} ${myScore}pts vs 🔵 ${enemy.name} ${enScore}pts`,
            `🏆 *${winner.name}* wins! Looted *${fmtMoney(lootAmt)}* from ${loser.name}'s vault.`,
            winnerTopMVP ? `🥇 MVP: @${winnerTopMVP[0]} with ${winnerTopMVP[1]} war points` : ''
        ].filter(Boolean).join('\n'));

        myFac.activeWar  = null;
        enemy.activeWar  = null;
        myFac.lastWar    = now();
        enemy.lastWar    = now();
        await myFac.save();
        await enemy.save();
    } catch(e) { console.error('resolveWar error', e); }
}

async function resolveWarIfExpired(fac) {
    if (!fac.activeWar) return;
    if (now() >= fac.activeWar.endsAt) await resolveWar(fac, false);
}

// Auto-check wars every 5 minutes and resolve expired ones
setInterval(async () => {
    try {
        const warFactions = await Faction.find({ 'activeWar.endsAt': { $lte: Date.now() } }).exec();
        for (const f of warFactions) { await resolveWar(f, false); }
    } catch(e) {}
}, 5 * 60 * 1000);

// ------------- THE AUCTION HOUSE -------------
cast({ pattern: 'auction', desc: 'Auction commands', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const action = (args && args[0]) ? args[0].toLowerCase() : null;
        const pId = await getPlayerId(conn, sender);

        if (!action) return conn.sendMessage(from, { text: 'Usage: auction <list|create|bid> [args]' }, { quoted: mek });
        
        if (action === 'list') { 
            const open = await Auction.find({ open: true, endsAt: { $gt: now() } }).limit(20).exec(); 
            if (!open.length) return conn.sendMessage(from, { text: 'No open auctions currently.' }, { quoted: mek }); 
            const txt = open.map(a => `🏷️ ID: *${a.auctionId}*\n📦 Item: ${a.itemId} x${a.qty}\n🧑‍💼 Seller: ${a.seller === 'SYSTEM' ? '🤖 AI SYSTEM' : '@'+a.seller}\n💸 Highest Bid: ${a.highestBid ? fmtMoney(a.highestBid) : 'None (Starts at '+fmtMoney(a.startingBid)+')'}\n⏳ Ends in: ${shortTime(a.endsAt - now())}`).join('\n\n'); 
            const mentions = open.filter(a => a.seller !== 'SYSTEM').map(a => toJid(a.seller));
            return conn.sendMessage(from, { text: `🔔 *Open Auctions:*\n\n${txt}\n\n*Command:* auction bid <ID> <amount>`, mentions }, { quoted: mek }); 
        }

        if (action === 'create') {
            const p = await getOrCreatePlayer(pId);
            const itemId = (args[1] || '').toLowerCase();
            const startBid = parseInt(args[2]);
            const hours = parseInt(args[3]);

            if (!itemId || isNaN(startBid) || isNaN(hours) || startBid <= 0 || hours <= 0) {
                return conn.sendMessage(from, { text: 'Usage: auction create <item_id> <starting_bid> <hours>' }, { quoted: mek });
            }

            const qty = p.inventory.get(itemId) || 0;
            if (qty <= 0) return conn.sendMessage(from, { text: `You don't have a ${itemId} in your inventory.` }, { quoted: mek });

            p.inventory.set(itemId, qty - 1);
            if (p.equippedWeapon === itemId) p.equippedWeapon = null;
            if (p.equippedArmor === itemId) p.equippedArmor = null;
            
            logAction(p, `Listed ${itemId} on Auction`);
            await p.save();

            const aucId = `AUC-${Math.random().toString(36).substr(2, 5).toUpperCase()}`;
            const auc = new Auction({
                auctionId: aucId, itemId: itemId, qty: 1, seller: pId, startingBid: startBid, highestBid: 0, endsAt: now() + (hours * 60 * 60 * 1000)
            });
            await auc.save();
            return conn.sendMessage(from, { text: `✅ Auction Created! ID: *${aucId}* | Item: ${itemId} | Starting at ${fmtMoney(startBid)}` }, { quoted: mek });
        }

        if (action === 'bid') {
            const p = await getOrCreatePlayer(pId);
            const aucId = (args[1] || '').toUpperCase();
            const bidAmt = parseInt(args[2]);

            if (!aucId || isNaN(bidAmt)) return conn.sendMessage(from, { text: 'Usage: auction bid <auctionId> <amount>' }, { quoted: mek });
            
            const auc = await Auction.findOne({ auctionId: aucId, open: true }).exec();
            if (!auc || auc.endsAt < now()) return conn.sendMessage(from, { text: 'Auction not found or already ended.' }, { quoted: mek });

            if (auc.seller === pId) return conn.sendMessage(from, { text: 'You cannot bid on your own auction.' }, { quoted: mek });
            
            const minBid = auc.highestBid > 0 ? Math.floor(auc.highestBid * 1.05) : auc.startingBid;
            if (bidAmt < minBid) return conn.sendMessage(from, { text: `Bid too low! Minimum bid is ${fmtMoney(minBid)} (5% higher than last).` }, { quoted: mek });

            if (p.money < bidAmt) return conn.sendMessage(from, { text: `You don't have enough money for this bid.` }, { quoted: mek });

            p.money -= bidAmt;
            p.moneySpent += bidAmt;
            
            if (auc.highestBidder) {
                const prevBidder = await Player.findById(auc.highestBidder);
                if (prevBidder) { 
                    prevBidder.money += auc.highestBid; 
                    logAction(prevBidder, `Outbid on ${auc.itemId} (Refunded ${fmtMoney(auc.highestBid)})`);
                    await prevBidder.save(); 
                }
            }

            auc.highestBid = bidAmt;
            auc.highestBidder = pId;
            
            logAction(p, `Placed bid of ${fmtMoney(bidAmt)} on ${auc.itemId}`);
            const titleMsg = checkTitles(p);
            await p.save(); await auc.save();

            return conn.sendMessage(from, { text: `🎉 You are now the highest bidder for *${auc.itemId}* with ${fmtMoney(bidAmt)}!` + titleMsg }, { quoted: mek });
        }

    } catch (e) { console.error('auction error', e); }
});

// ------------- Forbes & Crypto Modules -------------
cast({ pattern: 'forbes', desc: 'Richest players', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        // Only fetch registered players with real usernames
        const players = await Player.find({
            isChildNpc: { $ne: true },
            username:   { $exists: true, $nin: [null, ''] },
        }).lean().exec();

        const medals = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
        const richList = [];

        for (const p of players) {
            if (!p.username || p.username === p._id) continue;
            let nw = (p.money || 0) + (p.bank || 0);

            // Properties — safe iteration regardless of Map or plain object
            const props = p.properties instanceof Map
                ? [...p.properties.entries()]
                : Object.entries(p.properties || {});
            for (const [propId, qty] of props) {
                const shopIt = DEFAULT_SHOP.find(s => s.id === propId);
                if (shopIt && qty > 0) nw += SHOP_BASE_PRICES[propId] || shopIt.price;
            }

            // Crypto — safe iteration
            const crypto = p.cryptoPortfolio instanceof Map
                ? [...p.cryptoPortfolio.entries()]
                : Object.entries(p.cryptoPortfolio || {});
            for (const [coin, amt] of crypto) {
                if (amt > 0 && global.market?.[coin]) nw += amt * global.market[coin];
            }

            nw -= (p.debt || 0);
            richList.push({ id: p._id, username: p.username, nw, money: p.money || 0 });
        }

        richList.sort((a,b) => b.nw - a.nw);
        const top = richList.filter(r => r.nw > 0).slice(0, 10);

        if (!top.length) return conn.sendMessage(from, { text: `🏆 *FORBES*\n\nNo data yet. Players need money to appear here.` }, { quoted: mek });

        let txt = `🏆 *FORBES RICHEST PLAYERS*\n_(Wallet + Bank + Assets)_\n\n`;
        const mentionsArray = [];
        top.forEach((r, i) => {
            mentionsArray.push(toJid(r.id));
            txt += `${medals[i]} *${r.username}* — ${fmtMoney(r.nw)} NW\n`;
        });
        return conn.sendMessage(from, { text: txt, mentions: mentionsArray }, { quoted: mek });
    } catch (e) {
        console.error('forbes error', e);
        return conn.sendMessage(from, { text: `❌ Forbes error: ${e.message}` }, { quoted: mek });
    }
});

cast({ pattern: 'crypto', desc: 'Check crypto market', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    // Format tiny prices properly (e.g. SHIB, PEPE)
    function fmtCryptoPrice(p) {
        if (p >= 1)      return `$${p.toFixed(2)}`;
        if (p >= 0.01)   return `$${p.toFixed(4)}`;
        if (p >= 0.0001) return `$${p.toFixed(6)}`;
        return `$${p.toFixed(8)}`;
    }
    function fmtSupply(n) {
        if (n >= 1e12) return `${(n/1e12).toFixed(0)}T`;
        if (n >= 1e9)  return `${(n/1e9).toFixed(0)}B`;
        if (n >= 1e6)  return `${(n/1e6).toFixed(0)}M`;
        return n.toLocaleString();
    }

    let txt = `📈 *WEIRDOS WORLD CRYPTO EXCHANGE*
_Prices shift every 7 minutes_

`;
    for (const coin in global.market) {
        const price   = global.market[coin];
        // Show 24h change: compare to price 24h ago (stored in global.cryptoPrices24h)
        // Fall back to default price only if no 24h history exists
        if (!global.cryptoPrices24h) global.cryptoPrices24h = {};
        const price24h = global.cryptoPrices24h[coin] || price; // if no history, 0% change
        const pctChg  = price24h > 0 ? ((price - price24h) / price24h * 100) : 0;
        const arrow   = pctChg >= 0 ? '📈' : '📉';
        const sign    = pctChg >= 0 ? '+' : '';
        const cap     = global.cryptoSupplyCaps?.[coin];
        const sold    = global.cryptoSupplySold?.[coin] || 0;
        let supplyStr = '';
        if (cap) {
            const remaining = Math.max(0, cap - sold);
            const pctSold   = Math.min(100, (sold / cap * 100));
            const filled    = Math.floor(pctSold / 10);
            const bar       = '█'.repeat(filled) + '░'.repeat(10 - filled);
            supplyStr = `
   🏦 ${bar} ${pctSold.toFixed(1)}% sold | *${fmtSupply(remaining)}* of ${fmtSupply(cap)} remaining`;
        }
        txt += `${arrow} *${coin}* — ${fmtCryptoPrice(price)} (${sign}${pctChg.toFixed(1)}%)${supplyStr}
`;
    }
    txt += [
        ``,
        `📖 *HOW TO USE CRYPTO:*`,
        ``,
        `*Buy (spend dollars):*`,
        `  buycrypto BTC 500      — spend $500 on BTC`,
        `  buycrypto BTC $500     — same, dollar sign optional`,
        ``,
        `*Buy (exact tokens):*`,
        `  buycrypto SHIB 1000000 — buy 1M SHIB tokens`,
        `  buycrypto BTC 0.001t   — buy 0.001 BTC (add t = tokens)`,
        `  _Tip: For cheap coins (SHIB/PEPE/DOGE), default is token mode._`,
        `  _For expensive coins (BTC/ETH), default is dollar mode._`,
        ``,
        `*Sell:*`,
        `  sellcrypto BTC 0.05    — sell 0.05 BTC`,
        `  sellcrypto SHIB all    — sell all your SHIB`,
        ``,
        `*Transfer:*`,
        `  wirecrypto @player BTC 0.01 — send 0.01 BTC to someone`,
        `  paycrypto @player ETH 0.1   — pay someone in crypto`,
        ``,
        `*View:*`,
        `  portfolio              — your holdings + P&L`,
        `  cryptoboard            — top holders by coin`,
        `  cryptoboard BTC        — top BTC holders`,
        ``,
        `*Supply caps enforce real-world scarcity.*`,
        `*When supply runs low, prices rise. Buy crypto in shop*`,
        `*or from other players via wirecrypto.*`,
    ].join('\n');
    return conn.sendMessage(from, { text: txt }, { quoted: mek });
});

cast({ pattern: 'buycrypto', desc: 'Buy Crypto', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
        
        if (args.length < 2) return conn.sendMessage(from, { text: [
            `Usage:`,
            `• *buycrypto BTC 500* — spend $500 on BTC`,
            `• *buycrypto BTC $500* — same, dollar sign optional`,
            `• *buycrypto SHIB 2* — buy exactly 2 SHIB tokens`,
            `• *buycrypto SHIB 2000000* — buy 2 million SHIB`,
        ].join('\n') }, { quoted: mek });

        const coin = args[0].toUpperCase();
        if (!global.market[coin]) return conn.sendMessage(from, { text: `Invalid coin. Use *crypto* to see the market.` }, { quoted: mek });

        const coinPrice = global.market[coin];
        const rawArg    = args[1].toString().replace(/^\$/, ''); // strip leading $
        const rawNum    = parseFloat(rawArg);
        if (isNaN(rawNum) || rawNum <= 0) return conn.sendMessage(from, { text: `Enter a valid amount.` }, { quoted: mek });

        // Detect mode: if buying qty would cost < 1 cent, treat as dollar spend
        // If rawNum looks like a token quantity (e.g. 2, 0.5, 1000000) use qty mode
        // If rawNum looks like a dollar amount (e.g. 500, 50000) use dollar mode
        // Heuristic: if rawNum * coinPrice < rawNum then it's qty mode (coin is cheap)
        //            if coinPrice > 1 and rawNum < 100000 assume dollars
        //            User can force qty by typing a decimal like 0.5 or known small coins
        let qtyToBuy, dollars;
        const costIfQty    = rawNum * coinPrice;
        const costIfDollar = rawNum;

        // Explicit qty mode: buycrypto SHIB 2  (buying 2 SHIB at $0.00002 each = tiny cost)
        // Dollar mode: buycrypto BTC 500  (spending $500)
        // Rule: if coinPrice < 1 (cheap coins like SHIB/PEPE) → qty mode by default
        //       if coinPrice >= 1 → dollar mode by default  
        //       User can override by appending 't' for tokens: buycrypto BTC 0.001t
        const forceQty = args[1].toString().toLowerCase().endsWith('t');
        const rawClean = rawNum;

        if (forceQty || coinPrice < 1) {
            // Token/qty mode — buying exact number of coins
            qtyToBuy = rawClean;
            dollars  = qtyToBuy * coinPrice;
        } else {
            // Dollar mode — spending exact dollar amount
            dollars  = rawClean;
            qtyToBuy = dollars / coinPrice;
        }

        if (p.money < dollars) return conn.sendMessage(from, { text: `Not enough cash. Need ${fmtMoney(dollars)}, you have ${fmtMoney(p.money)}.` }, { quoted: mek });

        // Enforce supply cap — no more coins once cap is reached
        const cap      = global.cryptoSupplyCaps?.[coin];
        const sold     = global.cryptoSupplySold?.[coin] || 0;
        if (cap && sold + qtyToBuy > cap) {
            const remaining = Math.max(0, cap - sold);
            if (remaining <= 0) return conn.sendMessage(from, { text: [
                `❌ *${coin} supply exhausted!*`,
                `All ${(cap/1e6).toFixed(0)}M ${coin} have been bought up.`,
                `Buy from other players on the market: *market ${coin.toLowerCase()}*`
            ].join('\n') }, { quoted: mek });
            // Partial fill
            const partialDollars = remaining * global.market[coin];
            return conn.sendMessage(from, { text: [
                `⚠️ Only ${remaining.toFixed(6)} ${coin} left before cap!`,
                `Max you can buy: ${remaining.toFixed(6)} ${coin} for ${fmtMoney(partialDollars)}`,
                `Use: buycrypto ${coin} ${Math.floor(partialDollars)}`
            ].join('\n') }, { quoted: mek });
        }

        // Minimum $1 purchase — prevent free buys on tiny-price coins
        const actualCost = Math.max(1, Math.floor(dollars));
        if (p.money < actualCost) return conn.sendMessage(from, { text: `Not enough cash. Need ${fmtMoney(actualCost)}, you have ${fmtMoney(p.money)}.` }, { quoted: mek });

        if (!global.cryptoSupplySold) global.cryptoSupplySold = {};
        global.cryptoSupplySold[coin] = (global.cryptoSupplySold[coin] || 0) + qtyToBuy;

        p.money -= actualCost;
        p.moneySpent = (p.moneySpent||0) + actualCost;
        // Safe portfolio update — handles both Map and plain object
        if (p.cryptoPortfolio instanceof Map) {
            p.cryptoPortfolio.set(coin, (p.cryptoPortfolio.get(coin) || 0) + qtyToBuy);
        } else {
            p.cryptoPortfolio = p.cryptoPortfolio || {};
            p.cryptoPortfolio[coin] = (p.cryptoPortfolio[coin] || 0) + qtyToBuy;
            p.markModified('cryptoPortfolio');
        }
        logAction(p, `Bought ${coin} for ${fmtMoney(actualCost)}`);
        logFinancial(p, `Crypto buy: ${qtyToBuy.toFixed(6)} ${coin}`, -actualCost);

        const titleMsg = checkTitles(p);
        await p.save();

        return conn.sendMessage(from, { text: `✅ *@${p._id}* bought *${qtyToBuy.toFixed(6)} ${coin}* for *${fmtMoney(actualCost)}*!` + titleMsg, mentions: [toJid(p._id)] }, { quoted: mek });
    } catch (e) { console.error(e); }
});

cast({ pattern: 'sellcrypto', desc: 'Sell Crypto', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });
        
        if (args.length < 2) return conn.sendMessage(from, { text: 'Usage: sellcrypto <coin> <amount>\nExample: sellcrypto BTC 0.05' }, { quoted: mek });

        const coin = args[0].toUpperCase();
        const qtyToSell = parseFloat(args[1]);

        if (!global.market[coin]) return conn.sendMessage(from, { text: `Invalid coin.` }, { quoted: mek });
        if (isNaN(qtyToSell) || qtyToSell <= 0) return conn.sendMessage(from, { text: `Enter a valid amount to sell.` }, { quoted: mek });

        const currentBalance = p.cryptoPortfolio.get(coin) || 0;
        if (currentBalance < qtyToSell) return conn.sendMessage(from, { text: `You don't have enough ${coin}. Your balance: ${currentBalance.toFixed(6)}` }, { quoted: mek });
        
        const profit = qtyToSell * global.market[coin];
        
        p.cryptoPortfolio.set(coin, currentBalance - qtyToSell);
        p.money = capBal((p.money||0) + profit); // enforce wallet cap on sell proceeds
        // Return coins to circulating supply when sold
        if (global.cryptoSupplySold?.[coin]) {
            global.cryptoSupplySold[coin] = Math.max(0, (global.cryptoSupplySold[coin] || 0) - qtyToSell);
        }
        logAction(p, `Sold ${coin} for ${fmtMoney(profit)}`);
        logFinancial(p, `Crypto sell: ${qtyToSell.toFixed(6)} ${coin}`, profit);
        await p.save();
        
        return conn.sendMessage(from, { text: `✅ *@${p._id}* sold ${qtyToSell.toFixed(6)} ${coin} for ${fmtMoney(profit)}!`, mentions: [toJid(p._id)] }, { quoted: mek });
    } catch (e) { console.error(e); }
});

