const PlayerShopSchema = new mongoose.Schema({
    listingId:  { type: String, required: true, unique: true },
    sellerId:   { type: String, required: true },
    itemId:     { type: String, required: true },
    qty:        { type: Number, default: 1 },
    priceEach:  { type: Number, required: true },
    listedAt:   { type: Number, default: Date.now },
    active:     { type: Boolean, default: true }
});
const PlayerShopListing = mongoose.models.RPGPlayerShop || mongoose.model('RPGPlayerShop', PlayerShopSchema);

// ─────────────────────────────────────────────────────────────────────────────
// SCHEMA: Stock Market
// ─────────────────────────────────────────────────────────────────────────────
const StockSchema = new mongoose.Schema({
    ticker:     { type: String, required: true, unique: true },
    name:       { type: String, required: true },
    price:      { type: Number, required: true },
    basePrice:  { type: Number, required: true },
    sector:     { type: String, default: 'General' },
    lastChange: { type: Number, default: 0 } // % change last tick
});
const Stock = mongoose.models.RPGStock || mongoose.model('RPGStock', StockSchema);

const StockPortfolioSchema = new mongoose.Schema({
    _id:        { type: String }, // playerId
    holdings:   { type: Map, of: Number, default: {} }, // ticker -> shares owned
    avgCost:    { type: Map, of: Number, default: {} }  // ticker -> avg cost per share
});
