async function ensureStocks() {
    try {
        await ensureMongo();
        for (const s of DEFAULT_STOCKS) {
            await Stock.updateOne({ ticker: s.ticker }, { $setOnInsert: s }, { upsert: true });
        }
    } catch (e) { console.error('ensureStocks error', e); }
}
ensureStocks();

// Stock market price engine — ticks every 5 minutes
setInterval(async () => {
    try {
        if (mongoose.connection.readyState !== 1) return;
        const stocks = await Stock.find({});
        for (const s of stocks) {
            const drift = s.price < s.basePrice * 0.3 ? 0.08 : s.price > s.basePrice * 4 ? -0.08 : 0;
            const changePct = ((Math.random() * 0.18) - 0.085) + drift;
            s.lastChange = Math.round(changePct * 10000) / 100;
            s.price = Math.max(1, Math.round(s.price * (1 + changePct) * 100) / 100);
            await s.save();
        }
    } catch (e) { console.error('Stock tick error:', e); }
}, 5 * 60 * 1000);

