// ─────────────────────────────────────────────────────────────────────────────
// HELPER: item display name lookup (shop + prey)
// ─────────────────────────────────────────────────────────────────────────────
function getItemName(itemId) {
    const shop = DEFAULT_SHOP.find(s => s.id === itemId);
    if (shop) return shop.name;
    const prey = PREY_LIST.find(p => p.id === itemId);
    if (prey) return prey.name;
    const recipe = CRAFTING_RECIPES.find(r => r.result === itemId);
    if (recipe) return recipe.name;
    return itemId;
}

