cast({ pattern: 'crimes', desc: 'List all crimes including advanced', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    let txt = `🔪 *ALL AVAILABLE CRIMES*\n\n`;
    txt += `*── Basic Crimes ──*\n`;
    for (const c of CRIMES) {
        txt += `• *${c.id}* — ${c.name} | 💰 $${c.rewardMin}-$${c.rewardMax} | ⚡ ${c.energy} energy | ❌ ${Math.round(c.failChance*100)}% fail\n`;
    }
    txt += `\n*── Advanced Crimes ──*\n`;
    for (const c of ADVANCED_CRIMES) {
        const reqs = [];
        if (c.requiresWeapon) reqs.push('🔫 Armed');
        if (c.requiresStat) reqs.push(Object.entries(c.requiresStat).map(([k,v]) => `${k.toUpperCase()} ${v}+`).join(', '));
        txt += `• *${c.id}* — ${c.name}\n  📖 ${c.desc}\n  💰 $${c.rewardMin.toLocaleString()}-$${c.rewardMax.toLocaleString()} | ⚡ ${c.energy} | ❌ ${Math.round(c.failChance*100)}% fail\n  📋 Requires: ${reqs.join(' | ') || 'None'}\n\n`;
    }
    txt += `*Command:* crime <crimeId>`;
    return conn.sendMessage(from, { text: txt }, { quoted: mek });
});

cast({ pattern: 'heist', desc: 'Attempt an advanced crime', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Action restricted. You are in hospital/jail for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });

        const crimeId = args && args[0] ? args[0].toLowerCase() : null;
        if (!crimeId) {
            let txt = `🔫 *Advanced Heists*\nUsage: heist <crimeId>\n\n`;
            for (const c of ADVANCED_CRIMES) {
                txt += `• *${c.id}* — ${c.name}: ${c.desc}\n`;
            }
            return conn.sendMessage(from, { text: txt }, { quoted: mek });
        }

        const crime = ADVANCED_CRIMES.find(c => c.id === crimeId);
        if (!crime) return conn.sendMessage(from, { text: `Unknown heist. Use 'heist' to see the list.` }, { quoted: mek });

        // Cooldown (shared with crime cooldown key but tracked separately per heist via lastCrime + crimeId hash)
        const elapsed = now() - (p.lastCrime || 0);
        if (elapsed < crime.cooldownMs) return conn.sendMessage(from, { text: `⏳ You need to lay low. Wait ${shortTime(crime.cooldownMs - elapsed)}.` }, { quoted: mek });

        if (p.energy < crime.energy) return conn.sendMessage(from, { text: `⚡ Not enough energy. Need ${crime.energy}.` }, { quoted: mek });

        // Stat requirements
        if (crime.requiresStat) {
            for (const [stat, minVal] of Object.entries(crime.requiresStat)) {
                if ((p[stat] || 0) < minVal) {
                    return conn.sendMessage(from, { text: `❌ You need ${stat.toUpperCase()} ${minVal}+ for this heist. (You have ${p[stat] || 0})` }, { quoted: mek });
                }
            }
        }

        // Weapon requirement
        if (crime.requiresWeapon) {
            const guns = ['pistol', 'taser', 'ar15', 'goldengun', 'deagle', 'musket', 'precisionrifle', 'brassknuckles', 'machete', 'trenchknife', 'umbrella', 'cricketbat', 'katana', 'ninjato', 'sniper', 'flammenwerfer'];
            if (!p.equippedWeapon || !guns.includes(p.equippedWeapon)) {
                return conn.sendMessage(from, { text: `🔫 You need a weapon equipped for this heist!` }, { quoted: mek });
            }
        }

        p.energy -= crime.energy;
        p.lastCrime = now();

        // Skill bonus: dex reduces fail chance
        const skillBonus = Math.min(0.25, (p.dexterity + p.speed) * 0.005);
        // Bomb bonus
        const hasBomb = (p.inventory.get('homemadebomb') || 0) > 0;
        const bombBonus = hasBomb ? 0.20 : 0;
        if (hasBomb) { p.inventory.set('homemadebomb', p.inventory.get('homemadebomb') - 1); }

        const effectiveFailChance = Math.max(0.05, crime.failChance - skillBonus - bombBonus);

        if (Math.random() < effectiveFailChance) {
            // FAIL
            const damage = Math.floor(15 + Math.random() * 35);
            p.health = Math.max(0, p.health - damage);
            const fine = Math.max(500, Math.floor(p.money * (0.08 + Math.random() * 0.12)));
            p.money = Math.max(0, p.money - fine);

            let jailMsg = '';
            if (p.health <= 0 || Math.random() < 0.5) {
                p.jailedUntil = now() + crime.jailTime; p.inJail = true;
                p.jailWorkDone = 0; p.lawyerCallUsed = false; p.sentencedAt = now(); p.sentenceMs = crime.jailTime;
                p.health = Math.max(1, p.health);
                jailMsg = `\n🚔 Caught! Jailed for ${shortTime(crime.jailTime)}.`;
            }

            logAction(p, `Failed heist: ${crime.name} (-${fmtMoney(fine)})`);
            await p.save();
            return conn.sendMessage(from, { text: `❌ *HEIST FAILED — ${crime.name.toUpperCase()}*\n\nThe operation went sideways.\n💔 -${damage} HP\n💸 Fined ${fmtMoney(fine)}${jailMsg}${hasBomb ? '\n💣 Bomb was used.' : ''}` }, { quoted: mek });
        } else {
            // SUCCESS
            const { min: cMin, max: cMax } = liveCrimeReward(crime.rewardMin, crime.rewardMax);
            const gross = applySeasonalBonus(Math.floor(cMin + Math.random() * (cMax - cMin)), 'crime');
            const { net: reward, vat } = applyVAT(gross);
            const xp = Math.floor(8 + Math.random()*12); // no stat scaling
            p.money += reward;
            addTaxableIncome(p, reward);
            p.exp += xp;
            p.crimesCommitted += 1;
            const leveled = await tryLevelUp(p);
            const titleMsg = checkTitles(p);

            logAction(p, `Pulled off heist: ${crime.name} (+${fmtMoney(reward)})`);
            logGlobal('🔫', `*${p.username || p._id}* pulled off *${crime.name}* and netted ${fmtMoney(reward)}!`);
            await p.save();
            return conn.sendMessage(from, {
                text: `💰 *HEIST SUCCESS — ${crime.name.toUpperCase()}*\n\n${crime.desc}\n\n✅ Gross: ${fmtMoney(gross)} | 🏛️ VAT (12%): -${fmtMoney(vat)} | *Net: ${fmtMoney(reward)}*\n✨ +${xp} EXP${leveled ? `\n🎉 Level Up! Now Level ${p.level}!` : ''}${hasBomb ? '\n💣 Bomb gave you a critical edge.' : ''}${titleMsg}`
            }, { quoted: mek });
        }
    } catch (e) { console.error('heist error', e); }
});

