cast({ pattern: 'recipes', desc: 'View all crafting recipes', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        let txt = `🔧 *CRAFTING RECIPES*\n_Craft with: craft <recipeId>_\n\n`;

        for (const r of CRAFTING_RECIPES) {
            const ingList = Object.entries(r.ingredients).map(([k, v]) => `${v}x ${getItemName(k)}`).join(' + ');
            const haveAll = Object.entries(r.ingredients).every(([k, v]) => (p.inventory.get(k) || 0) >= v);
            const skillOk = (p.huntingSkill || 0) >= r.skillRequired;
            const status = haveAll && skillOk ? '✅' : '🔒';
            txt += `${status} *${r.id}* — ${r.name}\n`;
            txt += `   📖 ${r.desc}\n`;
            txt += `   🧰 Needs: ${ingList}\n`;
            txt += `   ⚡ Energy: ${r.energyCost} | 🏹 Skill req: ${r.skillRequired}\n\n`;
        }

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('recipes error', e); }
});

cast({ pattern: 'craft', desc: 'Craft an item', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Action restricted. Hospitalized/Jailed for ${shortTime(p.jailedUntil - now())}.` }, { quoted: mek });

        const recipeId = args && args[0] ? args[0].toLowerCase() : null;
        if (!recipeId) return conn.sendMessage(from, { text: `Usage: craft <recipeId>\nSee all recipes with: recipes` }, { quoted: mek });

        const recipe = CRAFTING_RECIPES.find(r => r.id === recipeId);
        if (!recipe) return conn.sendMessage(from, { text: `❌ Unknown recipe. Use 'recipes' to see all.` }, { quoted: mek });

        if ((p.huntingSkill || 0) < recipe.skillRequired) {
            return conn.sendMessage(from, { text: `🔒 Crafting skill too low! Need Hunting/Crafting Skill ${recipe.skillRequired}. (Yours: ${p.huntingSkill || 0})` }, { quoted: mek });
        }

        if (p.energy < recipe.energyCost) return conn.sendMessage(from, { text: `⚡ Not enough energy. Need ${recipe.energyCost}.` }, { quoted: mek });

        // Check ingredients
        const missing = [];
        for (const [ingId, qty] of Object.entries(recipe.ingredients)) {
            const has = p.inventory.get(ingId) || 0;
            if (has < qty) missing.push(`${qty - has} more ${getItemName(ingId)}`);
        }
        if (missing.length) return conn.sendMessage(from, { text: `❌ Missing ingredients:\n• ${missing.join('\n• ')}` }, { quoted: mek });

        // Consume ingredients
        for (const [ingId, qty] of Object.entries(recipe.ingredients)) {
            p.inventory.set(ingId, (p.inventory.get(ingId) || 0) - qty);
        }

        // Grant result
        p.inventory.set(recipe.result, (p.inventory.get(recipe.result) || 0) + recipe.qty);
        p.energy -= recipe.energyCost;
        p.huntingSkill = (p.huntingSkill || 0) + 1; // crafting improves skill
        p.exp += 15;

        const leveled = await tryLevelUp(p);
        logAction(p, `Crafted ${recipe.qty}x ${recipe.name}`);
        await p.save();

        return conn.sendMessage(from, {
            text: `🔧 *CRAFTED!*\n\nYou combined the ingredients and created *${recipe.qty}x ${recipe.name}*!\n📖 ${recipe.desc}\n\n✨ +15 EXP | 🏹 Craft Skill +1${leveled ? `\n🎉 Level Up! Now Level ${p.level}!` : ''}`
        }, { quoted: mek });
    } catch (e) { console.error('craft error', e); }
});

