cast({ pattern: 'stocks', desc: 'View the stock market', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const all = await Stock.find({}).sort({ ticker: 1 }).exec();
        if (!all.length) return conn.sendMessage(from, { text: 'Stock market is loading, try again shortly.' }, { quoted: mek });

        // Optional sector filter
        const filter = args && args[0] ? args[0].toUpperCase() : null;
        const list = filter ? all.filter(s => s.sector.toUpperCase().includes(filter) || s.ticker === filter) : all;

        let txt = `📊 *TORN CITY STOCK EXCHANGE*\n_Updates every 5 minutes_\n\n`;
        for (const s of list) {
            const arrow = s.lastChange >= 0 ? '📈' : '📉';
            const sign = s.lastChange >= 0 ? '+' : '';
            txt += `${arrow} *${s.ticker}* — ${s.name}\n`;
            txt += `   💲 $${s.price.toFixed(2)} | ${sign}${s.lastChange}% | 🏭 ${s.sector}\n\n`;
        }
        txt += `*Commands:*\nbuystock <TICKER> <shares>\nsellstock <TICKER> <shares>\nportfolio`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('stocks error', e); }
});

cast({ pattern: 'buystock', desc: 'Buy shares in a company', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Action restricted. Hospitalized/Jailed.` }, { quoted: mek });
        if (!args || args.length < 2) return conn.sendMessage(from, { text: `Usage: buystock <TICKER> <shares>\nExample: buystock ARMS 10` }, { quoted: mek });

        const ticker = args[0].toUpperCase();
        const shares = parseInt(args[1]);
        if (isNaN(shares) || shares <= 0) return conn.sendMessage(from, { text: `Enter a valid number of shares.` }, { quoted: mek });

        const stock = await Stock.findOne({ ticker }).exec();
        if (!stock) return conn.sendMessage(from, { text: `Unknown ticker. Use 'stocks' to see the market.` }, { quoted: mek });

        const totalCost = Math.ceil(stock.price * shares * 100) / 100;
        if (p.money < totalCost) return conn.sendMessage(from, { text: `💸 Not enough cash. Buying ${shares} shares of ${ticker} costs ${fmtMoney(totalCost)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });

        // Update portfolio
        let port = await StockPortfolio.findById(pId).exec();
        if (!port) port = new StockPortfolio({ _id: pId });

        const currentShares = port.holdings.get(ticker) || 0;
        const currentAvg = port.avgCost.get(ticker) || 0;
        const newAvg = ((currentAvg * currentShares) + totalCost) / (currentShares + shares);

        port.holdings.set(ticker, currentShares + shares);
        port.avgCost.set(ticker, Math.round(newAvg * 100) / 100);

        p.money -= totalCost;
        p.moneySpent += totalCost;

        logAction(p, `Bought ${shares} shares of ${ticker} @ $${stock.price.toFixed(2)}`);
        await p.save();
        await port.save();

        return conn.sendMessage(from, {
            text: `📈 *STOCK PURCHASED*\n\n*${shares} shares* of *${ticker}* (${stock.name})\nPrice per share: $${stock.price.toFixed(2)}\nTotal cost: ${fmtMoney(totalCost)}\nAvg cost basis: $${newAvg.toFixed(2)}\n\n💰 Remaining cash: ${fmtMoney(p.money)}`
        }, { quoted: mek });
    } catch (e) { console.error('buystock error', e); }
});

cast({ pattern: 'sellstock', desc: 'Sell shares in a company', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });

        if (!args || args.length < 2) return conn.sendMessage(from, { text: `Usage: sellstock <TICKER> <shares|all>\nExample: sellstock ARMS 5` }, { quoted: mek });

        const ticker = args[0].toUpperCase();
        const stock = await Stock.findOne({ ticker }).exec();
        if (!stock) return conn.sendMessage(from, { text: `Unknown ticker. Use 'stocks' to see the market.` }, { quoted: mek });

        const port = await StockPortfolio.findById(pId).exec();
        const ownedShares = port ? (port.holdings.get(ticker) || 0) : 0;
        if (ownedShares <= 0) return conn.sendMessage(from, { text: `You don't own any ${ticker} shares.` }, { quoted: mek });

        const qty = args[1].toLowerCase() === 'all' ? ownedShares : parseInt(args[1]);
        if (isNaN(qty) || qty <= 0) return conn.sendMessage(from, { text: `Enter a valid number of shares.` }, { quoted: mek });
        if (qty > ownedShares) return conn.sendMessage(from, { text: `You only own ${ownedShares} shares of ${ticker}.` }, { quoted: mek });

        const proceeds = Math.floor(stock.price * qty * 100) / 100;
        const avgCost = port.avgCost.get(ticker) || 0;
        const costBasis = avgCost * qty;
        const profitLoss = proceeds - costBasis;
        const plSign = profitLoss >= 0 ? '+' : '';
        const plEmoji = profitLoss >= 0 ? '📈' : '📉';

        port.holdings.set(ticker, ownedShares - qty);
        if (ownedShares - qty === 0) {
            port.avgCost.delete(ticker);
        }

        p.money += proceeds;
        logAction(p, `Sold ${qty} shares of ${ticker} for ${fmtMoney(proceeds)} (${plSign}${fmtMoney(profitLoss)})`);
        await p.save();
        await port.save();

        return conn.sendMessage(from, {
            text: `${plEmoji} *STOCK SOLD*\n\n*${qty} shares* of *${ticker}* (${stock.name})\nSale price per share: $${stock.price.toFixed(2)}\nTotal proceeds: ${fmtMoney(proceeds)}\n${plEmoji} P&L: ${plSign}${fmtMoney(profitLoss)}\n\n💰 New balance: ${fmtMoney(p.money)}`
        }, { quoted: mek });
    } catch (e) { console.error('sellstock error', e); }
});


cast({ pattern: 'cryptoboard', desc: 'cryptoboard [coin] — Top crypto holders', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const filterCoin = args[0] ? args[0].toUpperCase() : null;
        if (filterCoin && !global.market?.[filterCoin]) {
            return conn.sendMessage(from, { text: `❌ Unknown coin *${filterCoin}*. Use *crypto* to see available coins.` }, { quoted: mek });
        }

        const players = await Player.find({ isChildNpc: { $ne: true } })
            .select('username _id cryptoPortfolio').lean().exec();

        if (filterCoin) {
            // Show top holders of a specific coin
            const holders = players
                .map(p => {
                    const port = p.cryptoPortfolio instanceof Map ? Object.fromEntries(p.cryptoPortfolio) : (p.cryptoPortfolio || {});
                    const qty  = port[filterCoin] || 0;
                    return { name: p.username || p._id, qty, value: qty * (global.market[filterCoin] || 0) };
                })
                .filter(h => h.qty > 0)
                .sort((a, b) => b.qty - a.qty)
                .slice(0, 10);

            if (!holders.length) return conn.sendMessage(from, { text: `No one holds *${filterCoin}* yet.` }, { quoted: mek });

            function fmtQty(n) {
                if (n >= 1e12) return `${(n/1e12).toFixed(2)}T`;
                if (n >= 1e9)  return `${(n/1e9).toFixed(2)}B`;
                if (n >= 1e6)  return `${(n/1e6).toFixed(2)}M`;
                if (n >= 1000) return `${(n/1000).toFixed(2)}K`;
                return n.toFixed(4);
            }
            const medals = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
            const cap  = global.cryptoSupplyCaps?.[filterCoin];
            const sold = global.cryptoSupplySold?.[filterCoin] || 0;
            const lines = [
                `🪙 *TOP ${filterCoin} HOLDERS*`,
                cap ? `Supply: ${fmtQty(sold)} / ${fmtQty(cap)} sold` : ``,
                ``
            ];
            holders.forEach((h, i) => {
                lines.push(`${medals[i]} *${h.name}* — ${fmtQty(h.qty)} ${filterCoin} ≈ ${fmtMoney(Math.floor(h.value))}`);
            });
            return conn.sendMessage(from, { text: lines.filter(Boolean).join('\n') }, { quoted: mek });
        } else {
            // Show top holder per coin (richest in each)
            const coinMap = {};
            for (const p of players) {
                const port = p.cryptoPortfolio instanceof Map ? Object.fromEntries(p.cryptoPortfolio) : (p.cryptoPortfolio || {});
                for (const [coin, qty] of Object.entries(port)) {
                    if (!qty || qty <= 0 || !global.market?.[coin]) continue;
                    const val = qty * global.market[coin];
                    if (!coinMap[coin] || val > coinMap[coin].val) {
                        coinMap[coin] = { name: p.username || p._id, qty, val };
                    }
                }
            }
            const lines = [`🏆 *TOP CRYPTO HOLDERS (by coin)*`, ``];
            for (const coin of Object.keys(global.market)) {
                const h = coinMap[coin];
                if (h) lines.push(`🪙 *${coin}*: ${h.name} — ${h.qty.toFixed(4)} (≈ ${fmtMoney(Math.floor(h.val))})`);
            }
            lines.push(``, `Tip: *cryptoboard BTC* for top BTC holders`);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }
    } catch(e) { console.error('cryptoboard error', e); }
});

cast({ pattern: 'portfolio', desc: 'View your stock portfolio', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        const port = await StockPortfolio.findById(pId).exec();

        if (!port || port.holdings.size === 0) {
            return conn.sendMessage(from, { text: `📊 You don't own any stocks. Use 'stocks' to browse the market.` }, { quoted: mek });
        }

        let totalValue = 0;
        let totalCostBasis = 0;
        let txt = `📊 *${p.username || pId}'s STOCK PORTFOLIO*\n\n`;

        // Fetch all stocks in one query to avoid N+1
        const allStocks = await Stock.find({}).exec();
        const stockMap = {};
        for (const s of allStocks) stockMap[s.ticker] = s;

        for (const [ticker, shares] of port.holdings.entries()) {
            if (!shares || shares <= 0) continue;
            const stock = stockMap[ticker];
            if (!stock) continue; // stock removed from market, skip gracefully
            const value = stock.price * shares;
            const avgCost = port.avgCost.get(ticker) || 0;
            const cost = avgCost * shares;
            const pl = value - cost;
            const plSign = pl >= 0 ? '+' : '';
            const plEmoji = pl >= 0 ? '📈' : '📉';
            totalValue += value;
            totalCostBasis += cost;
            txt += `${plEmoji} *${ticker}* — ${stock.name}\n`;
            txt += `   📦 ${shares} shares @ $${stock.price.toFixed(2)} = ${fmtMoney(value)}\n`;
            txt += `   💵 Avg cost: $${avgCost.toFixed(2)} | P&L: ${plSign}${fmtMoney(pl)}\n\n`;
        }

        const totalPL = totalValue - totalCostBasis;
        const plSign = totalPL >= 0 ? '+' : '';
        txt += `─────────────────\n`;
        txt += `💼 Portfolio Value: ${fmtMoney(totalValue)}\n`;
        txt += `📊 Total P&L: ${plSign}${fmtMoney(totalPL)}\n`;
        txt += `💰 Cash on Hand: ${fmtMoney(p.money)}`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('portfolio error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMANDS: PLAYER SHOPS (market stalls)
