cast({ pattern: 'myshop', desc: 'Manage your player shop listings', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const listings = await PlayerShopListing.find({ sellerId: pId, active: true }).exec();

        if (!listings.length) {
            return conn.sendMessage(from, { text: `🏪 *Your Shop*\nYou have no active listings.\n\nList an item with: listitem <itemId> <qty> <priceEach>` }, { quoted: mek });
        }

        let txt = `🏪 *Your Active Listings*\n\n`;
        for (const l of listings) {
            txt += `• *${l.listingId}* | ${getItemName(l.itemId)} x${l.qty} @ ${fmtMoney(l.priceEach)} each\n`;
        }
        txt += `\n*Commands:*\nlistitem <itemId> <qty> <priceEach>\ncancellist <listingId>`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('myshop error', e); }
});

cast({ pattern: 'listitem', desc: 'List an item in the player market', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Action restricted. Hospitalized/Jailed.` }, { quoted: mek });

        if (!args || args.length < 3) return conn.sendMessage(from, { text: `Usage: listitem <itemId> <qty> <priceEach>\nExample: listitem medkit 5 200` }, { quoted: mek });

        const itemId = args[0].toLowerCase();
        const qty = parseInt(args[1]);
        const priceEach = parseInt(args[2]);

        if (isNaN(qty) || qty <= 0) return conn.sendMessage(from, { text: `Enter a valid quantity.` }, { quoted: mek });
        if (isNaN(priceEach) || priceEach <= 0) return conn.sendMessage(from, { text: `Enter a valid price per item.` }, { quoted: mek });

        const owned = p.inventory.get(itemId) || 0;
        if (owned < qty) return conn.sendMessage(from, { text: `❌ You don't have ${qty}x ${getItemName(itemId)}. (You have ${owned})` }, { quoted: mek });

        // Deduct from inventory (held in escrow)
        p.inventory.set(itemId, owned - qty);

        const listingId = `MKT-${Math.random().toString(36).substr(2, 6).toUpperCase()}`;
        const listing = new PlayerShopListing({
            listingId, sellerId: pId, itemId, qty, priceEach, active: true
        });

        logAction(p, `Listed ${qty}x ${getItemName(itemId)} on market @ ${fmtMoney(priceEach)} each`);
        await p.save();
        await listing.save();

        return conn.sendMessage(from, {
            text: `🏪 *LISTING CREATED!*\n\nID: *${listingId}*\nItem: ${getItemName(itemId)} x${qty}\nPrice: ${fmtMoney(priceEach)} each\nTotal value: ${fmtMoney(priceEach * qty)}\n\nOthers can buy it with: buyitem ${listingId}`
        }, { quoted: mek });
    } catch (e) { console.error('listitem error', e); }
});

cast({ pattern: 'market', desc: 'Browse the player market', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const filter = args && args[0] ? args[0].toLowerCase() : null;
        const query = { active: true };
        if (filter) query.itemId = filter;

        const listings = await PlayerShopListing.find(query).sort({ priceEach: 1 }).limit(15).exec();
        if (!listings.length) return conn.sendMessage(from, { text: `🏪 The market is empty right now.\nSell your items with: listitem <itemId> <qty> <price>` }, { quoted: mek });

        let txt = `🏪 *PLAYER MARKET*${filter ? ` — ${filter}` : ''}\n_Showing cheapest first_\n\n`;
        for (const l of listings) {
            txt += `• *${l.listingId}* | ${getItemName(l.itemId)} x${l.qty}\n`;
            txt += `  💰 ${fmtMoney(l.priceEach)} each | Total: ${fmtMoney(l.priceEach * l.qty)}\n`;
            txt += `  👤 Seller: @${l.sellerId}\n\n`;
        }
        txt += `*Buy with:* buyitem <listingId> [qty]\n*Filter:* market <itemId>`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('market error', e); }
});

cast({ pattern: 'buyitem', desc: 'Buy from the player market', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Action restricted. Hospitalized/Jailed.` }, { quoted: mek });
        if (!args || !args[0]) return conn.sendMessage(from, { text: `Usage: buyitem <listingId> [qty]\nExample: buyitem MKT-AB12 3` }, { quoted: mek });

        const listingId = args[0].toUpperCase();
        const listing = await PlayerShopListing.findOne({ listingId, active: true }).exec();
        if (!listing) return conn.sendMessage(from, { text: `❌ Listing not found or already sold.` }, { quoted: mek });

        if (listing.sellerId === pId) return conn.sendMessage(from, { text: `You can't buy your own listing!` }, { quoted: mek });

        const requestedQty = args[1] ? parseInt(args[1]) : listing.qty;
        if (isNaN(requestedQty) || requestedQty <= 0) return conn.sendMessage(from, { text: `Enter a valid quantity.` }, { quoted: mek });
        if (requestedQty > listing.qty) return conn.sendMessage(from, { text: `Only ${listing.qty} available in this listing.` }, { quoted: mek });

        const totalCost = listing.priceEach * requestedQty;
        if (p.money < totalCost) return conn.sendMessage(from, { text: `💸 Not enough cash. Costs ${fmtMoney(totalCost)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });

        // Transfer money
        p.money -= totalCost;
        p.moneySpent += totalCost;

        // Give item to buyer
        p.inventory.set(listing.itemId, (p.inventory.get(listing.itemId) || 0) + requestedQty);

        // Pay seller
        const seller = await Player.findById(listing.sellerId).exec();
        if (seller) {
            seller.money += totalCost;
            logAction(seller, `Sold ${requestedQty}x ${getItemName(listing.itemId)} on market for ${fmtMoney(totalCost)}`);
            await seller.save();
        }

        // Update listing
        listing.qty -= requestedQty;
        if (listing.qty <= 0) listing.active = false;
        await listing.save();

        logAction(p, `Bought ${requestedQty}x ${getItemName(listing.itemId)} from market for ${fmtMoney(totalCost)}`);
        await p.save();

        return conn.sendMessage(from, {
            text: `✅ *PURCHASE COMPLETE!*\n\nYou bought *${requestedQty}x ${getItemName(listing.itemId)}* for ${fmtMoney(totalCost)}.\nItem added to your inventory.`
        }, { quoted: mek });
    } catch (e) { console.error('buyitem error', e); }
});

cast({ pattern: 'cancellist', desc: 'Cancel a market listing and reclaim your item', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (!args || !args[0]) return conn.sendMessage(from, { text: `Usage: cancellist <listingId>` }, { quoted: mek });

        const listingId = args[0].toUpperCase();
        const listing = await PlayerShopListing.findOne({ listingId, sellerId: pId, active: true }).exec();
        if (!listing) return conn.sendMessage(from, { text: `❌ Listing not found or doesn't belong to you.` }, { quoted: mek });

        // Return items from escrow
        p.inventory.set(listing.itemId, (p.inventory.get(listing.itemId) || 0) + listing.qty);
        listing.active = false;
        await listing.save();
        await p.save();

        return conn.sendMessage(from, { text: `✅ Listing *${listingId}* cancelled. *${listing.qty}x ${getItemName(listing.itemId)}* returned to your inventory.` }, { quoted: mek });
    } catch (e) { console.error('cancellist error', e); }
});

// =============================================================================
// ==================== V11 EXPANSION: TAX SYSTEM & SCRATCH CARDS =============
// =============================================================================

// ─────────────────────────────────────────────────────────────────────────────
// TAX BRACKETS (progressive — the richer you are, the harder the IRS hits)
// These apply to INCOME per cycle, not total wealth (wealth tax is separate)
// ─────────────────────────────────────────────────────────────────────────────
const TAX_BRACKETS = [
    { min: 0,              max: 5000,         rate: 0.05,  label: '5%  — Street Hustler'          },
    { min: 5000,           max: 20000,        rate: 0.12,  label: '12% — Low Income'              },
    { min: 20000,          max: 75000,        rate: 0.22,  label: '22% — Working Class'           },
    { min: 75000,          max: 250000,       rate: 0.32,  label: '32% — Middle Income'           },
    { min: 250000,         max: 1000000,      rate: 0.45,  label: '45% — High Earner'             },
    { min: 1000000,        max: 10000000,     rate: 0.60,  label: '60% — Elite'                   },
    { min: 10000000,       max: 100000000,    rate: 0.72,  label: '72% — Mogul'                   },
    { min: 100000000,      max: 1000000000,   rate: 0.82,  label: '82% — Oligarch'                },
    { min: 1000000000,     max: Infinity,     rate: 0.92,  label: '92% — Weirdos World Overlord'  },
];

const TAX_CYCLE_MS = 45 * 60 * 1000; // Tax assessed every 45 minutes

function calcTax(taxableIncome) {
    // President perk: -2% off all tax brackets when active
    const presDiscount = (global.wwPresident && global.wwPresident.termEndsAt > Date.now()) ? 0.02 : 0;
    let tax = 0;
    for (const bracket of TAX_BRACKETS) {
        if (taxableIncome <= bracket.min) break;
        const taxable = Math.min(taxableIncome, bracket.max) - bracket.min;
        tax += taxable * bracket.rate;
    }
    return Math.floor(tax);
}

function getTaxBracket(income) {
    for (let i = TAX_BRACKETS.length - 1; i >= 0; i--) {
        if (income >= TAX_BRACKETS[i].min) return TAX_BRACKETS[i];
    }
    return TAX_BRACKETS[0];
}

// ─────────────────────────────────────────────────────────────────────────────
// HELPER: Record taxable income (called whenever player earns money)
// Patch this into existing income sources via a wrapper
// ─────────────────────────────────────────────────────────────────────────────
function addTaxableIncome(player, amount) {
    if (!amount || amount <= 0) return;
    if (!global.weirdo_tax_enabled) return; // tax off
    player.taxableIncome = (player.taxableIncome || 0) + amount;
}

// ─────────────────────────────────────────────────────────────────────────────
// IRS AUDIT INTERVAL — runs every 6 hours, assesses tax on all players
// ─────────────────────────────────────────────────────────────────────────────
setInterval(async () => {
    try {
        if (mongoose.connection.readyState !== 1) return;
        if (!global.weirdo_tax_enabled) return; // tax system disabled
        const now_ts = Date.now();
        const players = await Player.find({ taxableIncome: { $gt: 0 } }).exec();

        for (const p of players) {
            const sinceLastCycle = now_ts - (p.lastTaxCycle || now_ts);
            if (sinceLastCycle < TAX_CYCLE_MS) continue;

            const owed = calcTax(p.taxableIncome || 0);
            if (owed > 0) {
                p.taxOwed = (p.taxOwed || 0) + owed;
                logAction(p, `🏛️ IRS assessed ${fmtMoney(owed)} tax on ${fmtMoney(p.taxableIncome)} income`);
            }
            p.taxableIncome = 0;
            p.lastTaxCycle = now_ts;
            await p.save();
        }

        // IRS RAID: Players with taxOwed > 500k and overdue 1.5 cycles get auto-raided
        const delinquent = await Player.find({ taxOwed: { $gt: 500000 } }).exec();
        for (const p of delinquent) {
            const overdue = now_ts - (p.lastTaxCycle || now_ts);
            if (overdue > 1.5 * TAX_CYCLE_MS && !p.underAudit) {
                p.underAudit = true;
                p.auditExpiresAt = now_ts + (30 * 60 * 1000);
                p.taxEvasionStrikes = (p.taxEvasionStrikes || 0) + 1;
                logAction(p, `🚨 IRS Auto-Raid triggered!`);

                // Seize 30% of total owed: wallet first, then bank, then properties
                let toSeize = Math.floor(p.taxOwed * 0.30);
                let seized  = 0;

                // 1 — wallet
                const wTake = Math.min(Math.max(0, p.money || 0), toSeize);
                p.money    = Math.max(0, (p.money || 0) - wTake);
                toSeize   -= wTake; seized += wTake;

                // 2 — bank
                const bankBal = p.bank || 0;
                const bTake   = Math.min(bankBal, toSeize);
                p.bank        = Math.max(0, bankBal - bTake);
                toSeize      -= bTake; seized += bTake;

                // 3 — properties (forced sale at 50%)
                if (toSeize > 0) {
                    const propEntries = p.properties instanceof Map
                        ? [...p.properties.entries()]
                        : Object.entries(p.properties || {});
                    for (const [propId, qty] of propEntries) {
                        if (toSeize <= 0 || !qty || qty <= 0) continue;
                        const shopItem = DEFAULT_SHOP.find(s => s.id === propId);
                        if (!shopItem) continue;
                        const qtyToSell  = Math.min(qty, Math.ceil(toSeize / (shopItem.price * 0.50)));
                        const propSeized = Math.floor(shopItem.price * qtyToSell * 0.50);
                        const newQty     = qty - qtyToSell;
                        if (p.properties instanceof Map) p.properties.set(propId, newQty);
                        else p.properties[propId] = newQty;
                        toSeize -= propSeized; seized += propSeized;
                    }
                    p.markModified('properties');
                }

                p.taxOwed = Math.max(0, p.taxOwed - seized);
                p.taxPaid = (p.taxPaid || 0) + seized;
                logAction(p, `🏛️ IRS auto-seized ${fmtMoney(seized)} (wallet+bank+properties)`);
                await p.save();
            }
        }
    } catch (e) { console.error('IRS interval error:', e); }
}, 15 * 60 * 1000); // IRS ticks every 15 minutes

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: taxinfo — View your tax situation
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'taxinfo', desc: 'View your IRS tax status', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        const bracket = getTaxBracket(p.taxableIncome || 0);
        const projectedTax = calcTax(p.taxableIncome || 0);
        const auditStatus = p.underAudit && p.auditExpiresAt > Date.now()
            ? `🚨 *UNDER AUDIT* — expires in ${shortTime(p.auditExpiresAt - Date.now())}`
            : '✅ Clear';

        const txt = [
            `🏛️ *IRS TAX RECORD — ${p.username || pId}*`,
            ``,
            `📊 Current Tax Bracket: ${bracket.label}`,
            `💼 Taxable Income (this cycle): ${fmtMoney(p.taxableIncome || 0)}`,
            `📋 Projected Tax Bill: ${fmtMoney(projectedTax)}`,
            ``,
            `💸 Tax Currently Owed: *${fmtMoney(p.taxOwed || 0)}*`,
            `✅ Lifetime Tax Paid: ${fmtMoney(p.taxPaid || 0)}`,
            `🕵️ Lifetime Tax Evaded: ${fmtMoney(p.taxEvaded || 0)}`,
            `⚠️ Evasion Strikes: ${p.taxEvasionStrikes || 0}/3 (3 = IRS Raid)`,
            ``,
            `🔎 Audit Status: ${auditStatus}`,
            ``,
            `*Commands:*`,
            `paytax <amount|all> — Pay your tax bill`,
            `evadetax — Attempt to hide income (risky)`,
            `taxrates — View all tax brackets`,
        ].join('\n');

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('taxinfo error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: taxrates — Display tax bracket table
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'taxrates', desc: 'View all tax brackets', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    let txt = `🏛️ *TORN CITY INTERNAL REVENUE SERVICE*\n_Progressive Income Tax Brackets_\n\n`;
    for (const b of TAX_BRACKETS) {
        const range = b.max === Infinity
            ? `$${b.min.toLocaleString()}+`
            : `$${b.min.toLocaleString()} – $${b.max.toLocaleString()}`;
        txt += `• ${b.label}\n  Income Range: ${range}\n\n`;
    }
    txt += `_Tax is assessed every 45 minutes on your earned income._\n`;
    txt += `_Failing to pay leads to audits, asset seizure, and jail time._\n\n`;
    txt += `*Pay your taxes:* paytax <amount|all>`;
    return conn.sendMessage(from, { text: txt }, { quoted: mek });
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: paytax — Pay your tax bill
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'paytax', desc: 'Pay your tax bill', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Serve your time first.` }, { quoted: mek });

        if ((p.taxOwed || 0) <= 0) {
            return conn.sendMessage(from, { text: `🏛️ You're all clear with the IRS! No taxes owed.\n\n_Taxable income this cycle: ${fmtMoney(p.taxableIncome || 0)}_` }, { quoted: mek });
        }

        const input = args && args[0] ? args[0].toLowerCase() : null;
        if (!input) return conn.sendMessage(from, { text: `Usage: paytax <amount|all>\nYou currently owe: ${fmtMoney(p.taxOwed)}` }, { quoted: mek });

        let amount = input === 'all' ? p.taxOwed : parseInt(input);
        if (isNaN(amount) || amount <= 0) return conn.sendMessage(from, { text: `Enter a valid amount.` }, { quoted: mek });
        amount = Math.min(amount, p.taxOwed);

        const totalAvailable = (p.money || 0) + (p.bank || 0);
        if (totalAvailable < amount) return conn.sendMessage(from, { text: `💸 Not enough total funds. You need ${fmtMoney(amount)} but have ${fmtMoney(p.money)} in wallet + ${fmtMoney(p.bank || 0)} in bank = ${fmtMoney(totalAvailable)}.` }, { quoted: mek });

        // Drain wallet first, then bank for the remainder
        const fromWallet = Math.min(p.money || 0, amount);
        p.money          = Math.max(0, (p.money || 0) - fromWallet);
        const fromBank   = Math.min(p.bank || 0, amount - fromWallet);
        p.bank           = Math.max(0, (p.bank || 0) - fromBank);
        p.taxOwed       -= amount;
        p.taxPaid        = (p.taxPaid || 0) + amount;
        const paidNote   = fromBank > 0 ? ` (${fmtMoney(fromWallet)} from wallet + ${fmtMoney(fromBank)} from bank)` : ``;

        // Paying in full clears audit status
        if (p.taxOwed <= 0) {
            p.taxOwed = 0;
            p.underAudit = false;
            p.auditExpiresAt = 0;
            if (p.taxEvasionStrikes > 0) p.taxEvasionStrikes = Math.max(0, p.taxEvasionStrikes - 1);
        }

        const titleMsg = checkTitles(p);
        logAction(p, `Paid ${fmtMoney(amount)} in taxes to the IRS${paidNote}`);
        await p.save();

        const remaining = p.taxOwed > 0 ? `\n⚠️ Remaining balance: ${fmtMoney(p.taxOwed)}` : `\n✅ Your account is now fully settled with the IRS!`;
        return conn.sendMessage(from, {
            text: `🏛️ *TAX PAYMENT RECEIVED*\n\nAmount Paid: ${fmtMoney(amount)}\n💰 Remaining Balance: ${fmtMoney(p.money)}${remaining}${titleMsg}`
        }, { quoted: mek });
    } catch (e) { console.error('paytax error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: evadetax — Attempt to hide your income from the IRS
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'evadetax', desc: 'Attempt to evade your taxes (risky)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 You can't evade taxes from a hospital bed.` }, { quoted: mek });

        if ((p.taxOwed || 0) <= 0 && (p.taxableIncome || 0) <= 0) {
            return conn.sendMessage(from, { text: `🏛️ Nothing to evade — you have no outstanding tax.` }, { quoted: mek });
        }

        if (p.underAudit && p.auditExpiresAt > Date.now()) {
            return conn.sendMessage(from, { text: `🚨 The IRS has eyes on you! You're under audit — you CANNOT evade right now.` }, { quoted: mek });
        }

        // Base success chance — dexterity helps, strikes against you
        const baseChance = 0.45;
        const dexBonus = Math.min(0.20, (p.dexterity || 0) * 0.008);
        const strikesPenalty = (p.taxEvasionStrikes || 0) * 0.10;
        const successChance = Math.max(0.05, baseChance + dexBonus - strikesPenalty);

        const targetAmount = p.taxOwed > 0 ? p.taxOwed : calcTax(p.taxableIncome || 0);

        if (Math.random() < successChance) {
            // SUCCESS — income wiped, tax avoided
            const evaded = targetAmount;
            if (p.taxOwed > 0) {
                p.taxEvaded = (p.taxEvaded || 0) + p.taxOwed;
                p.taxOwed = 0;
            } else {
                p.taxEvaded = (p.taxEvaded || 0) + evaded;
                p.taxableIncome = 0; // scrubbed the records
            }

            logAction(p, `Successfully evaded ${fmtMoney(evaded)} in taxes 🕵️`);
            await p.save();
            return conn.sendMessage(from, {
                text: `🕵️ *TAX EVASION — SUCCESS*\n\nYour offshore accounts and shell companies absorbed the trail.\n💨 ${fmtMoney(evaded)} in taxes quietly... disappeared.\n\n⚠️ *Warning:* The IRS has long memories. Each successful evasion raises your audit risk permanently.\n📊 Evasion Strikes: ${p.taxEvasionStrikes}/3`
            }, { quoted: mek });
        } else {
            // CAUGHT
            p.taxEvasionStrikes = (p.taxEvasionStrikes || 0) + 1;
            p.underAudit = true;
            p.auditExpiresAt = Date.now() + (30 * 60 * 1000); // 30 min audit

            let consequence = '';

            if (p.taxEvasionStrikes >= 3) {
                // THIRD STRIKE — full raid, jail, and asset seizure from wallet + bank
                const totalHeld  = (p.money || 0) + (p.bank || 0);
                const seized     = Math.floor(totalHeld * 0.50);
                const extraTax   = Math.floor(targetAmount * 0.50);
                const wSeize     = Math.min(p.money || 0, seized);
                const bSeize     = Math.min(p.bank || 0, seized - wSeize);
                p.money          = Math.max(0, (p.money || 0) - wSeize);
                p.bank           = Math.max(0, (p.bank  || 0) - bSeize);
                p.taxOwed        = Math.max(0, (p.taxOwed || 0) - seized) + targetAmount + extraTax;
                p.jailedUntil    = Date.now() + (30 * 60 * 1000);
                p.health         = Math.max(1, p.health - 40);
                p.taxEvasionStrikes = 0;
                consequence = `\n\n🚨 *THIRD STRIKE — IRS FULL RAID!*\n💸 Assets Seized: ${fmtMoney(seized)} (wallet + bank)\n📋 Remaining Tax + 50% Penalty: ${fmtMoney(p.taxOwed)}\n🚔 Jailed for 30 minutes\n💔 -40 HP from the arrest struggle`;
            } else if (p.taxEvasionStrikes === 2) {
                // Second strike — 25% penalty on owed
                const penalty = Math.floor(targetAmount * 0.25);
                p.taxOwed = (p.taxOwed || 0) + targetAmount + penalty;
                consequence = `\n\n⚠️ *SECOND STRIKE!*\n📋 Original tax + 25% penalty added: ${fmtMoney(targetAmount + penalty)}\n🔎 Under IRS audit for 12 hours\n🪝 One more strike = Full Asset Raid`;
            } else {
                // First strike — tax doubled
                p.taxOwed = (p.taxOwed || 0) + targetAmount;
                consequence = `\n\n⚠️ *FIRST STRIKE!*\n📋 Tax bill doubled: ${fmtMoney(targetAmount)}\n🔎 Under IRS audit for 12 hours`;
            }

            logAction(p, `Caught evading taxes! Strike ${p.taxEvasionStrikes}. Owed: ${fmtMoney(p.taxOwed)}`);
            await p.save();
            return conn.sendMessage(from, {
                text: `🚨 *TAX EVASION — CAUGHT!*\n\nAn IRS agent flagged your account during a routine sweep.\n🔍 Audit Strike: ${p.taxEvasionStrikes}/3${consequence}\n\n_Pay with:_ paytax all`
            }, { quoted: mek });
        }
    } catch (e) { console.error('evadetax error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: irsaudit — Creator-only: manually audit a player
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'irsaudit', desc: 'Creator: Force IRS audit on a player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: '❌ Access Denied. Creator command only.' }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId) return conn.sendMessage(from, { text: 'Tag a player to audit.' }, { quoted: mek });

        const t = await getOrCreatePlayer(targetId);

        const assessed  = calcTax(t.taxableIncome || 0);
        const totalOwed = assessed + (t.taxOwed || 0);
        if (totalOwed <= 0) return conn.sendMessage(from, { text: `@${targetId} owes no tax.`, mentions:[toJid(targetId)] }, { quoted: mek });

        let toCollect = totalOwed;
        let seized    = 0;
        const breakdown = [];

        // 1 — Drain wallet
        const fromWallet = Math.min(Math.max(0, t.money || 0), toCollect);
        if (fromWallet > 0) {
            t.money    = Math.max(MIN_WALLET, (t.money || 0) - fromWallet);
            toCollect -= fromWallet;
            seized    += fromWallet;
            breakdown.push(`💵 Wallet: −${fmtMoney(fromWallet)}`);
        }

        // 2 — Drain bank
        const bankBal    = t.bank || 0;
        const fromBank   = Math.min(bankBal, toCollect);
        if (fromBank > 0) {
            t.bank    = Math.max(0, bankBal - fromBank);
            toCollect -= fromBank;
            seized    += fromBank;
            breakdown.push(`🏦 Bank: −${fmtMoney(fromBank)}`);
        }

        // 3 — Liquidate properties (50% of market value — forced sale)
        if (toCollect > 0) {
            const propEntries = t.properties instanceof Map
                ? [...t.properties.entries()]
                : Object.entries(t.properties || {});

            for (const [propId, qty] of propEntries) {
                if (toCollect <= 0 || !qty || qty <= 0) continue;
                const shopItem = DEFAULT_SHOP.find(s => s.id === propId);
                if (!shopItem) continue;
                const saleValue = Math.floor(shopItem.price * qty * 0.50); // forced sale 50%
                if (saleValue <= 0) continue;
                const take = Math.min(saleValue, toCollect);
                // Remove proportional qty
                const qtyToSell = Math.ceil(take / (shopItem.price * 0.50));
                const actualQtySold = Math.min(qty, qtyToSell);
                const actualTake    = Math.floor(shopItem.price * actualQtySold * 0.50);
                const newQty        = qty - actualQtySold;
                if (t.properties instanceof Map) t.properties.set(propId, newQty);
                else t.properties[propId] = newQty;
                toCollect -= actualTake;
                seized    += actualTake;
                breakdown.push(`🏠 ${shopItem.name} ×${actualQtySold} (forced sale): −${fmtMoney(actualTake)}`);
            }
            t.markModified('properties');
        }

        const remaining = Math.max(0, toCollect);
        t.taxOwed       = remaining;
        t.taxableIncome = 0;
        t.taxPaid       = (t.taxPaid || 0) + seized;
        t.underAudit    = true;
        t.auditExpiresAt = Date.now() + (60 * 60 * 1000);
        t.taxEvasionStrikes = Math.min(3, (t.taxEvasionStrikes || 0) + 1);

        if (remaining > 100_000) {
            t.jailedUntil = Date.now() + (60 * 60 * 1000);
            t.inJail      = true;
            t.jailWorkDone = 0; t.lawyerCallUsed = false;
            t.sentencedAt = Date.now(); t.sentenceMs = 60*60*1000;
        }

        logAction(t, `🚨 IRS Audit — seized ${fmtMoney(seized)}, remaining ${fmtMoney(remaining)}`);
        logGlobal('🏛️', `*${t.username || targetId}* was hit by an IRS audit! 💸 ${fmtMoney(seized)} seized.`);
        await t.save();

        return conn.sendMessage(from, {
            text: [
                `👑 *IRS AUDIT — @${targetId}*`, ``,
                `📋 Tax assessed: ${fmtMoney(assessed)}`,
                `💸 Total owed: ${fmtMoney(totalOwed)}`,
                ``, `*Seized:*`,
                ...breakdown,
                ``, `✅ Total seized: *${fmtMoney(seized)}*`,
                remaining > 0 ? `⚠️ Remaining debt: *${fmtMoney(remaining)}*` : `✅ Debt fully cleared`,
                remaining > 100_000 ? `⛓️ Jailed 1 hour (remaining debt > $100k)` : ``,
                `🔴 Strike ${t.taxEvasionStrikes}/3`,
            ].filter(s => s !== '').join('\n'),
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch (e) { console.error('irsaudit error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: taxleader — Top taxpayers (bragging rights)
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'taxleader', desc: 'Top taxpayers leaderboard', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const players = await Player.find({ taxPaid: { $gt: 0 }, isChildNpc: { $ne: true } }).sort({ taxPaid: -1 }).limit(10).exec();
        if (!players.length) return conn.sendMessage(from, { text: `🏛️ No taxpayers yet. Use paytax to contribute!` }, { quoted: mek });

        let txt = `🏛️ *IRS HALL OF HONOUR*\n_Top Lifetime Taxpayers_\n\n`;
        const taxMentions = [];
        players.forEach((p, i) => {
            const name = p.username || '(no name)';
            taxMentions.push(toJid(p._id));
            txt += `${i + 1}. *${name}* @${p._id} — Paid: ${fmtMoney(p.taxPaid || 0)}\n`;
        });
        txt += `\n_Paying taxes increases your civic title and unlocks perks._`;

        return conn.sendMessage(from, { text: txt, mentions: taxMentions }, { quoted: mek });
    } catch (e) { console.error('taxleader error', e); }
});

// =============================================================================
// ====================== SCRATCH CARD SYSTEM ==================================
// =============================================================================

// ─────────────────────────────────────────────────────────────────────────────
// SCRATCH CARD PRIZES (weighted)
// ─────────────────────────────────────────────────────────────────────────────
const SCRATCH_PRIZES = [
    // weight, label, type, value
    // Card cost: $10,000 | House edge: ~50% | Jackpot is rare
    { weight: 45,   emoji: '💨', label: 'Nothing',              type: 'cash',    value: 0 },
    { weight: 22,   emoji: '🪙', label: '$1,500 cash',          type: 'cash',    value: 1500 },
    { weight: 13,   emoji: '💵', label: '$4,000 cash',          type: 'cash',    value: 4000 },
    { weight: 8,    emoji: '💵', label: '$8,000 cash',          type: 'cash',    value: 8000 },
    { weight: 5,    emoji: '💰', label: '$18,000 cash',         type: 'cash',    value: 18000 },
    { weight: 3,    emoji: '💰', label: '$40,000 cash',         type: 'cash',    value: 40000 },
    { weight: 2,    emoji: '⚡', label: 'Full Energy Restore',  type: 'energy',  value: 999 },
    { weight: 1.5,  emoji: '❤️',  label: 'Full Health Restore',  type: 'health',  value: 999 },
    { weight: 0.3,  emoji: '🏆', label: '$200,000 BIG WIN',     type: 'cash',    value: 200000 },
    { weight: 0.15, emoji: '🎒', label: 'Free Medkit',          type: 'item',    value: 'medkit' },
    { weight: 0.05, emoji: '🌟', label: '🎰 JACKPOT — $1,500,000!!!', type: 'jackpot', value: 1500000 },
];

const SCRATCH_TOTAL_WEIGHT = SCRATCH_PRIZES.reduce((s, p) => s + p.weight, 0);

function rollScratchPrize() {
    let roll = Math.random() * SCRATCH_TOTAL_WEIGHT;
    for (const prize of SCRATCH_PRIZES) {
        roll -= prize.weight;
        if (roll <= 0) return prize;
    }
    return SCRATCH_PRIZES[0];
}

const SCRATCH_CARD_COST    = 10000;     // base $10k per card — iC() applied at usage
const SCRATCH_COOLDOWN_MS  = 30 * 60 * 1000; // 30 minutes between scratches (was 10)
const SCRATCH_DAILY_MAX    = 5;              // max 5 cards per day (bulk still limited)

// Animated scratch symbols
const SCRATCH_SYMBOLS = ['🍒', '💎', '7️⃣', '🍋', '⭐', '🔔', '🃏', '💰', '🎰', '🃏', '👑'];
function randSym() { return SCRATCH_SYMBOLS[Math.floor(Math.random() * SCRATCH_SYMBOLS.length)]; }

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: scratch — Buy and scratch a card
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'scratch', desc: 'Buy a scratch card', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Can't scratch cards from jail. Pay your dues first.` }, { quoted: mek });

        // Parse optional quantity (max 5 per day total)
        const qty = Math.min(5, Math.max(1, parseInt(args && args[0]) || 1));

        // Daily cap check
        const todayKey = `scratch_${new Date().toISOString().split('T')[0]}`;
        const usedToday = p.cooldowns?.[todayKey] || 0;
        if (usedToday >= SCRATCH_DAILY_MAX) {
            return conn.sendMessage(from, { text: `🎟️ Daily limit reached — you've scratched *${SCRATCH_DAILY_MAX}* cards today.\nCome back tomorrow for more.` }, { quoted: mek });
        }
        const allowed = Math.min(qty, SCRATCH_DAILY_MAX - usedToday);

        const totalCost = iC(SCRATCH_CARD_COST) * allowed;

        // Cooldown
        const elapsed = Date.now() - (p.lastScratch || 0);
        if (elapsed < SCRATCH_COOLDOWN_MS) {
            return conn.sendMessage(from, { text: `🎟️ Wait ${shortTime(SCRATCH_COOLDOWN_MS - elapsed)} before your next scratch.\n_Cost: ${fmtMoney(iC(SCRATCH_CARD_COST))} per card | Max ${SCRATCH_DAILY_MAX}/day_` }, { quoted: mek });
        }

        if (p.money < totalCost) return conn.sendMessage(from, { text: `💸 Each card costs ${fmtMoney(iC(SCRATCH_CARD_COST))}. ${qty} cards = ${fmtMoney(totalCost)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });

        p.money -= totalCost;
        p.moneySpent += totalCost;
        p.lastScratch = Date.now();
        p.scratchCardsUsed = (p.scratchCardsUsed || 0) + allowed;
        if (!p.cooldowns) p.cooldowns = {};
        p.cooldowns[todayKey] = usedToday + allowed;
        p.markModified('cooldowns');

        // Feed 10% of card cost to casino jackpot
        global.casinoJackpot = (global.casinoJackpot || 0) + Math.floor(totalCost * 0.10);

        let totalWon = 0;
        let resultLines = [];
        let bigWin = false;

        for (let i = 0; i < allowed; i++) {
            const prize = rollScratchPrize();
            const grid = `${randSym()} ${randSym()} ${randSym()}`;

            let wonLine = '';
            if (prize.type === 'jackpot') {
                const jackpotBonus = Math.floor((global.casinoJackpot || 0) * 0.25);
                const jackpotWin = prize.value + jackpotBonus;
                p.money += jackpotWin;
                addTaxableIncome(p, jackpotWin);
                global.casinoJackpot = Math.floor((global.casinoJackpot || 0) * 0.75);
                totalWon += jackpotWin;
                wonLine = `🌟 *JACKPOT!!!* → +${fmtMoney(jackpotWin)} (incl. ${fmtMoney(jackpotBonus)} from Casino Jackpot!)`;
                bigWin = true;
            } else if (prize.type === 'cash') {
                if (prize.value > 0) {
                    p.money += prize.value;
                    addTaxableIncome(p, prize.value);
                    totalWon += prize.value;
                    wonLine = `${prize.emoji} *${prize.label}* → +${fmtMoney(prize.value)}`;
                    if (prize.value >= 100000) bigWin = true;
                } else {
                    wonLine = `${prize.emoji} *${prize.label}*`;
                }
            } else if (prize.type === 'energy') {
                p.energy = Math.min(p.maxEnergy, p.energy + 999);
                wonLine = `${prize.emoji} *${prize.label}* → Energy fully restored!`;
            } else if (prize.type === 'health') {
                p.health = Math.min(p.maxHealth, p.health + 999);
                wonLine = `${prize.emoji} *${prize.label}* → Health fully restored!`;
            } else if (prize.type === 'item') {
                p.inventory.set(prize.value, (p.inventory.get(prize.value) || 0) + 1);
                wonLine = `${prize.emoji} *${prize.label}* → Added to inventory!`;
            }

            if (qty === 1) {
                resultLines.push(`🎟️ *Card ${i + 1}:*  [ ${grid} ]\n   ${wonLine}`);
            } else {
                resultLines.push(`Card ${i + 1}: ${wonLine}`);
            }
        }

        const titleMsg = checkTitles(p);
        logAction(p, `Scratched ${allowed} card(s). Won ${fmtMoney(totalWon)}`);
        if (totalWon > 0) { p.totalEarned = (p.totalEarned||0) + totalWon; addTaxableIncome(p, totalWon); }
        await p.save();

        let header = allowed === 1
            ? `🎟️ *SCRATCH CARD*\n_Cost: ${fmtMoney(totalCost)} | ${SCRATCH_DAILY_MAX - usedToday - allowed} cards left today_\n\n`
            : `🎟️ *SCRATCH CARDS x${allowed}*\n_Cost: ${fmtMoney(totalCost)} | ${SCRATCH_DAILY_MAX - usedToday - allowed} left today_\n\n`;

        let footer = `\n─────────────────\n`;
        footer += totalWon > 0
            ? `💰 *Total Won: ${fmtMoney(totalWon)}*`
            : `😔 *Better luck next time!*`;
        footer += bigWin ? `\n🎉 *BIG WIN! The IRS is watching...*` : '';
        footer += `\n💳 Balance: ${fmtMoney(p.money)}`;
        footer += titleMsg;

        return conn.sendMessage(from, { text: header + resultLines.join('\n') + footer }, { quoted: mek });
    } catch (e) { console.error('scratch error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: scratchodds — Show prize table + odds
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'scratchodds', desc: 'View scratch card prize table', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    let txt = `🎟️ *SCRATCH CARD PRIZE TABLE*\n_Each card costs ${fmtMoney(iC(SCRATCH_CARD_COST))}_\n\n`;
    for (const p of SCRATCH_PRIZES) {
        const odds = ((p.weight / SCRATCH_TOTAL_WEIGHT) * 100).toFixed(2);
        txt += `${p.emoji} ${p.label.padEnd(28)} ${odds}%\n`;
    }
    txt += `\n💡 *Tips:*\n`;
    txt += `• Buy up to 10 cards at once: scratch 5\n`;
    txt += `• 10% of card cost feeds the Casino Jackpot\n`;
    txt += `• Big wins are taxable income — check taxinfo\n`;
    txt += `• Jackpot prize also grabs 25% of the Casino Jackpot pool`;
    return conn.sendMessage(from, { text: txt }, { quoted: mek });
});

// ─────────────────────────────────────────────────────────────────────────────
// PATCH: wrap existing income-generating commands to track taxable income
// This runs at load time and patches the addTaxableIncome helper into the
// money-earning flow via a lightweight post-save hook on the Player model.
// Rather than rewriting every command, we track via a Mongoose post-save
// middleware that compares money delta — simpler and non-breaking.
// ─────────────────────────────────────────────────────────────────────────────
// NOTE TO DEVELOPER: For accurate taxable income tracking, call
//   addTaxableIncome(p, earnedAmount)
// in any command where the player earns money (crimes, work, heists, etc.)
// The IRS interval will assess tax on p.taxableIncome each 24h cycle.
// The most impactful places to add this are: crime success, work success,
// heist success, daily reward, and bank rob success.


// =============================================================================
// ==================== V12: MISSING CREATOR COMMANDS =========================
// =============================================================================

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: giveplayer — Creator sends any amount to any player (no limit)
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'giveplayer', desc: 'Creator: Give cash to any player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: '❌ Access Denied. Creator command only.' }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        const amount = parseInt(args[1]);

        if (!targetId) return conn.sendMessage(from, { text: 'Usage: giveplayer @player <amount>' }, { quoted: mek });
        if (isNaN(amount) || amount <= 0) return conn.sendMessage(from, { text: 'Enter a valid amount.' }, { quoted: mek });

        const t = await getOrCreatePlayer(targetId);
        t.money += amount;
        logAction(t, `👑 Creator gifted ${fmtMoney(amount)}`);
        await t.save();

        return conn.sendMessage(from, {
            text: `👑 *GOD MODE TRANSFER*\n\n${fmtMoney(amount)} has been wired to *@${targetId}*.\nTheir new balance: ${fmtMoney(t.money)}`,
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch (e) { console.error('giveplayer error', e); }
});

