// ─────────────────────────────────────────────────────────────────────────────
// SCHEMAS: Matches, Bets, League Standings
// ─────────────────────────────────────────────────────────────────────────────
const FootballMatchSchema = new mongoose.Schema({
    matchId:    { type: String, required: true, unique: true },
    leagueId:   { type: String, required: true },
    homeTeam:   { type: String, required: true },
    awayTeam:   { type: String, required: true },
    homeGoals:  { type: Number, default: null },
    awayGoals:  { type: Number, default: null },
    odds:       { type: String, default: null }, // JSON string
    status:     { type: String, default: 'upcoming' }, // upcoming | live | finished
    kickoff:    { type: Number, required: true },
    finishedAt: { type: Number, default: 0 },
    matchday:   { type: Number, default: 1 },
    season:     { type: String, default: '2024/25' }
});

const FootballBetSchema = new mongoose.Schema({
    betId:        { type: String, required: true, unique: true },
    playerId:     { type: String, required: true },
    stake:        { type: Number, required: true },
    type:         { type: String, default: 'single' }, // single | acca
    selections:   { type: Array,  default: [] },
    // Each selection: { matchId, market, selection, odds, result: null|'won'|'lost' }
    totalOdds:    { type: Number, default: 1 },
    potentialWin: { type: Number, default: 0 },
    status:       { type: String, default: 'pending' }, // pending | won | lost
    settledAt:    { type: Number, default: 0 },
    placedAt:     { type: Number, default: Date.now }
});

const FootballStandingSchema = new mongoose.Schema({
    leagueId: { type: String, required: true },
    team:     { type: String, required: true },
    played:   { type: Number, default: 0 },
    won:      { type: Number, default: 0 },
    drawn:    { type: Number, default: 0 },
    lost:     { type: Number, default: 0 },
    gf:       { type: Number, default: 0 },
    ga:       { type: Number, default: 0 },
    points:   { type: Number, default: 0 },
    season:   { type: String, default: '2024/25' }
});
FootballStandingSchema.index({ leagueId: 1, points: -1 });

const FootballMatch    = mongoose.models.RPGFootballMatch    || mongoose.model('RPGFootballMatch',    FootballMatchSchema);
const FootballBet      = mongoose.models.RPGFootballBet      || mongoose.model('RPGFootballBet',      FootballBetSchema);
const FootballStanding = mongoose.models.RPGFootballStanding || mongoose.model('RPGFootballStanding', FootballStandingSchema);

// ─────────────────────────────────────────────────────────────────────────────
// ODDS ENGINE — generates realistic decimal odds with house margin
// ─────────────────────────────────────────────────────────────────────────────
function generateMatchOdds(homeTeam, awayTeam, leagueId) {
    const isContinent = ['UCL', 'UEL'].includes(leagueId);
    const homeBias = isContinent ? 0.38 : 0.44;
    const toOdds = (p) => Math.round((1 / Math.max(0.01, p * 0.92)) * 100) / 100;

    const homeWinP = Math.max(0.10, homeBias  + (Math.random() * 0.12 - 0.06));
    const drawP    = Math.max(0.10, 0.27      + (Math.random() * 0.06 - 0.03));
    const awayWinP = Math.max(0.10, 1 - homeWinP - drawP);

    const homeGoalProbs = [0.18, 0.33, 0.30, 0.19];
    const awayGoalProbs = [0.25, 0.35, 0.26, 0.14];
    const bttsYesP = Math.max(0.15, Math.min(0.85, 0.52 + (Math.random() * 0.10 - 0.05)));

    const homeGoalOdds = {};
    const awayGoalOdds = {};
    [0, 1, 2, 3].forEach((g, i) => {
        homeGoalOdds[g] = toOdds(homeGoalProbs[i]);
        awayGoalOdds[g] = toOdds(awayGoalProbs[i]);
    });

    return {
        homeWin:   toOdds(homeWinP),
        draw:      toOdds(drawP),
        awayWin:   toOdds(awayWinP),
        bttsYes:   toOdds(bttsYesP),
        bttsNo:    toOdds(1 - bttsYesP),
        homeGoals: homeGoalOdds,
        awayGoals: awayGoalOdds
    };
}

// ─────────────────────────────────────────────────────────────────────────────
// MATCH RESULT ENGINE — weighted random goals
// ─────────────────────────────────────────────────────────────────────────────
function simulateScore() {
    const goalDist = [
        { goals: 0, w: 20 }, { goals: 1, w: 34 }, { goals: 2, w: 27 },
        { goals: 3, w: 13 }, { goals: 4, w: 5  }, { goals: 5, w: 1  }
    ];
    function randGoals() {
        let r = Math.random() * 100;
        for (const d of goalDist) { r -= d.w; if (r <= 0) return d.goals; }
        return 0;
    }
    return { homeGoals: randGoals(), awayGoals: randGoals() };
}

// ─────────────────────────────────────────────────────────────────────────────
// BET SETTLEMENT — returns true if selection won
// ─────────────────────────────────────────────────────────────────────────────
function settleBetSelection(sel, homeGoals, awayGoals) {
    const { market, selection } = sel;
    switch (market) {
        case '1x2':
            if (selection === 'home') return homeGoals > awayGoals;
            if (selection === 'draw') return homeGoals === awayGoals;
            if (selection === 'away') return awayGoals > homeGoals;
            return false;
        case 'homegoals':
            return parseInt(selection) === Math.min(homeGoals, 3);
        case 'awaygoals':
            return parseInt(selection) === Math.min(awayGoals, 3);
        case 'btts':
            if (selection === 'yes') return homeGoals > 0 && awayGoals > 0;
            if (selection === 'no')  return homeGoals === 0 || awayGoals === 0;
            return false;
        default:
            return false;
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// STANDINGS UPDATER
// ─────────────────────────────────────────────────────────────────────────────
async function updateStandings(match) {
    try {
        const { leagueId, homeTeam, awayTeam, homeGoals, awayGoals, season } = match;

        async function getRow(team) {
            let r = await FootballStanding.findOne({ leagueId, team, season }).exec();
            if (!r) r = new FootballStanding({ leagueId, team, season });
            return r;
        }

        const home = await getRow(homeTeam);
        const away = await getRow(awayTeam);

        home.played++; away.played++;
        home.gf += homeGoals; home.ga += awayGoals;
        away.gf += awayGoals; away.ga += homeGoals;

        if (homeGoals > awayGoals) {
            home.won++; home.points += 3; away.lost++;
        } else if (homeGoals === awayGoals) {
            home.drawn++; home.points++;
            away.drawn++; away.points++;
        } else {
            away.won++; away.points += 3; home.lost++;
        }

        await home.save();
        await away.save();
    } catch (e) { console.error('updateStandings error:', e); }
}

// ─────────────────────────────────────────────────────────────────────────────
// MATCH SCHEDULER — ensures each league always has queued fixtures
// ─────────────────────────────────────────────────────────────────────────────
async function ensureUpcomingMatches() {
    try {
        if (mongoose.connection.readyState !== 1) return;
        const nowTs = Date.now();

        for (const [leagueId, league] of Object.entries(FOOTBALL_LEAGUES)) {
            const upcoming = await FootballMatch.countDocuments({ leagueId, status: { $in: ['upcoming', 'live'] } }).exec();
            if (upcoming >= 2) continue;

            const teams = [...league.teams];
            const recentMatches = await FootballMatch.find({
                leagueId, finishedAt: { $gt: nowTs - 60 * 60 * 1000 }
            }).exec();
            const usedPairs = new Set(recentMatches.map(m => `${m.homeTeam}|${m.awayTeam}`));

            let scheduled = 0;
            let attempts = 0;

            while (scheduled < 2 && attempts < 30) {
                attempts++;
                const hi = Math.floor(Math.random() * teams.length);
                let ai  = Math.floor(Math.random() * teams.length);
                while (ai === hi) ai = Math.floor(Math.random() * teams.length);

                const home = teams[hi], away = teams[ai];
                const pairKey = `${home}|${away}`;
                if (usedPairs.has(pairKey)) continue;

                const already = await FootballMatch.findOne({ leagueId, homeTeam: home, awayTeam: away, status: { $in: ['upcoming', 'live'] } }).exec();
                if (already) continue;

                const odds = generateMatchOdds(home, away, leagueId);
                // Stagger kickoffs: first match 2-5 mins, second 6-12 mins
                const delay = scheduled === 0
                    ? (2 + Math.floor(Math.random() * 3)) * 60 * 1000
                    : (6 + Math.floor(Math.random() * 6)) * 60 * 1000;

                const matchId = `${leagueId}-${Date.now().toString(36).toUpperCase()}-${Math.random().toString(36).substr(2, 4).toUpperCase()}`;

                const newMatch = new FootballMatch({
                    matchId, leagueId, homeTeam: home, awayTeam: away,
                    odds: JSON.stringify(odds), status: 'upcoming',
                    kickoff: nowTs + delay, season: '2024/25',
                    matchday: Math.floor(Math.random() * 38) + 1
                });

                await newMatch.save();
                usedPairs.add(pairKey);
                scheduled++;
            }
        }
    } catch (e) { console.error('ensureUpcomingMatches error:', e); }
}

// ─────────────────────────────────────────────────────────────────────────────
// FOOTBALL ENGINE INTERVAL — ticks every 5 minutes
// ─────────────────────────────────────────────────────────────────────────────
setInterval(async () => {
    try {
        if (mongoose.connection.readyState !== 1) return;
        const nowTs = Date.now();

        // Kick off matches whose time has arrived
        const toKickOff = await FootballMatch.find({ status: 'upcoming', kickoff: { $lte: nowTs } }).exec();
        for (const m of toKickOff) { m.status = 'live'; await m.save(); }

        // Simulate and finish all live matches
        const liveMatches = await FootballMatch.find({ status: 'live' }).exec();
        for (const match of liveMatches) {
            const score = simulateScore();
            match.homeGoals  = score.homeGoals;
            match.awayGoals  = score.awayGoals;
            match.status     = 'finished';
            match.finishedAt = nowTs;
            await match.save();

            await updateStandings(match);

            // Settle all bets that have this match as a leg
            const pendingBets = await FootballBet.find({ status: 'pending', 'selections.matchId': match.matchId }).exec();

            for (const bet of pendingBets) {
                // Mark each matching selection as won or lost
                for (const sel of bet.selections) {
                    if (sel.matchId === match.matchId && sel.result === null) {
                        sel.result = settleBetSelection(sel, match.homeGoals, match.awayGoals) ? 'won' : 'lost';
                    }
                }

                const anyLost     = bet.selections.some(s => s.result === 'lost');
                const allSettled  = bet.selections.every(s => s.result !== null);

                if (anyLost) {
                    bet.status    = 'lost';
                    bet.settledAt = nowTs;
                    await bet.save();
                    const bettor = await Player.findById(bet.playerId).exec();
                    if (bettor) {
                        logAction(bettor, `⚽ Bet ${bet.betId} LOST — ${match.homeTeam} ${match.homeGoals}-${match.awayGoals} ${match.awayTeam}`);
                        await bettor.save();
                    }
                } else if (allSettled) {
                    bet.status    = 'won';
                    bet.settledAt = nowTs;
                    await bet.save();
                    const bettor = await Player.findById(bet.playerId).exec();
                    if (bettor) {
                        // Cap betting win at $10B profit max
                        const MAX_BET_WIN = 10_000_000_000;
                        const cappedWin   = Math.min(bet.potentialWin, bet.stake + MAX_BET_WIN);
                        const profit      = Math.max(0, cappedWin - bet.stake);
                        bettor.money += cappedWin;
                        addTaxableIncome(bettor, profit);
                        // Instant 30% tax on profit over $1M
                        if (profit >= 1_000_000) {
                            const rate       = profit >= 1_000_000_000 ? 0.50 : profit >= 100_000_000 ? 0.40 : 0.30;
                            const instantTax = Math.floor(profit * rate);
                            bettor.money     = Math.max(0, bettor.money - instantTax);
                            bettor.taxPaid   = (bettor.taxPaid || 0) + instantTax;
                        }
                        logAction(bettor, `⚽ Bet ${bet.betId} WON! +${fmtMoney(cappedWin)}${cappedWin < bet.potentialWin ? ' (capped)' : ''}`);
                        await bettor.save();
                    }
                } else {
                    // More legs still pending — just save partial settlement
                    await bet.save();
                }
            }
        }

        // Top up upcoming fixtures
        await ensureUpcomingMatches();

    } catch (e) { console.error('Football engine interval error:', e); }
}, 5 * 60 * 1000);

// Seed matches shortly after bot starts
setTimeout(ensureUpcomingMatches, 8000);

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: fixtures — List upcoming and live matches
// Usage: fixtures [leagueId]
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'fixtures', desc: 'View upcoming football fixtures', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const leagueFilter = args && args[0] ? args[0].toUpperCase() : null;
        const query = { status: { $in: ['upcoming', 'live'] } };
        if (leagueFilter && FOOTBALL_LEAGUES[leagueFilter]) query.leagueId = leagueFilter;

        const matches = await FootballMatch.find(query).sort({ kickoff: 1 }).limit(21).exec();

        if (!matches.length) {
            const ids = Object.keys(FOOTBALL_LEAGUES).join(' | ');
            return conn.sendMessage(from, { text: `⚽ No upcoming fixtures right now. They refresh every 5 minutes.\nAvailable leagues: ${ids}` }, { quoted: mek });
        }

        const nowTs = Date.now();
        let txt = `⚽ *UPCOMING FIXTURES*${leagueFilter ? ` — ${FOOTBALL_LEAGUES[leagueFilter].name}` : ' — All Leagues'}\n\n`;

        for (const match of matches) {
            const leagueName = FOOTBALL_LEAGUES[match.leagueId]?.name || match.leagueId;
            const timeLabel = match.status === 'live' ? '🟢 *LIVE*'
                            : match.kickoff > nowTs   ? `⏱️ in ${shortTime(match.kickoff - nowTs)}`
                            : '🟢 Starting...';
            const o = match.odds ? JSON.parse(match.odds) : null;

            txt += `🏟️ *${leagueName}*\n`;
            txt += `*${match.homeTeam}* vs *${match.awayTeam}*\n`;
            txt += `🆔 \`${match.matchId}\`  ${timeLabel}\n`;
            if (o) txt += `📊 1X2: H *${o.homeWin}* | D *${o.draw}* | A *${o.awayWin}*\n`;
            txt += `\n`;
        }

        txt += `*Place a bet:* bet <matchId> <market> <selection> <stake>\n`;
        txt += `*Full odds:* matchodds <matchId>\n`;
        txt += `*Leagues:* PL | LL | BL | SA | L1 | UCL | UEL`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('fixtures error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: matchodds — Show full odds card for a match
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'matchodds', desc: 'View full odds for a match', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const matchId = args && args[0] ? args[0].toUpperCase() : null;
        if (!matchId) return conn.sendMessage(from, { text: 'Usage: matchodds <matchId>\nGet IDs from: fixtures' }, { quoted: mek });

        const match = await FootballMatch.findOne({ matchId }).exec();
        if (!match) return conn.sendMessage(from, { text: `Match \`${matchId}\` not found.` }, { quoted: mek });

        if (match.status === 'finished') {
            return conn.sendMessage(from, {
                text: `⚽ Match finished!\n*${match.homeTeam}* ${match.homeGoals} — ${match.awayGoals} *${match.awayTeam}*\n\nUse results to see recent scores.`
            }, { quoted: mek });
        }

        const o = match.odds ? JSON.parse(match.odds) : null;
        if (!o) return conn.sendMessage(from, { text: `Odds not yet available for this match.` }, { quoted: mek });

        const league = FOOTBALL_LEAGUES[match.leagueId]?.name || match.leagueId;
        let txt = `⚽ *${league}*\n`;
        txt += `🏟️ *${match.homeTeam}* vs *${match.awayTeam}*\n`;
        txt += `🆔 \`${match.matchId}\`\n\n`;

        txt += `📊 *Match Result (market: 1x2)*\n`;
        txt += `  🏠 Home Win  (home):  *${o.homeWin}*\n`;
        txt += `  🤝 Draw      (draw):  *${o.draw}*\n`;
        txt += `  ✈️  Away Win  (away):  *${o.awayWin}*\n\n`;

        txt += `🏠 *Home Team Goals (market: homegoals)*\n`;
        [0,1,2,3].forEach(g => { txt += `  Scores ${g}+:  *${o.homeGoals[g]}*\n`; });

        txt += `\n✈️ *Away Team Goals (market: awaygoals)*\n`;
        [0,1,2,3].forEach(g => { txt += `  Scores ${g}+:  *${o.awayGoals[g]}*\n`; });

        txt += `\n⚽ *Both Teams to Score (market: btts)*\n`;
        txt += `  Yes (yes):  *${o.bttsYes}*\n`;
        txt += `  No  (no):   *${o.bttsNo}*\n\n`;

        txt += `*Example bets:*\n`;
        txt += `bet ${match.matchId} 1x2 home 1000\n`;
        txt += `bet ${match.matchId} btts yes 500\n`;
        txt += `bet ${match.matchId} homegoals 2 800\n`;
        txt += `\n_For accumulators: see betacca_`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('matchodds error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: bet — Place a single bet
// Usage: bet <matchId> <market> <selection> <stake>
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'bet', desc: 'Place a football bet', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 You can't place bets from hospital/jail.` }, { quoted: mek });

        if (!args || args.length < 4) {
            return conn.sendMessage(from, {
                text: [
                    `⚽ *SINGLE BET*`,
                    `Usage: bet <matchId> <market> <selection> <stake>`,
                    ``,
                    `*Markets & valid selections:*`,
                    `• 1x2        → home | draw | away`,
                    `• homegoals  → 0 | 1 | 2 | 3`,
                    `• awaygoals  → 0 | 1 | 2 | 3`,
                    `• btts       → yes | no`,
                    ``,
                    `*Examples:*`,
                    `bet PL-XXX-XXXX 1x2 home 1000`,
                    `bet UCL-YYY-YYYY btts yes 500`,
                    `bet BL-ZZZ-ZZZZ awaygoals 1 800`,
                    ``,
                    `_Get match IDs from: fixtures_`
                ].join('\n')
            }, { quoted: mek });
        }

        const matchId   = args[0].toUpperCase();
        const market    = args[1].toLowerCase();
        const selection = args[2].toLowerCase();
        const stake     = parseInt(args[3]);

        if (isNaN(stake) || stake < 50)  return conn.sendMessage(from, { text: `Minimum bet is ${fmtMoney(50)}.` }, { quoted: mek });
        if (p.money < stake)              return conn.sendMessage(from, { text: `💸 Not enough cash. You have ${fmtMoney(p.money)}.` }, { quoted: mek });

        const match = await FootballMatch.findOne({ matchId, status: 'upcoming' }).exec();
        if (!match) return conn.sendMessage(from, { text: `Match not found or betting is closed (may have already kicked off). Check fixtures.` }, { quoted: mek });

        const o = match.odds ? JSON.parse(match.odds) : null;
        if (!o) return conn.sendMessage(from, { text: `Odds not available for this match yet.` }, { quoted: mek });

        // Validate and look up odds
        let selectionOdds = null;
        if (market === '1x2') {
            if      (selection === 'home') selectionOdds = o.homeWin;
            else if (selection === 'draw') selectionOdds = o.draw;
            else if (selection === 'away') selectionOdds = o.awayWin;
            else return conn.sendMessage(from, { text: `For 1x2: use home | draw | away` }, { quoted: mek });
        } else if (market === 'homegoals') {
            const g = parseInt(selection);
            if ([0,1,2,3].includes(g)) selectionOdds = o.homeGoals[g];
            else return conn.sendMessage(from, { text: `For homegoals: use 0 | 1 | 2 | 3` }, { quoted: mek });
        } else if (market === 'awaygoals') {
            const g = parseInt(selection);
            if ([0,1,2,3].includes(g)) selectionOdds = o.awayGoals[g];
            else return conn.sendMessage(from, { text: `For awaygoals: use 0 | 1 | 2 | 3` }, { quoted: mek });
        } else if (market === 'btts') {
            if      (selection === 'yes') selectionOdds = o.bttsYes;
            else if (selection === 'no')  selectionOdds = o.bttsNo;
            else return conn.sendMessage(from, { text: `For btts: use yes | no` }, { quoted: mek });
        } else {
            return conn.sendMessage(from, { text: `Unknown market. Use: 1x2 | homegoals | awaygoals | btts` }, { quoted: mek });
        }

        if (!selectionOdds) return conn.sendMessage(from, { text: `Could not find odds for that selection.` }, { quoted: mek });

        const potentialWin = Math.floor(stake * selectionOdds);
        const betId = `BET-${Date.now().toString(36).toUpperCase().slice(-5)}-${Math.random().toString(36).substr(2,3).toUpperCase()}`;

        p.money    -= stake;
        p.moneySpent += stake;
        logAction(p, `Placed bet ${betId}: ${match.homeTeam} v ${match.awayTeam} — ${market} ${selection} @ ${selectionOdds} (${fmtMoney(stake)})`);

        const bet = new FootballBet({
            betId, playerId: pId, stake, type: 'single',
            selections: [{ matchId, market, selection, odds: selectionOdds, result: null }],
            totalOdds: selectionOdds, potentialWin, status: 'pending'
        });

        await bet.save();
        await p.save();

        return conn.sendMessage(from, {
            text: [
                `✅ *BET PLACED!*`,
                ``,
                `🎟️ ID: \`${betId}\``,
                `⚽ *${match.homeTeam}* vs *${match.awayTeam}*`,
                `📊 Market: *${market.toUpperCase()}* → *${selection.toUpperCase()}*`,
                `📈 Odds: *${selectionOdds}*`,
                `💵 Stake: ${fmtMoney(stake)}`,
                `🏆 To Win: *${fmtMoney(potentialWin)}*`,
                ``,
                `_Results simulate every 5 minutes. Track with: mybets_`
            ].join('\n')
        }, { quoted: mek });
    } catch (e) { console.error('bet error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: betacca — Place a multi-leg accumulator bet
// Usage: betacca <stake> <matchId1> <market1> <sel1> <matchId2> <market2> <sel2> ...
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'betacca', desc: 'Place an accumulator bet', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 You can't place bets from hospital/jail.` }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 Held captive. Use 'escape' or 'payransom'.` }, { quoted: mek });

        if (!args || args.length < 4) {
            return conn.sendMessage(from, {
                text: [
                    `⚽ *ACCUMULATOR BET*`,
                    `Usage: betacca <stake> <matchId> <market> <selection> [more legs...]`,
                    ``,
                    `*Example (2-leg acca):*`,
                    `betacca 1000 PL-ABC 1x2 home UCL-XYZ btts yes`,
                    ``,
                    `*Markets:* 1x2 (home/draw/away) | btts (yes/no) | homegoals 0-3 | awaygoals 0-3`,
                    `• Min 2 legs, max 8 legs | Odds multiply per leg`,
                    `_Match IDs from: fixtures_`
                ].join('\n')
            }, { quoted: mek });
        }

        const stake = parseInt(args[0]);
        if (isNaN(stake) || stake < 50) return conn.sendMessage(from, { text: `Minimum stake is ${fmtMoney(50)}.` }, { quoted: mek });
        if (p.money < stake)             return conn.sendMessage(from, { text: `💸 Not enough cash. You have ${fmtMoney(p.money)}.` }, { quoted: mek });

        // Parse legs as flat triplets: matchId market selection matchId market selection ...
        const rest = args.slice(1);
        if (rest.length % 3 !== 0) return conn.sendMessage(from, { text: `Each leg needs exactly 3 values: matchId market selection\nExample: PL-ABC 1x2 home` }, { quoted: mek });

        const legsRaw = [];
        for (let i = 0; i < rest.length; i += 3) {
            legsRaw.push({ matchId: rest[i].toUpperCase(), market: rest[i+1].toLowerCase(), selection: rest[i+2].toLowerCase() });
        }

        if (legsRaw.length < 2) return conn.sendMessage(from, { text: `Accumulator needs at least 2 legs.` }, { quoted: mek });
        if (legsRaw.length > 8) return conn.sendMessage(from, { text: `Maximum 8 legs per accumulator.` }, { quoted: mek });

        const selections = [];
        let totalOdds = 1;
        const summaryLines = [];

        for (const leg of legsRaw) {
            const { matchId, market, selection } = leg;

            if (selections.some(s => s.matchId === matchId)) {
                return conn.sendMessage(from, { text: `Duplicate match: ${matchId}. Each match can only appear once.` }, { quoted: mek });
            }

            const match = await FootballMatch.findOne({ matchId, status: 'upcoming' }).exec();
            if (!match) return conn.sendMessage(from, { text: `Match \`${matchId}\` not found or already started.` }, { quoted: mek });

            const o = match.odds ? JSON.parse(match.odds) : null;
            if (!o) return conn.sendMessage(from, { text: `Odds not available for ${matchId}.` }, { quoted: mek });

            let selectionOdds = null;
            if (market === '1x2') {
                if      (selection === 'home') selectionOdds = o.homeWin;
                else if (selection === 'draw') selectionOdds = o.draw;
                else if (selection === 'away') selectionOdds = o.awayWin;
            } else if (market === 'homegoals') {
                const g = parseInt(selection);
                if ([0,1,2,3].includes(g)) selectionOdds = o.homeGoals[g];
            } else if (market === 'awaygoals') {
                const g = parseInt(selection);
                if ([0,1,2,3].includes(g)) selectionOdds = o.awayGoals[g];
            } else if (market === 'btts') {
                if      (selection === 'yes') selectionOdds = o.bttsYes;
                else if (selection === 'no')  selectionOdds = o.bttsNo;
            }

            if (!selectionOdds) return conn.sendMessage(from, { text: `Invalid market/selection in leg: "${matchId} ${market} ${selection}"` }, { quoted: mek });

            totalOdds = Math.round(totalOdds * selectionOdds * 100) / 100;
            selections.push({ matchId, market, selection, odds: selectionOdds, result: null });
            summaryLines.push(`  Leg ${selections.length}: *${match.homeTeam}* v *${match.awayTeam}* — ${market} *${selection}* @ ${selectionOdds}`);
        }

        const potentialWin = Math.floor(stake * totalOdds);
        const betId = `ACCA-${Date.now().toString(36).toUpperCase().slice(-5)}-${Math.random().toString(36).substr(2,3).toUpperCase()}`;

        p.money      -= stake;
        p.moneySpent += stake;
        logAction(p, `Placed ${selections.length}-leg acca ${betId}: stake ${fmtMoney(stake)}, odds ${totalOdds}`);

        const bet = new FootballBet({
            betId, playerId: pId, stake, type: 'acca',
            selections, totalOdds, potentialWin, status: 'pending'
        });

        await bet.save();
        await p.save();

        return conn.sendMessage(from, {
            text: [
                `✅ *ACCUMULATOR PLACED!*`,
                ``,
                `🎟️ ID: \`${betId}\``,
                `📋 *${selections.length}-Leg Accumulator:*`,
                ...summaryLines,
                ``,
                `📈 Combined Odds: *${totalOdds}*`,
                `💵 Stake: ${fmtMoney(stake)}`,
                `🏆 Potential Win: *${fmtMoney(potentialWin)}*`,
                ``,
                `_All legs must win. One loss ends the bet._`
            ].join('\n')
        }, { quoted: mek });
    } catch (e) { console.error('betacca error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: mybets — View your bets
// Usage: mybets [pending | won | lost]
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'mybets', desc: 'View your football bets', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const filter = args && args[0] ? args[0].toLowerCase() : 'all';

        const query = { playerId: pId };
        if (filter === 'pending') query.status = 'pending';
        else if (filter === 'won')  query.status = 'won';
        else if (filter === 'lost') query.status = 'lost';

        const bets = await FootballBet.find(query).sort({ placedAt: -1 }).limit(10).exec();
        if (!bets.length) {
            return conn.sendMessage(from, {
                text: `🎟️ No bets found (filter: ${filter}).\n\nFilters: mybets pending | won | lost`
            }, { quoted: mek });
        }

        let txt = `🎟️ *YOUR BETS* — ${filter.toUpperCase()}\n\n`;
        for (const bet of bets) {
            const statusEmoji = { won: '✅', lost: '❌', pending: '⏳' }[bet.status] || '⏳';
            txt += `${statusEmoji} \`${bet.betId}\` — ${bet.type.toUpperCase()}\n`;
            txt += `   💵 ${fmtMoney(bet.stake)} @ *${bet.totalOdds}* → 🏆 ${fmtMoney(bet.potentialWin)}\n`;
            for (const sel of bet.selections) {
                const r = sel.result === 'won' ? '✅' : sel.result === 'lost' ? '❌' : '⏳';
                txt += `   ${r} \`${sel.matchId}\` ${sel.market} *${sel.selection}* @ ${sel.odds}\n`;
            }
            txt += `\n`;
        }

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('mybets error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: results — View recent match scores
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'results', desc: 'View recent football results', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const leagueFilter = args && args[0] ? args[0].toUpperCase() : null;
        const query = { status: 'finished' };
        if (leagueFilter && FOOTBALL_LEAGUES[leagueFilter]) query.leagueId = leagueFilter;

        const matches = await FootballMatch.find(query).sort({ finishedAt: -1 }).limit(15).exec();
        if (!matches.length) {
            return conn.sendMessage(from, { text: `⚽ No results yet. Matches simulate every 5 minutes.` }, { quoted: mek });
        }

        let txt = `⚽ *RECENT RESULTS*${leagueFilter ? ` — ${FOOTBALL_LEAGUES[leagueFilter]?.name}` : ''}\n\n`;
        for (const match of matches) {
            const league = FOOTBALL_LEAGUES[match.leagueId]?.name || match.leagueId;
            const outcome = match.homeGoals > match.awayGoals ? '🏠 Home Win'
                          : match.homeGoals < match.awayGoals ? '✈️ Away Win'
                          : '🤝 Draw';
            txt += `${outcome} — *${league}*\n`;
            txt += `*${match.homeTeam}* ${match.homeGoals} — ${match.awayGoals} *${match.awayTeam}*\n\n`;
        }
        txt += `Filter: results PL | results UCL | results BL`;

        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('results error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: standings — View a league table
// Usage: standings <leagueId>
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'standings', desc: 'View league standings table', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const leagueId = args && args[0] ? args[0].toUpperCase() : 'PL';
        const league   = FOOTBALL_LEAGUES[leagueId];
        if (!league) {
            return conn.sendMessage(from, {
                text: `Unknown league. Available: ${Object.keys(FOOTBALL_LEAGUES).join(' | ')}`
            }, { quoted: mek });
        }

        const rows = await FootballStanding
            .find({ leagueId, season: '2024/25' })
            .sort({ points: -1, gf: -1 })
            .exec();

        if (!rows.length) {
            return conn.sendMessage(from, {
                text: `📊 No standings yet for ${league.name}.\nStandings update automatically as matches finish (every 5 min).`
            }, { quoted: mek });
        }

        let table = `${league.name} — 2024/25\n\n`;
        table += `Pos  Team               P   W  D  L  GF GA GD  Pts\n`;
        table += `────────────────────────────────────────────────\n`;

        rows.forEach((r, i) => {
            const gd      = r.gf - r.ga;
            const gdStr   = gd >= 0 ? `+${gd}` : `${gd}`;
            const team    = r.team.padEnd(18).slice(0, 18);
            const pos     = String(i + 1).padStart(3);
            table += `${pos}. ${team} ${String(r.played).padStart(2)}  ${String(r.won).padStart(2)} ${String(r.drawn).padStart(2)} ${String(r.lost).padStart(2)}  ${String(r.gf).padStart(2)} ${String(r.ga).padStart(2)} ${gdStr.padStart(3)}  ${String(r.points).padStart(3)}\n`;
        });

        table += `\nLeagues: PL | LL | BL | SA | L1 | UCL | UEL`;

        return conn.sendMessage(from, { text: `\`\`\`${table}\`\`\`` }, { quoted: mek });
    } catch (e) { console.error('standings error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: betleader — Top football bettors by profit
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'betleader', desc: 'Top football bettors leaderboard', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const wonBets = await FootballBet.find({ status: 'won' }).exec();
        const totals  = {};
        for (const b of wonBets) {
            totals[b.playerId] = (totals[b.playerId] || 0) + (b.potentialWin - b.stake);
        }

        const sorted = Object.entries(totals).sort((a, b) => b[1] - a[1]).slice(0, 10);
        if (!sorted.length) return conn.sendMessage(from, { text: `🏆 No winning bets yet!` }, { quoted: mek });

        let txt = `🏆 *TOP FOOTBALL BETTORS*\n_Ranked by total profit_\n\n`;
        const betMentions = [];
        for (let i = 0; i < sorted.length; i++) {
            const [pid, profit] = sorted[i];
            if (pid.startsWith('child_')) continue;
            const pl = await Player.findById(pid).exec();
            const name = pl?.username || '(no name)';
            betMentions.push(toJid(pid));
            txt += `${i + 1}. *${name}* @${pid} — Profit: ${fmtMoney(profit)}\n`;
        }

        return conn.sendMessage(from, { text: txt, mentions: betMentions }, { quoted: mek });
    } catch (e) { console.error('betleader error', e); }
});

// =============================================================================
// COMMAND: faction crime — Group crimes with prestige rewards
// =============================================================================
cast({ pattern: 'factioncrime', desc: 'Commit a crime with your faction', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);

        if (!p.faction) return conn.sendMessage(from, { text: `You need to be in a faction to commit faction crimes.` }, { quoted: mek });
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `🚑 Can't do faction crimes from hospital/jail.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });

        const f = await Faction.findById(p.faction).exec();
        if (!f) return conn.sendMessage(from, { text: `Your faction no longer exists.` }, { quoted: mek });

        const crimeId = (args && args[0]) ? args[0].toLowerCase() : null;
        if (!crimeId) {
            const list = FACTION_CRIMES.map(c =>
                `• *${c.id}* — ${c.name} (${c.minMembers}+ members, ${shortTime(c.cooldownMs)} cooldown, 😤${c.energy} energy)\n  ${c.desc}`
            ).join('\n');
            const tier = getFactionPerkTier(f.prestige || 0);
            return conn.sendMessage(from, {
                text: `🏢 *Faction Crimes*\n\n${list}\n\nUsage: factioncrime <crime_id>\n\n🏅 Faction Prestige: ${f.prestige || 0} (${tier.name})`
            }, { quoted: mek });
        }

        const crime = FACTION_CRIMES.find(c => c.id === crimeId);
        if (!crime) return conn.sendMessage(from, { text: `Unknown faction crime. Type *factioncrime* to see options.` }, { quoted: mek });

        // Cooldown check
        const elapsed = now() - (f.lastFactionCrime || 0);
        if (elapsed < crime.cooldownMs) return conn.sendMessage(from, { text: `⏳ Faction crime on cooldown. Ready in: ${shortTime(crime.cooldownMs - elapsed)}` }, { quoted: mek });

        // Energy check
        if (p.energy < crime.energy) return conn.sendMessage(from, { text: `Not enough energy. This crime needs ${crime.energy}.` }, { quoted: mek });

        // Member count check — any healthy faction member with enough energy
        // (location check removed — members coordinate through the bot, not geography)
        const presentMembers = [];
        for (const mId of f.members) {
            const mp = await getOrCreatePlayer(mId);
            if (!isHospitalized(mp) && (mp.energy || 0) >= crime.energy) {
                presentMembers.push(mp);
            }
        }

        if (presentMembers.length < crime.minMembers) {
            return conn.sendMessage(from, {
                text: [
                    `❌ Need at least *${crime.minMembers}* faction members with ${crime.energy}+ energy.`,
                    `Currently available: ${presentMembers.length}/${f.members.length} members`,
                    ``,
                    `Members may be hospitalized, jailed, or low on energy.`,
                    `Check member status: *faction info*`
                ].join('\n')
            }, { quoted: mek });
        }

        // Deduct energy from all participating members
        for (const mp of presentMembers) {
            mp.energy -= crime.energy;
            await mp.save();
        }

        // Success chance based on combined stats
        const combinedStr = presentMembers.reduce((s, mp) => s + (mp.strength || 1), 0);
        const successChance = Math.min(0.85, 0.3 + (combinedStr / 500));
        const success = Math.random() < successChance;

        f.lastFactionCrime = now();

        if (success) {
            const { min: cMin, max: cMax } = liveCrimeReward(crime.rewardMin, crime.rewardMax);
            const gross = Math.floor(cMin + Math.random() * (cMax - cMin));
            const { net: reward, vat } = applyVAT(gross);
            const prestigeGain = crime.prestige;
            const cut = Math.floor(reward / presentMembers.length);

            f.prestige = (f.prestige || 0) + prestigeGain;
            await addFactionXP(f, 100); // faction XP for completing a crime

            // Check if prestige tier improved — if so, update all members
            const newTier = getFactionPerkTier(f.prestige);
            const oldTier = getFactionPerkTier((f.prestige || 0) - prestigeGain);
            const tierUp = newTier.tier > oldTier.tier;

            for (const mp of presentMembers) {
                mp.money += cut;
                mp.crimeLevel = Math.min(100, (mp.crimeLevel || 0) + 10); // crime heat for participating
                addTaxableIncome(mp, cut);
                logAction(mp, `Faction crime: ${crime.name} (+${fmtMoney(cut)})`);
                logFinancial(mp, `Faction Crime: ${crime.name}`, cut);
                if (tierUp) applyFactionPerks(mp, newTier);
                await mp.save();
            }

            await f.save();
            logGlobal('🏢', `*${f.name}* faction pulled off a *${crime.name}*! +${prestigeGain} prestige${tierUp ? ` — Promoted to ${newTier.name}!` : ''}`);

            const tierUpMsg = tierUp ? `\n🎖️ *FACTION TIER UP!* ${oldTier.name} → *${newTier.name}*\nAll members received new perks!` : '';
            return conn.sendMessage(from, {
                text: [
                    `✅ *FACTION CRIME SUCCESS — ${crime.name.toUpperCase()}*`,
                    ``,
                    `${crime.desc}`,
                    ``,
                    `💰 Gross: ${fmtMoney(gross)} | 🏛️ VAT: -${fmtMoney(gross - reward)} | Net: ${fmtMoney(reward)}`,
                    `👥 Split between ${presentMembers.length} members = *${fmtMoney(cut)} each*`,
                    `🏅 Faction prestige +${prestigeGain} → ${f.prestige}`,
                    tierUpMsg
                ].filter(Boolean).join('\n')
            }, { quoted: mek });

        } else {
            const fine = Math.floor(1000 + Math.random() * 5000);
            f.funds = Math.max(0, (f.funds || 0) - fine);
            // Jail the initiator and penalize participants
            p.jailedUntil = now() + (15 * 60 * 1000); p.inJail = true;
            p.jailWorkDone = 0; p.lawyerCallUsed = false; p.sentencedAt = now(); p.sentenceMs = 15*60*1000;
            p.crimeLevel  = Math.min(100, (p.crimeLevel || 0) + 20);
            await f.save();
            await p.save();
            return conn.sendMessage(from, {
                text: [
                    `❌ *FACTION CRIME FAILED — ${crime.name.toUpperCase()}*`,
                    ``,
                    `The operation went sideways.`,
                    `💸 Faction fined ${fmtMoney(fine)} from treasury`,
                    `⛓️ You've been jailed for 15 minutes`,
                    `🔴 Crime heat +20`
                ].join('\n')
            }, { quoted: mek });
        }
    } catch (e) { console.error('factioncrime error', e); }
});

// COMMAND: inflate — Creator-only, fully persistent via MongoDB
// =============================================================================
cast({ pattern: 'inflate', desc: 'Multiply all expenses (Creator only)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator command only.` }, { quoted: mek });

        const multiplier = parseFloat(args[0]);
        if (isNaN(multiplier) || multiplier <= 0) {
            return conn.sendMessage(from, {
                text: [
                    `💹 *Inflate — Usage: inflate <multiplier>*`,
                    `inflate 2 → everything x2 | inflate 0.5 → halved`,
                    ``,
                    `Current multiplier: *x${global.INFLATION_MULT}* (stored in DB)`,
                    ``,
                    `Scales ALL costs persistently:`,
                    `• Shop prices (DB) | Travel tickets`,
                    `• Hospital fees | Bailout & paymeds rates`,
                    `• Gear maintenance | Faction dues`,
                    `• Ransom caps | Prestige cost`,
                    ``,
                    `Gains/income: unchanged.`
                ].join('\n')
            }, { quoted: mek });
        }

        const prevMult = global.INFLATION_MULT;

        // ── 1. Update global and save to DB immediately ───────────────────────
        global.INFLATION_MULT = parseFloat((prevMult * multiplier).toFixed(8));
        await saveGameConfig();

        // ── 2. Update all ShopItem prices in DB ───────────────────────────────
        const items = await ShopItem.find().exec();
        let shopCount = 0;
        for (const it of items) {
            it.price = Math.ceil(it.price * multiplier);
            await it.save();
            shopCount++;
        }

        // ── 3. Keep DEFAULT_SHOP in sync (in-memory reference used by some commands) ──
        for (const it of DEFAULT_SHOP) {
            it.price = Math.ceil(it.price * multiplier);
        }

        // ── NOTE ──────────────────────────────────────────────────────────────
        // LOCATIONS base costs are intentionally NOT mutated.
        // iC() reads global.INFLATION_MULT at call time, so travel costs auto-scale.
        // Same applies to hospital fees, maintenance, dues, ransom, prestige.

        logGlobal('💹', `Inflation x${multiplier} applied (total x${global.INFLATION_MULT}) — ${shopCount} shop prices updated!`);
        return conn.sendMessage(from, {
            text: [
                `💹 *INFLATION APPLIED — x${multiplier}*`,
                ``,
                `x${prevMult} → *x${global.INFLATION_MULT}* (saved to DB — survives restarts)`,
                ``,
                `🛒 ${shopCount} shop items updated`,
                `✈️ Travel: Mexico ${fmtMoney(iC(5000))} | London ${fmtMoney(iC(12000))} | Japan ${fmtMoney(iC(20000))} | Swiss ${fmtMoney(iC(35000))}`,
                `🔧 Legendary maintenance: ${fmtMoney(iC(50000))}/hr | Epic: ${fmtMoney(iC(15000))}/hr`,
                `🏥 Hospital fee (lv1): ${fmtMoney(iC(500))} | Bailout: ${fmtMoney(iC(500))}/min`,
                `🏢 Faction dues: ${fmtMoney(iC(5000))}/hr | ⭐ Prestige: ${fmtMoney(iC(1_000_000_000))}`,
                ``,
                `Gains: unchanged.`
            ].join('\n')
        }, { quoted: mek });
    } catch (e) { console.error('inflate error', e); }
});

// =============================================================================
// COMMAND: resetinflation — Restore all prices back to base values
// =============================================================================
cast({ pattern: 'resetinflation', desc: 'Reset all prices to base (Creator only)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator command only.` }, { quoted: mek });

        const prevMult = global.INFLATION_MULT;
        if (prevMult === 1) {
            return conn.sendMessage(from, { text: `ℹ️ Inflation is already at x1 (base prices). Nothing to reset.` }, { quoted: mek });
        }

        // ── Restore DB prices from SHOP_BASE_PRICES (true original, never mutated) ──
        const items = await ShopItem.find().exec();
        let count = 0, purged = 0;
        for (const it of items) {
            if (SHOP_BASE_PRICES[it.id] !== undefined) {
                // Known item — restore exact base price
                it.price = SHOP_BASE_PRICES[it.id];
                await it.save();
                count++;
            } else {
                // Orphan item not in current code — delete it so ensureShop recreates it clean
                await ShopItem.deleteOne({ id: it.id });
                purged++;
            }
        }
        // ── Restore DEFAULT_SHOP memory from same frozen map ─────────────────
        for (const it of DEFAULT_SHOP) {
            if (SHOP_BASE_PRICES[it.id] !== undefined) it.price = SHOP_BASE_PRICES[it.id];
        }
        // ── Recreate any items that were purged or missing ────────────────────
        await ensureShop();

        // ── Reset multiplier and persist ──────────────────────────────────────
        global.INFLATION_MULT = 1;
        await saveGameConfig();

        logGlobal('💹', `Economy RESET to base prices by creator. Was x${prevMult}. ${count} restored, ${purged} orphans purged.`);
        return conn.sendMessage(from, {
            text: [
                `🔄 *INFLATION RESET*`,
                ``,
                `Was: x${prevMult} → Now: *x1 (base)*`,
                `_Saved to DB — survives restarts_`,
                ``,
                `🛒 ${count} items restored to base price`,
                purged > 0 ? `🗑️ ${purged} orphan/corrupted items purged & recreated` : null,
                `✈️ Travel: Mexico ${fmtMoney(5000)} | London ${fmtMoney(12000)} | Japan ${fmtMoney(20000)} | Swiss ${fmtMoney(35000)}`,
                `🔫 Shotgun: ${fmtMoney(8000)} | AR-15: ${fmtMoney(15000)} | Nuclear Briefcase: ${fmtMoney(2000000)}`,
            ].filter(Boolean).join('\n')
        }, { quoted: mek });
    } catch (e) { console.error('resetinflation error', e); }
});

