// =============================================================================
// COMMAND: battleboard — Top players by combat power, stats, and battle records
// =============================================================================
cast({ pattern: 'battleboard', desc: 'Top players by power, stats and battle record', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const sub = (args[0] || 'power').toLowerCase();
        const VALID = ['power', 'wins', 'ratio', 'kos', 'defends'];
        if (!VALID.includes(sub)) {
            return conn.sendMessage(from, { text: `Usage: battleboard [power|wins|ratio|kos|defends]\n\n• *power*   — ranked by total stats + level\n• *wins*    — ranked by total attack wins\n• *ratio*   — ranked by W/L ratio (min 5 fights)\n• *kos*     — ranked by KOs dealt (attacksWon)\n• *defends* — ranked by successful defends` }, { quoted: mek });
        }

        const allPlayers = await Player.find({}).lean().exec();
        if (!allPlayers.length) return conn.sendMessage(from, { text: `No players yet.` }, { quoted: mek });

        // Calculate combat power score for each player
        function combatPower(p) {
            const lvlMult = 1 + ((p.level || 1) - 1) * 0.08;
            const stats   = (p.strength || 3) + (p.defense || 3) + (p.speed || 3) + (p.dexterity || 3);
            const gear    = getGearBonuses(p);
            const gearSum = gear.atkBonus + gear.defBonus + gear.strBonus + gear.spdBonus + gear.dexBonus;
            const petPow  = getPetCombatData(p)?.power || 0;
            return Math.floor((stats + gearSum + petPow) * lvlMult);
        }

        function winRatio(p) {
            const wins   = (p.attacksWon || 0) + (p.defendsWon || 0);
            const losses = (p.attacksLost || 0) + (p.defendsLost || 0);
            const total  = wins + losses;
            if (total < 5) return -1; // not enough fights
            return wins / total;
        }

        let sorted, title, scoreFn;
        if (sub === 'power') {
            sorted  = allPlayers.sort((a,b) => combatPower(b) - combatPower(a));
            title   = `⚔️ *BATTLE BOARD — COMBAT POWER*`;
            scoreFn = p => `⚡ ${combatPower(p).toLocaleString()} CP`;
        } else if (sub === 'wins') {
            sorted  = allPlayers.sort((a,b) => ((b.attacksWon||0)+(b.defendsWon||0)) - ((a.attacksWon||0)+(a.defendsWon||0)));
            title   = `🏆 *BATTLE BOARD — TOTAL WINS*`;
            scoreFn = p => `✅ ${(p.attacksWon||0)+(p.defendsWon||0)} wins`;
        } else if (sub === 'ratio') {
            sorted  = allPlayers.filter(p => (p.attacksWon||0)+(p.attacksLost||0)+(p.defendsWon||0)+(p.defendsLost||0) >= 5)
                                .sort((a,b) => winRatio(b) - winRatio(a));
            title   = `📊 *BATTLE BOARD — WIN RATIO* _(min 5 fights)_`;
            scoreFn = p => { const r = winRatio(p); return r < 0 ? `— not enough` : `${(r*100).toFixed(1)}% W/L`; };
        } else if (sub === 'kos') {
            sorted  = allPlayers.sort((a,b) => (b.attacksWon||0) - (a.attacksWon||0));
            title   = `💀 *BATTLE BOARD — KOs DEALT*`;
            scoreFn = p => `💀 ${p.attacksWon||0} KOs`;
        } else {
            sorted  = allPlayers.sort((a,b) => (b.defendsWon||0) - (a.defendsWon||0));
            title   = `🛡️ *BATTLE BOARD — SUCCESSFUL DEFENDS*`;
            scoreFn = p => `🛡️ ${p.defendsWon||0} defends`;
        }

        const top = sorted.slice(0, 10);
        const MEDALS = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

        let txt = `${title}\n\n`;
        for (let i = 0; i < top.length; i++) {
            const p   = top[i];
            const pet = p.pet?.type ? `${({ dog:'🐶',cat:'🐱',parrot:'🦜',penguin:'🐧',wolf:'🐺',bear:'🐻',shark:'🦈',dragon:'🐉' })[p.pet.type]||'🐾'} Lv${p.pet.level||1}` : '';
            const lvl = `Lv${p.level||1}`;
            const rec = `${p.attacksWon||0}W-${p.attacksLost||0}L | ${p.defendsWon||0}D-${p.defendsLost||0}FL`;
            txt += `${MEDALS[i]} *${p.username || p._id}* ${lvl} ${pet}\n`;
            txt += `   ${scoreFn(p)} | 📋 ${rec}\n\n`;
        }

        txt += `_View modes: battleboard power | wins | ratio | kos | defends_`;
        return conn.sendMessage(from, { text: txt }, { quoted: mek });
    } catch (e) { console.error('battleboard error', e); }
});
