cast({ pattern: 'drains', desc: 'See your hourly drain costs', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const total = p.money + (p.bank || 0);
        const wealthRate = getWealthTaxRate(total);
        let propTaxPerHour = 0;
        for (const [propId, qty] of (p.properties || new Map()).entries()) {
            const shopIt = DEFAULT_SHOP.find(s => s.id === propId);
            if (shopIt && qty > 0) propTaxPerHour += Math.ceil(shopIt.price * PROPERTY_TAX_RATE * qty);
        }
        let gearCostPerHour = 0;
        const gSlots = ['equippedWeapon','equippedArmor','equippedHelmet','equippedGloves','equippedKneePads','equippedBoots'];
        for (const slot of gSlots) {
            if (!p[slot]) continue;
            gearCostPerHour += iC(GEAR_MAINTENANCE_BASE[getItemRarity(p[slot])] || 200);
        }
        const wealthTaxPerHour = Math.ceil(total * wealthRate);
        const factionDues = p.faction ? iC(FACTION_DUES_BASE) : 0;
        const totalPerHour = propTaxPerHour + gearCostPerHour + wealthTaxPerHour + factionDues;
        const insStatus = p.gearInsurance ? `🛡️ Active (${p.gearInsuranceExpiresAt > now() ? shortTime(p.gearInsuranceExpiresAt - now()) + ' left' : 'expired'})` : `❌ None — gear can be lost on death`;
        return conn.sendMessage(from, { text: [
            `📊 *Your Hourly Drains*`, ``,
            `🏠 Property Tax: ${fmtMoney(propTaxPerHour)}/hr`,
            `🔧 Gear Maintenance: ${fmtMoney(gearCostPerHour)}/hr`,
            `💸 Wealth Tax (${(wealthRate*100).toFixed(1)}%): ${fmtMoney(wealthTaxPerHour)}/hr`,
            `🏢 Faction Dues: ${fmtMoney(factionDues)}/hr`, ``,
            `💀 *Total: ${fmtMoney(totalPerHour)}/hr*`, ``,
            `🛡️ Insurance: ${insStatus}`,
            p.prestigeLevel > 0 ? `⭐ Prestige P${p.prestigeLevel}: +${p.prestigeLevel * 5}% train gains` : null
        ].filter(Boolean).join('\n') }, { quoted: mek });
    } catch (e) { console.error('drains error', e); }
});

// =============================================================================
// WEATHER SYSTEM — Updates every 30 min. Affects travel and flights.
// =============================================================================
const WEATHER_CONDITIONS = ['☀️ Clear', '🌤️ Partly Cloudy', '🌧️ Rain', '⛈️ Thunderstorm', '🌨️ Blizzard', '🌪️ Hurricane', '🌫️ Dense Fog'];

if (!global.cityWeather) {
    global.cityWeather = {};
    const cities = ['Weirdos World','Mexico','London','Japan','Switzerland','Dubai','New York','Paris','Lagos','Moscow','Sydney','Rio de Janeiro'];
    for (const c of cities) global.cityWeather[c] = '☀️ Clear';
}

function updateWeather() {
    const cities = ['Weirdos World','Mexico','London','Japan','Switzerland','Dubai','New York','Paris','Lagos','Moscow','Sydney','Rio de Janeiro'];
    for (const city of cities) {
        if (Math.random() < 0.35) { // 35% chance weather changes per city per tick
            const w = WEATHER_CONDITIONS[Math.floor(Math.random() * WEATHER_CONDITIONS.length)];
            const old = global.cityWeather[city];
            global.cityWeather[city] = w;
            if (WEATHER_SEVERITY[w] >= 3 && WEATHER_SEVERITY[old] < 3) {
                logGlobal('🌪️', `*WEATHER ALERT* — ${city} is experiencing *${w}*! Flights and travel disrupted.`);
            }
        }
    }
}
setInterval(updateWeather, 30 * 60 * 1000);

function isTravelBlocked(city) {
    const w = global.cityWeather[city] || '☀️ Clear';
    return WEATHER_SEVERITY[w] >= 3; // Blizzard, Hurricane block travel
}

function travelWarning(city) {
    const w = global.cityWeather[city] || '☀️ Clear';
    const sev = WEATHER_SEVERITY[w];
    if (sev >= 3) return `⛔ *${city}* is currently experiencing *${w}*. All travel is blocked.`;
    if (sev >= 2) return `⚠️ *${city}* has *${w}*. Travel is risky — +50% flight time.`;
    if (sev >= 1) return `🌧️ *${city}* has *${w}* — minor delays possible.`;
    return null;
}

cast({ pattern: 'weather', desc: 'Check weather conditions in all cities', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const lines = [`🌍 *WEIRDOS WORLD WEATHER REPORT*`, ``];
        for (const [city, w] of Object.entries(global.cityWeather)) {
            const sev = WEATHER_SEVERITY[w] || 0;
            const status = sev >= 3 ? '⛔ BLOCKED' : sev >= 2 ? '⚠️ DANGEROUS' : sev >= 1 ? '🔶 DELAYS' : '✅ CLEAR';
            lines.push(`${w} *${city}* — ${status}`);
        }
        lines.push(``, `_Updates every 30 minutes. Severe weather blocks all travel._`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) { console.error('weather error', e); }
});

