// =============================================================================
// AGE & DEATH SYSTEM
// Players have an age (days since registration). Random death chance on actions.
// On death: lose everything, start fresh. 5% chance per fatal event.
// =============================================================================
function getPlayerAge(p) {
    const born = p.bornAt || (p.createdAt ? new Date(p.createdAt).getTime() : Date.now());
    const ms   = Date.now() - born;
    const days = Math.floor(ms / 86400000);
    const hrs  = Math.floor((ms % 86400000) / 3600000);
    return { days, hrs, born };
}

async function rollDeathChance(p, conn, from, mek, context) {
    if (Math.random() > 0.05) return false; // 5% chance
    // Death — wipe everything and restart
    const age = getPlayerAge(p);
    p.deathCount = (p.deathCount || 0) + 1;
    const oldName = p.username;
    const oldLevel = p.level;

    // Wipe all assets
    p.money      = 100;
    p.bank       = 0;
    p.level      = 1;
    p.exp        = 0;
    p.strength   = 3; p.defense = 3; p.speed = 3; p.dexterity = 3;
    p.health     = 100; p.maxHealth = 100;
    p.energy     = 100;
    p.inventory  = new Map();
    p.properties = new Map();
    p.pet        = null;
    p.faction    = null;
    p.spouse     = null; p.marriageRole = null; p.marriedAt = 0;
    p.activeDrugs = [];
    p.equippedWeapon = null; p.equippedArmor = null;
    p.equippedHelmet = null; p.equippedGloves = null;
    p.equippedKneePads = null; p.equippedBoots = null;
    p.jailedUntil = 0;
    p.crimeLevel  = 0;
    // Tax debt and shark loan SURVIVE death — can't escape debt by dying
    // p.taxOwed preserved intentionally
    p.taxableIncome = 0;
    p.investments   = [];
    // Shark loan: keeps the debt but resets compound timer to now (mercy on interest)
    if (p.activeLoan && p.activeLoan.owed > 0) {
        p.activeLoan.lastCompound = Date.now();
        p.activeLoan.takenAt = Date.now(); // restart grace period
    }
    p.bornAt      = Date.now(); // reset age
    p.markModified('inventory'); p.markModified('properties'); p.markModified('activeDrugs');
    await p.save();

    logGlobal('💀', `*${oldName}* (Level ${oldLevel}) has DIED at age ${age.days} days during ${context}. They lose EVERYTHING and start over.`);

    await conn.sendMessage(from, {
        text: [
            `💀 *YOU DIED*`,``,
            `While ${context}, death came for you.`,``,
            `📅 Age at death: *${age.days} days, ${age.hrs} hours*`,
            `🎖️ Level at death: *${oldLevel}*`,
            `💀 Total deaths: *${p.deathCount}*`,``,
            `You have lost *EVERYTHING*.`,
            `You wake up broke, level 1, with nothing.`,``,
            `_This is Weirdos World. Nobody lives forever._`
        ].join('\n')
    }, { quoted: mek });
    return true;
}

