// =============================================================================
// PLAYER-TO-PLAYER LOANS
// Players can lend money to others and set their own interest rate.
// =============================================================================
const P2PLoanSchema = new Schema({
    lenderId:   { type: String, required: true },
    borrowerId: { type: String, required: true },
    principal:  { type: Number, required: true },
    owed:       { type: Number, required: true },
    ratePerHour:{ type: Number, default: 0.05 }, // 5% per hour default
    takenAt:    { type: Number, default: Date.now },
    lastCompound:{ type: Number, default: Date.now },
    status:     { type: String, default: 'active' }, // active | paid
}, { collection: 'weirdo_p2ploans' });
const P2PLoan = mongoose.models.WWRPGP2PLoan || mongoose.model('WWRPGP2PLoan', P2PLoanSchema);

cast({ pattern: 'lend', desc: 'lend @player <amount> [interest%/hr] — Lend money to another player', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't lend from jail.` }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId || targetId === pId) return conn.sendMessage(from, { text: `Usage: lend @player <amount> [interest%]\ne.g. lend @player 50000 10\n(10% interest per hour, default 5%)` }, { quoted: mek });

        const amount   = parseInt(args[1]);
        const rateArg  = parseFloat(args[2]);
        const rateHr   = isNaN(rateArg) ? 0.05 : Math.min(0.50, Math.max(0.01, rateArg / 100));

        if (!amount || amount <= 0) return conn.sendMessage(from, { text: `Enter a valid amount.` }, { quoted: mek });
        if (p.money < amount) return conn.sendMessage(from, { text: `You only have ${fmtMoney(p.money)} in your wallet.` }, { quoted: mek });

        // Check borrower doesn't already have an active p2p loan from this lender
        const existing = await P2PLoan.findOne({ lenderId: pId, borrowerId: targetId, status: 'active' }).exec();
        if (existing) return conn.sendMessage(from, { text: `You already have an active loan with @${targetId}. They need to pay it off first.` }, { quoted: mek });

        const borrower = await getOrCreatePlayer(targetId);
        p.money   -= amount;
        borrower.money += amount;

        const loan = new P2PLoan({ lenderId: pId, borrowerId: targetId, principal: amount, owed: amount, ratePerHour: rateHr, takenAt: Date.now(), lastCompound: Date.now() });
        await loan.save();
        await p.save();
        await borrower.save();

        logGlobal('💸', `*${p.username || pId}* lent *${fmtMoney(amount)}* to *${borrower.username || targetId}* at ${(rateHr*100).toFixed(0)}%/hr interest.`);
        return conn.sendMessage(from, {
            text: [`💸 *LOAN ISSUED*`,``, `You lent *${fmtMoney(amount)}* to @${targetId}`,`📈 Interest: *${(rateHr*100).toFixed(0)}% per hour* (compounds hourly)`,``,`They can pay with: *repay @you <amount>*`].join('\n'),
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch(e) { console.error('lend error', e); }
});

cast({ pattern: 'plrepay', desc: 'plrepay @lender <amount|all> — Repay a player-to-player loan', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const lenderId = await getTargetId(conn, mek, args, 0);
        if (!lenderId) return conn.sendMessage(from, { text: `Usage: repay @lender <amount|all>` }, { quoted: mek });

        const loan = await P2PLoan.findOne({ borrowerId: pId, lenderId, status: 'active' }).exec();
        if (!loan) return conn.sendMessage(from, { text: `You have no active loan from @${lenderId}.` }, { quoted: mek });

        // Apply hourly compound interest
        const hoursElapsed = (Date.now() - loan.lastCompound) / 3600000;
        const ticks = Math.floor(hoursElapsed);
        if (ticks > 0) {
            for (let i = 0; i < ticks; i++) loan.owed = Math.ceil(loan.owed * (1 + loan.ratePerHour));
            loan.lastCompound = Date.now();
        }

        const amtArg = (args[1] || '').toLowerCase();
        const pay    = amtArg === 'all' ? Math.min(p.money, loan.owed) : parseInt(args[1]);
        if (!pay || pay <= 0) return conn.sendMessage(from, { text: `You owe *${fmtMoney(loan.owed)}*.\nUsage: repay @${lenderId} <amount|all>` }, { quoted: mek });
        if (p.money < pay) return conn.sendMessage(from, { text: `Not enough cash. You have ${fmtMoney(p.money)}, owe ${fmtMoney(loan.owed)}.` }, { quoted: mek });

        p.money -= pay;
        loan.owed -= pay;

        const lender = await getOrCreatePlayer(lenderId);
        lender.money += pay;
        await lender.save();

        if (loan.owed <= 0) {
            loan.status = 'paid';
            await loan.save(); await p.save();
            return conn.sendMessage(from, { text: `✅ *LOAN CLEARED!* You repaid @${lenderId} in full.`, mentions: [toJid(lenderId)] }, { quoted: mek });
        }
        await loan.save(); await p.save();
        return conn.sendMessage(from, { text: `💸 Paid *${fmtMoney(pay)}* to @${lenderId}. Remaining: *${fmtMoney(loan.owed)}*`, mentions: [toJid(lenderId)] }, { quoted: mek });
    } catch(e) { console.error('repay error', e); }
});

cast({ pattern: 'myloans', desc: 'View all loans you gave and received', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId   = await getPlayerId(conn, sender);
        const given = await P2PLoan.find({ lenderId: pId, status: 'active' }).exec();
        const rcvd  = await P2PLoan.find({ borrowerId: pId, status: 'active' }).exec();

        const lines = [`💸 *YOUR LOANS*`, ``];
        if (given.length) {
            lines.push(`📤 *Money you lent out:*`);
            for (const l of given) {
                const hrs = (Date.now() - l.lastCompound) / 3600000;
                const live = Math.ceil(l.owed * Math.pow(1 + l.ratePerHour, Math.floor(hrs)));
                lines.push(`  @${l.borrowerId} — owes *${fmtMoney(live)}* @ ${(l.ratePerHour*100).toFixed(0)}%/hr`);
            }
            lines.push(``);
        }
        if (rcvd.length) {
            lines.push(`📥 *Money you owe:*`);
            for (const l of rcvd) {
                const hrs = (Date.now() - l.lastCompound) / 3600000;
                const live = Math.ceil(l.owed * Math.pow(1 + l.ratePerHour, Math.floor(hrs)));
                lines.push(`  To @${l.lenderId} — *${fmtMoney(live)}* @ ${(l.ratePerHour*100).toFixed(0)}%/hr`);
                lines.push(`  Repay: *plrepay @${l.lenderId} all*`);
            }
        }
        if (!given.length && !rcvd.length) lines.push(`No active loans.`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) { console.error('myloans error', e); }
});

// =============================================================================
// CREDIT SCORE — Affects loan shark max and interest rate
// Score: 300 (terrible) to 850 (excellent)
// Factors: on-time loan repayments, wealth level, crime level, tax compliance
// =============================================================================
function getCreditScore(p) {
    let score = 580; // base

    // Wealth — more money = better credit
    const total = (p.money || 0) + (p.bank || 0);
    if (total >= 10_000_000)  score += 80;
    else if (total >= 1_000_000) score += 50;
    else if (total >= 100_000)   score += 20;
    else if (total < 1000)       score -= 50;

    // Crime level — high crime = bad credit
    const heat = p.crimeLevel || 0;
    if (heat >= 75) score -= 100;
    else if (heat >= 50) score -= 60;
    else if (heat >= 25) score -= 30;
    else if (heat === 0) score += 30;

    // Tax compliance
    if ((p.taxOwed || 0) > 1_000_000) score -= 80;
    else if ((p.taxOwed || 0) > 100_000) score -= 40;
    else if ((p.taxPaid || 0) > 500_000) score += 40;

    // Level — higher level = established citizen
    const lvl = p.level || 1;
    if (lvl >= 50) score += 50;
    else if (lvl >= 20) score += 25;
    else if (lvl < 5) score -= 20;

    // Deaths
    if ((p.deathCount || 0) >= 3) score -= 60;
    else if ((p.deathCount || 0) >= 1) score -= 20;

    return Math.min(850, Math.max(300, score));
}

function creditRating(score) {
    // Rates MUST match economy.js loan system exactly
    if (score >= 750) return { label: '⭐ Excellent', maxLoan: 2_000_000, hourlyRate: 0.005 };
    if (score >= 680) return { label: '✅ Good',      maxLoan: 1_000_000, hourlyRate: 0.008 };
    if (score >= 580) return { label: '🟡 Fair',      maxLoan: 500_000,   hourlyRate: 0.010 };
    if (score >= 480) return { label: '🔴 Poor',      maxLoan: 200_000,   hourlyRate: 0.012 };
    return               { label: '💀 Very Poor',     maxLoan: 50_000,    hourlyRate: 0.015 };
}

cast({ pattern: 'creditscore', desc: 'Check your credit score and loan eligibility', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p     = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const score = getCreditScore(p);
        const { label, maxLoan, hourlyRate } = creditRating(score);
        // Project what 500k would cost at this rate
        const sampleLoan = 500_000;
        const proj6h  = Math.ceil(sampleLoan * Math.pow(1 + hourlyRate, 4));  // 6h - 2h grace
        const proj24h = Math.ceil(sampleLoan * Math.pow(1 + hourlyRate, 22)); // 24h - 2h grace
        return conn.sendMessage(from, { text: [
            `📊 *CREDIT SCORE*`, ``,
            `Score: *${score}/850* — ${label}`, ``,
            `💳 Max loan: *${fmtMoney(maxLoan)}*`,
            `📈 Your rate: *${(hourlyRate*100).toFixed(1)}%/hr* (hourly compounding, 2hr grace)`,
            ``,
            `Example — $500k loan would cost:`,
            `   After 6hr: ~${fmtMoney(proj6h)}`,
            `   After 24hr: ~${fmtMoney(proj24h)}`,
            ``,
            `Improve your score:`,
            `• Pay taxes on time`,
            `• Keep crime heat low`,
            `• Accumulate wealth`,
            `• Level up`,
            `• Don't die`
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('creditscore error', e); }
});

// =============================================================================
// IN-GAME NEWS FEED — Shows recent game events
// =============================================================================
const NEWS_MAX = 100;
if (!global.wwNewsLog) global.wwNewsLog = [];

// Load persisted news from DB on startup
(async () => {
    try {
        const db = await connectDB();
        const saved = await db.collection('ww_news').find().sort({ at: -1 }).limit(NEWS_MAX).toArray();
        if (saved.length && global.wwNewsLog.length === 0) {
            global.wwNewsLog = saved.map(n => ({ ts: n.ts, category: n.category, msg: n.msg }));
        }
    } catch(e) { /* non-critical — starts empty if DB unavailable */ }
})();

cast({ pattern: 'news', desc: 'Read the Weirdos World news feed', category: 'rpg', filename: __filename }, async (conn, mek, m, { from, args }) => {
    try {
        const filter = (args[0] || '').toLowerCase();
        let items = global.wwNewsLog || [];
        if (filter) items = items.filter(n => n.category?.toLowerCase().includes(filter) || n.msg?.toLowerCase().includes(filter));
        if (!items.length) return conn.sendMessage(from, { text: `📰 No news yet. Get out there and make some.` }, { quoted: mek });

        const lines = [`📰 *WEIRDOS WORLD NEWS*`, `_${items.length} recent events_`, ``];
        for (const n of items.slice(0, 20)) {
            lines.push(`[${n.ts}] ${n.msg}`);
        }
        lines.push(``, `_Filter: news crime | news gambling | news attack_`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) { console.error('news error', e); }
});

// =============================================================================
// GLOBAL COMMAND COOLDOWN — Prevents spam (1 second between any commands)
// =============================================================================
const cmdCooldowns = new Map(); // playerId → lastCmdAt
const CMD_GLOBAL_CD = 1500; // 1.5 seconds

function checkGlobalCooldown(playerId) {
    const last = cmdCooldowns.get(playerId) || 0;
    const diff = Date.now() - last;
    if (diff < CMD_GLOBAL_CD) return CMD_GLOBAL_CD - diff;
    cmdCooldowns.set(playerId, Date.now());
    return 0;
}

