// NEW CASINO GAME: DICE POKER — Roll 5 dice, bet on your hand
// gamble dice <amount>
// =============================================================================
cast({ pattern: 'dicegame', desc: 'dicegame <amount> — Roll 5 dice for poker hands', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't gamble from hospital.` }, { quoted: mek });
        const amount = parseInt(args[0]);
        if (!amount || amount <= 0) return conn.sendMessage(from, { text: [`🎲 *DICE POKER*`,``,`Roll 5 dice and score based on the hand.`,``,`Payouts:`,`• Five of a kind — 7x`,`• Four of a kind — 3.5x`,`• Full house (3+2) — 2x`,`• Three of a kind — 1.5x`,`• Two pair — 1.1x`,`• Pair — no payout`,`• Nothing — lose bet`,``,`*dicegame <amount>*`].join('\n') }, { quoted: mek });
        const MAX_BET = 50_000_000;
        if (amount > MAX_BET) return conn.sendMessage(from, { text: `Max bet: ${fmtMoney(MAX_BET)}` }, { quoted: mek });
        if (p.money < amount) return conn.sendMessage(from, { text: `Not enough cash.` }, { quoted: mek });

        const dice = Array.from({length:5}, () => Math.floor(Math.random()*6)+1);
        const counts = {};
        dice.forEach(d => counts[d] = (counts[d]||0)+1);
        const vals = Object.values(counts).sort((a,b)=>b-a);

        let mult = 0, hand = '';
        if (vals[0] === 5)                          { mult = 7;    hand = '🎯 FIVE OF A KIND!'; }
        else if (vals[0] === 4)                      { mult = 3.5;  hand = '🔥 FOUR OF A KIND!'; }
        else if (vals[0] === 3 && vals[1] === 2)     { mult = 2;    hand = '🏠 FULL HOUSE!'; }
        else if (vals[0] === 3)                      { mult = 1.5;  hand = '✅ THREE OF A KIND'; }
        else if (vals[0] === 2 && vals[1] === 2)     { mult = 1.1;  hand = '👥 TWO PAIR'; }
        else if (vals[0] === 2)                      { mult = 0;    hand = '🎲 ONE PAIR — no payout'; }
        else                                         { mult = 0;    hand = '💀 NOTHING'; }

        p.money -= amount;
        const winAmount = mult > 0 ? Math.floor(amount * mult) : 0;
        if (winAmount > 0) {
            p.money += winAmount;
            addTaxableIncome(p, winAmount - amount);
            logFinancial(p, `Dice game win`, winAmount - amount);
        } else {
            global.casinoJackpot += Math.floor(amount * 0.05);
        }
        await p.save();
        return conn.sendMessage(from, { text: [
            `🎲 *DICE POKER*`,``,
            `Dice: ${dice.map(d=>`[${d}]`).join(' ')}`,``,
            `${hand}`,
            mult > 0 ? `💰 *Won ${fmtMoney(winAmount)}!* (${mult}x)` : `💸 Lost ${fmtMoney(amount)}.`
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('dicegame error', e); }
});

