// ─────────────────────────────────────────────────────────────────────────────
// DRUG ADDICTION SYSTEM
// Heavy drug use causes addiction. Addicted players get stat penalties.
// Must pay for rehab or stats degrade further.
// ─────────────────────────────────────────────────────────────────────────────
const ADDICTION_THRESHOLDS = [0, 5, 15, 30, 60, 100]; // uses needed per drug to reach each level
const REHAB_COST = [0, 50000, 200000, 500000, 1500000, 5000000]; // rehab cost per addiction level
const REHAB_TIME = [0, 2, 6, 12, 24, 48]; // hours in rehab per level

function getAddictionPenalty(p) {
    const lvl = p.addictionLevel || 0;
    if (lvl === 0) return {};
    return {
        strPenalty: lvl * 2,
        defPenalty: lvl * 2,
        spdPenalty: lvl,
        energyPenalty: lvl * 10,
        label: ['', '😰 Mild', '😨 Moderate', '😱 Heavy', '💀 Severe', '☠️ Terminal'][lvl],
    };
}

cast({ pattern: 'rehab', desc: 'Check addiction status or enter rehab', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p   = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const sub = (args[0] || 'status').toLowerCase();
        const lvl = p.addictionLevel || 0;
        const pen = getAddictionPenalty(p);

        if (sub === 'status') {
            if (lvl === 0) return conn.sendMessage(from, { text: [`💊 *ADDICTION STATUS*`, ``, `You are *clean*. No active addiction.`, ``, `_Using the same drug repeatedly builds addiction._`].join('\n') }, { quoted: mek });
            if (p.inRehab && p.rehabUntil > now()) {
                return conn.sendMessage(from, { text: [`🏥 *IN REHAB*`, ``, `Drug: ${p.addictionDrug}`, `Addiction Level: ${lvl}/5 — ${pen.label}`, `Leaving rehab in: ${shortTime(p.rehabUntil - now())}`, ``, `_Rest up. You're getting better._`].join('\n') }, { quoted: mek });
            }
            return conn.sendMessage(from, { text: [
                `💊 *ADDICTION STATUS*`, ``,
                `Drug: *${p.addictionDrug || 'Unknown'}*`,
                `Level: *${lvl}/5 — ${pen.label}*`,
                ``, `Penalties:`,
                `  STR -${pen.strPenalty} | DEF -${pen.defPenalty} | SPD -${pen.spdPenalty}`,
                `  Energy max -${pen.energyPenalty}`,
                ``, `Rehab cost: *${fmtMoney(iC(REHAB_COST[lvl]))}* | Duration: ${REHAB_TIME[lvl]} hours`,
                `Enter rehab: *rehab enter*`,
            ].join('\n') }, { quoted: mek });
        }

        if (sub === 'enter') {
            if (lvl === 0) return conn.sendMessage(from, { text: `You're not addicted. Enjoy your clean life.` }, { quoted: mek });
            if (p.inRehab && p.rehabUntil > now()) return conn.sendMessage(from, { text: `You're already in rehab!` }, { quoted: mek });
            const cost = iC(REHAB_COST[lvl]);
            if (p.money < cost) return conn.sendMessage(from, { text: `Rehab costs ${fmtMoney(cost)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
            p.money    -= cost;
            p.inRehab   = true;
            p.rehabUntil = now() + REHAB_TIME[lvl] * 3600000;
            p.jailedUntil = p.rehabUntil; // locked in rehab (no fighting)
            logFinancial(p, `Rehab for ${p.addictionDrug} addiction`, -cost);
            await p.save();
            return conn.sendMessage(from, { text: [`🏥 *CHECKED INTO REHAB*`, ``, `Cost: *${fmtMoney(cost)}*`, `Duration: *${REHAB_TIME[lvl]} hours*`, ``, `You'll be addiction-free when you get out.`].join('\n') }, { quoted: mek });
        }

        return conn.sendMessage(from, { text: `Usage: rehab status | rehab enter` }, { quoted: mek });
    } catch(e) { console.error('rehab error', e); }
});

// Check addiction on rehab exit
setInterval(async () => {
    try {
        const players = await Player.find({ inRehab: true, rehabUntil: { $lte: Date.now() } }).exec();
        for (const p of players) {
            p.inRehab = false; p.rehabUntil = 0; p.jailedUntil = 0;
            p.addictionLevel = 0; p.addictionDrug = null;
            logGlobal('🏥', `*${p.username||p._id}* completed rehab and is now *clean*!`);
            await p.save();
        }
    } catch(e) {}
}, 10 * 60 * 1000);

