// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'jailstatus', desc: 'View jail options while incarcerated', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (!isHospitalized(p)) return conn.sendMessage(from, { text: `You're not in jail or hospital.` }, { quoted: mek });
        const remaining = p.jailedUntil - now();
        const isJailed  = p.inJail === true;

        if (isJailed) {
            return conn.sendMessage(from, { text: [
                `⛓️ *IN JAIL* — ${shortTime(remaining)} remaining`,
                ``,
                `*Your options:*`,
                `🔨 *jailwork* — Work prison shifts (-12 min each, max 3 per sentence, total -36 min)`,
                `📞 *lawyercall* — Your lawyer cuts 50% off immediately (costs ${fmtMoney(10000*(p.level||1))}, once per sentence)`,
                `📞 *callawyer @player* — Ask a friend with a Law degree to help (scales with their qualification)`,
                `💰 *bailout <amount>* — Bribe the cops (expensive, max 50% off)`,
                `🤝 *helpbailout @player* — Ask a friend to pay your bail`,
                `🏃 *jailbreak* — Risky escape attempt (35% chance, +30min if caught)`,
                ``,
                `_You CANNOT use medkits in jail. Medkits are for hospital only._`,
            `💸 Bail processing fee on release: *${fmtMoney(Math.min(30000,Math.max(1000,Math.floor(((p.sentenceMs||0)/60000)/35*30000))))}*`,
            ].join('\n') }, { quoted: mek });
        } else {
            return conn.sendMessage(from, { text: [
                `🏥 *IN HOSPITAL* — ${shortTime(remaining)} remaining`,
                `HP: ${p.health}/${p.maxHealth||100} (need 40 HP to be discharged)`,
                ``,
                `*Your options:*`,
                `💊 *use medkit* — Heals 5-10 HP each. Reach 40 HP to leave.`,
                `💰 *paymeds <amount>* — Pay private doctors to cut your stay (max 60% off)`,
                `📞 *callnurse @player* — Ask a friend with a Nursing degree to treat you (faster recovery)`,
                `⏳ Wait — HP recovers naturally over time`,
            ].join('\n') }, { quoted: mek });
        }
    } catch(e) { console.error('jailstatus error', e); }
});

cast({ pattern: 'jailwork', desc: 'Work while jailed for sentence reduction', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (!isHospitalized(p)) return conn.sendMessage(from, { text: `You're not in jail.` }, { quoted: mek });
        if ((p.jailWorkDone || 0) >= 3) return conn.sendMessage(from, { text: `You've already done the maximum 3 work shifts this sentence.\nUse *lawyercall* or wait out the remaining time.` }, { quoted: mek });
        // Prison gang bonus: -5 extra minutes per shift
        const gangBonus = p.prisonGang ? 5 * 60 * 1000 : 0;
        const reduction = 12 * 60 * 1000 + gangBonus;
        p.jailedUntil  -= reduction;
        p.jailWorkDone  = (p.jailWorkDone || 0) + 1;
        p.manualLabor   = (p.manualLabor || 0) + 2;
        p.cooldowns = p.cooldowns || {};
        p.cooldowns.jailwork = now();
        p.markModified('cooldowns');
        await p.save();
        return conn.sendMessage(from, { text: [
            `🔨 *JAIL WORK SHIFT*`, ``,
            `⏱️ Sentence reduced by *${shortTime(reduction)}*${gangBonus ? ` (incl. ⛓️ +5min gang bonus)` : ''}`,
            `💪 +2 Manual Labor`,
            `Remaining: *${shortTime(Math.max(0, p.jailedUntil - now()))}*`,
            `Shifts used: *${p.jailWorkDone}/3*`,
            ``,
            `_No pay — you work to earn your freedom._`,
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('jailwork error', e); }
});

cast({ pattern: 'lawyercall', desc: 'Call your lawyer for 50% sentence reduction (once per sentence)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const p = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (!isHospitalized(p)) return conn.sendMessage(from, { text: `You're not in jail.` }, { quoted: mek });
        if (p.lawyerCallUsed) return conn.sendMessage(from, { text: `You already used your lawyer call this sentence.` }, { quoted: mek });
        const cost = 10000 * (p.level || 1);
        if (p.money < cost) return conn.sendMessage(from, { text: `Lawyer fee: ${fmtMoney(cost)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
        const remaining  = p.jailedUntil - now();
        const reduction  = Math.floor(remaining * 0.50);
        p.jailedUntil   -= reduction;
        p.money         -= cost;
        p.lawyerCallUsed = true;
        // Law degree gives extra discount
        if ((p.degrees||[]).some(d => d.startsWith('law_'))) {
            p.jailedUntil -= Math.floor(reduction * 0.20); // extra 20% off
        }
        logFinancial(p, `Lawyer call`, -cost);
        await p.save();
        return conn.sendMessage(from, { text: [
            `📞 *LAWYER CALL*`, ``,
            `Cost: ${fmtMoney(cost)}`,
            `Sentence reduced by 50%${(p.degrees||[]).some(d=>d.startsWith('law_')) ? ' + 20% (Law degree)' : ''}`,
            `Remaining: *${shortTime(Math.max(0, p.jailedUntil - now()))}*`,
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('lawyercall error', e); }
});

cast({ pattern: 'visitjail', desc: 'Visit a jailed friend and boost their morale', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId     = await getPlayerId(conn, sender);
        const p       = await getOrCreatePlayer(pId);
        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId || targetId === pId) return conn.sendMessage(from, { text: `Usage: visitjail @player` }, { quoted: mek });
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `You can't visit from jail.` }, { quoted: mek });
        const target = await getOrCreatePlayer(targetId);
        if (!isHospitalized(target)) return conn.sendMessage(from, { text: `@${targetId} isn't in jail.`, mentions: [toJid(targetId)] }, { quoted: mek });
        if ((target.jailVisitedBy || []).includes(pId)) return conn.sendMessage(from, { text: `You already visited them this sentence.` }, { quoted: mek });
        // Reduce their time by 5 min, give them energy
        target.jailedUntil   -= 5 * 60 * 1000;
        target.energy         = Math.min(target.maxEnergy || 100, (target.energy || 0) + 10);
        target.jailVisitedBy  = [...(target.jailVisitedBy || []), pId];
        await target.save();
        return conn.sendMessage(from, { text: `🤝 You visited *@${targetId}* in jail! Their sentence was reduced by 5 minutes.`, mentions: [toJid(targetId)] }, { quoted: mek });
    } catch(e) { console.error('visitjail error', e); }
});

