const BLACK_MARKET_ITEMS = [
    { id: 'silencer',       name: 'Silenced Pistol',     type: 'weapon', atkBonus: 55,  price: 120000,  rarity: 'rare',      desc: '+55 Atk. Silent — no crime heat on use.' },
    { id: 'emp',            name: 'EMP Device',          type: 'weapon', atkBonus: 80,  price: 300000,  rarity: 'epic',      desc: '+80 Atk. Disables target gear for 1 fight.' },
    { id: 'explosivebelt',  name: 'Explosive Vest',      type: 'armor',  defBonus: 150, price: 500000,  rarity: 'epic',      desc: '+150 Def. One-time use — explodes on KO.' },
    { id: 'poisonblade',    name: 'Poison Blade',        type: 'weapon', atkBonus: 120, price: 800000,  rarity: 'legendary', desc: '+120 Atk. Poisons target: -5 HP/min for 1hr.' },
    { id: 'ghostsuit',      name: 'Ghost Suit',          type: 'armor',  defBonus: 200, price: 2000000, rarity: 'legendary', desc: '+200 Def. Immune to pickpocket and kidnap.' },
    { id: 'megaboost',      name: 'Stat Booster',        type: 'consumable', heal: 0,   price: 5000000, rarity: 'legendary', desc: '+10 to ALL stats permanently. One use.' },
    { id: 'forgeddocs',     name: 'Forged Documents',    type: 'consumable', heal: 0,   price: 200000,  rarity: 'rare',      desc: 'Instantly clears crime heat to 0.' },
    { id: 'invisibilitydrug',name: 'Invisibility Drug',  type: 'drug',   heal: 0,       price: 750000,  rarity: 'epic',      desc: '8hrs rob immunity + can\'t be attacked.' },
];

// Black market stock resets every 6 hours with random selection of 4-6 items
if (!global.blackMarketStock) {
    global.blackMarketStock = { items: [], refreshAt: 0 };
}
function refreshBlackMarket() {
    if (Date.now() < global.blackMarketStock.refreshAt) return;
    const count = 4 + Math.floor(Math.random() * 3);
    const shuffled = [...BLACK_MARKET_ITEMS].sort(() => Math.random() - 0.5);
    global.blackMarketStock = {
        items: shuffled.slice(0, count).map(item => ({ ...item, stock: 1 + Math.floor(Math.random() * 3) })),
        refreshAt: Date.now() + 6 * 60 * 60 * 1000,
    };
}
setInterval(refreshBlackMarket, 60 * 60 * 1000);
refreshBlackMarket();

cast({ pattern: 'blackmarket', desc: 'Browse illegal black market items', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId  = await getPlayerId(conn, sender);
        const p    = await getOrCreatePlayer(pId);
        const sub  = (args[0] || 'browse').toLowerCase();
        refreshBlackMarket();

        if (sub === 'browse' || sub === 'list') {
            const timeLeft = global.blackMarketStock.refreshAt - Date.now();
            const lines = [`🕵️ *BLACK MARKET*`, `_Refreshes in ${shortTime(timeLeft)}_`, ``];
            global.blackMarketStock.items.forEach((item, i) => {
                const rarityEmoji = { common:'⚪', uncommon:'🟢', rare:'🔵', epic:'🟣', legendary:'🟡' }[item.rarity] || '⚪';
                lines.push(`${rarityEmoji} *${i+1}. ${item.name}* — ${fmtMoney(iC(item.price))} (${item.stock} left)`);
                lines.push(`   ${item.desc}`);
            });
            lines.push(``, `Buy: *deal <number>* e.g. *deal 1*`);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }
        return conn.sendMessage(from, { text: `Browse: *blackmarket* | Buy: *deal <number>*` }, { quoted: mek });
    } catch(e) { console.error('blackmarket error', e); }
});

cast({ pattern: 'deal', desc: 'Buy from the black market', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p    = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Use *jailstatus* for options.` }, { quoted: mek });
        refreshBlackMarket();
        const idx  = (parseInt(args[0]) || 0) - 1;
        const item = global.blackMarketStock.items[idx];
        if (!item) return conn.sendMessage(from, { text: `Invalid selection. Type *blackmarket* to browse.` }, { quoted: mek });
        if (item.stock <= 0) return conn.sendMessage(from, { text: `💨 Sold out. Check back after refresh.` }, { quoted: mek });
        const price = iC(item.price);
        if (p.money < price) return conn.sendMessage(from, { text: `Not enough cash. Costs ${fmtMoney(price)}, you have ${fmtMoney(p.money)}.` }, { quoted: mek });

        p.money -= price;
        p.moneySpent = (p.moneySpent||0) + price;
        item.stock--;
        p.crimeLevel = Math.min(100, (p.crimeLevel || 0) + 5); // black market raises heat

        // Special item handling
        if (item.id === 'megaboost') {
            p.strength  += 10; p.defense  += 10; p.speed    += 10; p.dexterity += 10;
            logAction(p, `Used Stat Booster from black market`);
        } else if (item.id === 'forgeddocs') {
            p.crimeLevel = 0;
            logAction(p, `Used forged documents — crime heat cleared`);
        } else if (item.id === 'invisibilitydrug') {
            p.robImmunityUntil = now() + 8 * 60 * 60 * 1000;
        } else {
            // Add to inventory
            const inv = p.inventory instanceof Map ? p.inventory : new Map(Object.entries(p.inventory||{}));
            inv.set(item.id, (inv.get(item.id)||0) + 1);
            p.inventory = inv;
        }
        p.markModified('inventory');
        const achievMsg = await awardAchievements(p);
        await p.save();
        logFinancial(p, `Black market: ${item.name}`, -price);
        return conn.sendMessage(from, { text: [
            `🕵️ *DEAL DONE*`, ``,
            `📦 ${item.name} acquired`,
            `💸 Paid: ${fmtMoney(price)}`,
            `🔴 Crime heat +5`,
            item.id === 'megaboost' ? `💪 All stats +10!` : null,
            item.id === 'forgeddocs' ? `✅ Crime heat cleared!` : null,
        ].filter(Boolean).join('\n') + achievMsg }, { quoted: mek });
    } catch(e) { console.error('deal error', e); }
});

