// ─────────────────────────────────────────────────────────────────────────────
// STOCK MARKET EVENTS — Random news that shocks specific sectors
// ─────────────────────────────────────────────────────────────────────────────
const STOCK_EVENTS = [
    { name: 'Tech Boom',         sector: 'Tech',          mult: 1.40, desc: '🚀 AI revolution drives Tech stocks up 40%!' },
    { name: 'Tech Crash',        sector: 'Tech',          mult: 0.55, desc: '💻 Major hack wipes 45% off Tech valuations!' },
    { name: 'Crime Wave',        sector: 'Crime',         mult: 1.35, desc: '🦹 City crime surge boosts underworld stocks!' },
    { name: 'Police Crackdown',  sector: 'Crime',         mult: 0.60, desc: '🚔 Mass arrests tank Crime sector stocks!' },
    { name: 'Arms Deal',         sector: 'Defense',       mult: 1.50, desc: '💣 Massive weapons contract signed — Defense up 50%!' },
    { name: 'Peace Treaty',      sector: 'Defense',       mult: 0.65, desc: '☮️ Global peace talks crater Defense stocks!' },
    { name: 'Drug Legalisation', sector: 'Pharma',        mult: 1.60, desc: '💊 Surprise legalisation rockets Pharma stocks!' },
    { name: 'Casino Raid',       sector: 'Entertainment', mult: 0.50, desc: '🃏 Federal raid closes all casinos — Entertainment crashes!' },
    { name: 'High Rollers',      sector: 'Entertainment', mult: 1.45, desc: '🎰 Record gambling revenue — Entertainment soars!' },
    { name: 'Supply Chain Hit',  sector: 'Logistics',     mult: 0.70, desc: '🚢 Port blockade hammers Logistics sector!' },
    { name: 'Market Panic',      sector: 'ALL',           mult: 0.75, desc: '📉 Global market panic — all sectors down 25%!' },
    { name: 'Bull Run',          sector: 'ALL',           mult: 1.25, desc: '📈 Investor confidence surge — everything up 25%!' },
];

// Fire random stock event every 4-8 hours
setInterval(async () => {
    try {
        if (Math.random() > 0.30) return; // 30% chance per check
        const evt = STOCK_EVENTS[Math.floor(Math.random() * STOCK_EVENTS.length)];
        const STOCK_LIST = [
            { ticker: 'TORN', sector: 'Conglomerate' }, { ticker: 'BLCK', sector: 'Crime' },
            { ticker: 'MXCO', sector: 'Crime' }, { ticker: 'ARMS', sector: 'Defense' },
            { ticker: 'NRCO', sector: 'Pharma' }, { ticker: 'CASP', sector: 'Entertainment' },
            { ticker: 'SMUG', sector: 'Logistics' }, { ticker: 'HKRS', sector: 'Tech' },
        ];
        const affected = STOCK_LIST.filter(s => evt.sector === 'ALL' || s.sector === evt.sector);
        for (const s of affected) {
            await Stock.updateOne({ ticker: s.ticker }, { $mul: { price: evt.mult } }).exec().catch(()=>{});
        }
        logGlobal('📊', `*MARKET EVENT: ${evt.name}* — ${evt.desc}`);
    } catch(e) {}
}, 2 * 60 * 60 * 1000);

// ─────────────────────────────────────────────────────────────────────────────
// CRYPTO PUMP/DUMP — Players can coordinate buys to move the market
// Large buy = small price increase. Large sell = small price decrease.
// Whale alert: if single trade is >$10M it's announced globally
// ─────────────────────────────────────────────────────────────────────────────
// Wire into existing buycrypto/sellcrypto commands via a post-trade hook
// (stored in global.cryptoLastTrades for reference)
if (!global.cryptoLastTrades) global.cryptoLastTrades = {};

function applyCryptoPriceImpact(coin, usdAmount, isBuy) {
    if (!global.CRYPTO_PRICES) global.CRYPTO_PRICES = {};
    if (!global.CRYPTO_PRICES[coin]) global.CRYPTO_PRICES[coin] = { BTC: 50000, ETH: 3000, WWT: 1, DOGE: 0.15 }[coin] || 100;
    const impact = Math.min(0.05, usdAmount / 50_000_000); // max 5% price move per trade
    const mult   = isBuy ? (1 + impact) : (1 - impact);
    global.CRYPTO_PRICES[coin] = Math.max(0.001, global.CRYPTO_PRICES[coin] * mult);
    if (usdAmount >= 10_000_000) {
        logGlobal('🐋', `*WHALE ALERT* — A massive ${isBuy ? 'buy' : 'sell'} of ${coin} worth ${fmtMoney(usdAmount)} just moved the market ${isBuy ? '📈' : '📉'}!`);
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// MARRIAGE PERKS — Joint bank, intimacy stat, combined property limit
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'jointbank', desc: 'jointbank <deposit|withdraw|balance> <amount> — Shared account with spouse', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        if (!p.spouse) return conn.sendMessage(from, { text: `💍 You need to be married to use the joint bank.` }, { quoted: mek });
        const sub = (args[0] || 'balance').toLowerCase();
        const amt = parseInt(args[1]);

        if (sub === 'balance') {
            return conn.sendMessage(from, { text: [
                `💑 *JOINT BANK ACCOUNT*`,
                `Balance: *${fmtMoney(p.jointBankBalance || 0)}*`,
                `Spouse: @${p.spouse}`,
                ``,
                `Commands: jointbank deposit <amount> | withdraw <amount>`
            ].join('\n') }, { quoted: mek });
        }

        if (sub === 'deposit') {
            if (!amt || amt <= 0 || p.money < amt) return conn.sendMessage(from, { text: `Invalid amount or insufficient funds.` }, { quoted: mek });
            p.money -= amt;
            p.jointBankBalance = (p.jointBankBalance || 0) + amt;
            // Sync to spouse
            const spouse = await getOrCreatePlayer(p.spouse);
            spouse.jointBankBalance = p.jointBankBalance;
            await spouse.save(); await p.save();
            return conn.sendMessage(from, { text: `💑 Deposited ${fmtMoney(amt)} to joint account.\nBalance: *${fmtMoney(p.jointBankBalance)}*` }, { quoted: mek });
        }

        if (sub === 'withdraw') {
            if (!amt || amt <= 0 || (p.jointBankBalance || 0) < amt) return conn.sendMessage(from, { text: `Insufficient joint balance. Have: ${fmtMoney(p.jointBankBalance || 0)}` }, { quoted: mek });
            p.jointBankBalance -= amt;
            p.money = capBal((p.money || 0) + amt);
            const spouse = await getOrCreatePlayer(p.spouse);
            spouse.jointBankBalance = p.jointBankBalance;
            await spouse.save(); await p.save();
            return conn.sendMessage(from, { text: `💑 Withdrew ${fmtMoney(amt)} from joint account.\nBalance: *${fmtMoney(p.jointBankBalance)}*` }, { quoted: mek });
        }
    } catch(e) { console.error('jointbank error', e); }
});

