// ─────────────────────────────────────────────────────────────────────────────
// PLAYER-RUN CASINOS
// Buy casino property → set house edge → other players gamble and you collect edge
// ─────────────────────────────────────────────────────────────────────────────
const CASINO_SETUP_COST = 50_000_000; // $50M to open a casino

cast({ pattern: 'mycasino', desc: 'mycasino setup|setedge|stats — Run your own casino', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p   = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const sub = (args[0] || 'stats').toLowerCase();

        if (sub === 'setup') {
            if (p.ownsCasino) return conn.sendMessage(from, { text: `You already own a casino!` }, { quoted: mek });
            if (p.money < CASINO_SETUP_COST) return conn.sendMessage(from, { text: `Opening a casino costs *${fmtMoney(CASINO_SETUP_COST)}*. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
            p.money -= CASINO_SETUP_COST;
            p.moneySpent = (p.moneySpent||0) + CASINO_SETUP_COST;
            p.ownsCasino = true;
            p.casinoHouseEdge = 0.05; // 5% default
            p.casinoEarnings  = 0;
            await p.save();
            logGlobal('🎰', `*${p.username||p._id}* just opened their own casino!`);
            return conn.sendMessage(from, { text: [
                `🎰 *CASINO OPENED!*`,
                `Cost: ${fmtMoney(CASINO_SETUP_COST)}`,
                `House edge: *5%* (change with: mycasino setedge <1-15>)`,
                ``,
                `Players can now gamble at your casino with: *visitcasino @you*`,
                `You earn the house edge on every bet placed.`,
                `Check earnings: *mycasino stats*`,
            ].join('\n') }, { quoted: mek });
        }

        if (sub === 'setedge') {
            if (!p.ownsCasino) return conn.sendMessage(from, { text: `You don't own a casino. Setup with: *mycasino setup*` }, { quoted: mek });
            const edge = parseFloat(args[1]);
            if (isNaN(edge) || edge < 1 || edge > 15) return conn.sendMessage(from, { text: `House edge must be between 1% and 15%.` }, { quoted: mek });
            p.casinoHouseEdge = edge / 100;
            await p.save();
            return conn.sendMessage(from, { text: `🎰 House edge set to *${edge}%*. Higher edge = more earnings but fewer players.` }, { quoted: mek });
        }

        if (!p.ownsCasino) return conn.sendMessage(from, { text: [`🎰 You don't own a casino.`, `Open one for ${fmtMoney(CASINO_SETUP_COST)}: *mycasino setup*`].join('\n') }, { quoted: mek });
        return conn.sendMessage(from, { text: [
            `🎰 *YOUR CASINO*`,
            `House Edge: *${((p.casinoHouseEdge||0.05)*100).toFixed(1)}%*`,
            `Total Earnings: *${fmtMoney(p.casinoEarnings||0)}*`,
            ``,
            `Players visit with: *visitcasino @${p._id}*`,
            `Change edge: *mycasino setedge <1-15>*`,
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('mycasino error', e); }
});

cast({ pattern: 'visitcasino', desc: 'visitcasino @owner <amount> — Gamble at another player\'s casino', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const ownerId = await getTargetId(conn, mek, args, 0);
        const amount  = parseInt(args[1]);
        if (!ownerId || ownerId === pId) return conn.sendMessage(from, { text: `Usage: visitcasino @owner <amount>` }, { quoted: mek });
        if (!amount || amount <= 0 || p.money < amount) return conn.sendMessage(from, { text: `Enter a valid amount. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
        const owner = await getOrCreatePlayer(ownerId);
        if (!owner.ownsCasino) return conn.sendMessage(from, { text: `@${ownerId} doesn't own a casino.`, mentions: [toJid(ownerId)] }, { quoted: mek });

        const edge = owner.casinoHouseEdge || 0.05;
        // 50/50 coin flip adjusted by house edge
        const playerWins = Math.random() > 0.5 + edge/2;
        const houseCut   = Math.floor(amount * edge);
        p.money -= amount;

        if (playerWins) {
            const winAmount = Math.floor(amount * (1 - edge));
            p.money = capBal((p.money||0) + amount + winAmount);
            owner.casinoEarnings = (owner.casinoEarnings||0) + houseCut;
            owner.money = capBal((owner.money||0) + houseCut);
            addTaxableIncome(p, winAmount);
            await owner.save(); await p.save();
            return conn.sendMessage(from, { text: `🎰 You won at *${owner.username||ownerId}'s Casino*!\n+${fmtMoney(winAmount)} (after ${((edge*100).toFixed(0))}% house cut)` }, { quoted: mek });
        } else {
            owner.casinoEarnings = (owner.casinoEarnings||0) + amount;
            owner.money = capBal((owner.money||0) + amount);
            addTaxableIncome(owner, amount);
            await owner.save(); await p.save();
            return conn.sendMessage(from, { text: `🎰 You lost *${fmtMoney(amount)}* at *${owner.username||ownerId}'s Casino*. The house always wins.` }, { quoted: mek });
        }
    } catch(e) { console.error('visitcasino error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// SEASONAL EVENTS — Automatic bonuses at certain times of year
// ─────────────────────────────────────────────────────────────────────────────
function getSeasonalEvent() {
    const d   = new Date();
    const m   = d.getMonth() + 1;
    const day = d.getDate();
    if (m === 12 && day >= 20) return { name: '🎄 Christmas', incomeBonus: 0.50, crimeBonus: 0, xpBonus: 0.25, msg: 'Ho ho ho! +50% income & +25% XP all week!' };
    if (m === 10 && day >= 28) return { name: '🎃 Halloween',  incomeBonus: 0,    crimeBonus: 0.25, xpBonus: 0.50, msg: 'Trick or treat! +25% crime rewards & +50% XP!' };
    if (m === 1  && day <= 3)  return { name: '🎆 New Year',   incomeBonus: 1.0,  crimeBonus: 0.50, xpBonus: 1.0,  msg: 'New Year! DOUBLE income, +50% crime, DOUBLE XP!' };
    if (m === 2  && day === 14)return { name: '💕 Valentine\'s',incomeBonus:0.25, crimeBonus: 0,    xpBonus: 0.25, msg: 'Happy Valentine\'s! +25% income & XP for lovers!' };
    return null;
}

if (!global.lastSeasonalAnnounce) global.lastSeasonalAnnounce = 0;
setInterval(() => {
    const evt = getSeasonalEvent();
    if (!evt) return;
    if (Date.now() - global.lastSeasonalAnnounce < 6 * 60 * 60 * 1000) return;
    global.lastSeasonalAnnounce = Date.now();
    logGlobal('🎉', `*${evt.name} EVENT ACTIVE!* ${evt.msg}`);
}, 60 * 60 * 1000);

cast({ pattern: 'season', desc: 'Check current seasonal event bonuses', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const evt = getSeasonalEvent();
        if (!evt) return conn.sendMessage(from, { text: [`🗓️ *NO SEASONAL EVENT*`, ``, `Watch for special events around:`, `• 🎄 Christmas (Dec 20–Jan 1)`, `• 🎃 Halloween (Oct 28–31)`, `• 🎆 New Year (Jan 1–3)`, `• 💕 Valentine's Day (Feb 14)`].join('\n') }, { quoted: mek });
        return conn.sendMessage(from, { text: [
            `🎉 *${evt.name} EVENT ACTIVE!*`, ``,
            `${evt.msg}`, ``,
            evt.incomeBonus > 0 ? `💰 Income bonus: +${(evt.incomeBonus*100).toFixed(0)}%` : null,
            evt.crimeBonus  > 0 ? `🦹 Crime bonus: +${(evt.crimeBonus*100).toFixed(0)}%` : null,
            evt.xpBonus     > 0 ? `⭐ XP bonus: +${(evt.xpBonus*100).toFixed(0)}%` : null,
        ].filter(Boolean).join('\n') }, { quoted: mek });
    } catch(e) {}
});

// Helper — apply seasonal bonus to any income/xp
function applySeasonalBonus(base, type) {
    const evt = getSeasonalEvent();
    if (!evt) return base;
    if (type === 'income') return Math.floor(base * (1 + (evt.incomeBonus || 0)));
    if (type === 'crime')  return Math.floor(base * (1 + (evt.crimeBonus  || 0)));
    if (type === 'xp')     return Math.floor(base * (1 + (evt.xpBonus     || 0)));
    return base;
}

