cast({ pattern: 'referral', desc: 'referral code | referral stats — Your referral program', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p   = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const sub = (args[0] || 'code').toLowerCase();

        if (!p.referralCode) {
            // Generate unique code
            p.referralCode = `WW${p._id.slice(-4).toUpperCase()}${Math.floor(Math.random()*1000)}`;
            await p.save();
        }

        if (sub === 'stats') {
            return conn.sendMessage(from, { text: [
                `🔗 *YOUR REFERRAL STATS*`, ``,
                `Your code: *${p.referralCode}*`,
                `Players referred: *${p.referralCount || 0}*`,
                `Lifetime earnings: *${fmtMoney(p.referralEarnings || 0)}*`,
                ``,
                `Share your code! New players enter it during *joinrpg* or with *usecode ${p.referralCode}*`,
                `You earn 5% of their income for 7 days after they join.`,
            ].join('\n') }, { quoted: mek });
        }

        return conn.sendMessage(from, { text: [
            `🔗 *YOUR REFERRAL CODE: ${p.referralCode}*`, ``,
            `Share this with friends!`,
            `They enter it with: *usecode ${p.referralCode}*`,
            ``,
            `💰 You earn 5% of their income for 7 days`,
            `🎁 They get a $50,000 starter bonus`,
            ``,
            `Referred ${p.referralCount || 0} players so far.`
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('referral error', e); }
});

cast({ pattern: 'usecode', desc: 'usecode <referral_code> — Enter a friend\'s referral code', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const code = (args[0] || '').toUpperCase();
        if (!code) return conn.sendMessage(from, { text: `Usage: usecode <referral_code>` }, { quoted: mek });
        if (p.referredBy) return conn.sendMessage(from, { text: `You already used a referral code.` }, { quoted: mek });
        if (p.referralCode === code) return conn.sendMessage(from, { text: `Can't use your own code.` }, { quoted: mek });
        // Find referrer
        const referrer = await Player.findOne({ referralCode: code }).exec();
        if (!referrer) return conn.sendMessage(from, { text: `Code not found: *${code}*` }, { quoted: mek });
        p.referredBy = referrer._id.toString();
        p.money = capBal((p.money||0) + 50000); // starter bonus
        referrer.referralCount = (referrer.referralCount||0) + 1;
        await referrer.save(); await p.save();
        logGlobal('🔗', `*${p.username||pId}* joined using *${referrer.username||referrer._id}*'s referral code!`);
        return conn.sendMessage(from, { text: [`✅ *REFERRAL CODE APPLIED!*`, ``, `Referred by: *${referrer.username||referrer._id}*`, `🎁 You received: *$50,000* starter bonus!`, ``, `Your referrer earns 5% of your income for 7 days.`].join('\n') }, { quoted: mek });
    } catch(e) { console.error('usecode error', e); }
});

