// Extended recipe list shows all recipes including existing ones
cast({ pattern: 'craftlist', desc: 'View all available crafting recipes', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const lines = [`🔨 *FULL CRAFTING LIST*`, ``];
        lines.push(`*Standard Recipes:*`);
        lines.push(`• smokebomb: bullets×2 + medkit → escape jail`, `• firstaidkit: medkit×2 + energydrink`, `• molotov: bullets×3 → area damage`, `• stungrenade: pepperspray + energydrink → stun`, `• superpoison: escapedsnake + tarantula`);
        lines.push(``, `*Expanded Recipes:*`);
        for (const r of EXPANDED_RECIPES) {
            const ing = Object.entries(r.ingredients).map(([k,v])=>`${k}×${v}`).join(' + ');
            lines.push(`• *${r.name}* — ${ing} → ${r.result.id}×${r.result.qty} (${Math.round(r.successRate*100)}% success)`);
            lines.push(`  ${r.desc}`);
        }
        lines.push(``, `Use: *craft <recipe_name>* — e.g. *craft mega_medkit*`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) {}
});

// Wire expanded recipes into existing craft command
// Find recipe across both lists
function findRecipe(name) {
    return EXPANDED_RECIPES.find(r => r.id.toLowerCase() === name.toLowerCase() || r.name.toLowerCase() === name.toLowerCase());
}

cast({ pattern: 'craftx', desc: 'Craft an expanded recipe (craftx <recipe>)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p      = await getOrCreatePlayer(await getPlayerId(conn, sender));
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `⛓️ Action blocked — you're in ${p.inJail ? 'jail' : 'hospital'}. Use *jailstatus* for options.` }, { quoted: mek });
        const rcpId  = args.join('_').toLowerCase();
        const recipe = findRecipe(rcpId);
        if (!recipe) return conn.sendMessage(from, { text: `Recipe not found. See *craftlist* for all recipes.` }, { quoted: mek });

        // Check ingredients
        for (const [item, qty] of Object.entries(recipe.ingredients)) {
            const owned = p.inventory instanceof Map ? (p.inventory.get(item)||0) : (p.inventory?.[item]||0);
            if (owned < qty) return conn.sendMessage(from, { text: `❌ Need *${item}×${qty}*. You have ${owned}.` }, { quoted: mek });
        }

        // Consume ingredients
        const inv = p.inventory instanceof Map ? p.inventory : new Map(Object.entries(p.inventory||{}));
        for (const [item, qty] of Object.entries(recipe.ingredients)) {
            inv.set(item, (inv.get(item)||0) - qty);
        }

        if (Math.random() > recipe.successRate) {
            p.inventory = inv; p.markModified('inventory'); await p.save();
            return conn.sendMessage(from, { text: `💥 *CRAFTING FAILED* — Materials consumed. Try again.` }, { quoted: mek });
        }

        inv.set(recipe.result.id, (inv.get(recipe.result.id)||0) + recipe.result.qty);
        p.inventory = inv; p.markModified('inventory');
        const achievMsg = await awardAchievements(p);
        await p.save();
        return conn.sendMessage(from, { text: [`🔨 *CRAFTED: ${recipe.name}*`, `Got: *${recipe.result.id}×${recipe.result.qty}*${achievMsg}`].join('\n') }, { quoted: mek });
    } catch(e) { console.error('craftx error', e); }
});

