if (!global.npcVendorActive) global.npcVendorActive = {};

// NPC vendors rotate every hour — 30% chance per city per hour
setInterval(() => {
    const cities = Object.keys(NPC_VENDOR_POOLS);
    for (const city of cities) {
        // Clear expired vendors
        if (global.npcVendorActive[city] && global.npcVendorActive[city].expiresAt <= Date.now()) {
            delete global.npcVendorActive[city];
        }
        // 30% chance per hour to spawn a vendor if none active
        if (!global.npcVendorActive[city] && Math.random() < 0.30) {
            const def  = NPC_VENDOR_POOLS[city];
            const pool = def.pools[Math.floor(Math.random() * def.pools.length)];
            // Add stock limits — each item limited quantity
            const stock = {};
            pool.forEach(it => { stock[it.id] = it.qty || 1; });
            global.npcVendorActive[city] = {
                name: def.name, city, items: pool, stock,
                expiresAt: Date.now() + 3*60*60*1000,
                spawnedAt: Date.now(),
            };
            logGlobal('🕵️', `*${def.name}* just set up shop in *${city}*! Discounted items for 3 hours — *npcvendor* while in ${city}.`);
        }
    }
}, 60 * 60 * 1000);

cast({ pattern: 'npcvendor', desc: 'Check for underground vendor in your city', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p    = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const city = normLoc(p.location);
        const sub  = (args[0] || 'browse').toLowerCase();
        // Clean expired vendors
        for (const c in global.npcVendorActive) { if (global.npcVendorActive[c].expiresAt < Date.now()) delete global.npcVendorActive[c]; }
        const vendor = global.npcVendorActive[city];

        if (!vendor) return conn.sendMessage(from, { text: [`🕵️ No underground vendor in *${city}* right now.`, ``, `Vendors appear randomly in cities 3-5 times per day.`, `Watch the news feed for announcements.`].join('\n') }, { quoted: mek });

        if (sub === 'browse') {
            const lines = [`🕵️ *${vendor.name}* is in *${city}*!`, `_Expires in ${shortTime(vendor.expiresAt - Date.now())}_`, ``];
            vendor.items.forEach((item, i) => {
                const shopIt = DEFAULT_SHOP.find(s => s.id === item.id);
                const baseP  = shopIt?.price || 0;
                const price  = Math.floor(iC(baseP) * item.discount);
                const stock  = vendor.stock?.[item.id] ?? (item.qty || 1);
                const stockStr = stock <= 0 ? ' ❌ *SOLD OUT*' : stock === 1 ? ' _(last one!)_' : ` _(${stock} left)_`;
                lines.push(`${i+1}. *${shopIt?.name||item.id}* — ${fmtMoney(price)} (${Math.round((1-item.discount)*100)}% off!)${stockStr}`);
            });
            lines.push(``, `Buy: *npcvendor buy <number>*`);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }

        if (sub === 'buy') {
            const idx  = (parseInt(args[1])||0) - 1;
            const item = vendor.items[idx];
            if (!item) return conn.sendMessage(from, { text: `Invalid item. Use *npcvendor* to browse.` }, { quoted: mek });
            const stock = vendor.stock?.[item.id] ?? (item.qty || 1);
            if (stock <= 0) return conn.sendMessage(from, { text: `❌ *Sold out!* ${item.id} is gone. Check back next time.` }, { quoted: mek });
            const shopIt = DEFAULT_SHOP.find(s => s.id === item.id);
            const price  = Math.floor(iC(shopIt?.price||0) * item.discount);
            if (p.money < price) return conn.sendMessage(from, { text: `Not enough cash. Need ${fmtMoney(price)}.` }, { quoted: mek });
            // Decrement stock
            if (vendor.stock) vendor.stock[item.id] = Math.max(0, stock - 1);
            p.money -= price;
            p.moneySpent = (p.moneySpent||0) + price;
            const inv = p.inventory instanceof Map ? p.inventory : new Map(Object.entries(p.inventory||{}));
            inv.set(item.id, (inv.get(item.id)||0) + 1);
            p.inventory = inv; p.markModified('inventory');
            logFinancial(p, `NPC vendor buy: ${item.id} from ${vendor.name}`, -price);
            await p.save();
            const remaining = vendor.stock?.[item.id] ?? 0;
            return conn.sendMessage(from, { text: `🕵️ *Bought from ${vendor.name}!*\n${shopIt?.name||item.id} for ${fmtMoney(price)}${remaining === 0 ? '\n⚠️ Last one — now sold out!' : remaining === 1 ? '\n_(Only 1 left!)_' : ''}` }, { quoted: mek });
        }
    } catch(e) { console.error('npcvendor error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// UNDERGROUND FIGHTING LEAGUE — Bracket tournaments, spectator betting
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'league', desc: 'league join|bracket|bet|leaderboard — Underground Fighting League', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const sub = (args[0] || 'leaderboard').toLowerCase();

        if (sub === 'join') {
            const ENTRY_FEE = iC(100000);
            if (p.money < ENTRY_FEE) return conn.sendMessage(from, { text: `Entry fee: ${fmtMoney(ENTRY_FEE)}. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
            // Check for open tournament
            let tournament = await Tournament.findOne({ status: 'open' }).exec();
            if (!tournament) {
                // Create new one
                const tId = `T${Date.now().toString(36).toUpperCase()}`;
                tournament = new Tournament({ id: tId, entryFee: ENTRY_FEE, prizePool: 0 });
            }
            if (tournament.players.find(pl => pl.playerId === pId)) return conn.sendMessage(from, { text: `You're already registered for this tournament!` }, { quoted: mek });
            p.money -= ENTRY_FEE;
            tournament.prizePool += ENTRY_FEE;
            tournament.players.push({ playerId: pId, name: p.username||pId, wins: 0, eliminated: false, power: (p.strength||3)+(p.defense||3)+(p.speed||3)+(p.dexterity||3) });
            await tournament.save(); await p.save();
            const needed = Math.max(0, 4 - tournament.players.length);
            if (tournament.players.length >= 4 && tournament.players.length % 2 === 0) {
                // Auto-start when we have 4+ even players
                tournament.status = 'active'; tournament.startedAt = now();
                await tournament.save();
                logGlobal('🥊', `*TOURNAMENT ${tournament.id} STARTED!* ${tournament.players.length} fighters entered. Prize pool: ${fmtMoney(tournament.prizePool)}. Use *league bracket ${tournament.id}* to follow!`);
            }
            return conn.sendMessage(from, { text: [`🥊 *REGISTERED FOR TOURNAMENT ${tournament.id}!*`, `Entry fee: ${fmtMoney(ENTRY_FEE)}`, `Players: ${tournament.players.length} (${needed > 0 ? `need ${needed} more to start` : 'starting soon!'})`, `Prize pool: *${fmtMoney(tournament.prizePool)}*`].join('\n') }, { quoted: mek });
        }

        if (sub === 'bracket') {
            const tId = args[1];
            const t   = tId ? await Tournament.findOne({ id: tId.toUpperCase() }).exec() : await Tournament.findOne({ status: { $in: ['open','active'] } }).exec();
            if (!t) return conn.sendMessage(from, { text: `No tournament found. Join one: *league join*` }, { quoted: mek });
            const lines = [`🥊 *TOURNAMENT ${t.id}* — ${t.status.toUpperCase()}`, `Prize Pool: *${fmtMoney(t.prizePool)}*`, ``];
            lines.push(`*Fighters:*`);
            t.players.forEach(pl => lines.push(`  ${pl.eliminated ? '❌' : '✅'} *${pl.name}* — Wins: ${pl.wins} | Power: ${pl.power}`));
            if (t.winner) lines.push(``, `🏆 *WINNER: ${t.winner}*`);
            lines.push(``, `Bet on a fighter: *league bet ${t.id} @player <amount>*`);
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }

        if (sub === 'fight') {
            // Simulate next round for active tournament (creator only)
            if (pId !== '2348084644182') return conn.sendMessage(from, { text: `Creator only.` }, { quoted: mek });
            const t = await Tournament.findOne({ status: 'active' }).exec();
            if (!t) return conn.sendMessage(from, { text: `No active tournament.` }, { quoted: mek });
            const alive = t.players.filter(pl => !pl.eliminated);
            if (alive.length <= 1) {
                const winner = alive[0];
                t.winner = winner?.name || 'Unknown';
                t.status = 'finished';
                // Pay winner
                if (winner) {
                    const winnerP = await getOrCreatePlayer(winner.playerId);
                    winnerP.money = capBal((winnerP.money||0) + t.prizePool);
                    winnerP.leagueWins = (winnerP.leagueWins||0) + 1;
                    winnerP.leaguePoints = (winnerP.leaguePoints||0) + 100;
                    addTaxableIncome(winnerP, t.prizePool);
                    await winnerP.save();
                }
                await t.save();
                logGlobal('🏆', `*TOURNAMENT OVER!* Winner: *${t.winner}* takes *${fmtMoney(t.prizePool)}*!`);
                return conn.sendMessage(from, { text: `🏆 Tournament concluded! Winner: *${t.winner}*` }, { quoted: mek });
            }
            // Pair up remaining fighters and simulate bouts
            const results = [];
            for (let i = 0; i < alive.length - 1; i += 2) {
                const a = alive[i], b = alive[i+1];
                const aScore = a.power * (0.8 + Math.random() * 0.4);
                const bScore = b.power * (0.8 + Math.random() * 0.4);
                const winner = aScore > bScore ? a : b;
                const loser  = aScore > bScore ? b : a;
                winner.wins++;
                loser.eliminated = true;
                results.push(`  ⚔️ *${winner.name}* def. ${loser.name}`);
                winner.leaguePoints = (winner.leaguePoints||0) + 10;
            }
            await t.save();
            logGlobal('🥊', `Tournament round complete!\n${results.join('\n')}`);
            return conn.sendMessage(from, { text: [`🥊 *ROUND COMPLETE*`, ...results, ``, `Remaining: ${t.players.filter(p=>!p.eliminated).length} fighters`].join('\n') }, { quoted: mek });
        }

        // Leaderboard
        const top = await Player.find({ leaguePoints: { $gt: 0 } }).sort({ leaguePoints: -1 }).limit(10).exec();
        const lines = [`🥊 *FIGHT LEAGUE RANKINGS*`, ``];
        const leagueMentions = [];
        top.forEach((pl, i) => {
            leagueMentions.push(toJid(pl._id));
            lines.push(`${i+1}. *${pl.username||'(no name)'}* (@${pl._id}) — ${pl.leaguePoints} pts | ${pl.leagueWins||0} tournament wins`);
        });
        if (!top.length) lines.push(`No fighters ranked yet. Join a tournament: *league join*`);
        return conn.sendMessage(from, { text: lines.join('\n'), mentions: leagueMentions }, { quoted: mek });
    } catch(e) { console.error('league error', e); }
});

// ─────────────────────────────────────────────────────────────────────────────
// OFFSHORE BANKING — Reduce IRS visibility. Available in Switzerland/Dubai only.
// ─────────────────────────────────────────────────────────────────────────────
cast({ pattern: 'offshore', desc: 'offshore deposit|withdraw|balance — Bank secretly abroad', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const p    = await getOrCreatePlayer(await getPlayerId(conn, sender));
        const sub  = (args[0] || 'balance').toLowerCase();
        const city = normLoc(p.location);
        const OFFSHORE_CITIES = ['Switzerland', 'Dubai'];
        const FEE_RATE = 0.08; // 8% deposit fee (secrecy costs money)
        const WITHDRAWAL_DELAY = 6 * 60 * 60 * 1000; // 6hr withdrawal delay

        if (!OFFSHORE_CITIES.includes(city) && sub !== 'balance') {
            return conn.sendMessage(from, { text: [`🏦 *OFFSHORE BANKING*`, ``, `Only available in: *Switzerland* and *Dubai*`, `Travel there first to open/use an offshore account.`].join('\n') }, { quoted: mek });
        }

        if (sub === 'balance') {
            if (!(p.offshoreBank > 0)) return conn.sendMessage(from, { text: [`🏦 *OFFSHORE ACCOUNT*`, ``, `Balance: *$0*`, `No offshore account. Travel to Switzerland or Dubai to open one.`].join('\n') }, { quoted: mek });
            return conn.sendMessage(from, { text: [`🏦 *OFFSHORE ACCOUNT — ${p.offshoreCity||'Unknown'}*`, `Balance: *${fmtMoney(p.offshoreBank||0)}*`, ``, `⚠️ IRS cannot directly seize offshore funds`, `⚠️ 8% fee on deposits | 6hr withdrawal delay`].join('\n') }, { quoted: mek });
        }

        if (sub === 'deposit') {
            const amount = parseInt(args[1]);
            if (!amount || amount <= 0 || p.money < amount) return conn.sendMessage(from, { text: `Invalid amount or insufficient funds.` }, { quoted: mek });
            const fee = Math.ceil(amount * FEE_RATE);
            const deposited = amount - fee;
            p.money -= amount;
            p.offshoreBank = Math.min(MAX_BALANCE, (p.offshoreBank||0) + deposited);
            p.offshoreCity = city;
            logFinancial(p, `Offshore deposit (8% fee)`, -amount);
            await p.save();
            return conn.sendMessage(from, { text: [`🏦 *OFFSHORE DEPOSIT — ${city}*`, `Amount: ${fmtMoney(amount)}`, `Fee (8%): -${fmtMoney(fee)}`, `Deposited: *${fmtMoney(deposited)}*`, `Balance: ${fmtMoney(p.offshoreBank)}`, ``, `⚠️ IRS cannot touch these funds directly`].join('\n') }, { quoted: mek });
        }

        if (sub === 'withdraw') {
            const amount = parseInt(args[1]);
            if (!amount || amount <= 0 || (p.offshoreBank||0) < amount) return conn.sendMessage(from, { text: `Insufficient offshore balance. Have: ${fmtMoney(p.offshoreBank||0)}` }, { quoted: mek });
            const last = p.lastOffshoreTransfer || 0;
            if (now() - last < WITHDRAWAL_DELAY) return conn.sendMessage(from, { text: `⏳ Withdrawal processing. Available in ${shortTime(WITHDRAWAL_DELAY - (now()-last))}.` }, { quoted: mek });
            p.offshoreBank -= amount;
            p.money = capBal((p.money||0) + amount);
            p.lastOffshoreTransfer = now();
            logFinancial(p, `Offshore withdrawal`, amount);
            await p.save();
            return conn.sendMessage(from, { text: `🏦 Withdrew *${fmtMoney(amount)}* from offshore. Balance: ${fmtMoney(p.offshoreBank)}` }, { quoted: mek });
        }
    } catch(e) { console.error('offshore error', e); }
});

// Wire seasonal bonus into crime rewards
const _origApplyVAT_torn = applyVAT;
// Apply seasonal bonus to crime reward before it's given
// (inline in crime command via applySeasonalBonus)

// Wire referral 5% cut — check on any income if player was referred within 7 days
async function payReferralCut(p, earnedAmount) {
    if (!p.referredBy || !earnedAmount) return;
    const joinedAt = p.bornAt || p.createdAt?.getTime() || 0;
    if (Date.now() - joinedAt > 7 * 24 * 60 * 60 * 1000) return; // 7-day window
    const cut = Math.floor(earnedAmount * 0.05);
    if (cut <= 0) return;
    const referrer = await Player.findById(p.referredBy).exec().catch(()=>null);
    if (!referrer) return;
    referrer.money = capBal((referrer.money||0) + cut);
    referrer.referralEarnings = (referrer.referralEarnings||0) + cut;
    addTaxableIncome(referrer, cut);
    await referrer.save();
}


// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: callawyer @player — Ask a friend with a law degree to help you escape jail
// Their law qualification level determines how much time is cut
// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// COMMAND: callawyer — Request a friend to represent you. They must accept.
// COMMAND: lawyer accept/decline — The helper responds to the request.
// ─────────────────────────────────────────────────────────────────────────────
if (!global.lawyerRequests) global.lawyerRequests = new Map(); // helperId → { requesterId, requesterName, expiresAt }

cast({ pattern: 'callawyer', desc: 'callawyer @player — Ask a friend with a Law degree to represent you in jail', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId      = await getPlayerId(conn, sender);
        const p        = await getOrCreatePlayer(pId);
        const helperId = await getTargetId(conn, mek, args, 0);

        if (!helperId) return conn.sendMessage(from, { text: [
            `⚖️ *CALL A LAWYER*`,``,
            `Usage: *callawyer @friend*`,``,
            `Your friend needs a Law qualification:`,
            `  📜 Certificate — cuts 15% off sentence`,
            `  📋 Diploma — cuts 30% off`,
            `  🎓 Masters — cuts 50% off`,
            `  🏅 PhD — cuts 65% off + fee halved`,``,
            `They type *lawyer accept* to help, *lawyer decline* to refuse.`,
        ].join('\n') }, { quoted: mek });

        if (!isHospitalized(p) || !p.inJail) return conn.sendMessage(from, { text: `⛓️ You're not in jail.` }, { quoted: mek });
        if (helperId === pId) return conn.sendMessage(from, { text: `You can't be your own lawyer.` }, { quoted: mek });
        if (p.lawyerCallUsed) return conn.sendMessage(from, { text: `⚖️ You've already used a lawyer this sentence.\nRemaining: *${shortTime(Math.max(0, p.jailedUntil - now()))}*` }, { quoted: mek });

        const helper = await getOrCreatePlayer(helperId);
        if (isHospitalized(helper)) return conn.sendMessage(from, { text: `❌ @${helperId} is in ${helper.inJail?'jail':'hospital'} — they can't help.`, mentions:[toJid(helperId)] }, { quoted: mek });

        const lawDegrees = (helper.degrees||[]).filter(d => d.startsWith('law_'));
        if (!lawDegrees.length) return conn.sendMessage(from, { text: `❌ @${helperId} has no Law qualification.\nThey need: *school enroll law*`, mentions:[toJid(helperId)] }, { quoted: mek });

        // Store pending request (5 min to respond)
        global.lawyerRequests.set(helperId, {
            requesterId:   pId,
            requesterName: p.username || pId,
            expiresAt:     now() + 5*60*1000,
            from,
        });

        return conn.sendMessage(from, {
            text: [
                `⚖️ *LAWYER REQUEST SENT to @${helperId}*`,``,
                `Waiting for them to respond...`,
                `They type: *lawyer accept* or *lawyer decline*`,
                `⏳ Request expires in 5 minutes.`,
            ].join('\n'),
            mentions: [toJid(helperId)]
        }, { quoted: mek });
    } catch(e) { console.error('callawyer error', e); }
});

cast({ pattern: 'lawyer', desc: 'lawyer accept|decline — Respond to a lawyer request', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const helperId = await getPlayerId(conn, sender);
        const sub      = (args[0]||'').toLowerCase();
        if (!['accept','decline'].includes(sub)) return conn.sendMessage(from, { text: `Usage: *lawyer accept* or *lawyer decline*` }, { quoted: mek });

        const req = global.lawyerRequests.get(helperId);
        if (!req) return conn.sendMessage(from, { text: `⚖️ You have no pending lawyer requests.` }, { quoted: mek });
        if (req.expiresAt < now()) {
            global.lawyerRequests.delete(helperId);
            return conn.sendMessage(from, { text: `⏰ That request expired.` }, { quoted: mek });
        }
        global.lawyerRequests.delete(helperId);

        if (sub === 'decline') {
            return conn.sendMessage(from, {
                text: `❌ You declined *${req.requesterName}*'s lawyer request.`,
            }, { quoted: mek });
        }

        // ACCEPT — apply the reduction
        const helper = await getOrCreatePlayer(helperId);
        const p      = await getOrCreatePlayer(req.requesterId);
        if (!isHospitalized(p) || !p.inJail) {
            return conn.sendMessage(from, { text: `ℹ️ *${req.requesterName}* is no longer in jail.` }, { quoted: mek });
        }
        if (p.lawyerCallUsed) {
            return conn.sendMessage(from, { text: `ℹ️ *${req.requesterName}* already used a lawyer this sentence.` }, { quoted: mek });
        }

        const lawDegrees   = (helper.degrees||[]).filter(d => d.startsWith('law_'));
        const lawLevel     = Math.max(...lawDegrees.map(d => parseInt(d.split('_')[1])||1));
        const QUAL_NAMES   = { 1:'Certificate', 2:'Diploma', 3:'Masters', 4:'PhD' };
        const REDUCTIONS   = { 1:0.15, 2:0.30, 3:0.50, 4:0.65 };
        const reductionPct = REDUCTIONS[lawLevel] || 0.15;
        const lawLabel     = QUAL_NAMES[lawLevel];
        const remaining    = p.jailedUntil - now();
        const reduction    = Math.floor(remaining * reductionPct);

        if (lawLevel === 4 && p.sentenceMs > 0) p.sentenceMs = Math.floor(p.sentenceMs * 0.5);
        p.jailedUntil   -= reduction;
        p.lawyerCallUsed = true;
        const freed = p.jailedUntil <= now();
        if (freed) { p.jailedUntil = 0; p.inJail = false; p.jailWorkDone = 0; p.sentenceMs = 0; }
        await p.save();

        logGlobal('⚖️', `*${helper.username||helperId}* (Law ${lawLabel}) represented *${p.username||req.requesterId}* — ${freed?'released!':Math.round(reductionPct*100)+'% off'}`);

        // Notify the helper
        await conn.sendMessage(from, {
            text: [
                `⚖️ *Case handled for ${req.requesterName}*`,``,
                `Qualification: *Law ${lawLabel}*`,
                `Sentence reduced: *${Math.round(reductionPct*100)}%* (${shortTime(reduction)} saved)`,
                freed ? `✅ They've been released!` : `⏳ They still have ${shortTime(Math.max(0,p.jailedUntil-now()))} left`,
            ].join('\n')
        }, { quoted: mek });

        // Notify the requester in game chat
        if (global.wwGameChat) {
            await broadcastToGame(`⚖️ *${helper.username||helperId}* just represented *${p.username||req.requesterId}* in court! ${freed?'Released!':'Sentence cut by '+Math.round(reductionPct*100)+'%.'}`);
        }
    } catch(e) { console.error('lawyer accept error', e); }
});
