// 🚨 WANTEDLIST — Top 10 most wanted criminals (highest crime heat)
// =============================================================================
cast({ pattern: 'wantedlist', desc: 'Top 10 most wanted criminals right now', category: 'rpg', filename: __filename }, async (conn, mek, m, { from }) => {
    try {
        const wanted = await Player.find({ crimeLevel: { $gte: 20 } }).sort({ crimeLevel: -1 }).limit(10).exec();
        if (!wanted.length) return conn.sendMessage(from, { text: `🚨 No wanted criminals right now. The streets are quiet.` }, { quoted: mek });
        const medals = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];
        const lines  = [`🚨 *MOST WANTED — WEIRDOS WORLD*`,``, `Report them with *callcops @player*`,``];
        wanted.forEach((pl, i) => {
            const heat  = pl.crimeLevel || 0;
            const label = heat >= 80 ? '🔴 EXTREME' : heat >= 60 ? '🟠 HIGH' : heat >= 40 ? '🟡 MEDIUM' : '🟢 LOW';
            lines.push(`${medals[i]} *${pl.username || pl._id}* — Heat: ${heat}/100 ${label}`);
        });
        lines.push(``,`_Tip: Catch them with callcops for a reward!_`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) { console.error('wantedlist error', e); }
});

// =============================================================================
// ⛓️ PRISON GANG — Jailed players can form mini-gangs for perks
// =============================================================================
cast({ pattern: 'prisongang', desc: 'prisongang form|join|list|tax — Organise while in jail', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const sub = (args[0] || 'list').toLowerCase();

        if (sub === 'form') {
            if (!isInJail(p)) return conn.sendMessage(from, { text: `⛓️ You need to be in jail to form a prison gang.` }, { quoted: mek });
            if (p.prisonGang) return conn.sendMessage(from, { text: `You're already in a prison gang: *${p.prisonGang}*. Leave first.` }, { quoted: mek });
            const name = args.slice(1).join(' ').trim();
            if (!name || name.length < 2 || name.length > 20) return conn.sendMessage(from, { text: `Usage: *prisongang form <name>* (2–20 chars)` }, { quoted: mek });
            p.prisonGang = name;
            p.prisonGangRole = 'boss';
            await p.save();
            return conn.sendMessage(from, { text: [`⛓️ *PRISON GANG FORMED!*`,``,`Gang: *${name}*`,`Your role: 👑 Boss`,``,`Recruit others: *prisongang recruit @player*`,`Gang perks: reduced jailwork cooldown, shared bail`].join('\n') }, { quoted: mek });
        }

        if (sub === 'join') {
            if (!isInJail(p)) return conn.sendMessage(from, { text: `Must be in jail to join a prison gang.` }, { quoted: mek });
            const targetId = await getTargetId(conn, mek, args, 1);
            if (!targetId) return conn.sendMessage(from, { text: `Usage: *prisongang join @boss*` }, { quoted: mek });
            const boss = await getOrCreatePlayer(targetId);
            if (!boss.prisonGang || boss.prisonGangRole !== 'boss') return conn.sendMessage(from, { text: `@${targetId} is not a prison gang boss.`, mentions:[toJid(targetId)] }, { quoted: mek });
            if (!isInJail(boss)) return conn.sendMessage(from, { text: `That gang boss is no longer in jail.` }, { quoted: mek });
            p.prisonGang = boss.prisonGang;
            p.prisonGangRole = 'member';
            await p.save();
            return conn.sendMessage(from, {
                text: [`⛓️ *JOINED PRISON GANG: ${boss.prisonGang}*`,`Role: 👤 Member`,`Jailwork gives extra -5 min while in the gang.`].join('\n'),
                mentions:[toJid(targetId)]
            }, { quoted: mek });
        }

        if (sub === 'leave') {
            if (!p.prisonGang) return conn.sendMessage(from, { text: `You're not in a prison gang.` }, { quoted: mek });
            const g = p.prisonGang;
            p.prisonGang = null; p.prisonGangRole = null;
            await p.save();
            return conn.sendMessage(from, { text: `You left *${g}*.` }, { quoted: mek });
        }

        if (sub === 'list') {
            const gangs = await Player.find({ prisonGang: { $ne: null }, jailedUntil: { $gt: now() }, inJail: true }).sort({ prisonGang: 1 }).exec();
            if (!gangs.length) return conn.sendMessage(from, { text: `⛓️ No active prison gangs right now.` }, { quoted: mek });
            const grouped = {};
            gangs.forEach(pl => { if (!grouped[pl.prisonGang]) grouped[pl.prisonGang] = []; grouped[pl.prisonGang].push(pl); });
            const lines = [`⛓️ *ACTIVE PRISON GANGS*`,``];
            for (const [name, members] of Object.entries(grouped)) {
                const boss = members.find(m => m.prisonGangRole==='boss');
                lines.push(`👑 *${name}* — ${members.length} member(s)`);
                lines.push(`   Boss: @${boss?._id||'?'} | Members: ${members.map(m=>m.username||m._id).join(', ')}`);
            }
            return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
        }

        return conn.sendMessage(from, { text: `Usage: *prisongang form <name>* | *prisongang join @boss* | *prisongang list* | *prisongang leave*` }, { quoted: mek });
    } catch(e) { console.error('prisongang error', e); }
});

// Also: prisongang members get -5 min bonus on jailwork
// Hook this into jailwork by adding a check after reduction line
// =============================================================================
cast({ pattern: 'lottery', desc: 'lottery buy [qty] | jackpot | draw (creator)', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const sub = (args[0] || 'jackpot').toLowerCase();
        const cfg = await GameConfig.findById('game_config').exec() || new GameConfig();
        const weekKey = getWeekKey();

        // Auto-reset player tickets if new week
        if (p.lotteryLastDraw !== weekKey) { p.lotteryTickets = 0; p.lotteryLastDraw = weekKey; }
        // Auto-reset config draw if new week
        if (cfg.lotteryDrawKey !== weekKey) {
            cfg.lotteryDrawKey = weekKey;
            cfg.lotteryTotalTickets = 0;
            await cfg.save();
        }

        if (sub === 'jackpot' || sub === 'info') {
            return conn.sendMessage(from, { text: [
                `🎟️ *WEIRDOS WORLD LOTTERY*`, ``,
                `💰 *Current Jackpot: ${fmtMoney(cfg.lotteryJackpot || 5000000)}*`,
                `🎫 Total tickets this week: ${cfg.lotteryTotalTickets || 0}`,
                `🎫 Your tickets: ${p.lotteryTickets || 0}/20`,
                `📅 Draw: Every Sunday at midnight`,
                ``, `Ticket price: *$5,000 each* | Max 20 per week`,
                `Buy: *lottery buy <qty>*`,
                ``, `_More tickets = better odds. Jackpot rolls over if no winner._`
            ].join('\n') }, { quoted: mek });
        }

        if (sub === 'buy') {
            if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't buy lottery tickets from jail/hospital.` }, { quoted: mek });
            const qty = Math.max(1, Math.min(20, parseInt(args[1]) || 1));
            const remaining = 20 - (p.lotteryTickets || 0);
            if (remaining <= 0) return conn.sendMessage(from, { text: `🎫 You've already bought the max 20 tickets this week!\nCheck back next week.` }, { quoted: mek });
            const buyQty = Math.min(qty, remaining);
            const cost   = buyQty * 5000;
            if (p.money < cost) return conn.sendMessage(from, { text: `💸 Need ${fmtMoney(cost)} for ${buyQty} ticket(s). You have ${fmtMoney(p.money)}.` }, { quoted: mek });
            p.money         -= cost;
            p.lotteryTickets = (p.lotteryTickets || 0) + buyQty;
            p.lotteryLastDraw = weekKey;
            cfg.lotteryJackpot    = (cfg.lotteryJackpot || 5000000) + Math.floor(cost * 0.70); // 70% of ticket sales go to jackpot
            cfg.lotteryTotalTickets = (cfg.lotteryTotalTickets || 0) + buyQty;
            logFinancial(p, `Lottery tickets x${buyQty}`, -cost);
            await p.save(); await cfg.save();
            return conn.sendMessage(from, { text: [
                `🎟️ *TICKETS PURCHASED!*`, ``,
                `Bought: *${buyQty} ticket(s)*`,
                `Cost: ${fmtMoney(cost)}`,
                `Your tickets this week: *${p.lotteryTickets}/20*`,
                `💰 Jackpot now: *${fmtMoney(cfg.lotteryJackpot)}*`,
                `📅 Draw: Sunday midnight. Good luck!`
            ].join('\n') }, { quoted: mek });
        }

        // Creator-only manual draw
        if (sub === 'draw') {
            if (pId !== '2348084644182') return conn.sendMessage(from, { text: `❌ Creator only.` }, { quoted: mek });
            const totalTickets = cfg.lotteryTotalTickets || 0;
            if (totalTickets === 0) return conn.sendMessage(from, { text: `No tickets sold this week. Draw cancelled.` }, { quoted: mek });

            // Pick a random ticket number as winner
            const winTicket = Math.floor(Math.random() * totalTickets) + 1;
            // Find who holds that ticket by scanning players
            let cumulative = 0;
            let winner = null;
            const allPlayers = await Player.find({ lotteryLastDraw: weekKey, lotteryTickets: { $gt: 0 } }).exec();
            for (const pl of allPlayers) {
                cumulative += (pl.lotteryTickets || 0);
                if (winTicket <= cumulative) { winner = pl; break; }
            }

            const jackpot = cfg.lotteryJackpot || 5000000;
            if (winner) {
                winner.money = (winner.money || 0) + jackpot;
                logFinancial(winner, `🎟️ Lottery jackpot WIN!`, jackpot);
                addTaxableIncome(winner, jackpot);
                await winner.save();
                // Reset jackpot
                cfg.lotteryJackpot = 5000000;
                cfg.lotteryTotalTickets = 0;
                cfg.lotteryDrawKey = '';
                await cfg.save();
                logGlobal('🎟️', `*${winner.username || winner._id}* just won the *Lottery Jackpot* of *${fmtMoney(jackpot)}*! 🎉`);
                return conn.sendMessage(from, { text: [
                    `🎟️ *LOTTERY DRAW COMPLETE!*`, ``,
                    `🎉 *WINNER: @${winner._id}*`,
                    `💰 Jackpot: *${fmtMoney(jackpot)}*`,
                    `🎫 Total tickets: ${totalTickets}`,
                    ``, `Next jackpot starts at $5,000,000. Buy tickets: *lottery buy*`
                ].join('\n'), mentions: [toJid(winner._id)] }, { quoted: mek });
            } else {
                // Rollover
                await cfg.save();
                return conn.sendMessage(from, { text: `🎟️ No winner found. Jackpot rolls over to next week at ${fmtMoney(jackpot)}.` }, { quoted: mek });
            }
        }

        return conn.sendMessage(from, { text: `Usage: *lottery buy <qty>* | *lottery jackpot*` }, { quoted: mek });
    } catch(e) { console.error('lottery error', e); }
});

// =============================================================================
// 🏋️ GYM — Pay for membership, get 2× train gains for 7 days
// =============================================================================
cast({ pattern: 'gym', desc: 'gym join|status — Gym membership for 2× training gains', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const sub = (args[0] || 'status').toLowerCase();
        const MEMBERSHIP_COST = iC(250000); // $250k/week, inflation-scaled
        const DURATION = 7 * 24 * 60 * 60 * 1000; // 7 days

        if (sub === 'status' || sub === 'info') {
            const active = (p.gymExpiresAt || 0) > now();
            return conn.sendMessage(from, { text: [
                `🏋️ *WEIRDOS WORLD GYM*`, ``,
                active
                    ? `✅ *Membership ACTIVE* — expires in ${shortTime(p.gymExpiresAt - now())}`
                    : `❌ No active membership`,
                ``, `*Membership perks:*`,
                `• 2× stat gains on every *train* command`,
                `• +5 bonus XP per session`,
                `• Faster energy recovery`,
                ``, `Cost: *${fmtMoney(MEMBERSHIP_COST)}/week*`,
                `Join: *gym join*`
            ].join('\n') }, { quoted: mek });
        }

        if (sub === 'join' || sub === 'renew') {
            if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't join the gym from jail/hospital.` }, { quoted: mek });
            if (p.money < MEMBERSHIP_COST) return conn.sendMessage(from, { text: `💸 Gym membership costs ${fmtMoney(MEMBERSHIP_COST)}/week. You have ${fmtMoney(p.money)}.` }, { quoted: mek });
            p.money -= MEMBERSHIP_COST;
            // Stack on top of existing membership if still active
            const base = Math.max(now(), p.gymExpiresAt || 0);
            p.gymExpiresAt = base + DURATION;
            logFinancial(p, `Gym membership`, -MEMBERSHIP_COST);
            await p.save();
            return conn.sendMessage(from, { text: [
                `🏋️ *GYM MEMBERSHIP ACTIVE!*`, ``,
                `Cost: *${fmtMoney(MEMBERSHIP_COST)}*`,
                `Expires: *${new Date(p.gymExpiresAt).toDateString()}*`,
                ``, `All *train* sessions now give *2× stat gains* + bonus XP!`
            ].join('\n') }, { quoted: mek });
        }

        return conn.sendMessage(from, { text: `Usage: *gym status* | *gym join*` }, { quoted: mek });
    } catch(e) { console.error('gym error', e); }
});

// Hook gym bonus into train command at save time via helper
function getGymMultiplier(p) {
    return (p.gymExpiresAt || 0) > now() ? 2.0 : 1.0;
}

// =============================================================================
// 🌆 STREET HUSTLE — Flip goods in your city. 20-min cooldown. Risk of loss.
// =============================================================================

const HUSTLE_GOODS = [
    { name: 'Counterfeit Trainers', minProfit: 800,   maxProfit: 3000,   risk: 0.18, riskFine: [500,  2000],  city: null },
    { name: 'Stolen Electronics',   minProfit: 2000,  maxProfit: 8000,   risk: 0.28, riskFine: [1500, 5000],  city: null },
    { name: 'Black Market Meds',    minProfit: 3000,  maxProfit: 10000,  risk: 0.33, riskFine: [2000, 7000],  city: null },
    { name: 'Fake Designer Bags',   minProfit: 1200,  maxProfit: 5000,   risk: 0.22, riskFine: [800,  3000],  city: null },
    { name: 'Unlicensed Fireworks', minProfit: 2500,  maxProfit: 7000,   risk: 0.28, riskFine: [1500, 4000],  city: null },
    { name: 'Hot Watches',          minProfit: 6000,  maxProfit: 18000,  risk: 0.38, riskFine: [3000, 10000], city: 'London' },
    { name: 'Tequila Barrels',      minProfit: 4000,  maxProfit: 12000,  risk: 0.33, riskFine: [2000, 6000],  city: 'Mexico' },
    { name: 'Rare Electronics',     minProfit: 8000,  maxProfit: 25000,  risk: 0.43, riskFine: [5000, 15000], city: 'Japan' },
    { name: 'Uncut Diamonds',       minProfit: 12000, maxProfit: 38000,  risk: 0.48, riskFine: [6000, 20000], city: 'Switzerland' },
];

cast({ pattern: 'hustle', desc: 'Street hustle — flip goods in your city for quick cash', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't hustle from jail/hospital.` }, { quoted: mek });
        if (isInFlight(p)) return conn.sendMessage(from, { text: flightMsg(p) }, { quoted: mek });
        if (isKidnapped(p)) return conn.sendMessage(from, { text: `🔒 You're kidnapped. Escape first.` }, { quoted: mek });

        const COOLDOWN = 45 * 60 * 1000;
        if (now() - (p.lastHustle || 0) < COOLDOWN) {
            return conn.sendMessage(from, { text: `⏳ Lay low for ${shortTime(COOLDOWN - (now() - p.lastHustle))} before your next hustle.` }, { quoted: mek });
        }

        const city = normLoc(p.location);
        // Pick eligible goods (city-specific or universal)
        const eligible = HUSTLE_GOODS.filter(g => !g.city || g.city === city);
        const good = eligible[Math.floor(Math.random() * eligible.length)];

        // Notoriety bonus: higher city rep = better deals, lower risk
        const cityRep = (p.cityNotoriety || {})[city] || 0;
        const repBonus  = cityRep / 1000; // up to +10% profit at rep 100
        const riskMod   = Math.max(0, good.risk - cityRep / 500); // rep reduces risk

        p.lastHustle = now();
        p.crimeLevel = Math.min(100, (p.crimeLevel || 0) + 5);
        p.markModified('cityNotoriety');

        if (Math.random() < riskMod) {
            // BUSTED
            const fine = Math.floor(good.riskFine[0] + Math.random() * (good.riskFine[1] - good.riskFine[0]));
            const actualFine = Math.min(p.money, iC(fine));
            p.money = Math.max(0, p.money - actualFine);
            // Small notoriety loss on bust
            if (!p.cityNotoriety) p.cityNotoriety = {};
            p.cityNotoriety[city] = Math.max(0, (p.cityNotoriety[city] || 0) - 5);
            logFinancial(p, `Hustle bust — fined (${good.name})`, -actualFine);
            await p.save();
            return conn.sendMessage(from, { text: [
                `🚔 *HUSTLE GONE WRONG!*`, ``,
                `You tried to flip *${good.name}* in ${city}.`,
                `The cops were watching. You ran but dropped the goods.`,
                `💸 Fine: *${fmtMoney(actualFine)}*`,
                `🌡️ Crime heat +5`,
                ``, `_Try again in 20 minutes. Build city rep to reduce risk._`
            ].join('\n') }, { quoted: mek });
        }

        // SUCCESS
        const rawProfit = Math.floor(good.minProfit + Math.random() * (good.maxProfit - good.minProfit));
        const profit    = Math.floor(iC(rawProfit) * (1 + repBonus));
        const { net, vat } = applyVAT(profit);
        p.money = (p.money || 0) + net;
        p.totalEarned = (p.totalEarned || 0) + net;
        addTaxableIncome(p, net);
        // Build city notoriety on success
        if (!p.cityNotoriety) p.cityNotoriety = {};
        p.cityNotoriety[city] = Math.min(100, (p.cityNotoriety[city] || 0) + 3);
        logFinancial(p, `Street hustle (${good.name})`, net);
        const titleMsg = checkTitles(p);
        await p.save();
        return conn.sendMessage(from, { text: [
            `💼 *HUSTLE SUCCESSFUL!*`, ``,
            `You flipped *${good.name}* in ${city}.`,
            `💰 Profit: ${fmtMoney(profit)}${global.weirdo_tax_enabled ? ` — VAT ${fmtMoney(profit - net)} = *${fmtMoney(net)} net*` : ''}`,
            `📍 ${city} rep: ${p.cityNotoriety[city]}/100`,
            ``, `_Next hustle in 45 min. Higher city rep = better deals._`
        ].join('\n') + titleMsg }, { quoted: mek });
    } catch(e) { console.error('hustle error', e); }
});

