// =============================================================================
cast({ pattern: 'mugshot', desc: 'mugshot @player — View their crime record and rep', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const targetId = await getTargetId(conn, mek, args, 0) || pId;
        const target = await getOrCreatePlayer(targetId).catch(() => null);
        if (!target) return conn.sendMessage(from, { text: `Player not found.` }, { quoted: mek });

        const crimes   = target.crimesDone || 0;
        const wins     = target.attacksWon || 0;
        const jailed   = target.timesJailed || 0;
        const heat     = target.crimeLevel || 0;
        const rep      = target.socialRep || 0;
        const notoriety= Object.values(target.cityNotoriety || {}).reduce((a, b) => a + b, 0);

        const crimeRank = crimes >= 500 ? '👑 Godfather' : crimes >= 200 ? '🔴 Crime Lord' : crimes >= 100 ? '🟠 Career Criminal' : crimes >= 50 ? '🟡 Felon' : crimes >= 10 ? '⚪ Petty Criminal' : '🟢 Clean';
        const repRank   = rep >= 100 ? '🌟 Beloved' : rep >= 50 ? '💛 Respected' : rep >= 20 ? '👤 Known' : rep >= 0 ? '❓ Neutral' : '💀 Hated';

        return conn.sendMessage(from, { text: [
            `📋 *MUGSHOT — @${targetId}*`,
            `Username: *${target.username || 'Unknown'}* | Level: ${target.level || 1}`,
            ``, `⚖️ *CRIMINAL RECORD*`,
            `🦹 Crimes committed: *${crimes.toLocaleString()}* — ${crimeRank}`,
            `⚔️ PvP wins: *${wins}*`,
            `⛓️ Times jailed: *${jailed}*`,
            `🔥 Current heat: *${heat}/100*`,
            ``, `🌍 *REPUTATION*`,
            `💛 Social Rep: *${rep}* — ${repRank}`,
            `🗺️ Total City Notoriety: *${notoriety}*`,
            `💍 Marital status: ${target.spouse ? `Married to @${target.spouse}` : 'Single'}`,
            `👶 Children: ${(target.children||[]).length}`,
            `🏢 Faction: ${target.faction || 'None'}`,
        ].join('\n') }, { quoted: mek });
    } catch(e) { console.error('mugshot error', e); }
});

// =============================================================================
// 💀 SABOTAGE — Criminal act against another player's income/property
// =============================================================================
cast({ pattern: 'sabotage', desc: 'sabotage @player — Damage their property or business income', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from, args }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        if (isHospitalized(p)) return conn.sendMessage(from, { text: `Can't sabotage from jail/hospital.` }, { quoted: mek });

        const targetId = await getTargetId(conn, mek, args, 0);
        if (!targetId || targetId === pId) return conn.sendMessage(from, { text: `Usage: *sabotage @player*\nDamage someone's property income or career earnings.` }, { quoted: mek });

        const CD = 30 * 60 * 1000; // 30 min cooldown
        const cdKey = 'sabotage';
        if (now() - (p.cooldowns?.[cdKey] || 0) < CD) {
            return conn.sendMessage(from, { text: `⏳ Lay low for ${shortTime(CD - (now() - (p.cooldowns?.[cdKey] || 0)))} before next sabotage.` }, { quoted: mek });
        }

        const target = await getOrCreatePlayer(targetId).catch(() => null);
        if (!target) return conn.sendMessage(from, { text: `Player not found.` }, { quoted: mek });

        p.cooldowns        = p.cooldowns || {};
        p.cooldowns[cdKey] = now();
        p.crimeLevel       = Math.min(100, (p.crimeLevel || 0) + 15);
        p.markModified('cooldowns');

        // Criminology degree improves success chance
        const crimDeg   = (p.degrees||[]).some(d => d.startsWith('criminology_'));
        const succChance= 0.55 + (crimDeg ? 0.15 : 0);

        if (Math.random() > succChance) {
            // BUSTED — target finds out
            await p.save();
            return conn.sendMessage(from, {
                text: [`💀 *SABOTAGE FAILED*`, ``,
                    `You were spotted casing *@${targetId}*'s property.`,
                    `They'll be on alert now. Try again in 30 min.`,
                    `🌡️ Crime heat +15`
                ].join('\n'),
                mentions: [toJid(targetId)]
            }, { quoted: mek });
        }

        // SUCCESS — pick a sabotage type based on what target has
        const sabotageTypes = [];
        if (target.career?.jobId) sabotageTypes.push('career');
        const propEntries = target.properties instanceof Map ? [...target.properties.entries()] : Object.entries(target.properties || {});
        if (propEntries.some(([,v]) => v > 0)) sabotageTypes.push('property');
        sabotageTypes.push('money'); // always available

        const type = sabotageTypes[Math.floor(Math.random() * sabotageTypes.length)];
        let sabMsg = '';

        if (type === 'career' && target.career?.jobId) {
            // Sabotage: add a fake absence day (delays promotion, risks firing)
            target.career.daysAbsent = (target.career.daysAbsent || 0) + 2;
            target.markModified('career');
            sabMsg = `💼 Sabotaged @${targetId}'s workplace — forged 2 absence reports. Their promotion track is delayed!`;
        } else if (type === 'property') {
            // Destroy a small portion of property income by faking a maintenance emergency
            const fine = iC(Math.floor(5000 + Math.random() * 20000));
            target.money = Math.max(0, (target.money || 0) - fine);
            sabMsg = `🏠 Sabotaged @${targetId}'s property — triggered a fake maintenance emergency costing them ${fmtMoney(fine)}!`;
            logFinancial(target, `Sabotage damage from @${pId}`, -fine);
        } else {
            // Pickpocket-style cash drain
            const stolen = Math.floor(iC(2000 + Math.random() * 8000));
            const actual = Math.min(stolen, target.money || 0);
            target.money = Math.max(0, (target.money || 0) - actual);
            p.money      = (p.money || 0) + actual;
            sabMsg = `💸 Sabotaged @${targetId} — pickpocketed *${fmtMoney(actual)}* in the chaos!`;
            logFinancial(p, `Sabotage earnings from @${targetId}`, actual);
            logFinancial(target, `Sabotage loss from @${pId}`, -actual);
        }

        // Notoriety gain in current city
        if (!p.cityNotoriety) p.cityNotoriety = {};
        const city = normLoc(p.location);
        p.cityNotoriety[city] = Math.min(100, (p.cityNotoriety[city] || 0) + 5);
        p.markModified('cityNotoriety');

        await p.save(); await target.save();
        logAction(p, `Sabotaged @${targetId} (${type})`);
        return conn.sendMessage(from, {
            text: [`💀 *SABOTAGE SUCCESSFUL!*`, ``, sabMsg, ``, `🌡️ Crime heat +15 | +5 City Rep`].join('\n'),
            mentions: [toJid(targetId)]
        }, { quoted: mek });
    } catch(e) { console.error('sabotage error', e); }
});

