// =============================================================================
cast({ pattern: 'socialrep', desc: 'socialrep — Your social reputation and top social players', category: 'rpg', filename: __filename }, async (conn, mek, m, { sender, from }) => {
    try {
        const pId = await getPlayerId(conn, sender);
        const p   = await getOrCreatePlayer(pId);
        const top = await Player.find({ socialRep: { $gt: 0 } }).sort({ socialRep: -1 }).limit(10).exec();

        const repRank = (r) => r >= 200 ? '👑 Legend' : r >= 100 ? '🌟 Celebrity' : r >= 50 ? '💛 Respected' : r >= 20 ? '👤 Known' : '❓ Nobody';
        const medals  = ['🥇','🥈','🥉','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣','🔟'];

        const lines = [
            `💛 *SOCIAL REPUTATION*`, ``,
            `Your rep: *${p.socialRep || 0}* — ${repRank(p.socialRep || 0)}`,
            ``, `*Top 10 Most Respected:*`, ``
        ];
        top.forEach((pl, i) => lines.push(`${medals[i]} *${pl.username || pl._id}* — ${pl.socialRep} rep (${repRank(pl.socialRep)})`));
        lines.push(``, `Earn rep by: gifting items, tutoring, protecting, trading, completing quests`);
        return conn.sendMessage(from, { text: lines.join('\n') }, { quoted: mek });
    } catch(e) { console.error('socialrep error', e); }
});

