// SHOP DAILY STOCK REFILL
// Every day at midnight UTC, all shop items refill to maxStock.
// This creates a daily race — fastest buyers can resell at markup on the market.
// =============================================================================
(function scheduleShopRefill() {
    function msUntilMidnight() {
        const now2 = new Date();
        const midnight = new Date(now2);
        midnight.setUTCHours(24, 0, 0, 0);
        return midnight - now2;
    }

    async function doShopRefill() {
        try {
            if (mongoose.connection.readyState !== 1) return;
            // Reset ALL shop items to their maxStock
            const result = await ShopItem.updateMany(
                {},
                [{ $set: { stock: '$maxStock' } }]
            ).exec();
            console.log(`✅ Daily shop refill — ${result.modifiedCount} items restocked`);
            if (global.wwGameChat) {
                await broadcastToGame(
                    `🛒 *DAILY SHOP RESTOCK!*\n\nAll shop items have refilled to max stock!\n⚡ *First come, first served — buy now and resell on the market!*\n\nBrowse: *shop* | Resell: *listitem <id> <qty> <price>*`
                ).catch(() => {});
            }
        } catch(e) { console.error('Shop refill error:', e); }
        // Schedule next refill in 24h
        setTimeout(doShopRefill, 24 * 60 * 60 * 1000);
    }

    // First run at next midnight, then every 24h
    setTimeout(doShopRefill, msUntilMidnight());
    console.log(`⏰ Shop refill scheduled in ${Math.round(msUntilMidnight()/60000)} min`);
})();

// AUTONOMOUS CHILD NPC TICK — runs every 3 minutes
// Uses IDENTICAL formulas to real player commands.
// Every reward, damage, steal, career pay and crime fine uses the
// same live functions (liveJobPay, liveCrimeReward, getGearBonuses,
// calcDmg, hospitalTime, getCareerDailyPay, applyVAT) so numbers
// are always consistent with what human players see.
setInterval(async () => {
    try {
        if (mongoose.connection.readyState !== 1) return;
        if (!global.wwGameChat) return;

        const children = await Player.find({ isChildNpc: true }).exec();
        if (!children.length) return;

        const STATS  = ['strength','defense','speed','dexterity'];
        const CITIES = (Array.isArray(LOCATIONS) ? LOCATIONS : Object.values(LOCATIONS||{})).filter(l => !l.type && l.name && l.id).map(l => l.name);
        const RELATIONSHIP_NAMES_M = ['Zion','Kade','Remi','Blaze','Ace','Dex','Neo','Kai'];
        const RELATIONSHIP_NAMES_F = ['Nova','Skye','Zara','Luna','Aisha','Jade','Raya','Vee'];

        // Inline calcDmg and hospitalTime (same as real attack command)
        function _calcDmg(offensePower, defensePower, targetMaxHp, dexBonus) {
            const ratio = offensePower / Math.max(1, defensePower);
            const rng   = 0.82 + Math.random() * 0.36;
            const pct   = ratio >= 20 ? 1.0
                        : ratio >= 10 ? 0.60 + ((ratio-10)/10)*0.40
                        : ratio >= 5  ? 0.35 + ((ratio-5)/5)*0.25
                        : ratio >= 2  ? 0.18 + ((ratio-2)/3)*0.17
                        : Math.max(0.05, 0.04 + (ratio-0.5)*0.093);
            const hpDmg = Math.floor(targetMaxHp * pct * rng);
            let displayDmg = ratio >= 10 ? Math.floor(offensePower*0.22*rng)
                : ratio >= 5 ? Math.floor(hpDmg*(1-(ratio-5)/5) + (offensePower*0.22*rng)*((ratio-5)/5))
                : hpDmg;
            const crit = Math.random() < (dexBonus / (dexBonus + 200));
            if (crit) { const m = 1.20+Math.random()*0.30; return { dmg: Math.floor(displayDmg*m), hpDmg: Math.floor(hpDmg*m), crit: true }; }
            return { dmg: displayDmg, hpDmg, crit: false };
        }
        function _hospTime(rawDmg, maxHp) {
            return Math.min(30, Math.max(2, 2 + Math.floor((rawDmg / Math.max(1, maxHp)) * 28)));
        }

        for (const cp of children) {
            if (cp.jailedUntil && cp.jailedUntil > Date.now()) continue;

            let changed = false;
            const announcements = [];
            const displayName = (cp.username || 'Child').split(' ')[0] || cp.username || 'Child';

            // Passive regen
            if ((cp.energy||0) < (cp.maxEnergy||100)) { cp.energy = Math.min(cp.maxEnergy||100, (cp.energy||0)+20); changed = true; }
            if ((cp.health||0) < (cp.maxHealth||100)) { cp.health = Math.min(cp.maxHealth||100, (cp.health||0)+10); changed = true; }
            if ((cp.energy||0) < 10) { if (changed) await cp.save().catch(()=>{}); continue; }

            // Equal-weight action pool — every real player activity has a fair shot
            // 20 actions × ~5% each = even spread across all gameplay pillars
            const ACTIONS = [
                'train',       // stat gains (str/def/spd/dex)
                'work',        // JOBS array jobs
                'crime',       // CRIMES array crimes
                'heist',       // ADVANCED_CRIMES
                'career',      // clockin for career pay
                'factioncrime',// faction crime with crew
                'race',        // street race entry
                'gangrob',     // start/join gang rob
                'rob',         // solo rob a player
                'pvp',         // 1v1 attack
                'bankrob',     // bank robbery (high risk)
                'hustle',      // street hustle flip
                'hunt',        // hunt animals in city
                'beg',         // beg for small cash
                'obby',        // obstacle course (stats)
                'scratch',     // scratch card lottery
                'gamble',      // casino wager
                'gear',        // buy weapon/armor
                'property',    // buy income property
                'degree',      // earn a school degree
                'travel',      // fly to another city
                'faction',     // join parent's faction
                'relationship',// dating life
                'chat',        // talk in group
            ];
            const action = ACTIONS[Math.floor(Math.random() * ACTIONS.length)];

            // ── TRAIN — exact same formula as `train` command ──────────────
            if (action === 'train') {
                const stat = STATS[Math.floor(Math.random()*STATS.length)];
                const levelMult   = 1 + ((cp.level||1)-1) * 0.10;
                const prestigeMult= 1 + ((cp.prestigeLevel||0)) * 0.05;
                let gain = Math.max(1, Math.floor((1+Math.floor(Math.random()*2)) * levelMult * prestigeMult));
                cp[stat] = (cp[stat]||0) + gain;
                cp.energy = Math.max(0, (cp.energy||0)-10);
                cp.totalTrains = (cp.totalTrains||0)+1;
                changed = true;
                announcements.push(`🏋️ *${displayName}* trained *${stat}* +${gain} → ${cp[stat]}`);
            }

            // ── WORK — real JOBS array + liveJobPay ───────────────────────
            else if (action === 'work') {
                const eligible = JOBS.filter(j => (cp.level||1) >= (j.levelReq||1) && (cp.energy||0) >= j.energy);
                if (eligible.length) {
                    const job = eligible[Math.floor(Math.random()*eligible.length)];
                    const { min, max } = liveJobPay(job.rewardMin, job.rewardMax);
                    const grossPay = min + Math.floor(Math.random()*(max-min+1));
                    const { net: pay, vat } = applyVAT(grossPay);
                    cp.money = (cp.money||0) + pay;
                    cp.energy = Math.max(0,(cp.energy||0)-job.energy);
                    cp.jobsDone = (cp.jobsDone||0)+1;
                    cp.totalEarned = (cp.totalEarned||0)+pay;
                    cp.exp = (cp.exp||0)+(4+Math.floor(Math.random()*8)); // matches real work command
                    logFinancial(cp, `Job: ${job.name}`, pay);
                    changed = true;
                    announcements.push(`💼 *${displayName}* worked as *${job.name}* and earned *${fmtMoney(pay)}*${vat>0?` (after ${fmtMoney(vat)} tax)`:''}`);
                }
            }

            // ── CRIME — real CRIMES array + liveCrimeReward + applyVAT ────
            else if (action === 'crime') {
                const eligible = CRIMES.filter(c => (cp.energy||0) >= c.energy);
                if (eligible.length) {
                    const crime = eligible[Math.floor(Math.random()*eligible.length)];
                    const failed = Math.random() < crime.failChance;
                    if (!failed) {
                        const { min, max } = liveCrimeReward(crime.rewardMin, crime.rewardMax);
                        const grossReward = min + Math.floor(Math.random()*(max-min+1));
                        const { net: reward, vat } = applyVAT(grossReward);
                        cp.money = (cp.money||0)+reward;
                        cp.energy = Math.max(0,(cp.energy||0)-crime.energy);
                        cp.crimesDone = (cp.crimesDone||0)+1;
                        cp.crimeLevel = Math.min(100,(cp.crimeLevel||0)+10);
                        cp.exp = (cp.exp||0)+(5+Math.floor(Math.random()*15)); // matches real crime
                        cp.totalEarned = (cp.totalEarned||0)+reward;
                        logFinancial(cp, `Crime: ${crime.name}`, reward);
                        changed = true;
                        announcements.push(`🦹 *${displayName}* pulled off *${crime.name}* and got *${fmtMoney(reward)}*! 😈`);
                    } else {
                        // Caught — same consequences as real players
                        const fine = Math.floor(crime.rewardMin * 0.3 * (0.8+Math.random()*0.4));
                        const jailMins = 2 + Math.floor(Math.random()*8);
                        cp.money = Math.max(0,(cp.money||0)-fine);
                        cp.energy = Math.max(0,(cp.energy||0)-crime.energy);
                        cp.jailedUntil = Date.now() + jailMins*60*1000;
                        cp.inJail = true;
                        logFinancial(cp, `Crime failed — fine: ${crime.name}`, -fine);
                        changed = true;
                        announcements.push(`🚔 *${displayName}* got *caught* doing *${crime.name}*! Fined *${fmtMoney(fine)}*, jailed *${jailMins} min*.`);
                    }
                }
            }

            // ── CAREER — real COMPANIES/CAREER_JOBS + getCareerDailyPay ──
            else if (action === 'career') {
                if (!cp.career?.jobId) {
                    // Auto-assign a career based on degrees or stat
                    const companyIds = Object.keys(COMPANIES);
                    const affordable = companyIds.filter(cId => {
                        const company = COMPANIES[cId];
                        const job     = CAREER_JOBS[company.jobId];
                        if (!job) return false;
                        const playerQual = getPlayerQualLevel(cp, job.field);
                        return playerQual >= job.minQual;
                    });
                    const pool = affordable.length ? affordable : companyIds.filter(cId => {
                        const j = CAREER_JOBS[COMPANIES[cId]?.jobId];
                        return j && j.minQual === 0;
                    });
                    if (pool.length) {
                        const chosenId  = pool[Math.floor(Math.random()*pool.length)];
                        const company   = COMPANIES[chosenId];
                        const job       = CAREER_JOBS[company.jobId];
                        cp.career = { companyId: chosenId, jobId: company.jobId, rank: 1, lastClockIn: 0, daysWorked: 0, totalEarned: 0 };
                        cp.markModified('career');
                        changed = true;
                        announcements.push(`💼 *${displayName}* got hired at *${company.name}* as *${job?.name || company.jobId}*!`);
                    }
                } else {
                    // Clockin — same 24hr cycle as real players
                    const lastClock = cp.career.lastClockIn || 0;
                    if (Date.now() - lastClock >= 24*60*60*1000) {
                        const dailyPay = getCareerDailyPay(cp);
                        if (dailyPay > 0) {
                            const { net: pay, vat } = applyVAT(dailyPay);
                            cp.money = (cp.money||0)+pay;
                            cp.totalEarned = (cp.totalEarned||0)+pay;
                            cp.career.lastClockIn = Date.now();
                            cp.career.daysWorked  = (cp.career.daysWorked||0)+1;
                            cp.career.totalEarned = (cp.career.totalEarned||0)+pay;
                            logFinancial(cp, `Career: ${COMPANIES[cp.career.companyId]?.name} clockin`, pay);
                            cp.markModified('career');
                            changed = true;
                            if (Math.random() < 0.30) {
                                const company = COMPANIES[cp.career.companyId];
                                announcements.push(`💼 *${displayName}* clocked in at *${company?.name}* and earned *${fmtMoney(pay)}*`);
                            }
                        }
                    }
                }
            }

            // ── DEGREE — real SCHOOL_COURSES + intelligence requirement ───
            else if (action === 'degree') {
                const intel = cp.intelligence || 0;
                const hourSince = (Date.now()-(cp.lastAutoDegree||0))/(60*60*1000);
                if (intel >= 8 && hourSince >= 1 && (cp.degrees||[]).length < 4) {
                    const courseIds = Object.keys(SCHOOL_COURSES);
                    const available = courseIds.filter(cId => {
                        const existing = (cp.degrees||[]).find(d=>d.startsWith(cId+'_'));
                        const currLvl  = existing ? parseInt(existing.split('_')[1]) : 0;
                        return currLvl < 4;
                    });
                    if (available.length) {
                        const cId     = available[Math.floor(Math.random()*available.length)];
                        const course  = SCHOOL_COURSES[cId];
                        const existing = (cp.degrees||[]).find(d=>d.startsWith(cId+'_'));
                        const currLvl  = existing ? parseInt(existing.split('_')[1]) : 0;
                        const nextLvl  = currLvl + 1;
                        cp.degrees = [...(cp.degrees||[]).filter(d=>!d.startsWith(cId+'_')), `${cId}_${nextLvl}`];
                        cp.intelligence = (cp.intelligence||1) + (course.intGain[nextLvl-1]||2);
                        cp.lastAutoDegree = Date.now();
                        cp.exp = (cp.exp||0)+100;
                        cp.markModified('degrees');
                        changed = true;
                        const LNAMES = ['Certificate','Diploma','Masters','PhD'];
                        announcements.push(`🎓 *${displayName}* earned a *${LNAMES[nextLvl-1]} in ${course.name}*! 📜`);
                    }
                }
            }

            // ── RELATIONSHIP — unchanged (social, not financial) ──────────
            else if (action === 'relationship') {
                if (!cp.dating) {
                    if (Math.random() < 0.25) {
                        const myGender = cp.childGender || (Math.random()<0.5?'M':'F');
                        const pGender  = myGender === 'M' ? 'F' : 'M';
                        const namePool = pGender === 'M' ? RELATIONSHIP_NAMES_M : RELATIONSHIP_NAMES_F;
                        const pName    = namePool[Math.floor(Math.random()*namePool.length)];
                        cp.dating = `npc_${pName.toLowerCase()}_${Date.now()}`;
                        cp.datingName = pName; cp.datingRole = myGender==='M'?'boyfriend':'girlfriend';
                        cp.datingStartedAt = Date.now();
                        changed = true;
                        announcements.push(`${myGender==='M'?'👦❤️👧':'👧❤️👦'} *${displayName}* is now with *${pName}*! 💑`);
                    }
                } else if (Math.random() < 0.03) {
                    const exName = cp.datingName;
                    cp.exPartners = [...(cp.exPartners||[]), { id:cp.dating, name:exName, endedAt:Date.now() }];
                    cp.dating = null; cp.datingName = null; cp.datingRole = null; cp.datingStartedAt = 0;
                    changed = true;
                    announcements.push(`💔 *${displayName}* and *${exName}* broke up...`);
                }
            }

            // ── TRAVEL — deduct real flight cost via iC ───────────────────
            else if (action === 'travel') {
                if (!cp.travelingTo) {
                    const dest = (CITIES.length ? CITIES : ['Lagos','Mexico','London','New York','Dubai']).filter(c=>c!==(cp.location||'Weirdos World'));
                    const city = dest[Math.floor(Math.random()*dest.length)];
                    const destData = (Array.isArray(LOCATIONS)?LOCATIONS:Object.values(LOCATIONS||{})).find(l=>l.name===city && !l.type);
                    const fare = destData ? iC(destData.cost||1000) : iC(1000);
                    if ((cp.money||0) >= fare) {
                        cp.money = (cp.money||0)-fare;
                        cp.location = city;
                        logFinancial(cp, `Flight to ${city}`, -fare);
                        changed = true;
                        announcements.push(`✈️ *${displayName}* flew to *${city}*!`);
                    }
                }
            }

            // ── FACTION — join parent's faction ──────────────────────────
            else if (action === 'faction') {
                if (!cp.faction && cp.parentId) {
                    const parentP = await Player.findById(cp.parentId).exec().catch(()=>null);
                    if (parentP?.faction) {
                        const f = await Faction.findById(parentP.faction).exec().catch(()=>null);
                        if (f && !f.members.includes(cp._id)) {
                            cp.faction = parentP.faction;
                            f.members.push(cp._id);
                            await f.save().catch(()=>{});
                            changed = true;
                            announcements.push(`🏢 *${displayName}* joined faction *${f.name}*!`);
                        }
                    }
                }
            }

            // ── GEAR — buy from real DEFAULT_SHOP at real iC() prices ────
            else if (action === 'gear') {
                if (!cp.equippedWeapon) {
                    const affordable = DEFAULT_SHOP.filter(s =>
                        s.type === 'weapon' &&
                        iC(s.price) <= (cp.money||0) * 0.4 &&
                        iC(s.price) > 0
                    ).sort((a,b)=>b.price-a.price);
                    if (affordable.length) {
                        const item = affordable[0];
                        const cost = iC(item.price);
                        cp.equippedWeapon = item.id;
                        cp.money = (cp.money||0)-cost;
                        logFinancial(cp, `Bought weapon: ${item.name}`, -cost);
                        changed = true;
                        announcements.push(`🔪 *${displayName}* bought *${item.name}* and equipped it!`);
                    }
                } else if (!cp.equippedArmor) {
                    const affordable = DEFAULT_SHOP.filter(s =>
                        s.type === 'armor' &&
                        iC(s.price) <= (cp.money||0) * 0.4 &&
                        iC(s.price) > 0
                    ).sort((a,b)=>b.price-a.price);
                    if (affordable.length) {
                        const item = affordable[0];
                        const cost = iC(item.price);
                        cp.equippedArmor = item.id;
                        cp.money = (cp.money||0)-cost;
                        logFinancial(cp, `Bought armor: ${item.name}`, -cost);
                        changed = true;
                        announcements.push(`🛡️ *${displayName}* bought *${item.name}* for protection!`);
                    }
                }
            }

            // ── PVP — exact same offense/defense/steal formula as attack ──
            else if (action === 'pvp') {
                if (cp.equippedWeapon && !isHospitalized(cp)) {
                    const pvpCount = await Player.countDocuments({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp.parentId||cp._id}, health:{$gt:0} }).exec().catch(()=>0);
                    const pvpSkip  = pvpCount > 0 ? Math.floor(Math.random()*pvpCount) : 0;
                    const pvpPool  = pvpCount > 0 ? await Player.find({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp.parentId||cp._id}, health:{$gt:0} }).skip(pvpSkip).limit(5).lean().exec() : [];
                    const targets  = pvpPool;
                    if (targets.length) {
                        const target = targets[Math.floor(Math.random()*targets.length)];
                        const atkGear = getGearBonuses(cp);
                        const defGear = getGearBonuses(target);
                        const atkStr  = (cp.strength||1)+atkGear.strBonus;
                        const atkDef  = (cp.defense||1)+atkGear.defBonus;
                        const atkSpd  = (cp.speed||1)+atkGear.spdBonus;
                        const atkDex  = (cp.dexterity||1)+atkGear.dexBonus;
                        const defStr  = (target.strength||1)+defGear.strBonus;
                        const defDef  = (target.defense||1)+defGear.defBonus;
                        const defSpd  = (target.speed||1)+defGear.spdBonus;
                        const defDex  = (target.dexterity||1)+defGear.dexBonus;
                        const hpFac   = Math.max(0.20, (cp.health||100)/(cp.maxHealth||100));
                        const atkOff  = (atkStr*0.45+atkDex*0.25+atkSpd*0.20+atkDef*0.10)*(1+(atkGear.atkBonus/50))*hpFac;
                        const defDef2 = (defDef*0.50+defStr*0.20+defDex*0.20+defSpd*0.10);
                        const hitChance = Math.max(0.1,Math.min(0.95,0.5+((atkSpd-defDex)/(atkSpd+defDex+1))));
                        if (Math.random() <= hitChance) {
                            const { hpDmg } = _calcDmg(atkOff, defDef2, target.maxHealth||100, atkDex);
                            const tgt = await getOrCreatePlayer(target._id).catch(()=>null);
                            if (tgt) {
                                tgt.health = Math.max(0,(tgt.health||100)-hpDmg);
                                const won = tgt.health <= 0 || atkOff > defDef2;
                                if (won) {
                                    const stealPct = 0.05+Math.random()*0.05;
                                    const grossSteal = Math.floor((tgt.money||0)*stealPct);
                                    const { net: steal } = applyVAT(grossSteal);
                                    tgt.money = Math.max(0,(tgt.money||0)-grossSteal);
                                    cp.money = (cp.money||0)+steal;
                                    cp.attacksWon = (cp.attacksWon||0)+1;
                                    tgt.attacksLost = (tgt.attacksLost||0)+1;
                                    if (tgt.health<=0) {
                                        const hospMins = _hospTime(hpDmg, tgt.maxHealth||100);
                                        tgt.jailedUntil = Date.now()+hospMins*60*1000;
                                        tgt.inJail = false;
                                    }
                                    logFinancial(cp, `Attack win vs @${tgt._id}`, steal);
                                    logFinancial(tgt, `Attacked by @${cp._id}`, -grossSteal);
                                    await tgt.save().catch(()=>{});
                                    changed = true;
                                    announcements.push(`⚔️ *${displayName}* attacked *${tgt.username||tgt._id}* and ${tgt.health<=0?'knocked them out!':'won!'}  Stole *${fmtMoney(steal)}*`);
                                } else {
                                    const defOff  = (defStr*0.45+defDex*0.25+defSpd*0.20+defDef*0.10)*(1+(defGear.atkBonus/50));
                                    const atkDef2 = (atkDef*0.50+atkStr*0.20+atkDex*0.20+atkSpd*0.10);
                                    const { hpDmg: retDmg } = _calcDmg(defOff, atkDef2, cp.maxHealth||100, defDex);
                                    cp.health = Math.max(0,(cp.health||100)-retDmg);
                                    cp.attacksLost = (cp.attacksLost||0)+1;
                                    await tgt.save().catch(()=>{});
                                    changed = true;
                                    announcements.push(`💀 *${displayName}* attacked *${tgt.username||tgt._id}* and got beaten back! -${retDmg} HP`);
                                }
                            }
                        }
                    }
                }
            }

            // ── GAMBLE — real house edge (42% win, same as wager command) ─
            else if (action === 'gamble') {
                if ((cp.money||0) >= 1000) {
                    const bet = Math.floor(Math.min((cp.money||0)*0.10, 50000));
                    const games = ['slots','coinflip','dice','highlow'];
                    const game  = games[Math.floor(Math.random()*games.length)];
                    const won   = Math.random() < 0.38; // real house edge
                    if (won) {
                        const prize = Math.floor(bet*(1+Math.random()*0.7));
                        cp.money = (cp.money||0)+prize;
                        cp.totalEarned = (cp.totalEarned||0)+prize;
                        logFinancial(cp, `Gamble win (${game})`, prize);
                        changed = true;
                        announcements.push(`🎰 *${displayName}* won *${fmtMoney(prize)}* playing *${game}*! 🤑`);
                    } else {
                        cp.money = (cp.money||0)-bet;
                        cp.moneySpent = (cp.moneySpent||0)+bet;
                        logFinancial(cp, `Gamble loss (${game})`, -bet);
                        changed = true;
                        announcements.push(`🎰 *${displayName}* lost *${fmtMoney(bet)}* playing *${game}*... 😬`);
                    }
                }
            }

            // ── PROPERTY — buy from DEFAULT_SHOP at iC() prices ──────────
            else if (action === 'property') {
                const budget = cp.money||0;
                if (budget >= 50000) {
                    const affordable = DEFAULT_SHOP.filter(s =>
                        s.type === 'property' && s.incomeRate > 0 &&
                        iC(s.price) <= budget * 0.35
                    ).sort((a,b)=>b.incomeRate-a.incomeRate);
                    if (affordable.length) {
                        const prop = affordable[0];
                        const cost = iC(prop.price);
                        const currentQty = (cp.properties instanceof Map ? cp.properties.get(prop.id) : (cp.properties||{})[prop.id]) || 0;
                        if (currentQty < 2) {
                            cp.money = (cp.money||0)-cost;
                            cp.moneySpent = (cp.moneySpent||0)+cost;
                            if (cp.properties instanceof Map) cp.properties.set(prop.id, currentQty+1);
                            else { cp.properties = cp.properties||{}; cp.properties[prop.id] = currentQty+1; }
                            cp.markModified('properties');
                            logFinancial(cp, `Bought property: ${prop.name}`, -cost);
                            changed = true;
                            announcements.push(`🏠 *${displayName}* bought *${prop.name}* for ${fmtMoney(cost)}! Earns ${fmtMoney(prop.incomeRate)}/5 min`);
                        }
                    }
                }
            }

            // ── CHAT — organic lines that reference their actual state ────
            else if (action === 'chat') {
                const money = cp.money||0;
                const loc   = cp.location||'Weirdos World';
                const lvl   = cp.level||1;
                const chatLines = [
                    `Anyone want to duel? 🤜`,
                    `Grinding in ${loc} today 💪`,
                    `Level ${lvl} and still going strong`,
                    money > 100000 ? `Sitting on ${fmtMoney(money)} rn 💰` : `Need to make more money fr`,
                    cp.equippedWeapon ? `Try me with my ${cp.equippedWeapon} 😤` : `Shopping for a weapon`,
                    `Who's on the leaderboard? 👀`,
                    `This city never sleeps`,
                    cp.faction ? `Faction life is different 🔥` : `Looking for a good faction`,
                    cp.dating ? `${cp.datingName} is everything 💕` : `Single and focused 😤`,
                    `Coming for the top spot 👑`,
                ];
                const line = chatLines[Math.floor(Math.random()*chatLines.length)];
                await broadcastToGame(`*${cp.username||displayName}:* ${line}`).catch(()=>{});
            }

            // ── HEIST — real ADVANCED_CRIMES array ───────────────────────────
            else if (action === 'heist') {
                const eligible = (ADVANCED_CRIMES||[]).filter(c => (cp.level||1) >= (c.levelReq||1) && (cp.energy||0) >= (c.energy||30));
                if (eligible.length) {
                    const crime = eligible[Math.floor(Math.random()*eligible.length)];
                    const failed = Math.random() < (crime.failChance||0.70);
                    if (!failed) {
                        const { min, max } = liveCrimeReward(crime.rewardMin||5000, crime.rewardMax||20000);
                        const gross = min + Math.floor(Math.random()*(max-min+1));
                        const { net: reward, vat } = applyVAT(gross);
                        cp.money = (cp.money||0)+reward;
                        cp.energy = Math.max(0,(cp.energy||0)-(crime.energy||30));
                        cp.crimesDone = (cp.crimesDone||0)+1;
                        cp.exp = (cp.exp||0)+(15+Math.floor(Math.random()*20)); // heist xp
                        cp.totalEarned = (cp.totalEarned||0)+reward;
                        logFinancial(cp, `Heist: ${crime.name}`, reward);
                        changed = true;
                        announcements.push(`💰 *${displayName}* pulled off *${crime.name}* and scored *${fmtMoney(reward)}*! 🎯`);
                    } else {
                        const jailMins = 5 + Math.floor(Math.random()*15);
                        cp.energy = Math.max(0,(cp.energy||0)-(crime.energy||30));
                        cp.jailedUntil = Date.now()+jailMins*60*1000;
                        cp.inJail = true;
                        changed = true;
                        announcements.push(`🚔 *${displayName}* got caught on *${crime.name}* — jailed *${jailMins} min*!`);
                    }
                }
            }

            // ── FACTION CRIME — real FACTION_CRIMES rewards ───────────────────
            else if (action === 'factioncrime') {
                if (cp.faction && (cp.energy||0) >= 25) {
                    const fc = FACTION_CRIMES[Math.floor(Math.random()*FACTION_CRIMES.length)];
                    const failed = Math.random() < 0.40;
                    if (!failed) {
                        const { min, max } = liveCrimeReward(fc.rewardMin, fc.rewardMax);
                        const gross = min + Math.floor(Math.random()*(max-min+1));
                        const perMember = Math.floor(gross / (2 + Math.floor(Math.random()*2)));
                        const { net: reward } = applyVAT(perMember);
                        cp.money = (cp.money||0)+reward;
                        cp.energy = Math.max(0,(cp.energy||0)-fc.energy);
                        cp.totalEarned = (cp.totalEarned||0)+reward;
                        cp.exp = (cp.exp||0)+(10+Math.floor(Math.random()*15)); // faction crime xp
                        logFinancial(cp, `Faction crime: ${fc.name}`, reward);
                        changed = true;
                        announcements.push(`🏢 *${displayName}* ran a *${fc.name}* with the faction and earned *${fmtMoney(reward)}*!`);
                    } else {
                        cp.energy = Math.max(0,(cp.energy||0)-fc.energy);
                        changed = true;
                        announcements.push(`🚨 *${displayName}*'s faction crew got spotted running *${fc.name}*. Aborted!`);
                    }
                }
            }

            // ── RACE — enter and auto-complete a solo race ────────────────────
            else if (action === 'race') {
                if ((cp.money||0) >= iC(5000) && (cp.energy||0) >= 15) {
                    const entryFee = iC(5000 + Math.floor(Math.random()*15000));
                    // Speed + dex determines placement (1st–5th of 5)
                    const speedRating = (cp.speed||1) + (cp.dexterity||1) + Math.random()*20;
                    const placement   = speedRating > 40 ? 1 : speedRating > 25 ? 2 : speedRating > 15 ? 3 : 4;
                    const PRIZES      = { 1: 3.0, 2: 1.5, 3: 0.8, 4: 0 }; // multiplier on entry
                    const prize       = Math.floor(entryFee * (PRIZES[placement]||0));
                    cp.money  = (cp.money||0) - entryFee + prize;
                    cp.energy = Math.max(0,(cp.energy||0)-15);
                    if (prize > 0) {
                        logFinancial(cp, `Race: placed #${placement}`, prize - entryFee);
                        cp.totalEarned = (cp.totalEarned||0)+prize;
                    } else {
                        logFinancial(cp, `Race: entry fee (no place)`, -entryFee);
                    }
                    changed = true;
                    const placeTxt = ['🥇 1st','🥈 2nd','🥉 3rd','4th'][placement-1] || '4th';
                    announcements.push(prize > 0
                        ? `🏎️ *${displayName}* finished *${placeTxt}* in a street race! Won *${fmtMoney(prize)}*!`
                        : `🏎️ *${displayName}* raced and finished *${placeTxt}* — no payout.`
                    );
                }
            }

            // ── GANGROB — initiate or join an active gang rob ─────────────────
            else if (action === 'gangrob') {
                // Join an existing session if there is one, else start one vs a RANDOM player
                const openSessions = [...(global.gangRobSessions||new Map()).entries()]
                    .filter(([,s]) => !s.executedAt && Date.now() < s.expiresAt && !s.attackers.includes(cp._id));
                if (openSessions.length && Math.random() < 0.6) {
                    const [sessKey, sess] = openSessions[Math.floor(Math.random()*openSessions.length)];
                    sess.attackers.push(cp._id);
                    changed = true;
                    announcements.push(`🤝 *${displayName}* joined a gang rob on *${sess.targetName||'someone'}*!`);
                } else {
                    // Random skip so different players get targeted each time
                    const totalTargets = await Player.countDocuments({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp._id}, health:{$gt:0} }).exec().catch(()=>0);
                    if (totalTargets > 0) {
                        const skip = Math.floor(Math.random() * totalTargets);
                        const rTarget = await Player.findOne({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp._id}, health:{$gt:0} }).skip(skip).lean().exec().catch(()=>null);
                        if (rTarget) {
                            if (!global.gangRobSessions) global.gangRobSessions = new Map();
                            const targetKey = rTarget._id.toString();
                            if (!global.gangRobSessions.has(targetKey)) {
                                global.gangRobSessions.set(targetKey, {
                                    organizerId: cp._id, targetId: rTarget._id,
                                    targetName: rTarget.username||rTarget._id,
                                    attackers: [cp._id], city: cp.location||'Weirdos World',
                                    openUntil: Date.now()+3*60*1000,
                                    expiresAt: Date.now()+3*60*1000, executedAt: 0
                                });
                                setTimeout(() => { global.gangRobSessions.delete(targetKey); }, 3*60*1000);
                                changed = true;
                                announcements.push(`🤜 *${displayName}* opened a gang rob on *${rTarget.username||rTarget._id}*! Type *gangrob @${rTarget._id}* to join!`);
                            }
                        }
                    }
                }
            }

            // ── ROB — real rob formula from economy.js mirrored ──────────────
            else if (action === 'rob') {
                if (cp.equippedWeapon && (cp.energy||0) >= 15 && !isHospitalized(cp)) {
                    const robCount = await Player.countDocuments({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp._id}, money:{$gt:1000} }).exec().catch(()=>0);
                    const rTarget = robCount > 0 ? await Player.findOne({ registered:true, isChildNpc:{$ne:true}, _id:{$ne:cp._id}, money:{$gt:1000} }).skip(Math.floor(Math.random()*robCount)).lean().exec().catch(()=>null) : null;
                    if (rTarget && rTarget.location === cp.location) {
                        const atkPow = (cp.strength||1)+(cp.speed||1)+(cp.dexterity||1)+getGearBonuses(cp).atkBonus;
                        const defPow = (rTarget.defense||1)+(rTarget.speed||1)+getGearBonuses(rTarget).defBonus;
                        const won    = atkPow * (0.8+Math.random()*0.4) > defPow * (0.8+Math.random()*0.4);
                        cp.energy = Math.max(0,(cp.energy||0)-15);
                        if (won) {
                            const stealPct  = 0.05 + Math.random()*0.10;
                            const stolen    = Math.floor((rTarget.money||0) * stealPct);
                            const tgt       = await getOrCreatePlayer(rTarget._id).catch(()=>null);
                            if (tgt && stolen > 0) {
                                tgt.money = Math.max(0,(tgt.money||0)-stolen);
                                cp.money  = (cp.money||0)+stolen;
                                cp.totalEarned = (cp.totalEarned||0)+stolen;
                                logFinancial(cp,  `Rob win vs @${tgt._id}`,  stolen);
                                logFinancial(tgt, `Robbed by @${cp._id}`,   -stolen);
                                await tgt.save().catch(()=>{});
                                changed = true;
                                announcements.push(`🔫 *${displayName}* robbed *${tgt.username||tgt._id}* and got *${fmtMoney(stolen)}*!`);
                            }
                        }
                    }
                }
            }

                        // ── BANKROB — same success formula as real command ───────────────
            else if (action === 'bankrob') {
                const guns = ['pistol','taser','ar15','goldengun','deagle','precisionrifle','shotty','smg','ak47'];
                if (guns.includes(cp.equippedWeapon) && (cp.ammo||0) > 0 && (cp.energy||0) >= 50) {
                    cp.energy -= 50; cp.ammo -= 1;
                    const power = (cp.strength||1)+(cp.speed||1)+(cp.dexterity||1);
                    if (Math.random() < Math.min(0.40, 0.10+(power/1000))) {
                        const gross = Math.floor(10000 + Math.random()*40000);
                        const { net: loot } = applyVAT(gross);
                        cp.money = (cp.money||0)+loot; cp.totalEarned = (cp.totalEarned||0)+loot;
                        cp.banksRobbed = (cp.banksRobbed||0)+1; cp.exp = (cp.exp||0)+150;
                        cp.crimeLevel = Math.min(100,(cp.crimeLevel||0)+30);
                        logFinancial(cp, `Bank robbery`, loot); changed = true;
                        announcements.push(`🏦 *${displayName}* ROBBED THE BANK and escaped with *${fmtMoney(loot)}*! 💰`);
                    } else {
                        const fine = Math.floor((cp.money||0)*0.20);
                        cp.money = Math.max(0,(cp.money||0)-fine);
                        cp.jailedUntil = Date.now()+15*60*1000; cp.inJail = true;
                        logFinancial(cp, `Bank rob failed — fined`, -fine); changed = true;
                        announcements.push(`🚔 *${displayName}* got caught robbing the bank! Jailed 15 min, fined *${fmtMoney(fine)}*`);
                    }
                }
            }

            // ── HUNT — real PREY_LIST by city, sell at market price ──────────
            else if (action === 'hunt') {
                if ((cp.energy||0) >= 15) {
                    const city = normLoc(cp.location||'Weirdos World');
                    const regionPrey = PREY_LIST.filter(a => a.region === city);
                    if (regionPrey.length) {
                        const prey = regionPrey[Math.floor(Math.random()*regionPrey.length)];
                        const power = (cp.speed||1)+(cp.strength||1)+(cp.dexterity||1)+(cp.huntingSkill||0)*2;
                        cp.energy -= 15; cp.lastHunt = Date.now();
                        if (Math.random() < power/(power+prey.difficulty)) {
                            const sellPrice = Math.floor(prey.price * (0.6+(global.ECON_INDEX||1)*0.4));
                            cp.money = (cp.money||0)+sellPrice; cp.totalEarned = (cp.totalEarned||0)+sellPrice;
                            cp.huntingSkill = (cp.huntingSkill||0)+1;
                            logFinancial(cp, `Hunt: sold ${prey.name}`, sellPrice); changed = true;
                            announcements.push(`🏹 *${displayName}* hunted a *${prey.name}* in ${cp.location||'Weirdos World'} and sold it for *${fmtMoney(sellPrice)}*!`);
                        } else {
                            changed = true; // energy used
                            announcements.push(`🏹 *${displayName}* went hunting in ${cp.location||'Weirdos World'} but came back empty-handed.`);
                        }
                    }
                }
            }

            // ── HUSTLE — real HUSTLE_GOODS + city notoriety + iC() ───────────
            else if (action === 'hustle') {
                const HUSTLE_CD = 45*60*1000;
                if ((cp.money||0) >= 1000 && Date.now()-(cp.lastHustle||0) >= HUSTLE_CD) {
                    const city = normLoc(cp.location||'Weirdos World');
                    const eligible = HUSTLE_GOODS.filter(g => !g.city || g.city === city);
                    if (eligible.length) {
                        const good = eligible[Math.floor(Math.random()*eligible.length)];
                        const cityRep = ((cp.cityNotoriety||{})[city]||0);
                        cp.lastHustle = Date.now(); cp.crimeLevel = Math.min(100,(cp.crimeLevel||0)+5);
                        if (Math.random() < Math.max(0, good.risk - cityRep/500)) {
                            const fine = Math.floor(iC(good.riskFine[0]+Math.random()*(good.riskFine[1]-good.riskFine[0])));
                            cp.money = Math.max(0,(cp.money||0)-fine);
                            logFinancial(cp, `Hustle bust (${good.name})`, -fine); changed = true;
                            announcements.push(`🚔 *${displayName}* got busted hustling *${good.name}*! Fined *${fmtMoney(fine)}*`);
                        } else {
                            const rawProfit = Math.floor(good.minProfit+Math.random()*(good.maxProfit-good.minProfit));
                            const { net } = applyVAT(iC(rawProfit));
                            cp.money = (cp.money||0)+net; cp.totalEarned = (cp.totalEarned||0)+net;
                            logFinancial(cp, `Hustle: ${good.name}`, net); changed = true;
                            if (!cp.cityNotoriety) cp.cityNotoriety = {};
                            cp.cityNotoriety[city] = (cp.cityNotoriety[city]||0)+3;
                            announcements.push(`💼 *${displayName}* flipped *${good.name}* in ${cp.location||'Weirdos World'} for *${fmtMoney(net)}*!`);
                        }
                    }
                }
            }

            // ── BEG — small cash, 20% chance of getting beat up ─────────────
            else if (action === 'beg') {
                const BEG_CD = 2*60*1000;
                if (Date.now()-(cp.lastBeg||0) >= BEG_CD) {
                    cp.lastBeg = Date.now();
                    if (Math.random() < 0.20) {
                        const dmg = Math.floor(Math.random()*15)+5;
                        cp.health = Math.max(0,(cp.health||100)-dmg); changed = true;
                    } else {
                        const gross = Math.floor(Math.random()*1500)+500;
                        const { net: amount } = applyVAT(gross);
                        cp.money = (cp.money||0)+amount; cp.totalEarned = (cp.totalEarned||0)+amount;
                        logFinancial(cp, `Begging`, amount); changed = true;
                        announcements.push(`🤲 *${displayName}* begged in ${cp.location||'Weirdos World'} and got *${fmtMoney(amount)}*`);
                    }
                }
            }

            // ── OBBY — obstacle course, trains endurance + labor ─────────────
            else if (action === 'obby') {
                const OBBY_CD = 45*60*1000;
                const OBBY_COURSES2 = {
                    'Weirdos World':{energyCost:20,endGain:[1,2],labGain:[0,1],xp:25},
                    'Lagos':{energyCost:25,endGain:[1,3],labGain:[1,2],xp:35},
                    'Mexico':{energyCost:30,endGain:[2,4],labGain:[1,2],xp:50},
                    'London':{energyCost:30,endGain:[2,4],labGain:[1,3],xp:50},
                    'New York':{energyCost:35,endGain:[2,5],labGain:[2,3],xp:65},
                    'Paris':{energyCost:35,endGain:[3,5],labGain:[2,3],xp:65},
                    'Dubai':{energyCost:40,endGain:[3,6],labGain:[2,4],xp:80},
                    'Japan':{energyCost:40,endGain:[4,7],labGain:[3,5],xp:90},
                    'Switzerland':{energyCost:50,endGain:[5,9],labGain:[4,6],xp:120},
                };
                const city2 = normLoc(cp.location||'Weirdos World');
                const course = OBBY_COURSES2[city2] || OBBY_COURSES2['Weirdos World'];
                if ((cp.energy||0) >= course.energyCost && Date.now()-(cp.cooldowns?.lastObby||0) >= OBBY_CD) {
                    cp.energy -= course.energyCost;
                    if (!cp.cooldowns) cp.cooldowns = {};
                    cp.cooldowns.lastObby = Date.now();
                    const endGain = course.endGain[0]+Math.floor(Math.random()*(course.endGain[1]-course.endGain[0]+1));
                    const labGain = course.labGain[0]+Math.floor(Math.random()*(course.labGain[1]-course.labGain[0]+1));
                    cp.endurance = (cp.endurance||0)+endGain; cp.labor = (cp.labor||0)+labGain;
                    const newHpBonus = Math.floor(cp.endurance/5); const oldHpBonus = Math.floor(((cp.endurance-endGain)/5));
                    if (newHpBonus > oldHpBonus) cp.maxHealth = (cp.maxHealth||100)+(newHpBonus-oldHpBonus); // no cap
                    cp.exp = (cp.exp||0)+course.xp; changed = true;
                    announcements.push(`🏃 *${displayName}* completed the obby in ${cp.location||'Weirdos World'}! Endurance +${endGain}, Labor +${labGain}`);
                }
            }

            // ── SCRATCH — buy a scratch card at real iC() price ──────────────
            else if (action === 'scratch') {
                const cost = iC(SCRATCH_CARD_COST);
                if ((cp.money||0) >= cost) {
                    cp.money -= cost; cp.moneySpent = (cp.moneySpent||0)+cost;
                    // Roll prize using real SCRATCH_PRIZES weights
                    const totalW = SCRATCH_PRIZES.reduce((s,p)=>s+p.weight,0);
                    let roll2 = Math.random()*totalW;
                    let prize = SCRATCH_PRIZES[SCRATCH_PRIZES.length-1];
                    for (const pr of SCRATCH_PRIZES) { if ((roll2-=pr.weight)<=0) { prize=pr; break; } }
                    if (prize.type === 'cash' && prize.value > 0) {
                        cp.money = (cp.money||0)+prize.value; cp.totalEarned = (cp.totalEarned||0)+prize.value;
                        logFinancial(cp, `Scratch card win`, prize.value-cost); changed = true;
                        announcements.push(`🎟️ *${displayName}* scratched a card and won *${fmtMoney(prize.value)}*! 🎉`);
                    } else if (prize.type === 'jackpot') {
                        cp.money = (cp.money||0)+prize.value; cp.totalEarned = (cp.totalEarned||0)+prize.value;
                        logFinancial(cp, `Scratch card JACKPOT!`, prize.value); changed = true;
                        announcements.push(`🌟 *${displayName}* hit the *SCRATCH CARD JACKPOT* — *${fmtMoney(prize.value)}*!!! 🤑`);
                    } else {
                        logFinancial(cp, `Scratch card (no win)`, -cost); changed = true;
                    }
                }
            }

                        // ── Level up — same XP formula as real players ────────────────
            const xpNeeded = (cp.level||1)*100;
            if ((cp.exp||0) >= xpNeeded) {
                cp.level = (cp.level||1)+1;
                cp.maxHealth = Math.min(200,(cp.maxHealth||100)+5);
                cp.maxEnergy = Math.min(150,(cp.maxEnergy||100)+2);
                changed = true;
                announcements.push(`⭐ *${displayName}* leveled up to *Level ${cp.level}*! 🎉`);
            }

            if (changed) await cp.save().catch(e=>console.error('child tick save error:',e));

            if (announcements.length && global.wwGameChat) {
                const msg = announcements[Math.floor(Math.random()*announcements.length)];
                await broadcastToGame(msg).catch(()=>{});
            }
        }
    } catch(e) { console.error('Autonomous child tick error:', e); }
}, 3 * 60 * 1000); // every 3 minutes


// =============================================================================
// STARTUP: Auto-register all existing active players
// Players who played before the 'registered' field existed have registered:false
// or no registered field at all. This migration marks them as registered so they
// appear in leaderboards and gamestats without needing to re-run joinrpg.
// "Active" = has a username set AND either has money, level>1, or any stat>3.
// Ghost accounts (no username, no activity) stay unregistered.
// Safe to run on every restart — only touches accounts that need it.
// =============================================================================
setImmediate(async () => {
    try {
        await new Promise(res => setTimeout(res, 4000)); // wait for mongoose
        if (mongoose.connection.readyState !== 1) return;

        const result = await Player.updateMany(
            {
                registered: { $ne: true },        // not already registered
                isChildNpc: { $ne: true },         // not a child NPC
                username:   { $exists: true, $nin: [null, '', undefined] }, // has a username
                $or: [
                    { level:        { $gt: 1 } },
                    { money:        { $gt: 0 } },
                    { bank:         { $gt: 0 } },
                    { strength:     { $gt: 3 } },
                    { crimesDone:   { $gt: 0 } },
                    { totalEarned:  { $gt: 0 } },
                    { attacksWon:   { $gt: 0 } },
                ]
            },
            { $set: { registered: true } }
        ).exec();

        if (result.modifiedCount > 0) {
            console.log(`✅ Startup migration: auto-registered ${result.modifiedCount} existing active players.`);
        } else {
            console.log(`✅ Startup migration: all active players already registered.`);
        }
    } catch(e) {
        console.error('Auto-register migration error:', e);
    }
});
// These accumulate when syncChildToCoparents pushes invalid child subdocs.
// Runs once on bot start — safe to run repeatedly (idempotent).
// =============================================================================
setImmediate(async () => {
    try {
        await new Promise(res => setTimeout(res, 5000)); // wait for mongoose
        if (mongoose.connection.readyState !== 1) return;

        // Find all players who have children named 'Baby' with bornAt=0 or missing
        const players = await Player.find({
            'children.0': { $exists: true } // only players who have children
        }).exec();

        let cleaned = 0, removedTotal = 0;
        for (const p of players) {
            const before = (p.children||[]).length;
            // Remove ghost entries: name is 'Baby' AND bornAt is 0/missing
            p.children = (p.children||[]).filter(c =>
                c.name && c.name !== 'Baby' && c.bornAt && c.bornAt > 0
            );
            const removed = before - p.children.length;
            if (removed > 0) {
                p.markModified('children');
                await p.save().catch(e => console.error('cleanup save error:', e));
                cleaned++;
                removedTotal += removed;
            }
        }
        if (removedTotal > 0) {
            console.log(`🧹 Startup cleanup: removed ${removedTotal} ghost "Baby" children from ${cleaned} player accounts.`);
        } else {
            console.log(`✅ Startup cleanup: no ghost children found.`);
        }
    } catch(e) {
        console.error('Ghost children cleanup error:', e);
    }
});

console.log('✅ Weirdos World RPG V29 — All systems active');
